fn render_format_value(
    value: &Value,
    conversion: Option<FormatConversion>,
    format_spec: Option<&str>,
) -> Result<String, String> {
    match conversion {
        None if format_spec.map_or(true, str::is_empty) => str_value_checked(value),
        None => Ok(value.to_string()),
        Some(FormatConversion::Str) => str_value_checked(value),
        Some(FormatConversion::Repr) => repr_value_checked(value),
        Some(FormatConversion::Ascii) => ascii_repr_value_checked(value),
    }
}

fn format_builtin_value(
    value: &Value,
    conversion: Option<FormatConversion>,
    format_spec: Option<&str>,
) -> Result<String, String> {
    let rendered = render_format_value(value, conversion, format_spec)?;
    apply_format_spec(value, &rendered, conversion.is_some(), format_spec)
}

fn repr_value(value: &Value) -> String {
    let mut active = HashSet::new();
    repr_value_inner(value, &mut active)
}

fn str_value_checked(value: &Value) -> Result<String, String> {
    match value {
        Value::String(value) => Ok(value.clone()),
        Value::BigInt(value) => repr_big_int_checked(value),
        Value::List(_)
        | Value::Tuple(_)
        | Value::Set(_)
        | Value::FrozenSet(_)
        | Value::Dict(_)
        | Value::UserDict { .. }
        | Value::ScopeDict(_)
        | Value::SimpleNamespace { .. } => repr_value_checked(value),
        value => Ok(value.to_string()),
    }
}

fn repr_value_checked(value: &Value) -> Result<String, String> {
    let mut active = HashSet::new();
    repr_value_inner_checked(value, &mut active)
}

fn repr_value_inner_checked(value: &Value, active: &mut HashSet<usize>) -> Result<String, String> {
    match value {
        Value::String(value) => Ok(repr_string(value)),
        Value::Bytes(value) => Ok(repr_bytes(value)),
        Value::ByteArray(value) => Ok(format!("bytearray({})", repr_bytes(value))),
        Value::List(items) => {
            let ptr = Rc::as_ptr(items) as usize;
            if !active.insert(ptr) {
                return Ok("[...]".to_string());
            }
            let items = items.borrow();
            let rendered = items
                .iter()
                .map(|item| repr_value_inner_checked(item, active))
                .collect::<Result<Vec<_>, _>>()?
                .join(", ");
            active.remove(&ptr);
            Ok(format!("[{rendered}]"))
        }
        Value::Tuple(items) => repr_tuple_checked(items, active),
        Value::Set(items) => {
            let ptr = Rc::as_ptr(items) as usize;
            if !active.insert(ptr) {
                return Ok("{...}".to_string());
            }
            let items = items.borrow();
            let rendered = if items.is_empty() {
                "set()".to_string()
            } else {
                format!(
                    "{{{}}}",
                    items
                        .iter()
                        .map(|item| repr_value_inner_checked(item, active))
                        .collect::<Result<Vec<_>, _>>()?
                        .join(", ")
                )
            };
            active.remove(&ptr);
            Ok(rendered)
        }
        Value::FrozenSet(items) => {
            let ptr = Rc::as_ptr(items) as usize;
            if !active.insert(ptr) {
                return Ok("frozenset({...})".to_string());
            }
            let rendered = if items.is_empty() {
                "frozenset()".to_string()
            } else {
                format!(
                    "frozenset({{{}}})",
                    items
                        .iter()
                        .map(|item| repr_value_inner_checked(item, active))
                        .collect::<Result<Vec<_>, _>>()?
                        .join(", ")
                )
            };
            active.remove(&ptr);
            Ok(rendered)
        }
        Value::Dict(entries) => {
            let ptr = Rc::as_ptr(entries) as usize;
            if !active.insert(ptr) {
                return Ok("{...}".to_string());
            }
            let entries = entries.borrow();
            let rendered = entries
                .iter()
                .map(|(key, value)| {
                    Ok(format!(
                        "{}: {}",
                        repr_value_inner_checked(key, active)?,
                        repr_value_inner_checked(value, active)?
                    ))
                })
                .collect::<Result<Vec<_>, String>>()?
                .join(", ");
            active.remove(&ptr);
            Ok(format!("{{{rendered}}}"))
        }
        Value::UserDict { data } => {
            let ptr = Rc::as_ptr(data) as usize;
            if !active.insert(ptr) {
                return Ok("UserDict({...})".to_string());
            }
            let entries = data.borrow();
            let rendered = entries
                .iter()
                .map(|(key, value)| {
                    Ok(format!(
                        "{}: {}",
                        repr_value_inner_checked(key, active)?,
                        repr_value_inner_checked(value, active)?
                    ))
                })
                .collect::<Result<Vec<_>, String>>()?
                .join(", ");
            active.remove(&ptr);
            Ok(format!("UserDict({{{rendered}}})"))
        }
        Value::ScopeDict(scope) => {
            let entries = scope_dict_entries(scope);
            let rendered = entries
                .iter()
                .map(|(key, value)| {
                    Ok(format!(
                        "{}: {}",
                        repr_value_inner_checked(key, active)?,
                        repr_value_inner_checked(value, active)?
                    ))
                })
                .collect::<Result<Vec<_>, String>>()?
                .join(", ");
            Ok(format!("{{{rendered}}}"))
        }
        Value::SimpleNamespace { fields } => repr_simple_namespace_checked(fields, active),
        Value::Exception {
            type_name, args, ..
        } => Ok(format!("{type_name}{}", repr_exception_args_checked(args)?)),
        Value::AstNode { .. } => ast_repr_value_checked(value),
        Value::BigInt(value) => repr_big_int_checked(value),
        _ => Ok(repr_value(value)),
    }
}

fn repr_tuple_checked(items: &[Value], active: &mut HashSet<usize>) -> Result<String, String> {
    match items {
        [] => Ok("()".to_string()),
        [item] => Ok(format!("{},", repr_value_inner_checked(item, active)?))
            .map(|rendered| format!("({rendered})")),
        items => Ok(format!(
            "({})",
            items
                .iter()
                .map(|item| repr_value_inner_checked(item, active))
                .collect::<Result<Vec<_>, _>>()?
                .join(", ")
        )),
    }
}

fn repr_simple_namespace_checked(
    fields: &DictRef,
    active: &mut HashSet<usize>,
) -> Result<String, String> {
    let ptr = Rc::as_ptr(fields) as usize;
    if !active.insert(ptr) {
        return Ok("namespace(...)".to_string());
    }

    let fields = fields.borrow();
    let rendered = fields
        .iter()
        .filter_map(|(key, value)| match key {
            Value::String(name) => {
                Some(repr_value_inner_checked(value, active).map(|value| format!("{name}={value}")))
            }
            _ => None,
        })
        .collect::<Result<Vec<_>, _>>()?
        .join(", ");
    active.remove(&ptr);
    Ok(format!("namespace({rendered})"))
}

fn repr_exception_args_checked(args: &[Value]) -> Result<String, String> {
    Ok(match args {
        [] => "()".to_string(),
        [value] => format!("({})", repr_value_checked(value)?),
        values => {
            let rendered = values
                .iter()
                .map(repr_value_checked)
                .collect::<Result<Vec<_>, _>>()?
                .join(", ");
            format!("({rendered})")
        }
    })
}

fn repr_big_int_checked(value: &BigInt) -> Result<String, String> {
    let digits = value.abs().to_str_radix(10);
    let max_digits = get_int_max_str_digits();
    if max_digits != 0 && digits.len() > max_digits {
        return Err(int_string_conversion_limit_error(max_digits, digits.len()));
    }

    if value.is_negative() {
        Ok(format!("-{digits}"))
    } else {
        Ok(digits)
    }
}

