fn import_from(module: Value, name: &str) -> Result<Value, String> {
    match module {
        Value::Module {
            name: module_name,
            attrs,
        } => attrs.borrow().get(name).cloned().ok_or_else(|| {
            format!("ImportError: cannot import name '{name}' from '{module_name}'")
        }),
        value => Err(format!(
            "ImportError: cannot import name '{name}' from {value}"
        )),
    }
}

fn normalize_class_bases(bases: Vec<Value>) -> Result<Vec<Value>, String> {
    let mut normalized = Vec::new();

    for base in bases {
        match base {
            Value::Class { .. } => normalized.push(base),
            Value::Builtin(name) if is_class_like_builtin(&name) => {
                normalized.push(Value::Builtin(name));
            }
            Value::GenericAlias { origin, .. } => match *origin {
                Value::Class { .. } => normalized.push(*origin),
                Value::Builtin(name) if is_class_like_builtin(&name) => {
                    normalized.push(Value::Builtin(name));
                }
                origin => {
                    return Err(format!("class base must be a class, got {origin}"));
                }
            },
            value => {
                return Err(format!("class base must be a class, got {value}"));
            }
        }
    }

    Ok(normalized)
}

fn validate_type_constructor_bases(bases: &[Value]) -> Result<(), String> {
    let mut builtin_layout_bases = 0;
    for base in bases {
        if let Value::Builtin(name) = base {
            if is_final_builtin_type(name) {
                return Err(format!(
                    "TypeError: type '{name}' is not an acceptable base type"
                ));
            }
            if builtin_has_instance_layout(name) {
                builtin_layout_bases += 1;
            }
        }
    }

    if builtin_layout_bases > 1 {
        return Err("TypeError: multiple bases have instance lay-out conflict".to_string());
    }

    Ok(())
}

fn is_final_builtin_type(name: &str) -> bool {
    matches!(
        name,
        "bool" | "mappingproxy" | "Template" | "Interpolation" | "TemplateIter"
    )
}

fn builtin_has_instance_layout(name: &str) -> bool {
    matches!(
        name,
        "int"
            | "str"
            | "bytes"
            | "bytearray"
            | "list"
            | "dict"
            | "tuple"
            | "set"
            | "frozenset"
            | "float"
            | "complex"
            | "range"
            | "slice"
            | "SimpleNamespace"
    )
}

fn class_base_value(bases: &[Value]) -> Value {
    bases
        .first()
        .cloned()
        .unwrap_or_else(|| Value::Builtin("object".to_string()))
}

fn class_name_value(class_name: &str, attrs: &Scope) -> Value {
    attrs
        .borrow()
        .get(CLASS_NAME_ATTR)
        .cloned()
        .unwrap_or_else(|| Value::String(class_name.to_string()))
}

fn class_qualname_value(class_name: &str, attrs: &Scope) -> Value {
    attrs
        .borrow()
        .get(CLASS_QUALNAME_ATTR)
        .cloned()
        .unwrap_or_else(|| Value::String(class_name.to_string()))
}

fn function_qualname_value(function_name: &str, owner_class: Option<&Value>) -> Value {
    let Some(Value::Class {
        name: class_name,
        attrs,
        ..
    }) = owner_class
    else {
        return Value::String(function_name.to_string());
    };

    let Value::String(owner_qualname) = class_qualname_value(class_name, attrs) else {
        return Value::String(function_name.to_string());
    };
    Value::String(format!("{owner_qualname}.{function_name}"))
}

fn function_module_value(owner_class: Option<&Value>) -> Value {
    let Some(Value::Class { attrs, .. }) = owner_class else {
        return Value::String("__main__".to_string());
    };

    attrs
        .borrow()
        .get("__module__")
        .cloned()
        .unwrap_or_else(|| Value::String("__main__".to_string()))
}

fn class_dict_value(attrs: &Scope) -> Value {
    let mut entries = attrs
        .borrow()
        .iter()
        .filter(|(name, _)| !name.starts_with('\0'))
        .map(|(name, value)| (Value::String(name.clone()), value.clone()))
        .collect::<Vec<_>>();
    if !entries
        .iter()
        .any(|(key, _)| matches!(key, Value::String(name) if name == "__module__"))
    {
        entries.push((
            Value::String("__module__".to_string()),
            Value::String("__main__".to_string()),
        ));
    }
    if !entries
        .iter()
        .any(|(key, _)| matches!(key, Value::String(name) if name == "__doc__"))
    {
        entries.push((Value::String("__doc__".to_string()), Value::None));
    }
    dict_value(entries)
}

fn class_annotations_value(attrs: &Scope) -> Value {
    attrs
        .borrow()
        .get("__annotations__")
        .cloned()
        .unwrap_or_else(|| dict_value(Vec::new()))
}

fn mapping_proxy_from_entries(entries: Vec<(Value, Value)>) -> Value {
    mapping_proxy_value(Rc::new(RefCell::new(DictStorage::new(entries))))
}

fn scope_dict_value(scope: &Scope) -> Value {
    dict_value(scope_dict_entries(scope))
}

fn compile_int_argument(value: Value, name: &str) -> Result<i64, String> {
    match value {
        Value::Number(value) => Ok(value),
        Value::Bool(value) => Ok(bool_as_i64(value)),
        Value::BigInt(value) => value
            .to_i64()
            .ok_or_else(|| format!("OverflowError: compile() {name} is too large")),
        value => Err(format!(
            "TypeError: compile() {name} must be an integer, not {}",
            type_name(&value)
        )),
    }
}

fn call_sys_get_int_max_str_digits(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if !keywords.is_empty() {
        return Err("get_int_max_str_digits() does not accept keyword arguments".to_string());
    }
    if !args.is_empty() {
        return Err(format!(
            "get_int_max_str_digits() takes no arguments ({} given)",
            args.len()
        ));
    }

    Ok(Value::Number(get_int_max_str_digits() as i64))
}

fn call_sys_set_int_max_str_digits(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if !keywords.is_empty() {
        return Err("set_int_max_str_digits() does not accept keyword arguments".to_string());
    }
    if args.len() != 1 {
        return Err(format!(
            "set_int_max_str_digits() takes exactly one argument ({} given)",
            args.len()
        ));
    }

    let maxdigits = match args.into_iter().next().expect("length checked") {
        Value::Number(value) if value >= 0 => value as usize,
        Value::Bool(value) => bool_as_i64(value) as usize,
        Value::BigInt(value) if !value.is_negative() => value
            .to_usize()
            .ok_or_else(|| "ValueError: maxdigits is too large".to_string())?,
        Value::Number(_) | Value::BigInt(_) => {
            return Err("ValueError: maxdigits must be non-negative".to_string());
        }
        value => {
            return Err(format!(
                "TypeError: 'maxdigits' must be an integer, not {}",
                type_name(&value)
            ));
        }
    };

    set_int_max_str_digits(maxdigits)?;
    Ok(Value::None)
}

fn call_dis_get_instructions(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if !keywords.is_empty() {
        return Err("TypeError: get_instructions() does not accept keyword arguments".to_string());
    }
    if args.len() != 1 {
        return Err(format!(
            "TypeError: get_instructions() expected 1 argument, got {}",
            args.len()
        ));
    }

    let code = args.into_iter().next().expect("length checked");
    let Value::CodeObject {
        mode, instructions, ..
    } = code
    else {
        return Err(format!(
            "TypeError: don't know how to disassemble {} objects",
            type_name(&code)
        ));
    };

    let mut rows = Vec::new();
    for instruction in instructions {
        if let Instruction::LoadConst { value, .. } = instruction {
            rows.push(dis_instruction_value(DIS_LOAD_CONST_OPCODE, value)?);
        }
    }

    if mode == CodeMode::Exec {
        rows.push(dis_instruction_value(DIS_LOAD_CONST_OPCODE, Value::None)?);
    }

    Ok(list_value(rows))
}

fn dis_instruction_value(opcode: i64, argval: Value) -> Result<Value, String> {
    Ok(Value::SimpleNamespace {
        fields: dict_ref_from_entries(vec![
            (Value::String("opcode".to_string()), Value::Number(opcode)),
            (Value::String("argval".to_string()), argval),
        ])?,
    })
}

fn compile_source_text(source: Value) -> Result<String, String> {
    match source {
        Value::String(source) => Ok(source),
        Value::Bytes(bytes) | Value::ByteArray(bytes) => {
            decode_source_for_parse(&bytes).map_err(|message| format!("SyntaxError: {message}"))
        }
        value => Err(format!(
            "TypeError: compile() arg 1 must be a string, bytes or bytearray, not {}",
            type_name(&value)
        )),
    }
}

fn code_mode_from_string(mode: &str) -> Result<CodeMode, String> {
    match mode {
        "exec" => Ok(CodeMode::Exec),
        "eval" => Ok(CodeMode::Eval),
        "single" => Ok(CodeMode::Single),
        _ => Err(format!(
            "ValueError: compile() mode must be 'exec', 'eval' or 'single'"
        )),
    }
}

fn compile_code_object(source: Value, filename: String, mode: &str) -> Result<Value, String> {
    let mode = code_mode_from_string(mode)?;
    let instructions = match source {
        Value::AstNode { .. } => compile_ast_code_object(&source, mode)?,
        source => compile_source_code_object(source, mode)?,
    };

    Ok(Value::CodeObject {
        mode,
        filename,
        instructions,
        identity: Rc::new(()),
    })
}

fn compile_source_code_object(source: Value, mode: CodeMode) -> Result<Vec<Instruction>, String> {
    let source = compile_source_text(source)?;
    Ok(match mode {
        CodeMode::Exec => {
            let tokens =
                lex_for_parse(&source).map_err(|message| format!("SyntaxError: {message}"))?;
            let program = parse(&tokens).map_err(|message| format!("SyntaxError: {message}"))?;
            compile(&program).map_err(|message| format!("SyntaxError: {message}"))?
        }
        CodeMode::Eval => {
            let source = source.trim();
            let tokens =
                lex_for_parse(source).map_err(|message| format!("SyntaxError: {message}"))?;
            let expr = parse_eval(&tokens).map_err(|message| format!("SyntaxError: {message}"))?;
            compile_eval(&expr).map_err(|message| format!("SyntaxError: {message}"))?
        }
        CodeMode::Single => {
            let tokens =
                lex_for_parse(&source).map_err(|message| format!("SyntaxError: {message}"))?;
            let program =
                parse_interactive(&tokens).map_err(|message| format!("SyntaxError: {message}"))?;
            compile_interactive(&program).map_err(|message| format!("SyntaxError: {message}"))?
        }
    })
}

fn compile_ast_code_object(node: &Value, mode: CodeMode) -> Result<Vec<Instruction>, String> {
    match mode {
        CodeMode::Exec => {
            let program = syntax_program_from_ast_module(node)?;
            compile(&program).map_err(|message| format!("SyntaxError: {message}"))
        }
        CodeMode::Eval => {
            let expr = syntax_expr_from_ast_expression(node)?;
            compile_eval(&expr).map_err(|message| format!("SyntaxError: {message}"))
        }
        CodeMode::Single => {
            let program = syntax_program_from_ast_interactive(node)?;
            compile_interactive(&program).map_err(|message| format!("SyntaxError: {message}"))
        }
    }
}

fn syntax_program_from_ast_module(node: &Value) -> Result<syntax::Program, String> {
    ast_compile_expect_kind(node, "Module")?;
    Ok(syntax::Program {
        statements: ast_compile_stmt_list_field(node, "body")?,
    })
}

fn syntax_program_from_ast_interactive(node: &Value) -> Result<syntax::Program, String> {
    ast_compile_expect_kind(node, "Interactive")?;
    Ok(syntax::Program {
        statements: ast_compile_stmt_list_field(node, "body")?,
    })
}

fn syntax_expr_from_ast_expression(node: &Value) -> Result<syntax::Expr, String> {
    ast_compile_expect_kind(node, "Expression")?;
    ast_compile_expr(&ast_compile_required_field(node, "body")?)
}

fn ast_compile_stmt(node: &Value) -> Result<syntax::Stmt, String> {
    let _guard = AstCompileRecursionGuard::enter(node)?;
    ast_compile_validate_explicit_location_numbers(node)?;
    match ast_node_kind(node) {
        Some("Pass") => Ok(syntax::Stmt::Pass),
        Some("Expr") => Ok(syntax::Stmt::Expr(ast_compile_expr(
            &ast_compile_required_field(node, "value")?,
        )?)),
        Some("Assign") => Ok(syntax::Stmt::Assign {
            targets: ast_compile_nonempty_target_list_field(node, "targets", "Assign", "Store")?,
            value: ast_compile_expr(&ast_compile_required_field(node, "value")?)?,
        }),
        Some("AnnAssign") => Ok(syntax::Stmt::AnnAssign {
            target: ast_compile_target(&ast_compile_required_field(node, "target")?)?,
            annotation: ast_compile_expr(&ast_compile_required_field(node, "annotation")?)?,
            value: ast_compile_optional_expr_field(node, "value")?,
            simple: ast_compile_boolish_field(node, "simple")?,
        }),
        Some("TypeAlias") => Ok(syntax::Stmt::TypeAlias {
            name: ast_compile_name_target_field(node, "name")?,
            type_params: ast_compile_type_params_field(node, "type_params")?,
            value: ast_compile_expr(&ast_compile_required_field(node, "value")?)?,
        }),
        Some("AugAssign") => Ok(syntax::Stmt::AugAssign {
            target: ast_compile_target(&ast_compile_required_field(node, "target")?)?,
            op: ast_compile_binary_op(&ast_compile_required_field(node, "op")?)?,
            value: ast_compile_expr(&ast_compile_required_field(node, "value")?)?,
        }),
        Some("Delete") => Ok(syntax::Stmt::Delete {
            target: ast_compile_delete_targets_field(node, "targets")?,
        }),
        Some("FunctionDef") => Ok(syntax::Stmt::FunctionDef {
            name: ast_compile_string_field(node, "name")?,
            type_params: ast_compile_type_params_field(node, "type_params")?,
            params: ast_compile_arguments(&ast_compile_required_field(node, "args")?)?,
            body: ast_compile_nonempty_stmt_list_field(node, "body", "FunctionDef")?,
            decorators: ast_compile_expr_list_field(node, "decorator_list")?,
            returns: ast_compile_optional_expr_field(node, "returns")?,
        }),
        Some("AsyncFunctionDef") => Ok(syntax::Stmt::AsyncFunctionDef {
            name: ast_compile_string_field(node, "name")?,
            type_params: ast_compile_type_params_field(node, "type_params")?,
            params: ast_compile_arguments(&ast_compile_required_field(node, "args")?)?,
            body: ast_compile_nonempty_stmt_list_field(node, "body", "AsyncFunctionDef")?,
            decorators: ast_compile_expr_list_field(node, "decorator_list")?,
            returns: ast_compile_optional_expr_field(node, "returns")?,
        }),
        Some("ClassDef") => Ok(syntax::Stmt::ClassDef {
            name: ast_compile_string_field(node, "name")?,
            type_params: ast_compile_type_params_field(node, "type_params")?,
            bases: ast_compile_call_args_field(node, "bases")?,
            keywords: ast_compile_call_keywords_field(node, "keywords")?,
            body: ast_compile_nonempty_stmt_list_field(node, "body", "ClassDef")?,
            decorators: ast_compile_expr_list_field(node, "decorator_list")?,
        }),
        Some("Import") => Ok(syntax::Stmt::Import {
            is_lazy: ast_compile_boolish_field(node, "is_lazy")?,
            aliases: ast_compile_nonempty_import_aliases_field(node, "names", "Import")?,
        }),
        Some("ImportFrom") => {
            let (targets, level) = ast_compile_import_from_fields(node)?;
            Ok(syntax::Stmt::ImportFrom {
                is_lazy: ast_compile_boolish_field(node, "is_lazy")?,
                module: ast_compile_optional_string_field(node, "module")?,
                level,
                targets,
            })
        }
        Some("Return") => Ok(syntax::Stmt::Return(ast_compile_optional_expr_field(
            node, "value",
        )?)),
        Some("Global") => Ok(syntax::Stmt::Global(
            ast_compile_string_list_field(node, "names")
                .and_then(|names| ast_compile_nonempty_string_list(names, "Global"))?,
        )),
        Some("Nonlocal") => Ok(syntax::Stmt::Nonlocal(
            ast_compile_string_list_field(node, "names")
                .and_then(|names| ast_compile_nonempty_string_list(names, "Nonlocal"))?,
        )),
        Some("Assert") => Ok(syntax::Stmt::Assert {
            condition: ast_compile_expr(&ast_compile_required_field(node, "test")?)?,
            message: ast_compile_optional_expr_field(node, "msg")?,
        }),
        Some("Raise") => {
            let value = ast_compile_optional_expr_field(node, "exc")?;
            let cause = ast_compile_optional_expr_field(node, "cause")?;
            if value.is_none() && cause.is_some() {
                return Err("ValueError: Raise with cause but no exception".to_string());
            }
            Ok(syntax::Stmt::Raise { value, cause })
        }
        Some("If") => Ok(syntax::Stmt::If {
            condition: ast_compile_expr(&ast_compile_required_field(node, "test")?)?,
            then_body: ast_compile_nonempty_stmt_list_field(node, "body", "If")?,
            else_body: ast_compile_stmt_list_field(node, "orelse")?,
        }),
        Some("Match") => Ok(syntax::Stmt::Match {
            subject: ast_compile_expr(&ast_compile_required_field(node, "subject")?)?,
            cases: ast_compile_match_cases_field(node, "cases")?,
        }),
        Some("While") => Ok(syntax::Stmt::While {
            condition: ast_compile_expr(&ast_compile_required_field(node, "test")?)?,
            body: ast_compile_nonempty_stmt_list_field(node, "body", "While")?,
            else_body: ast_compile_stmt_list_field(node, "orelse")?,
        }),
        Some("For") => Ok(syntax::Stmt::For {
            target: ast_compile_target(&ast_compile_required_field(node, "target")?)?,
            iter: ast_compile_expr(&ast_compile_required_field(node, "iter")?)?,
            body: ast_compile_nonempty_stmt_list_field(node, "body", "For")?,
            else_body: ast_compile_stmt_list_field(node, "orelse")?,
        }),
        Some("With") => Ok(syntax::Stmt::With {
            items: ast_compile_nonempty_with_items_field(node, "items", "With")?,
            body: ast_compile_nonempty_stmt_list_field(node, "body", "With")?,
        }),
        Some("Try") => ast_compile_try_stmt(node, false),
        Some("TryStar") => ast_compile_try_stmt(node, true),
        Some("AsyncWith") => Ok(syntax::Stmt::AsyncWith {
            items: ast_compile_nonempty_with_items_field(node, "items", "AsyncWith")?,
            body: ast_compile_nonempty_stmt_list_field(node, "body", "AsyncWith")?,
        }),
        Some("AsyncFor") => Ok(syntax::Stmt::AsyncFor {
            target: ast_compile_target(&ast_compile_required_field(node, "target")?)?,
            iter: ast_compile_expr(&ast_compile_required_field(node, "iter")?)?,
            body: ast_compile_nonempty_stmt_list_field(node, "body", "AsyncFor")?,
            else_body: ast_compile_stmt_list_field(node, "orelse")?,
        }),
        Some("Break") => Ok(syntax::Stmt::Break),
        Some("Continue") => Ok(syntax::Stmt::Continue),
        None if matches!(node, Value::None) => Err("ValueError: None disallowed".to_string()),
        Some(kind) => Err(format!(
            "TypeError: compile() does not yet support AST statement {kind}"
        )),
        None => Err(format!(
            "TypeError: expected AST statement, got {}",
            type_name(node)
        )),
    }
}

fn ast_compile_expr(node: &Value) -> Result<syntax::Expr, String> {
    let _guard = AstCompileRecursionGuard::enter(node)?;
    ast_compile_validate_explicit_location_numbers(node)?;
    match ast_node_kind(node) {
        None if matches!(node, Value::None) => Err("ValueError: None disallowed".to_string()),
        Some("Constant") => ast_compile_constant_expr(&ast_compile_required_field(node, "value")?),
        Some("Name") => {
            ast_compile_validate_context(node, "Load")?;
            Ok(syntax::Expr::Name(ast_compile_name_identifier_field(
                node, "id",
            )?))
        }
        Some("Attribute") => {
            ast_compile_validate_context(node, "Load")?;
            Ok(syntax::Expr::Attribute {
                object: Box::new(ast_compile_expr(&ast_compile_required_field(
                    node, "value",
                )?)?),
                name: ast_compile_string_field(node, "attr")?,
            })
        }
        Some("BinOp") => Ok(syntax::Expr::Binary {
            left: Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "left",
            )?)?),
            op: ast_compile_binary_op(&ast_compile_required_field(node, "op")?)?,
            right: Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "right",
            )?)?),
        }),
        Some("UnaryOp") => Ok(syntax::Expr::Unary {
            op: ast_compile_unary_op(&ast_compile_required_field(node, "op")?)?,
            operand: Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "operand",
            )?)?),
        }),
        Some("BoolOp") => ast_compile_bool_op_expr(node),
        Some("Compare") => ast_compile_compare_expr(node),
        Some("Call") => ast_compile_call_expr(node),
        Some("List") => {
            ast_compile_validate_context(node, "Load")?;
            Ok(syntax::Expr::List(ast_compile_expr_list_field(
                node, "elts",
            )?))
        }
        Some("Tuple") => {
            ast_compile_validate_context(node, "Load")?;
            Ok(syntax::Expr::Tuple(ast_compile_expr_list_field(
                node, "elts",
            )?))
        }
        Some("Set") => Ok(syntax::Expr::Set(ast_compile_expr_list_field(
            node, "elts",
        )?)),
        Some("Dict") => ast_compile_dict_expr(node),
        Some("NamedExpr") => Ok(syntax::Expr::NamedExpr {
            name: ast_compile_name_target_field(node, "target")?,
            value: Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "value",
            )?)?),
        }),
        Some("Yield") => Ok(syntax::Expr::Yield {
            value: ast_compile_optional_expr_field(node, "value")?.map(Box::new),
        }),
        Some("YieldFrom") => Ok(syntax::Expr::YieldFrom(Box::new(ast_compile_expr(
            &ast_compile_required_ast_field(node, "value")?,
        )?))),
        Some("Await") => Ok(syntax::Expr::Await(Box::new(ast_compile_expr(
            &ast_compile_required_field(node, "value")?,
        )?))),
        Some("Starred") => {
            ast_compile_validate_context(node, "Load")?;
            Ok(syntax::Expr::Starred(Box::new(ast_compile_expr(
                &ast_compile_required_field(node, "value")?,
            )?)))
        }
        Some("ListComp") => Ok(syntax::Expr::ListComp {
            clauses: ast_compile_comprehension_clauses_field(node, "generators")?,
            element: Box::new(ast_compile_expr(&ast_compile_required_field(node, "elt")?)?),
        }),
        Some("SetComp") => Ok(syntax::Expr::SetComp {
            clauses: ast_compile_comprehension_clauses_field(node, "generators")?,
            element: Box::new(ast_compile_expr(&ast_compile_required_field(node, "elt")?)?),
        }),
        Some("GeneratorExp") => Ok(syntax::Expr::GeneratorComp {
            clauses: ast_compile_comprehension_clauses_field(node, "generators")?,
            element: Box::new(ast_compile_expr(&ast_compile_required_field(node, "elt")?)?),
        }),
        Some("DictComp") => {
            let clauses = ast_compile_comprehension_clauses_field(node, "generators")?;
            let value = Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "value",
            )?)?);
            match ast_compile_required_field(node, "key")? {
                Value::None => Ok(syntax::Expr::DictUnpackComp { value, clauses }),
                key => Ok(syntax::Expr::DictComp {
                    key: Box::new(ast_compile_expr(&key)?),
                    value,
                    clauses,
                }),
            }
        }
        Some("IfExp") => Ok(syntax::Expr::IfExpression {
            condition: Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "test",
            )?)?),
            then_branch: Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "body",
            )?)?),
            else_branch: Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "orelse",
            )?)?),
        }),
        Some("Subscript") => {
            ast_compile_validate_context(node, "Load")?;
            Ok(syntax::Expr::Subscript {
                object: Box::new(ast_compile_expr(&ast_compile_required_field(
                    node, "value",
                )?)?),
                index: Box::new(ast_compile_expr(&ast_compile_required_field(
                    node, "slice",
                )?)?),
            })
        }
        Some("Slice") => Ok(syntax::Expr::SliceLiteral {
            start: ast_compile_optional_expr_field(node, "lower")?.map(Box::new),
            stop: ast_compile_optional_expr_field(node, "upper")?.map(Box::new),
            step: ast_compile_optional_expr_field(node, "step")?.map(Box::new),
        }),
        Some("Lambda") => Ok(syntax::Expr::Lambda {
            params: ast_compile_arguments(&ast_compile_required_field(node, "args")?)?,
            body: Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "body",
            )?)?),
        }),
        Some("JoinedStr") => Ok(syntax::Expr::JoinedString(ast_compile_fstring_parts_field(
            node, "values",
        )?)),
        Some("TemplateStr") => Ok(syntax::Expr::TemplateString(
            ast_compile_template_string_parts_field(node, "values")?,
        )),
        Some("expr") => Err("TypeError: expected some sort of expr, but got expr()".to_string()),
        Some(kind) => Err(format!(
            "TypeError: compile() does not yet support AST expression {kind}"
        )),
        None => Err(format!(
            "TypeError: expected AST expression, got {}",
            type_name(node)
        )),
    }
}

fn ast_compile_constant_expr(value: &Value) -> Result<syntax::Expr, String> {
    match value {
        Value::Number(value) => Ok(syntax::Expr::Number(*value)),
        Value::BigInt(value) => Ok(syntax::Expr::BigInt(value.to_string())),
        Value::Float(value) => Ok(syntax::Expr::Float(value.to_string())),
        Value::Complex { real, imag } if *real == 0.0 => {
            Ok(syntax::Expr::Imaginary(imag.to_string()))
        }
        Value::String(value) => Ok(syntax::Expr::String(value.clone())),
        Value::Bytes(value) => Ok(syntax::Expr::Bytes(value.clone())),
        Value::Bool(value) => Ok(syntax::Expr::Bool(*value)),
        Value::None => Ok(syntax::Expr::None),
        Value::Ellipsis => Ok(syntax::Expr::Ellipsis),
        Value::Tuple(items) => Ok(syntax::Expr::Tuple(
            items
                .iter()
                .map(ast_compile_constant_expr)
                .collect::<Result<Vec<_>, _>>()?,
        )),
        Value::FrozenSet(items) => Ok(syntax::Expr::FrozenSet(
            items
                .iter()
                .map(ast_compile_constant_expr)
                .collect::<Result<Vec<_>, _>>()?,
        )),
        value => Err(format!(
            "TypeError: got an invalid type in Constant: {}",
            ast_constant_type_name(value)
        )),
    }
}

fn ast_constant_type_name(value: &Value) -> &str {
    match value {
        Value::Builtin(name) if is_class_like_builtin(name) => "type",
        _ => type_name(value),
    }
}

fn ast_compile_bool_op_expr(node: &Value) -> Result<syntax::Expr, String> {
    let op = ast_compile_logical_op(&ast_compile_required_field(node, "op")?)?;
    let values = ast_compile_list_field(node, "values")?;
    if values.len() < 2 {
        return Err("ValueError: BoolOp with less than 2 values".to_string());
    }
    let values = values
        .into_iter()
        .map(|value| ast_compile_expr(&value))
        .collect::<Result<Vec<_>, _>>()?;
    let mut values = values.into_iter();
    let first = values.next().expect("BoolOp length validated");
    Ok(values.fold(first, |left, right| syntax::Expr::Logical {
        left: Box::new(left),
        op: op.clone(),
        right: Box::new(right),
    }))
}

fn ast_compile_compare_expr(node: &Value) -> Result<syntax::Expr, String> {
    let left = ast_compile_expr(&ast_compile_required_field(node, "left")?)?;
    let ops = ast_compile_list_field(node, "ops")?
        .into_iter()
        .map(|op| ast_compile_comparison_op(&op))
        .collect::<Result<Vec<_>, _>>()?;
    let comparators = ast_compile_list_field(node, "comparators")?;
    if comparators.is_empty() {
        return Err("ValueError: Compare with no comparators".to_string());
    }
    if ops.len() != comparators.len() {
        return Err(
            "ValueError: Compare has a different number of comparators and operands".to_string(),
        );
    }
    let comparators = comparators
        .into_iter()
        .map(|comparator| ast_compile_expr(&comparator))
        .collect::<Result<Vec<_>, _>>()?;

    if ops.len() == 1 {
        Ok(syntax::Expr::Comparison {
            left: Box::new(left),
            op: ops[0].clone(),
            right: Box::new(comparators.into_iter().next().unwrap()),
        })
    } else {
        Ok(syntax::Expr::ChainedComparison {
            left: Box::new(left),
            comparisons: ops.into_iter().zip(comparators).collect(),
        })
    }
}

fn ast_compile_call_expr(node: &Value) -> Result<syntax::Expr, String> {
    let callee = Box::new(ast_compile_expr(&ast_compile_required_field(
        node, "func",
    )?)?);
    let args = ast_compile_call_args_field(node, "args")?;
    let keywords = ast_compile_call_keywords_field(node, "keywords")?;
    if keywords.is_empty()
        && args
            .iter()
            .all(|arg| matches!(arg, syntax::CallArg::Expr(_)))
    {
        return Ok(syntax::Expr::Call {
            callee,
            args: args
                .into_iter()
                .map(|arg| match arg {
                    syntax::CallArg::Expr(expr) => expr,
                    syntax::CallArg::Unpack(_) => unreachable!(),
                })
                .collect(),
        });
    }

    Ok(syntax::Expr::UnpackCall {
        callee,
        args,
        keywords,
    })
}

fn ast_compile_call_args_field(node: &Value, field: &str) -> Result<Vec<syntax::CallArg>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(ast_compile_call_arg)
        .collect()
}

fn ast_compile_call_arg(node: Value) -> Result<syntax::CallArg, String> {
    if ast_node_kind(&node) == Some("Starred") {
        ast_compile_validate_context(&node, "Load")?;
        let value = ast_compile_expr(&ast_compile_required_ast_field(&node, "value")?)?;
        return Ok(syntax::CallArg::Unpack(value));
    }
    Ok(syntax::CallArg::Expr(ast_compile_expr(&node)?))
}

fn ast_compile_dict_expr(node: &Value) -> Result<syntax::Expr, String> {
    let keys = ast_compile_list_field(node, "keys")?;
    let values = ast_compile_list_field(node, "values")?;
    if keys.len() != values.len() {
        return Err("ValueError: Dict doesn't have the same number of keys as values".to_string());
    }

    let items = keys
        .into_iter()
        .zip(values)
        .map(|(key, value)| {
            let value = ast_compile_expr(&value)?;
            if matches!(key, Value::None) {
                Ok(syntax::DictItem::Unpack(value))
            } else {
                Ok(syntax::DictItem::Entry {
                    key: ast_compile_expr(&key)?,
                    value,
                })
            }
        })
        .collect::<Result<Vec<_>, String>>()?;
    Ok(syntax::Expr::Dict(items))
}

fn ast_compile_target(node: &Value) -> Result<syntax::Target, String> {
    ast_compile_target_with_context(node, "Store")
}

fn ast_compile_target_with_context(node: &Value, expected: &str) -> Result<syntax::Target, String> {
    let _guard = AstCompileRecursionGuard::enter(node)?;
    ast_compile_validate_explicit_location_numbers(node)?;
    match ast_node_kind(node) {
        None if matches!(node, Value::None) => Err("ValueError: None disallowed".to_string()),
        Some("Name") => {
            ast_compile_validate_context(node, expected)?;
            Ok(syntax::Target::Name(ast_compile_name_identifier_field(
                node, "id",
            )?))
        }
        Some("Constant") => {
            Err("ValueError: expression which can't be assigned to in Store context".to_string())
        }
        Some("Attribute") => {
            ast_compile_validate_context(node, expected)?;
            Ok(syntax::Target::Attribute {
                object: Box::new(ast_compile_expr(&ast_compile_required_field(
                    node, "value",
                )?)?),
                name: ast_compile_string_field(node, "attr")?,
            })
        }
        Some("Subscript") => {
            ast_compile_validate_context(node, expected)?;
            ast_compile_subscript_target(node, expected)
        }
        Some("Tuple") => {
            ast_compile_validate_context(node, expected)?;
            Ok(syntax::Target::Tuple(
                ast_compile_target_list_field_with_context(node, "elts", expected)?,
            ))
        }
        Some("List") => {
            ast_compile_validate_context(node, expected)?;
            Ok(syntax::Target::List(
                ast_compile_target_list_field_with_context(node, "elts", expected)?,
            ))
        }
        Some("Starred") => {
            ast_compile_validate_context(node, expected)?;
            Ok(syntax::Target::Starred(Box::new(
                ast_compile_target_with_context(
                    &ast_compile_required_field(node, "value")?,
                    expected,
                )?,
            )))
        }
        Some(kind) => Err(format!(
            "TypeError: compile() does not yet support AST target {kind}"
        )),
        None => Err(format!(
            "TypeError: expected AST target, got {}",
            type_name(node)
        )),
    }
}

fn ast_compile_subscript_target(node: &Value, _expected: &str) -> Result<syntax::Target, String> {
    let object = Box::new(ast_compile_expr(&ast_compile_required_field(
        node, "value",
    )?)?);
    let slice = ast_compile_required_field(node, "slice")?;
    if ast_node_kind(&slice) == Some("Slice") {
        return Ok(syntax::Target::Slice {
            object,
            start: ast_compile_optional_expr_field(&slice, "lower")?,
            stop: ast_compile_optional_expr_field(&slice, "upper")?,
            step: ast_compile_optional_expr_field(&slice, "step")?,
        });
    }

    Ok(syntax::Target::Subscript {
        object,
        index: ast_compile_expr(&slice)?,
    })
}

fn ast_compile_arguments(node: &Value) -> Result<syntax::FunctionParams, String> {
    ast_compile_expect_kind(node, "arguments")?;
    let mut positional_only = ast_compile_param_list_field(node, "posonlyargs")?;
    let mut positional = ast_compile_param_list_field(node, "args")?;
    let defaults = ast_compile_list_field(node, "defaults")?;
    if defaults.len() > positional_only.len() + positional.len() {
        return Err("ValueError: more positional defaults than args".to_string());
    }
    let positional_default_start = positional_only.len() + positional.len() - defaults.len();
    for (index, default) in defaults.into_iter().enumerate() {
        let param_index = positional_default_start + index;
        let default = ast_compile_expr(&default)?;
        if param_index < positional_only.len() {
            positional_only[param_index].default = Some(default);
        } else {
            positional[param_index - positional_only.len()].default = Some(default);
        }
    }

    let mut keyword_only = ast_compile_param_list_field(node, "kwonlyargs")?;
    let keyword_defaults = ast_compile_list_field(node, "kw_defaults")?;
    if keyword_defaults.len() != keyword_only.len() {
        return Err("ValueError: length of kwonlyargs is not the same as kw_defaults".to_string());
    }
    for (param, default) in keyword_only.iter_mut().zip(keyword_defaults) {
        if !matches!(default, Value::None) {
            param.default = Some(ast_compile_expr(&default)?);
        }
    }

    let (vararg, vararg_annotation) =
        ast_compile_optional_arg_name_annotation(&ast_compile_required_field(node, "vararg")?)?;
    let (kwarg, kwarg_annotation) =
        ast_compile_optional_arg_name_annotation(&ast_compile_required_field(node, "kwarg")?)?;

    Ok(syntax::FunctionParams {
        positional_only,
        positional,
        vararg,
        vararg_annotation,
        keyword_only,
        kwarg,
        kwarg_annotation,
    })
}

fn ast_compile_param_list_field(node: &Value, field: &str) -> Result<Vec<syntax::Param>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|arg| {
            let (name, annotation) = ast_compile_arg_name_annotation(&arg)?;
            Ok(syntax::Param {
                name,
                annotation: annotation.map(|expr| *expr),
                default: None,
            })
        })
        .collect()
}

fn ast_compile_optional_arg_name_annotation(
    node: &Value,
) -> Result<(Option<String>, Option<Box<syntax::Expr>>), String> {
    if matches!(node, Value::None) {
        return Ok((None, None));
    }
    let (name, annotation) = ast_compile_arg_name_annotation(node)?;
    Ok((Some(name), annotation))
}

fn ast_compile_arg_name_annotation(
    node: &Value,
) -> Result<(String, Option<Box<syntax::Expr>>), String> {
    ast_compile_expect_kind(node, "arg")?;
    let name = ast_compile_string_field(node, "arg")?;
    let annotation = ast_compile_optional_expr_field(node, "annotation")?.map(Box::new);
    Ok((name, annotation))
}

fn ast_compile_call_keywords_field(
    node: &Value,
    field: &str,
) -> Result<Vec<syntax::CallKeyword>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(ast_compile_call_keyword)
        .collect()
}

fn ast_compile_call_keyword(node: Value) -> Result<syntax::CallKeyword, String> {
    ast_compile_expect_kind(&node, "keyword")?;
    let value = ast_compile_expr(&ast_compile_required_ast_field(&node, "value")?)?;
    match ast_compile_required_field(&node, "arg")? {
        Value::String(name) => Ok(syntax::CallKeyword::Named(name, value)),
        Value::None => Ok(syntax::CallKeyword::Unpack(value)),
        arg => Err(format!(
            "TypeError: keyword arg must be str or None, not {}",
            type_name(&arg)
        )),
    }
}

fn ast_compile_import_aliases_field(
    node: &Value,
    field: &str,
) -> Result<Vec<syntax::ImportAlias>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|alias| {
            ast_compile_expect_kind(&alias, "alias")?;
            Ok(syntax::ImportAlias {
                name: ast_compile_string_field(&alias, "name")?,
                asname: ast_compile_optional_string_field(&alias, "asname")?,
            })
        })
        .collect()
}

fn ast_compile_import_from_fields(
    node: &Value,
) -> Result<(syntax::ImportFromTargets, usize), String> {
    let aliases = ast_compile_nonempty_import_aliases_field(node, "names", "ImportFrom")?;
    let targets = match aliases.as_slice() {
        [alias] if alias.name == "*" => syntax::ImportFromTargets::Star,
        _ => syntax::ImportFromTargets::Aliases(aliases),
    };
    let level = match ast_compile_required_field(node, "level")? {
        Value::Number(level) if level >= 0 => level as usize,
        Value::Number(_) => return Err("ValueError: Negative ImportFrom level".to_string()),
        Value::None => 0,
        value => {
            return Err(format!(
                "TypeError: ImportFrom level must be a non-negative int, not {}",
                type_name(&value)
            ));
        }
    };
    Ok((targets, level))
}

fn ast_compile_validate_explicit_location_numbers(node: &Value) -> Result<(), String> {
    let Value::AstNode { kind, attrs, .. } = node else {
        return Ok(());
    };
    if !ast_kind_supports_location(kind) {
        return Ok(());
    }

    let lineno = ast_compile_location_number_field(attrs, "lineno")?;
    let col_offset = ast_compile_location_number_field(attrs, "col_offset")?;
    let end_lineno = ast_compile_location_number_field(attrs, "end_lineno")?;
    let end_col_offset = ast_compile_location_number_field(attrs, "end_col_offset")?;

    if let (Some(lineno), Some(end_lineno)) = (lineno, end_lineno) {
        if lineno > end_lineno {
            return Err(format!(
                "ValueError: AST node line range ({lineno}, {end_lineno}) is not valid"
            ));
        }

        if lineno < 0 && end_lineno != lineno {
            return Err(format!(
                "ValueError: AST node column range ({}, {}) for line range ({lineno}, {end_lineno}) is not valid",
                col_offset.unwrap_or(0),
                end_col_offset.unwrap_or(0),
            ));
        }

        if let (Some(col_offset), Some(end_col_offset)) = (col_offset, end_col_offset) {
            if col_offset < 0 && col_offset != end_col_offset {
                return Err(format!(
                    "ValueError: AST node column range ({col_offset}, {end_col_offset}) for line range ({lineno}, {end_lineno}) is not valid"
                ));
            }

            if lineno == end_lineno && col_offset > end_col_offset {
                return Err(format!(
                    "ValueError: line {lineno}, column {col_offset}-{end_col_offset} is not a valid range"
                ));
            }
        }
    } else if let (Some(col_offset), Some(end_col_offset)) = (col_offset, end_col_offset) {
        if col_offset < 0 && col_offset != end_col_offset {
            return Err(format!(
                "ValueError: AST node column range ({col_offset}, {end_col_offset}) for line range ({}, {}) is not valid",
                lineno.unwrap_or(0),
                end_lineno.unwrap_or(0),
            ));
        }
    }

    Ok(())
}

fn ast_compile_location_number_field(attrs: &DictRef, name: &str) -> Result<Option<i64>, String> {
    match lookup_string_key(attrs, name) {
        Some(Value::None) if matches!(name, "lineno" | "col_offset") => {
            Err("ValueError: invalid integer value: None".to_string())
        }
        Some(Value::None) => Ok(None),
        Some(Value::Number(value)) => Ok(Some(value)),
        Some(Value::Bool(value)) => Ok(Some(bool_as_i64(value))),
        Some(value) => Err(format!("ValueError: invalid integer value: {value}")),
        None => Ok(None),
    }
}

fn ast_compile_type_params_field(
    node: &Value,
    field: &str,
) -> Result<Vec<syntax::TypeParam>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|type_param| {
            let kind = match ast_node_kind(&type_param) {
                Some("TypeVar") => syntax::TypeParamKind::TypeVar,
                Some("TypeVarTuple") => syntax::TypeParamKind::TypeVarTuple,
                Some("ParamSpec") => syntax::TypeParamKind::ParamSpec,
                Some(kind) => {
                    return Err(format!("TypeError: unsupported type parameter node {kind}"));
                }
                None => {
                    return Err(format!(
                        "TypeError: expected type parameter, got {}",
                        type_name(&type_param)
                    ));
                }
            };
            let bound = if matches!(kind, syntax::TypeParamKind::TypeVar) {
                ast_compile_optional_expr_field(&type_param, "bound")?
            } else {
                None
            };
            Ok(syntax::TypeParam {
                kind,
                name: ast_compile_string_field(&type_param, "name")?,
                bound,
                default: ast_compile_optional_expr_field(&type_param, "default_value")?,
            })
        })
        .collect()
}

fn ast_compile_comprehension_clauses_field(
    node: &Value,
    field: &str,
) -> Result<Vec<syntax::ComprehensionClause>, String> {
    let clauses = ast_compile_list_field(node, field)?;
    if clauses.is_empty() {
        return Err("ValueError: comprehension with no generators".to_string());
    }
    clauses
        .into_iter()
        .map(|clause| {
            ast_compile_expect_kind(&clause, "comprehension")?;
            Ok(syntax::ComprehensionClause {
                is_async: ast_compile_boolish_field(&clause, "is_async")?,
                target: ast_compile_target(&ast_compile_required_ast_field(&clause, "target")?)?,
                iter: ast_compile_expr(&ast_compile_required_ast_field(&clause, "iter")?)?,
                ifs: ast_compile_expr_list_field(&clause, "ifs")?,
            })
        })
        .collect()
}

fn ast_compile_with_items_field(
    node: &Value,
    field: &str,
) -> Result<Vec<syntax::WithItem>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|item| {
            ast_compile_expect_kind(&item, "withitem")?;
            let optional_vars = ast_compile_required_field(&item, "optional_vars")?;
            Ok(syntax::WithItem {
                context_expr: ast_compile_expr(&ast_compile_required_ast_field(
                    &item,
                    "context_expr",
                )?)?,
                optional_vars: if matches!(optional_vars, Value::None) {
                    None
                } else {
                    Some(ast_compile_target(&optional_vars)?)
                },
            })
        })
        .collect()
}

fn ast_compile_except_handlers_field(
    node: &Value,
    field: &str,
) -> Result<Vec<syntax::ExceptHandler>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|handler| {
            ast_compile_expect_kind(&handler, "ExceptHandler")?;
            let name = match ast_compile_required_field(&handler, "name")? {
                Value::None => None,
                Value::String(name) => Some(name),
                value => {
                    return Err(format!(
                        "TypeError: ExceptHandler name must be str or None, not {}",
                        type_name(&value)
                    ));
                }
            };
            Ok(syntax::ExceptHandler {
                type_expr: ast_compile_except_type_expr(&ast_compile_required_field(
                    &handler, "type",
                )?)?,
                name,
                body: ast_compile_nonempty_stmt_list_field(&handler, "body", "ExceptHandler")?,
            })
        })
        .collect()
}

fn ast_compile_except_type_expr(node: &Value) -> Result<Option<syntax::Expr>, String> {
    match ast_node_kind(node) {
        None if matches!(node, Value::None) => Ok(None),
        Some(_) => ast_compile_expr(node).map(Some),
        None => Err(format!(
            "TypeError: expected ExceptHandler type, got {}",
            type_name(node)
        )),
    }
}

fn ast_compile_match_cases_field(
    node: &Value,
    field: &str,
) -> Result<Vec<syntax::MatchCase>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|case| {
            ast_compile_expect_kind(&case, "match_case")?;
            Ok(syntax::MatchCase {
                pattern: ast_compile_pattern(&ast_compile_required_ast_field(&case, "pattern")?)?,
                guard: ast_compile_optional_expr_field(&case, "guard")?,
                body: ast_compile_stmt_list_field(&case, "body")?,
            })
        })
        .collect()
}

fn ast_compile_pattern(node: &Value) -> Result<syntax::Pattern, String> {
    ast_compile_pattern_with_context(node, false)
}

fn ast_compile_pattern_with_context(
    node: &Value,
    allow_star: bool,
) -> Result<syntax::Pattern, String> {
    let _guard = AstCompileRecursionGuard::enter(node)?;
    match ast_node_kind(node) {
        Some("MatchValue") => {
            let value = ast_compile_expr(&ast_compile_required_field(node, "value")?)?;
            if matches!(value, syntax::Expr::Attribute { .. }) {
                if !ast_match_attribute_expr_is_valid(&value) {
                    return Err(ast_pattern_value_error());
                }
                Ok(syntax::Pattern::Value(value))
            } else if ast_match_value_literal_expr_is_valid(&value) {
                Ok(syntax::Pattern::Literal(value))
            } else {
                Err(ast_pattern_value_error())
            }
        }
        Some("MatchSingleton") => Ok(syntax::Pattern::Singleton(
            ast_compile_pattern_singleton_value(&ast_compile_required_field(node, "value")?)?,
        )),
        Some("MatchAs") => {
            let pattern = ast_compile_required_field(node, "pattern")?;
            let name = ast_compile_optional_string_field(node, "name")?;
            if let Some(name) = name.as_deref() {
                ast_validate_match_capture_name(name)?;
            }
            match (pattern, name) {
                (Value::None, None) => Ok(syntax::Pattern::Wildcard),
                (Value::None, Some(name)) => Ok(syntax::Pattern::Capture(name)),
                (pattern, Some(name)) => Ok(syntax::Pattern::As {
                    pattern: Box::new(ast_compile_pattern_with_context(&pattern, false)?),
                    name,
                }),
                (pattern, None) => ast_compile_pattern_with_context(&pattern, false),
            }
        }
        Some("MatchOr") => {
            let patterns = ast_compile_pattern_list_field(node, "patterns", false)?;
            if patterns.len() < 2 {
                return Err("ValueError: MatchOr requires at least 2 patterns".to_string());
            }
            ast_validate_or_pattern_capture_compatibility(&patterns)?;
            Ok(syntax::Pattern::Or(patterns))
        }
        Some("MatchSequence") => {
            let patterns = ast_compile_pattern_list_field(node, "patterns", true)?;
            ast_validate_at_most_one_star_pattern(&patterns)?;
            Ok(syntax::Pattern::Sequence(patterns))
        }
        Some("MatchMapping") => {
            let keys = ast_compile_expr_list_field(node, "keys")?;
            for key in &keys {
                if !ast_match_mapping_key_expr_is_valid(key) {
                    return Err(ast_pattern_value_error());
                }
            }
            let patterns = ast_compile_pattern_list_field(node, "patterns", false)?;
            if keys.len() != patterns.len() {
                return Err(
                    "ValueError: MatchMapping doesn't have the same number of keys as patterns"
                        .to_string(),
                );
            }
            let rest = ast_compile_optional_string_field(node, "rest")?;
            if let Some(name) = rest.as_deref() {
                ast_validate_match_capture_name(name)?;
            }
            Ok(syntax::Pattern::Mapping {
                entries: keys.into_iter().zip(patterns).collect(),
                rest,
            })
        }
        Some("MatchClass") => {
            let names = ast_compile_string_list_field(node, "kwd_attrs")?;
            let class = ast_compile_expr(&ast_compile_required_field(node, "cls")?)?;
            if !ast_match_class_expr_is_valid(&class) {
                return Err(ast_pattern_value_error());
            }
            let patterns = ast_compile_pattern_list_field(node, "kwd_patterns", false)?;
            if names.len() != patterns.len() {
                return Err("ValueError: MatchClass doesn't have the same number of keyword attributes as patterns".to_string());
            }
            let mut seen_names = HashSet::new();
            for name in &names {
                ast_validate_match_class_keyword_name(name)?;
                if !seen_names.insert(name.clone()) {
                    return Err(format!(
                        "ValueError: attribute name repeated in class pattern: {name}"
                    ));
                }
            }
            Ok(syntax::Pattern::Class {
                class,
                positional: ast_compile_pattern_list_field(node, "patterns", false)?,
                keywords: names.into_iter().zip(patterns).collect(),
            })
        }
        Some("MatchStar") => {
            if !allow_star {
                return Err(
                    "ValueError: MatchStar can only be used in sequence patterns".to_string(),
                );
            }
            let name = ast_compile_optional_string_field(node, "name")?;
            if let Some(name) = name.as_deref() {
                ast_validate_match_capture_name(name)?;
            }
            Ok(syntax::Pattern::Star(name))
        }
        Some(kind) => Err(format!(
            "TypeError: compile() does not yet support AST pattern {kind}"
        )),
        None => Err(format!(
            "TypeError: expected AST pattern, got {}",
            type_name(node)
        )),
    }
}

fn ast_compile_pattern_singleton_value(value: &Value) -> Result<syntax::Expr, String> {
    match value {
        Value::None => Ok(syntax::Expr::None),
        Value::Bool(value) => Ok(syntax::Expr::Bool(*value)),
        value => Err(format!(
            "ValueError: MatchSingleton value must be True, False, or None, not {}",
            type_name(value)
        )),
    }
}

fn ast_compile_pattern_list_field(
    node: &Value,
    field: &str,
    allow_star: bool,
) -> Result<Vec<syntax::Pattern>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|pattern| ast_compile_pattern_with_context(&pattern, allow_star))
        .collect()
}

fn ast_pattern_value_error() -> String {
    "ValueError: patterns may only match literals and attribute lookups".to_string()
}

fn ast_match_value_literal_expr_is_valid(expr: &syntax::Expr) -> bool {
    match expr {
        syntax::Expr::Number(_)
        | syntax::Expr::BigInt(_)
        | syntax::Expr::Float(_)
        | syntax::Expr::Imaginary(_)
        | syntax::Expr::String(_)
        | syntax::Expr::Bytes(_) => true,
        syntax::Expr::Unary { op, operand } => {
            matches!(op, syntax::UnaryOp::Negative)
                && matches!(
                    operand.as_ref(),
                    syntax::Expr::Number(_)
                        | syntax::Expr::BigInt(_)
                        | syntax::Expr::Float(_)
                        | syntax::Expr::Imaginary(_)
                )
        }
        syntax::Expr::Binary { left, op, right } => {
            matches!(op, syntax::BinaryOp::Add | syntax::BinaryOp::Subtract)
                && ast_match_signed_real_expr_is_valid(left)
                && matches!(right.as_ref(), syntax::Expr::Imaginary(_))
        }
        _ => false,
    }
}

fn ast_match_mapping_key_expr_is_valid(expr: &syntax::Expr) -> bool {
    ast_match_value_literal_expr_is_valid(expr)
        || matches!(expr, syntax::Expr::Bool(_) | syntax::Expr::None)
        || ast_match_attribute_expr_is_valid(expr)
}

fn ast_match_signed_real_expr_is_valid(expr: &syntax::Expr) -> bool {
    match expr {
        syntax::Expr::Number(_) | syntax::Expr::BigInt(_) | syntax::Expr::Float(_) => true,
        syntax::Expr::Unary { op, operand } => {
            matches!(op, syntax::UnaryOp::Negative)
                && matches!(
                    operand.as_ref(),
                    syntax::Expr::Number(_) | syntax::Expr::BigInt(_) | syntax::Expr::Float(_)
                )
        }
        _ => false,
    }
}

fn ast_match_attribute_expr_is_valid(expr: &syntax::Expr) -> bool {
    match expr {
        syntax::Expr::Attribute { object, .. } => ast_match_class_expr_is_valid(object),
        _ => false,
    }
}

fn ast_match_class_expr_is_valid(expr: &syntax::Expr) -> bool {
    match expr {
        syntax::Expr::Name(_) => true,
        syntax::Expr::Attribute { object, .. } => ast_match_class_expr_is_valid(object),
        _ => false,
    }
}

fn ast_validate_match_capture_name(name: &str) -> Result<(), String> {
    if name == "_" || name == "__debug__" || matches!(name, "True" | "False" | "None") {
        return Err(format!("ValueError: invalid capture name '{name}'"));
    }
    if !string_isidentifier(name) {
        return Err(format!("ValueError: invalid capture name '{name}'"));
    }
    Ok(())
}

fn ast_validate_match_class_keyword_name(name: &str) -> Result<(), String> {
    if matches!(name, "True" | "False" | "None") || !string_isidentifier(name) {
        return Err(format!(
            "ValueError: invalid keyword attribute name '{name}'"
        ));
    }
    Ok(())
}

fn ast_validate_at_most_one_star_pattern(patterns: &[syntax::Pattern]) -> Result<(), String> {
    if patterns
        .iter()
        .filter(|pattern| matches!(pattern, syntax::Pattern::Star(_)))
        .count()
        > 1
    {
        return Err("ValueError: multiple starred names in sequence pattern".to_string());
    }
    Ok(())
}

fn ast_validate_or_pattern_capture_compatibility(
    patterns: &[syntax::Pattern],
) -> Result<(), String> {
    let mut expected = None;
    for pattern in patterns {
        let mut names = HashSet::new();
        ast_collect_pattern_captures(pattern, &mut names)?;
        match &expected {
            Some(expected) if *expected != names => {
                return Err("ValueError: alternative patterns bind different names".to_string());
            }
            Some(_) => {}
            None => expected = Some(names),
        }
    }
    Ok(())
}

fn ast_collect_pattern_captures(
    pattern: &syntax::Pattern,
    names: &mut HashSet<String>,
) -> Result<(), String> {
    match pattern {
        syntax::Pattern::Capture(name) | syntax::Pattern::Star(Some(name)) => {
            ast_insert_pattern_capture(name, names)
        }
        syntax::Pattern::As { pattern, name } => {
            ast_collect_pattern_captures(pattern, names)?;
            ast_insert_pattern_capture(name, names)
        }
        syntax::Pattern::Or(patterns) | syntax::Pattern::Sequence(patterns) => {
            for pattern in patterns {
                ast_collect_pattern_captures(pattern, names)?;
            }
            Ok(())
        }
        syntax::Pattern::Mapping { entries, rest } => {
            for (_, pattern) in entries {
                ast_collect_pattern_captures(pattern, names)?;
            }
            if let Some(rest) = rest {
                ast_insert_pattern_capture(rest, names)?;
            }
            Ok(())
        }
        syntax::Pattern::Class {
            positional,
            keywords,
            ..
        } => {
            for pattern in positional {
                ast_collect_pattern_captures(pattern, names)?;
            }
            for (_, pattern) in keywords {
                ast_collect_pattern_captures(pattern, names)?;
            }
            Ok(())
        }
        syntax::Pattern::Literal(_)
        | syntax::Pattern::Singleton(_)
        | syntax::Pattern::Value(_)
        | syntax::Pattern::Wildcard
        | syntax::Pattern::Star(None) => Ok(()),
    }
}

fn ast_insert_pattern_capture(name: &str, names: &mut HashSet<String>) -> Result<(), String> {
    if !names.insert(name.to_string()) {
        return Err(format!(
            "ValueError: multiple assignments to name '{name}' in pattern"
        ));
    }
    Ok(())
}

fn ast_compile_fstring_parts_field(
    node: &Value,
    field: &str,
) -> Result<Vec<syntax::FStringPart>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|part| ast_compile_fstring_part(&part))
        .collect()
}

fn ast_compile_fstring_part(node: &Value) -> Result<syntax::FStringPart, String> {
    match ast_node_kind(node) {
        Some("Constant") => match ast_compile_required_field(node, "value")? {
            Value::String(value) => Ok(syntax::FStringPart::Literal(value)),
            value => Err(format!(
                "TypeError: JoinedStr literal parts must be strings, not {}",
                type_name(&value)
            )),
        },
        Some("FormattedValue") => Ok(syntax::FStringPart::Formatted {
            value: Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "value",
            )?)?),
            conversion: ast_compile_fstring_conversion_field(node, "conversion")?,
            format_spec: ast_compile_optional_format_spec_field(node, "format_spec")?,
        }),
        Some(kind) => Err(format!(
            "TypeError: compile() does not yet support JoinedStr part {kind}"
        )),
        None => Err(format!(
            "TypeError: expected JoinedStr part, got {}",
            type_name(node)
        )),
    }
}

fn ast_compile_template_string_parts_field(
    node: &Value,
    field: &str,
) -> Result<Vec<syntax::TemplateStringPart>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|part| ast_compile_template_string_part(&part))
        .collect()
}

fn ast_compile_template_string_part(node: &Value) -> Result<syntax::TemplateStringPart, String> {
    match ast_node_kind(node) {
        Some("Constant") => match ast_compile_required_field(node, "value")? {
            Value::String(value) => Ok(syntax::TemplateStringPart::Literal(value)),
            value => Err(format!(
                "TypeError: TemplateStr literal parts must be strings, not {}",
                type_name(&value)
            )),
        },
        Some("Interpolation") => Ok(syntax::TemplateStringPart::Interpolation {
            value: Box::new(ast_compile_expr(&ast_compile_required_field(
                node, "value",
            )?)?),
            expression: ast_compile_interpolation_text_field(node, "str")?,
            conversion: ast_compile_fstring_conversion_field(node, "conversion")?,
            format_spec: ast_compile_optional_format_spec_field(node, "format_spec")?,
        }),
        Some(kind) => Err(format!(
            "TypeError: compile() does not yet support TemplateStr part {kind}"
        )),
        None => Err(format!(
            "TypeError: expected TemplateStr part, got {}",
            type_name(node)
        )),
    }
}

fn ast_compile_optional_format_spec_field(
    node: &Value,
    field: &str,
) -> Result<Option<Vec<syntax::FStringPart>>, String> {
    match ast_compile_required_field(node, field)? {
        Value::None => Ok(None),
        value => {
            ast_compile_expect_kind(&value, "JoinedStr")?;
            ast_compile_fstring_parts_field(&value, "values").map(Some)
        }
    }
}

fn ast_compile_fstring_conversion_field(
    node: &Value,
    field: &str,
) -> Result<Option<syntax::FStringConversion>, String> {
    match ast_compile_required_field(node, field)? {
        Value::Number(-1) => Ok(None),
        Value::Number(115) => Ok(Some(syntax::FStringConversion::Str)),
        Value::Number(114) => Ok(Some(syntax::FStringConversion::Repr)),
        Value::Number(97) => Ok(Some(syntax::FStringConversion::Ascii)),
        Value::Number(value) => Err(format!(
            "TypeError: unsupported f-string conversion code {value}"
        )),
        value => Err(format!(
            "TypeError: field \"{field}\" must be an int conversion code, not {}",
            type_name(&value)
        )),
    }
}

fn ast_compile_interpolation_text_field(node: &Value, field: &str) -> Result<String, String> {
    match ast_compile_required_field(node, field)? {
        Value::String(value) => Ok(value),
        Value::None => Ok(String::new()),
        value => Err(format!(
            "TypeError: field \"{field}\" must be a string or None, not {}",
            type_name(&value)
        )),
    }
}

fn ast_compile_name_target_field(node: &Value, field: &str) -> Result<String, String> {
    let target = ast_compile_required_field(node, field)?;
    ast_compile_expect_kind(&target, "Name")?;
    ast_compile_name_identifier_field(&target, "id")
}

fn ast_compile_name_identifier_field(node: &Value, field: &str) -> Result<String, String> {
    match ast_compile_required_field(node, field)? {
        Value::String(name) => {
            ast_validate_name_identifier(&name)?;
            Ok(name)
        }
        value => Err(format!(
            "TypeError: identifier must be of type str, not {}",
            type_name(&value)
        )),
    }
}

fn ast_validate_name_identifier(name: &str) -> Result<(), String> {
    match name {
        "True" | "False" | "None" => Err(format!(
            "ValueError: identifier field can't represent '{name}' constant"
        )),
        _ => Ok(()),
    }
}

fn ast_compile_validate_context(node: &Value, expected: &str) -> Result<(), String> {
    let ctx = ast_compile_required_field(node, "ctx")?;
    match ast_node_kind(&ctx) {
        Some(kind) if kind == expected => Ok(()),
        Some("Load" | "Store" | "Del") => Err(format!(
            "ValueError: expression must have {expected} context"
        )),
        Some(kind) => Err(format!(
            "TypeError: expected some sort of expr_context, but got {kind}()"
        )),
        None => Err(format!(
            "TypeError: field \"ctx\" must be an expr_context, not {}",
            type_name(&ctx)
        )),
    }
}

fn ast_compile_try_stmt(node: &Value, is_star: bool) -> Result<syntax::Stmt, String> {
    let kind = if is_star { "TryStar" } else { "Try" };
    let body = ast_compile_nonempty_stmt_list_field(node, "body", kind)?;
    let handlers = ast_compile_except_handlers_field(node, "handlers")?;
    let else_body = ast_compile_stmt_list_field(node, "orelse")?;
    let finally_body = ast_compile_stmt_list_field(node, "finalbody")?;

    if handlers.is_empty() && finally_body.is_empty() {
        return Err(format!(
            "ValueError: {kind} has neither except handlers nor finalbody"
        ));
    }
    if handlers.is_empty() && !else_body.is_empty() {
        return Err(format!(
            "ValueError: {kind} has orelse but no except handlers"
        ));
    }

    if is_star {
        Ok(syntax::Stmt::TryStar {
            body,
            handlers,
            else_body,
            finally_body,
        })
    } else {
        Ok(syntax::Stmt::Try {
            body,
            handlers,
            else_body,
            finally_body,
        })
    }
}

fn ast_compile_delete_targets_field(node: &Value, field: &str) -> Result<syntax::Target, String> {
    let targets = ast_compile_nonempty_target_list_field(node, field, "Delete", "Del")?;
    match targets.as_slice() {
        [target] => Ok(target.clone()),
        _ => Ok(syntax::Target::Tuple(targets)),
    }
}

fn ast_compile_nonempty_stmt_list_field(
    node: &Value,
    field: &str,
    owner: &str,
) -> Result<Vec<syntax::Stmt>, String> {
    let statements = ast_compile_stmt_list_field(node, field)?;
    if statements.is_empty() {
        return Err(format!("ValueError: empty body on {owner}"));
    }
    Ok(statements)
}

fn ast_compile_nonempty_target_list_field(
    node: &Value,
    field: &str,
    owner: &str,
    expected: &str,
) -> Result<Vec<syntax::Target>, String> {
    let values = ast_compile_list_field(node, field)?;
    if values.is_empty() {
        return Err(format!("ValueError: empty targets on {owner}"));
    }
    values
        .into_iter()
        .map(|target| ast_compile_target_with_context(&target, expected))
        .collect()
}

fn ast_compile_nonempty_with_items_field(
    node: &Value,
    field: &str,
    owner: &str,
) -> Result<Vec<syntax::WithItem>, String> {
    let items = ast_compile_with_items_field(node, field)?;
    if items.is_empty() {
        return Err(format!("ValueError: empty items on {owner}"));
    }
    Ok(items)
}

fn ast_compile_nonempty_import_aliases_field(
    node: &Value,
    field: &str,
    owner: &str,
) -> Result<Vec<syntax::ImportAlias>, String> {
    let aliases = ast_compile_import_aliases_field(node, field)?;
    if aliases.is_empty() {
        return Err(format!("ValueError: empty names on {owner}"));
    }
    Ok(aliases)
}

fn ast_compile_nonempty_string_list(
    values: Vec<String>,
    owner: &str,
) -> Result<Vec<String>, String> {
    if values.is_empty() {
        return Err(format!("ValueError: empty names on {owner}"));
    }
    Ok(values)
}

fn ast_compile_required_field(node: &Value, field: &str) -> Result<Value, String> {
    ast_required_field(node, field).map_err(|_| {
        format!(
            "TypeError: required field \"{field}\" missing from {}",
            type_name(node)
        )
    })
}

fn ast_compile_required_ast_field(node: &Value, field: &str) -> Result<Value, String> {
    let value = ast_compile_required_field(node, field)?;
    if matches!(value, Value::None) {
        return Err(ast_required_field_value_error(node, field));
    }
    Ok(value)
}

fn ast_required_field_value_error(node: &Value, field: &str) -> String {
    format!(
        "ValueError: field '{field}' is required for {}",
        ast_node_kind(node).unwrap_or(type_name(node))
    )
}

fn ast_compile_list_field(node: &Value, field: &str) -> Result<Vec<Value>, String> {
    match ast_compile_required_field(node, field)? {
        Value::List(items) => Ok(items.borrow().clone()),
        Value::Tuple(items) => Ok(items.as_ref().clone()),
        value => Err(format!(
            "TypeError: field \"{field}\" must be a list, not {}",
            type_name(&value)
        )),
    }
}

fn ast_compile_stmt_list_field(node: &Value, field: &str) -> Result<Vec<syntax::Stmt>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|stmt| ast_compile_stmt(&stmt))
        .collect()
}

fn ast_compile_expr_list_field(node: &Value, field: &str) -> Result<Vec<syntax::Expr>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|expr| ast_compile_expr(&expr))
        .collect()
}

fn ast_compile_target_list_field_with_context(
    node: &Value,
    field: &str,
    expected: &str,
) -> Result<Vec<syntax::Target>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|target| ast_compile_target_with_context(&target, expected))
        .collect()
}

fn ast_compile_optional_expr_field(
    node: &Value,
    field: &str,
) -> Result<Option<syntax::Expr>, String> {
    match ast_compile_required_field(node, field)? {
        Value::None => Ok(None),
        value => ast_compile_expr(&value).map(Some),
    }
}

fn ast_compile_optional_string_field(node: &Value, field: &str) -> Result<Option<String>, String> {
    match ast_compile_required_field(node, field)? {
        Value::None => Ok(None),
        Value::String(value) => Ok(Some(value)),
        value => Err(format!(
            "TypeError: field \"{field}\" must be a string or None, not {}",
            type_name(&value)
        )),
    }
}

fn ast_compile_string_list_field(node: &Value, field: &str) -> Result<Vec<String>, String> {
    ast_compile_list_field(node, field)?
        .into_iter()
        .map(|value| match value {
            Value::String(value) => Ok(value),
            value => Err(format!(
                "TypeError: field \"{field}\" must contain strings, not {}",
                type_name(&value)
            )),
        })
        .collect()
}

fn ast_compile_boolish_field(node: &Value, field: &str) -> Result<bool, String> {
    match ast_compile_required_field(node, field)? {
        Value::Bool(value) => Ok(value),
        Value::Number(0) => Ok(false),
        Value::Number(1) => Ok(true),
        value => Err(format!(
            "TypeError: field \"{field}\" must be bool or 0/1 int, not {}",
            type_name(&value)
        )),
    }
}

fn ast_compile_string_field(node: &Value, field: &str) -> Result<String, String> {
    match ast_compile_required_field(node, field)? {
        Value::String(value) => Ok(value),
        Value::None => Err(ast_required_field_value_error(node, field)),
        value => Err(format!(
            "TypeError: field \"{field}\" must be a string, not {}",
            type_name(&value)
        )),
    }
}

fn ast_compile_expect_kind(node: &Value, expected: &str) -> Result<(), String> {
    match ast_node_kind(node) {
        Some(kind) if kind == expected => Ok(()),
        Some(kind) => Err(format!(
            "TypeError: expected AST node {expected}, got {kind}"
        )),
        None => Err(format!(
            "TypeError: expected AST node {expected}, got {}",
            type_name(node)
        )),
    }
}

struct AstCompileRecursionGuard {
    key: Option<usize>,
}

impl AstCompileRecursionGuard {
    fn enter(node: &Value) -> Result<Self, String> {
        let Value::AstNode { identity, .. } = node else {
            return Ok(Self { key: None });
        };
        let key = Rc::as_ptr(identity) as usize;
        let inserted = AST_COMPILE_ACTIVE_NODES.with(|active| {
            let mut active = active.borrow_mut();
            if active.contains(&key) {
                false
            } else {
                active.insert(key);
                true
            }
        });
        if !inserted {
            return Err(
                "RecursionError: maximum recursion depth exceeded while traversing AST".to_string(),
            );
        }
        Ok(Self { key: Some(key) })
    }
}

impl Drop for AstCompileRecursionGuard {
    fn drop(&mut self) {
        if let Some(key) = self.key {
            AST_COMPILE_ACTIVE_NODES.with(|active| {
                active.borrow_mut().remove(&key);
            });
        }
    }
}

fn ast_compile_binary_op(node: &Value) -> Result<syntax::BinaryOp, String> {
    match ast_node_kind(node) {
        Some("Add") => Ok(syntax::BinaryOp::Add),
        Some("Sub") => Ok(syntax::BinaryOp::Subtract),
        Some("Mult") => Ok(syntax::BinaryOp::Multiply),
        Some("MatMult") => Ok(syntax::BinaryOp::MatrixMultiply),
        Some("Div") => Ok(syntax::BinaryOp::TrueDivide),
        Some("FloorDiv") => Ok(syntax::BinaryOp::FloorDivide),
        Some("Mod") => Ok(syntax::BinaryOp::Modulo),
        Some("Pow") => Ok(syntax::BinaryOp::Power),
        Some("BitOr") => Ok(syntax::BinaryOp::BitOr),
        Some("BitXor") => Ok(syntax::BinaryOp::BitXor),
        Some("BitAnd") => Ok(syntax::BinaryOp::BitAnd),
        Some("LShift") => Ok(syntax::BinaryOp::LeftShift),
        Some("RShift") => Ok(syntax::BinaryOp::RightShift),
        Some(kind) => Err(format!("TypeError: unsupported binary operator {kind}")),
        None => Err(format!(
            "TypeError: expected binary operator, got {}",
            type_name(node)
        )),
    }
}

fn ast_compile_unary_op(node: &Value) -> Result<syntax::UnaryOp, String> {
    match ast_node_kind(node) {
        Some("Not") => Ok(syntax::UnaryOp::Not),
        Some("UAdd") => Ok(syntax::UnaryOp::Positive),
        Some("USub") => Ok(syntax::UnaryOp::Negative),
        Some("Invert") => Ok(syntax::UnaryOp::Invert),
        Some(kind) => Err(format!("TypeError: unsupported unary operator {kind}")),
        None => Err(format!(
            "TypeError: expected unary operator, got {}",
            type_name(node)
        )),
    }
}

fn ast_compile_logical_op(node: &Value) -> Result<syntax::LogicalOp, String> {
    match ast_node_kind(node) {
        Some("And") => Ok(syntax::LogicalOp::And),
        Some("Or") => Ok(syntax::LogicalOp::Or),
        Some(kind) => Err(format!("TypeError: unsupported boolean operator {kind}")),
        None => Err(format!(
            "TypeError: expected boolean operator, got {}",
            type_name(node)
        )),
    }
}

fn ast_compile_comparison_op(node: &Value) -> Result<syntax::ComparisonOp, String> {
    match ast_node_kind(node) {
        Some("Eq") => Ok(syntax::ComparisonOp::Equal),
        Some("NotEq") => Ok(syntax::ComparisonOp::NotEqual),
        Some("Lt") => Ok(syntax::ComparisonOp::Less),
        Some("LtE") => Ok(syntax::ComparisonOp::LessEqual),
        Some("Gt") => Ok(syntax::ComparisonOp::Greater),
        Some("GtE") => Ok(syntax::ComparisonOp::GreaterEqual),
        Some("In") => Ok(syntax::ComparisonOp::In),
        Some("NotIn") => Ok(syntax::ComparisonOp::NotIn),
        Some("Is") => Ok(syntax::ComparisonOp::Is),
        Some("IsNot") => Ok(syntax::ComparisonOp::IsNot),
        Some(kind) => Err(format!("TypeError: unsupported comparison operator {kind}")),
        None => Err(format!(
            "TypeError: expected comparison operator, got {}",
            type_name(node)
        )),
    }
}

fn ast_node(kind: &str, fields: Vec<(&str, Value)>) -> Value {
    ast_node_with_fields(kind, fields.iter().map(|(name, _)| *name).collect(), fields)
}

fn ast_node_with_fields(kind: &str, field_names: Vec<&str>, attrs: Vec<(&str, Value)>) -> Value {
    let field_names = field_names
        .iter()
        .map(|name| (*name).to_string())
        .collect::<Vec<_>>();
    let entries = attrs
        .into_iter()
        .map(|(name, value)| (Value::String(name.to_string()), value))
        .collect();
    Value::AstNode {
        kind: kind.to_string(),
        fields: field_names,
        attrs: Rc::new(RefCell::new(DictStorage::new(entries))),
        identity: Rc::new(()),
    }
}

fn ast_string_list(items: Vec<String>) -> Value {
    list_value(items.into_iter().map(Value::String).collect())
}

fn ast_nodes_list(items: Vec<Value>) -> Value {
    list_value(items)
}

fn ast_optional_expr(value: Option<&syntax::Expr>) -> Value {
    value.map(ast_expr_node).unwrap_or(Value::None)
}

fn ast_context_node(name: &str) -> Value {
    ast_node(name, Vec::new())
}

