fn ast_module_entries() -> Vec<(&'static str, Value)> {
    let mut entries = AST_MODULE_TYPE_NAMES
        .iter()
        .map(|name| {
            let builtin_name = if *name == "Interpolation" {
                "ast.Interpolation"
            } else {
                *name
            };
            (*name, Value::Builtin(builtin_name.to_string()))
        })
        .collect::<Vec<_>>();
    entries.extend([
        ("Set", Value::Builtin("ast.Set".to_string())),
        ("PyCF_ONLY_AST", Value::Number(1024)),
        ("parse", Value::Builtin("ast.parse".to_string())),
        ("dump", Value::Builtin("ast.dump".to_string())),
        ("compare", Value::Builtin("ast.compare".to_string())),
        (
            "literal_eval",
            Value::Builtin("ast.literal_eval".to_string()),
        ),
        (
            "copy_location",
            Value::Builtin("ast.copy_location".to_string()),
        ),
        (
            "fix_missing_locations",
            Value::Builtin("ast.fix_missing_locations".to_string()),
        ),
        (
            "increment_lineno",
            Value::Builtin("ast.increment_lineno".to_string()),
        ),
        (
            "get_docstring",
            Value::Builtin("ast.get_docstring".to_string()),
        ),
        (
            "get_source_segment",
            Value::Builtin("ast.get_source_segment".to_string()),
        ),
        ("iter_fields", Value::Builtin("ast.iter_fields".to_string())),
        (
            "iter_child_nodes",
            Value::Builtin("ast.iter_child_nodes".to_string()),
        ),
        ("walk", Value::Builtin("ast.walk".to_string())),
        ("NodeVisitor", Value::Builtin("NodeVisitor".to_string())),
        (
            "NodeTransformer",
            Value::Builtin("NodeTransformer".to_string()),
        ),
    ]);
    entries
}

fn ast_builtin_value_for_kind(kind: &str) -> Value {
    match kind {
        "Set" | "Interpolation" => Value::Builtin(format!("ast.{kind}")),
        kind => Value::Builtin(kind.to_string()),
    }
}

fn ast_direct_subclass_kinds(kind: &str) -> &'static [&'static str] {
    match kind {
        "AST" => &[
            "mod",
            "stmt",
            "expr",
            "expr_context",
            "boolop",
            "operator",
            "unaryop",
            "cmpop",
            "comprehension",
            "excepthandler",
            "arguments",
            "arg",
            "keyword",
            "alias",
            "withitem",
            "match_case",
            "pattern",
            "type_ignore",
            "type_param",
        ],
        "mod" => &["Module", "Interactive", "Expression", "FunctionType"],
        "stmt" => &[
            "FunctionDef",
            "AsyncFunctionDef",
            "ClassDef",
            "Return",
            "Delete",
            "Assign",
            "TypeAlias",
            "AugAssign",
            "AnnAssign",
            "For",
            "AsyncFor",
            "While",
            "If",
            "With",
            "AsyncWith",
            "Match",
            "Raise",
            "Try",
            "TryStar",
            "Assert",
            "Import",
            "ImportFrom",
            "Global",
            "Nonlocal",
            "Expr",
            "Pass",
            "Break",
            "Continue",
        ],
        "expr" => &[
            "BoolOp",
            "NamedExpr",
            "BinOp",
            "UnaryOp",
            "Lambda",
            "IfExp",
            "Dict",
            "Set",
            "ListComp",
            "SetComp",
            "DictComp",
            "GeneratorExp",
            "Await",
            "Yield",
            "YieldFrom",
            "Compare",
            "Call",
            "FormattedValue",
            "Interpolation",
            "JoinedStr",
            "TemplateStr",
            "Constant",
            "Attribute",
            "Subscript",
            "Starred",
            "Name",
            "List",
            "Tuple",
            "Slice",
        ],
        "expr_context" => &["Load", "Store", "Del"],
        "boolop" => &["And", "Or"],
        "operator" => &[
            "Add", "Sub", "Mult", "MatMult", "Div", "Mod", "Pow", "LShift", "RShift", "BitOr",
            "BitXor", "BitAnd", "FloorDiv",
        ],
        "unaryop" => &["Invert", "Not", "UAdd", "USub"],
        "cmpop" => &[
            "Eq", "NotEq", "Lt", "LtE", "Gt", "GtE", "Is", "IsNot", "In", "NotIn",
        ],
        "excepthandler" => &["ExceptHandler"],
        "pattern" => &[
            "MatchValue",
            "MatchSingleton",
            "MatchSequence",
            "MatchMapping",
            "MatchClass",
            "MatchStar",
            "MatchAs",
            "MatchOr",
        ],
        "type_ignore" => &["TypeIgnore"],
        "type_param" => &["TypeVar", "ParamSpec", "TypeVarTuple"],
        _ => &[],
    }
}

fn ast_base_kind(kind: &str) -> Option<&'static str> {
    if kind == "AST" {
        return None;
    }

    for candidate in AST_MODULE_TYPE_NAMES {
        if ast_direct_subclass_kinds(candidate).contains(&kind) {
            return Some(candidate);
        }
    }
    None
}

fn ast_kind_inherits(kind: &str, target: &str) -> bool {
    if kind == target {
        return true;
    }
    let Some(parent) = ast_base_kind(kind) else {
        return false;
    };
    ast_kind_inherits(parent, target)
}

fn call_ast_subclasses(args: Vec<Value>, keywords: Vec<(String, Value)>) -> Result<Value, String> {
    if !keywords.is_empty() {
        return Err("TypeError: __subclasses__() does not accept keyword arguments".to_string());
    }
    let [class] = args.as_slice() else {
        return Err(format!(
            "TypeError: __subclasses__() expected 0 arguments, got {}",
            args.len().saturating_sub(1)
        ));
    };
    let Value::Builtin(name) = class else {
        return Err("TypeError: descriptor '__subclasses__' requires a type".to_string());
    };
    let Some(kind) = ast_builtin_kind(name) else {
        return Err("TypeError: descriptor '__subclasses__' requires an AST type".to_string());
    };
    Ok(list_value(
        ast_direct_subclass_kinds(kind)
            .iter()
            .map(|kind| ast_builtin_value_for_kind(kind))
            .collect(),
    ))
}

fn ast_program_node(program: &syntax::Program, type_ignores: Vec<Value>) -> Value {
    ast_node(
        "Module",
        vec![
            (
                "body",
                ast_nodes_list(program.statements.iter().map(ast_stmt_node).collect()),
            ),
            ("type_ignores", list_value(type_ignores)),
        ],
    )
}

fn ast_interactive_node(program: &syntax::Program) -> Value {
    ast_node(
        "Interactive",
        vec![(
            "body",
            ast_nodes_list(program.statements.iter().map(ast_stmt_node).collect()),
        )],
    )
}

fn ast_expression_node(expr: &syntax::Expr) -> Value {
    ast_node("Expression", vec![("body", ast_expr_node(expr))])
}

fn ast_function_type_node(function_type: &syntax::FunctionType) -> Value {
    ast_node(
        "FunctionType",
        vec![
            (
                "argtypes",
                ast_nodes_list(function_type.arg_types.iter().map(ast_expr_node).collect()),
            ),
            ("returns", ast_expr_node(&function_type.returns)),
        ],
    )
}

fn ast_stmt_node(stmt: &syntax::Stmt) -> Value {
    match stmt {
        syntax::Stmt::Pass => ast_node("Pass", Vec::new()),
        syntax::Stmt::Expr(value) => ast_node("Expr", vec![("value", ast_expr_node(value))]),
        syntax::Stmt::Assign { targets, value } => ast_node(
            "Assign",
            vec![
                (
                    "targets",
                    ast_nodes_list(
                        targets
                            .iter()
                            .map(|target| ast_target_node(target, "Store"))
                            .collect(),
                    ),
                ),
                ("value", ast_expr_node(value)),
                ("type_comment", Value::None),
            ],
        ),
        syntax::Stmt::AnnAssign {
            target,
            annotation,
            value,
            simple,
        } => ast_node(
            "AnnAssign",
            vec![
                ("target", ast_target_node(target, "Store")),
                ("annotation", ast_expr_node(annotation)),
                (
                    "value",
                    value.as_ref().map(ast_expr_node).unwrap_or(Value::None),
                ),
                ("simple", Value::Number(*simple as i64)),
            ],
        ),
        syntax::Stmt::TypeAlias {
            name,
            type_params,
            value,
        } => ast_node(
            "TypeAlias",
            vec![
                (
                    "name",
                    ast_node(
                        "Name",
                        vec![
                            ("id", Value::String(name.clone())),
                            ("ctx", ast_context_node("Store")),
                        ],
                    ),
                ),
                (
                    "type_params",
                    ast_nodes_list(type_params.iter().map(ast_type_param_node).collect()),
                ),
                ("value", ast_expr_node(value)),
            ],
        ),
        syntax::Stmt::AugAssign { target, op, value } => ast_node(
            "AugAssign",
            vec![
                ("target", ast_target_node(target, "Store")),
                ("op", ast_binary_op_node(op)),
                ("value", ast_expr_node(value)),
            ],
        ),
        syntax::Stmt::Delete { target } => ast_node(
            "Delete",
            vec![(
                "targets",
                ast_nodes_list(vec![ast_target_node(target, "Del")]),
            )],
        ),
        syntax::Stmt::FunctionDef {
            name,
            type_params,
            params,
            body,
            decorators,
            returns,
        } => ast_function_def_node(
            "FunctionDef",
            name,
            type_params,
            params,
            body,
            decorators,
            returns.as_ref(),
        ),
        syntax::Stmt::AsyncFunctionDef {
            name,
            type_params,
            params,
            body,
            decorators,
            returns,
        } => ast_function_def_node(
            "AsyncFunctionDef",
            name,
            type_params,
            params,
            body,
            decorators,
            returns.as_ref(),
        ),
        syntax::Stmt::ClassDef {
            name,
            type_params,
            bases,
            keywords,
            body,
            decorators,
        } => ast_node(
            "ClassDef",
            vec![
                ("name", Value::String(name.clone())),
                (
                    "bases",
                    ast_nodes_list(bases.iter().map(ast_call_arg_node).collect()),
                ),
                (
                    "keywords",
                    ast_nodes_list(keywords.iter().map(ast_call_keyword_node).collect()),
                ),
                (
                    "body",
                    ast_nodes_list(body.iter().map(ast_stmt_node).collect()),
                ),
                (
                    "decorator_list",
                    ast_nodes_list(decorators.iter().map(ast_expr_node).collect()),
                ),
                (
                    "type_params",
                    ast_nodes_list(type_params.iter().map(ast_type_param_node).collect()),
                ),
            ],
        ),
        syntax::Stmt::Import { is_lazy, aliases } => ast_node(
            "Import",
            vec![
                (
                    "names",
                    ast_nodes_list(aliases.iter().map(ast_alias_node).collect()),
                ),
                ("is_lazy", Value::Number(*is_lazy as i64)),
            ],
        ),
        syntax::Stmt::ImportFrom {
            is_lazy,
            module,
            level,
            targets,
        } => ast_node(
            "ImportFrom",
            vec![
                (
                    "module",
                    module
                        .as_ref()
                        .map(|module| Value::String(module.clone()))
                        .unwrap_or(Value::None),
                ),
                ("names", ast_import_from_targets(targets)),
                ("level", Value::Number(*level as i64)),
                ("is_lazy", Value::Number(*is_lazy as i64)),
            ],
        ),
        syntax::Stmt::Return(value) => ast_node(
            "Return",
            vec![(
                "value",
                value.as_ref().map(ast_expr_node).unwrap_or(Value::None),
            )],
        ),
        syntax::Stmt::Global(names) => {
            ast_node("Global", vec![("names", ast_string_list(names.clone()))])
        }
        syntax::Stmt::Nonlocal(names) => {
            ast_node("Nonlocal", vec![("names", ast_string_list(names.clone()))])
        }
        syntax::Stmt::Assert { condition, message } => ast_node(
            "Assert",
            vec![
                ("test", ast_expr_node(condition)),
                (
                    "msg",
                    message.as_ref().map(ast_expr_node).unwrap_or(Value::None),
                ),
            ],
        ),
        syntax::Stmt::Raise { value, cause } => ast_node(
            "Raise",
            vec![
                (
                    "exc",
                    value.as_ref().map(ast_expr_node).unwrap_or(Value::None),
                ),
                (
                    "cause",
                    cause.as_ref().map(ast_expr_node).unwrap_or(Value::None),
                ),
            ],
        ),
        syntax::Stmt::If {
            condition,
            then_body,
            else_body,
        } => ast_node(
            "If",
            vec![
                ("test", ast_expr_node(condition)),
                (
                    "body",
                    ast_nodes_list(then_body.iter().map(ast_stmt_node).collect()),
                ),
                (
                    "orelse",
                    ast_nodes_list(else_body.iter().map(ast_stmt_node).collect()),
                ),
            ],
        ),
        syntax::Stmt::Match { subject, cases } => ast_node(
            "Match",
            vec![
                ("subject", ast_expr_node(subject)),
                (
                    "cases",
                    ast_nodes_list(cases.iter().map(ast_match_case_node).collect()),
                ),
            ],
        ),
        syntax::Stmt::Try {
            body,
            handlers,
            else_body,
            finally_body,
        } => ast_try_node("Try", body, handlers, else_body, finally_body),
        syntax::Stmt::TryStar {
            body,
            handlers,
            else_body,
            finally_body,
        } => ast_try_node("TryStar", body, handlers, else_body, finally_body),
        syntax::Stmt::With { items, body } => ast_with_node("With", items, body),
        syntax::Stmt::AsyncWith { items, body } => ast_with_node("AsyncWith", items, body),
        syntax::Stmt::While {
            condition,
            body,
            else_body,
        } => ast_node(
            "While",
            vec![
                ("test", ast_expr_node(condition)),
                (
                    "body",
                    ast_nodes_list(body.iter().map(ast_stmt_node).collect()),
                ),
                (
                    "orelse",
                    ast_nodes_list(else_body.iter().map(ast_stmt_node).collect()),
                ),
            ],
        ),
        syntax::Stmt::For {
            target,
            iter,
            body,
            else_body,
        } => ast_for_node("For", target, iter, body, else_body),
        syntax::Stmt::AsyncFor {
            target,
            iter,
            body,
            else_body,
        } => ast_for_node("AsyncFor", target, iter, body, else_body),
        syntax::Stmt::Break => ast_node("Break", Vec::new()),
        syntax::Stmt::Continue => ast_node("Continue", Vec::new()),
    }
}

fn ast_function_def_node(
    kind: &str,
    name: &str,
    type_params: &[syntax::TypeParam],
    params: &syntax::FunctionParams,
    body: &[syntax::Stmt],
    decorators: &[syntax::Expr],
    returns: Option<&syntax::Expr>,
) -> Value {
    ast_node(
        kind,
        vec![
            ("name", Value::String(name.to_string())),
            ("args", ast_arguments_node(params)),
            (
                "body",
                ast_nodes_list(body.iter().map(ast_stmt_node).collect()),
            ),
            (
                "decorator_list",
                ast_nodes_list(decorators.iter().map(ast_expr_node).collect()),
            ),
            ("returns", ast_optional_expr(returns)),
            ("type_comment", Value::None),
            (
                "type_params",
                ast_nodes_list(type_params.iter().map(ast_type_param_node).collect()),
            ),
        ],
    )
}

fn ast_try_node(
    kind: &str,
    body: &[syntax::Stmt],
    handlers: &[syntax::ExceptHandler],
    else_body: &[syntax::Stmt],
    finally_body: &[syntax::Stmt],
) -> Value {
    ast_node(
        kind,
        vec![
            (
                "body",
                ast_nodes_list(body.iter().map(ast_stmt_node).collect()),
            ),
            (
                "handlers",
                ast_nodes_list(handlers.iter().map(ast_except_handler_node).collect()),
            ),
            (
                "orelse",
                ast_nodes_list(else_body.iter().map(ast_stmt_node).collect()),
            ),
            (
                "finalbody",
                ast_nodes_list(finally_body.iter().map(ast_stmt_node).collect()),
            ),
        ],
    )
}

fn ast_with_node(kind: &str, items: &[syntax::WithItem], body: &[syntax::Stmt]) -> Value {
    ast_node(
        kind,
        vec![
            (
                "items",
                ast_nodes_list(items.iter().map(ast_with_item_node).collect()),
            ),
            (
                "body",
                ast_nodes_list(body.iter().map(ast_stmt_node).collect()),
            ),
            ("type_comment", Value::None),
        ],
    )
}

fn ast_for_node(
    kind: &str,
    target: &syntax::Target,
    iter: &syntax::Expr,
    body: &[syntax::Stmt],
    else_body: &[syntax::Stmt],
) -> Value {
    ast_node(
        kind,
        vec![
            ("target", ast_target_node(target, "Store")),
            ("iter", ast_expr_node(iter)),
            (
                "body",
                ast_nodes_list(body.iter().map(ast_stmt_node).collect()),
            ),
            (
                "orelse",
                ast_nodes_list(else_body.iter().map(ast_stmt_node).collect()),
            ),
            ("type_comment", Value::None),
        ],
    )
}

fn ast_expr_node(expr: &syntax::Expr) -> Value {
    match expr {
        syntax::Expr::Number(value) => ast_constant_node(Value::Number(*value)),
        syntax::Expr::BigInt(value) => {
            let normalized = value.replace('_', "");
            let value = BigInt::parse_bytes(normalized.as_bytes(), 10)
                .map(normalize_big_int)
                .unwrap_or_else(|| Value::String(value.clone()));
            ast_constant_node(value)
        }
        syntax::Expr::Float(value) => ast_constant_node(
            value
                .replace('_', "")
                .parse::<f64>()
                .map(Value::Float)
                .unwrap_or_else(|_| Value::String(value.clone())),
        ),
        syntax::Expr::Imaginary(value) => {
            let text = value.trim_end_matches(['j', 'J']).replace('_', "");
            ast_constant_node(Value::Complex {
                real: 0.0,
                imag: text.parse::<f64>().unwrap_or(0.0),
            })
        }
        syntax::Expr::String(value) => ast_constant_node(Value::String(value.clone())),
        syntax::Expr::Bytes(value) => ast_constant_node(Value::Bytes(value.clone())),
        syntax::Expr::Bool(value) => ast_constant_node(Value::Bool(*value)),
        syntax::Expr::None => ast_constant_node(Value::None),
        syntax::Expr::Ellipsis => ast_constant_node(Value::Ellipsis),
        syntax::Expr::Name(name) => ast_name_node(name, "Load"),
        syntax::Expr::Attribute { object, name } => ast_node(
            "Attribute",
            vec![
                ("value", ast_expr_node(object)),
                ("attr", Value::String(name.clone())),
                ("ctx", ast_context_node("Load")),
            ],
        ),
        syntax::Expr::Binary { left, op, right } => ast_node(
            "BinOp",
            vec![
                ("left", ast_expr_node(left)),
                ("op", ast_binary_op_node(op)),
                ("right", ast_expr_node(right)),
            ],
        ),
        syntax::Expr::Comparison { left, op, right } => ast_node(
            "Compare",
            vec![
                ("left", ast_expr_node(left)),
                ("ops", ast_nodes_list(vec![ast_comparison_op_node(op)])),
                ("comparators", ast_nodes_list(vec![ast_expr_node(right)])),
            ],
        ),
        syntax::Expr::ChainedComparison { left, comparisons } => ast_node(
            "Compare",
            vec![
                ("left", ast_expr_node(left)),
                (
                    "ops",
                    ast_nodes_list(
                        comparisons
                            .iter()
                            .map(|(op, _)| ast_comparison_op_node(op))
                            .collect(),
                    ),
                ),
                (
                    "comparators",
                    ast_nodes_list(
                        comparisons
                            .iter()
                            .map(|(_, expr)| ast_expr_node(expr))
                            .collect(),
                    ),
                ),
            ],
        ),
        syntax::Expr::Unary { op, operand } => ast_node(
            "UnaryOp",
            vec![
                ("op", ast_unary_op_node(op)),
                ("operand", ast_expr_node(operand)),
            ],
        ),
        syntax::Expr::Logical { left, op, right } => ast_node(
            "BoolOp",
            vec![
                ("op", ast_logical_op_node(op)),
                (
                    "values",
                    ast_nodes_list(vec![ast_expr_node(left), ast_expr_node(right)]),
                ),
            ],
        ),
        syntax::Expr::IfExpression {
            condition,
            then_branch,
            else_branch,
        } => ast_node(
            "IfExp",
            vec![
                ("test", ast_expr_node(condition)),
                ("body", ast_expr_node(then_branch)),
                ("orelse", ast_expr_node(else_branch)),
            ],
        ),
        syntax::Expr::NamedExpr { name, value } => ast_node(
            "NamedExpr",
            vec![
                ("target", ast_name_node(name, "Store")),
                ("value", ast_expr_node(value)),
            ],
        ),
        syntax::Expr::Yield { value } => ast_node(
            "Yield",
            vec![(
                "value",
                value.as_deref().map(ast_expr_node).unwrap_or(Value::None),
            )],
        ),
        syntax::Expr::YieldFrom(value) => {
            ast_node("YieldFrom", vec![("value", ast_expr_node(value))])
        }
        syntax::Expr::Await(value) => ast_node("Await", vec![("value", ast_expr_node(value))]),
        syntax::Expr::Starred(value) => ast_node(
            "Starred",
            vec![
                ("value", ast_expr_node(value)),
                ("ctx", ast_context_node("Load")),
            ],
        ),
        syntax::Expr::List(values) => ast_node(
            "List",
            vec![
                (
                    "elts",
                    ast_nodes_list(values.iter().map(ast_expr_node).collect()),
                ),
                ("ctx", ast_context_node("Load")),
            ],
        ),
        syntax::Expr::ListComp { element, clauses } => {
            ast_comprehension_expr_node("ListComp", vec![("elt", ast_expr_node(element))], clauses)
        }
        syntax::Expr::Set(values) => ast_node(
            "Set",
            vec![(
                "elts",
                ast_nodes_list(values.iter().map(ast_expr_node).collect()),
            )],
        ),
        syntax::Expr::FrozenSet(values) => ast_constant_node(frozen_set_value(
            values
                .iter()
                .map(ast_expr_constant_value)
                .collect::<Option<Vec<_>>>()
                .unwrap_or_default(),
        )),
        syntax::Expr::SetComp { element, clauses } => {
            ast_comprehension_expr_node("SetComp", vec![("elt", ast_expr_node(element))], clauses)
        }
        syntax::Expr::GeneratorComp { element, clauses } => ast_comprehension_expr_node(
            "GeneratorExp",
            vec![("elt", ast_expr_node(element))],
            clauses,
        ),
        syntax::Expr::Tuple(values) => ast_node(
            "Tuple",
            vec![
                (
                    "elts",
                    ast_nodes_list(values.iter().map(ast_expr_node).collect()),
                ),
                ("ctx", ast_context_node("Load")),
            ],
        ),
        syntax::Expr::Dict(items) => ast_dict_node(items),
        syntax::Expr::DictComp {
            key,
            value,
            clauses,
        } => ast_comprehension_expr_node(
            "DictComp",
            vec![("key", ast_expr_node(key)), ("value", ast_expr_node(value))],
            clauses,
        ),
        syntax::Expr::DictUnpackComp { value, clauses } => ast_comprehension_expr_node(
            "DictComp",
            vec![("key", Value::None), ("value", ast_expr_node(value))],
            clauses,
        ),
        syntax::Expr::Subscript { object, index } => ast_node(
            "Subscript",
            vec![
                ("value", ast_expr_node(object)),
                ("slice", ast_expr_node(index)),
                ("ctx", ast_context_node("Load")),
            ],
        ),
        syntax::Expr::SliceLiteral { start, stop, step } => {
            ast_slice_node(start.as_deref(), stop.as_deref(), step.as_deref())
        }
        syntax::Expr::Slice {
            object,
            start,
            stop,
            step,
        } => ast_node(
            "Subscript",
            vec![
                ("value", ast_expr_node(object)),
                (
                    "slice",
                    ast_slice_node(start.as_deref(), stop.as_deref(), step.as_deref()),
                ),
                ("ctx", ast_context_node("Load")),
            ],
        ),
        syntax::Expr::Call { callee, args } => ast_node(
            "Call",
            vec![
                ("func", ast_expr_node(callee)),
                (
                    "args",
                    ast_nodes_list(args.iter().map(ast_expr_node).collect()),
                ),
                ("keywords", list_value(Vec::new())),
            ],
        ),
        syntax::Expr::KeywordCall {
            callee,
            args,
            keywords,
        } => ast_node(
            "Call",
            vec![
                ("func", ast_expr_node(callee)),
                (
                    "args",
                    ast_nodes_list(args.iter().map(ast_expr_node).collect()),
                ),
                (
                    "keywords",
                    ast_nodes_list(
                        keywords
                            .iter()
                            .map(|(name, value)| ast_keyword_node(Some(name.as_str()), value))
                            .collect(),
                    ),
                ),
            ],
        ),
        syntax::Expr::UnpackCall {
            callee,
            args,
            keywords,
        } => ast_node(
            "Call",
            vec![
                ("func", ast_expr_node(callee)),
                (
                    "args",
                    ast_nodes_list(args.iter().map(ast_call_arg_node).collect()),
                ),
                (
                    "keywords",
                    ast_nodes_list(keywords.iter().map(ast_call_keyword_node).collect()),
                ),
            ],
        ),
        syntax::Expr::Lambda { params, body } => ast_node(
            "Lambda",
            vec![
                ("args", ast_arguments_node(params)),
                ("body", ast_expr_node(body)),
            ],
        ),
        syntax::Expr::JoinedString(parts) => ast_node(
            "JoinedStr",
            vec![(
                "values",
                ast_nodes_list(parts.iter().map(ast_fstring_part_node).collect()),
            )],
        ),
        syntax::Expr::TemplateString(parts) => ast_node(
            "TemplateStr",
            vec![(
                "values",
                ast_nodes_list(parts.iter().map(ast_template_string_part_node).collect()),
            )],
        ),
    }
}

fn ast_constant_node(value: Value) -> Value {
    ast_node("Constant", vec![("value", value), ("kind", Value::None)])
}

fn ast_expr_constant_value(expr: &syntax::Expr) -> Option<Value> {
    match expr {
        syntax::Expr::Number(value) => Some(Value::Number(*value)),
        syntax::Expr::BigInt(value) => {
            let normalized = value.replace('_', "");
            BigInt::parse_bytes(normalized.as_bytes(), 10)
                .map(normalize_big_int)
                .or_else(|| Some(Value::String(value.clone())))
        }
        syntax::Expr::Float(value) => value.replace('_', "").parse::<f64>().map(Value::Float).ok(),
        syntax::Expr::Imaginary(value) => {
            let text = value.trim_end_matches(['j', 'J']).replace('_', "");
            Some(Value::Complex {
                real: 0.0,
                imag: text.parse::<f64>().ok()?,
            })
        }
        syntax::Expr::String(value) => Some(Value::String(value.clone())),
        syntax::Expr::Bytes(value) => Some(Value::Bytes(value.clone())),
        syntax::Expr::Bool(value) => Some(Value::Bool(*value)),
        syntax::Expr::None => Some(Value::None),
        syntax::Expr::Ellipsis => Some(Value::Ellipsis),
        syntax::Expr::Tuple(values) => values
            .iter()
            .map(ast_expr_constant_value)
            .collect::<Option<Vec<_>>>()
            .map(tuple_value),
        syntax::Expr::FrozenSet(values) => values
            .iter()
            .map(ast_expr_constant_value)
            .collect::<Option<Vec<_>>>()
            .map(frozen_set_value),
        _ => None,
    }
}

fn ast_name_node(name: &str, ctx: &str) -> Value {
    ast_node(
        "Name",
        vec![
            ("id", Value::String(name.to_string())),
            ("ctx", ast_context_node(ctx)),
        ],
    )
}

fn ast_slice_node(
    start: Option<&syntax::Expr>,
    stop: Option<&syntax::Expr>,
    step: Option<&syntax::Expr>,
) -> Value {
    ast_node(
        "Slice",
        vec![
            ("lower", ast_optional_expr(start)),
            ("upper", ast_optional_expr(stop)),
            ("step", ast_optional_expr(step)),
        ],
    )
}

fn ast_target_node(target: &syntax::Target, ctx: &str) -> Value {
    match target {
        syntax::Target::Name(name) => ast_name_node(name, ctx),
        syntax::Target::Attribute { object, name } => ast_node(
            "Attribute",
            vec![
                ("value", ast_expr_node(object)),
                ("attr", Value::String(name.clone())),
                ("ctx", ast_context_node(ctx)),
            ],
        ),
        syntax::Target::Subscript { object, index } => ast_node(
            "Subscript",
            vec![
                ("value", ast_expr_node(object)),
                ("slice", ast_expr_node(index)),
                ("ctx", ast_context_node(ctx)),
            ],
        ),
        syntax::Target::Slice {
            object,
            start,
            stop,
            step,
        } => ast_node(
            "Subscript",
            vec![
                ("value", ast_expr_node(object)),
                (
                    "slice",
                    ast_slice_node(start.as_ref(), stop.as_ref(), step.as_ref()),
                ),
                ("ctx", ast_context_node(ctx)),
            ],
        ),
        syntax::Target::Starred(value) => ast_node(
            "Starred",
            vec![
                ("value", ast_target_node(value, ctx)),
                ("ctx", ast_context_node(ctx)),
            ],
        ),
        syntax::Target::Tuple(values) => ast_node(
            "Tuple",
            vec![
                (
                    "elts",
                    ast_nodes_list(
                        values
                            .iter()
                            .map(|target| ast_target_node(target, ctx))
                            .collect(),
                    ),
                ),
                ("ctx", ast_context_node(ctx)),
            ],
        ),
        syntax::Target::List(values) => ast_node(
            "List",
            vec![
                (
                    "elts",
                    ast_nodes_list(
                        values
                            .iter()
                            .map(|target| ast_target_node(target, ctx))
                            .collect(),
                    ),
                ),
                ("ctx", ast_context_node(ctx)),
            ],
        ),
    }
}

fn ast_dict_node(items: &[syntax::DictItem]) -> Value {
    let mut keys = Vec::new();
    let mut values = Vec::new();
    for item in items {
        match item {
            syntax::DictItem::Entry { key, value } => {
                keys.push(ast_expr_node(key));
                values.push(ast_expr_node(value));
            }
            syntax::DictItem::Unpack(value) => {
                keys.push(Value::None);
                values.push(ast_expr_node(value));
            }
        }
    }
    ast_node(
        "Dict",
        vec![
            ("keys", ast_nodes_list(keys)),
            ("values", ast_nodes_list(values)),
        ],
    )
}

fn ast_comprehension_expr_node(
    kind: &str,
    mut leading_fields: Vec<(&str, Value)>,
    clauses: &[syntax::ComprehensionClause],
) -> Value {
    leading_fields.push((
        "generators",
        ast_nodes_list(clauses.iter().map(ast_comprehension_node).collect()),
    ));
    ast_node(kind, leading_fields)
}

fn ast_comprehension_node(clause: &syntax::ComprehensionClause) -> Value {
    ast_node(
        "comprehension",
        vec![
            ("target", ast_target_node(&clause.target, "Store")),
            ("iter", ast_expr_node(&clause.iter)),
            (
                "ifs",
                ast_nodes_list(clause.ifs.iter().map(ast_expr_node).collect()),
            ),
            ("is_async", Value::Number(clause.is_async as i64)),
        ],
    )
}

fn ast_arguments_node(params: &syntax::FunctionParams) -> Value {
    let positional_defaults = params
        .positional_only
        .iter()
        .chain(params.positional.iter())
        .filter_map(|param| param.default.as_ref().map(ast_expr_node))
        .collect();
    ast_node(
        "arguments",
        vec![
            (
                "posonlyargs",
                ast_nodes_list(params.positional_only.iter().map(ast_param_node).collect()),
            ),
            (
                "args",
                ast_nodes_list(params.positional.iter().map(ast_param_node).collect()),
            ),
            (
                "vararg",
                params
                    .vararg
                    .as_ref()
                    .map(|name| ast_arg_node(name, params.vararg_annotation.as_deref()))
                    .unwrap_or(Value::None),
            ),
            (
                "kwonlyargs",
                ast_nodes_list(params.keyword_only.iter().map(ast_param_node).collect()),
            ),
            (
                "kw_defaults",
                ast_nodes_list(
                    params
                        .keyword_only
                        .iter()
                        .map(|param| {
                            param
                                .default
                                .as_ref()
                                .map(ast_expr_node)
                                .unwrap_or(Value::None)
                        })
                        .collect(),
                ),
            ),
            (
                "kwarg",
                params
                    .kwarg
                    .as_ref()
                    .map(|name| ast_arg_node(name, params.kwarg_annotation.as_deref()))
                    .unwrap_or(Value::None),
            ),
            ("defaults", ast_nodes_list(positional_defaults)),
        ],
    )
}

fn ast_param_node(param: &syntax::Param) -> Value {
    ast_arg_node(&param.name, param.annotation.as_ref())
}

fn ast_arg_node(name: &str, annotation: Option<&syntax::Expr>) -> Value {
    ast_node(
        "arg",
        vec![
            ("arg", Value::String(name.to_string())),
            ("annotation", ast_optional_expr(annotation)),
            ("type_comment", Value::None),
        ],
    )
}

fn ast_call_arg_node(arg: &syntax::CallArg) -> Value {
    match arg {
        syntax::CallArg::Expr(expr) => ast_expr_node(expr),
        syntax::CallArg::Unpack(expr) => ast_node(
            "Starred",
            vec![
                ("value", ast_expr_node(expr)),
                ("ctx", ast_context_node("Load")),
            ],
        ),
    }
}

fn ast_call_keyword_node(keyword: &syntax::CallKeyword) -> Value {
    match keyword {
        syntax::CallKeyword::Named(name, value) => ast_keyword_node(Some(name), value),
        syntax::CallKeyword::Unpack(value) => ast_keyword_node(None, value),
    }
}

fn ast_keyword_node(name: Option<&str>, value: &syntax::Expr) -> Value {
    ast_node(
        "keyword",
        vec![
            (
                "arg",
                name.map(|name| Value::String(name.to_string()))
                    .unwrap_or(Value::None),
            ),
            ("value", ast_expr_node(value)),
        ],
    )
}

fn ast_alias_node(alias: &syntax::ImportAlias) -> Value {
    ast_node(
        "alias",
        vec![
            ("name", Value::String(alias.name.clone())),
            (
                "asname",
                alias
                    .asname
                    .as_ref()
                    .map(|name| Value::String(name.clone()))
                    .unwrap_or(Value::None),
            ),
        ],
    )
}

fn ast_import_from_targets(targets: &syntax::ImportFromTargets) -> Value {
    match targets {
        syntax::ImportFromTargets::Star => ast_nodes_list(vec![ast_node(
            "alias",
            vec![
                ("name", Value::String("*".to_string())),
                ("asname", Value::None),
            ],
        )]),
        syntax::ImportFromTargets::Aliases(aliases) => {
            ast_nodes_list(aliases.iter().map(ast_alias_node).collect())
        }
    }
}

fn ast_except_handler_node(handler: &syntax::ExceptHandler) -> Value {
    ast_node(
        "ExceptHandler",
        vec![
            (
                "type",
                handler
                    .type_expr
                    .as_ref()
                    .map(ast_expr_node)
                    .unwrap_or(Value::None),
            ),
            (
                "name",
                handler
                    .name
                    .as_ref()
                    .map(|name| Value::String(name.clone()))
                    .unwrap_or(Value::None),
            ),
            (
                "body",
                ast_nodes_list(handler.body.iter().map(ast_stmt_node).collect()),
            ),
        ],
    )
}

fn ast_with_item_node(item: &syntax::WithItem) -> Value {
    ast_node(
        "withitem",
        vec![
            ("context_expr", ast_expr_node(&item.context_expr)),
            (
                "optional_vars",
                item.optional_vars
                    .as_ref()
                    .map(|target| ast_target_node(target, "Store"))
                    .unwrap_or(Value::None),
            ),
        ],
    )
}

fn ast_match_case_node(case: &syntax::MatchCase) -> Value {
    ast_node(
        "match_case",
        vec![
            ("pattern", ast_pattern_node(&case.pattern)),
            (
                "guard",
                case.guard
                    .as_ref()
                    .map(ast_expr_node)
                    .unwrap_or(Value::None),
            ),
            (
                "body",
                ast_nodes_list(case.body.iter().map(ast_stmt_node).collect()),
            ),
        ],
    )
}

fn ast_pattern_node(pattern: &syntax::Pattern) -> Value {
    match pattern {
        syntax::Pattern::Literal(expr) | syntax::Pattern::Value(expr) => {
            ast_node("MatchValue", vec![("value", ast_expr_node(expr))])
        }
        syntax::Pattern::Singleton(expr) => ast_node(
            "MatchSingleton",
            vec![("value", ast_pattern_singleton_value_node(expr))],
        ),
        syntax::Pattern::Capture(name) => ast_node(
            "MatchAs",
            vec![
                ("pattern", Value::None),
                ("name", Value::String(name.clone())),
            ],
        ),
        syntax::Pattern::Wildcard => ast_node(
            "MatchAs",
            vec![("pattern", Value::None), ("name", Value::None)],
        ),
        syntax::Pattern::Or(patterns) => ast_node(
            "MatchOr",
            vec![(
                "patterns",
                ast_nodes_list(patterns.iter().map(ast_pattern_node).collect()),
            )],
        ),
        syntax::Pattern::Sequence(patterns) => ast_node(
            "MatchSequence",
            vec![(
                "patterns",
                ast_nodes_list(patterns.iter().map(ast_pattern_node).collect()),
            )],
        ),
        syntax::Pattern::Mapping { entries, rest } => {
            let keys = entries.iter().map(|(key, _)| ast_expr_node(key)).collect();
            let patterns = entries
                .iter()
                .map(|(_, pattern)| ast_pattern_node(pattern))
                .collect();
            ast_node(
                "MatchMapping",
                vec![
                    ("keys", ast_nodes_list(keys)),
                    ("patterns", ast_nodes_list(patterns)),
                    (
                        "rest",
                        rest.as_ref()
                            .map(|name| Value::String(name.clone()))
                            .unwrap_or(Value::None),
                    ),
                ],
            )
        }
        syntax::Pattern::Class {
            class,
            positional,
            keywords,
        } => ast_node(
            "MatchClass",
            vec![
                ("cls", ast_expr_node(class)),
                (
                    "patterns",
                    ast_nodes_list(positional.iter().map(ast_pattern_node).collect()),
                ),
                (
                    "kwd_attrs",
                    ast_string_list(keywords.iter().map(|(name, _)| name.clone()).collect()),
                ),
                (
                    "kwd_patterns",
                    ast_nodes_list(
                        keywords
                            .iter()
                            .map(|(_, pattern)| ast_pattern_node(pattern))
                            .collect(),
                    ),
                ),
            ],
        ),
        syntax::Pattern::Star(name) => ast_node(
            "MatchStar",
            vec![(
                "name",
                name.as_ref()
                    .map(|name| Value::String(name.clone()))
                    .unwrap_or(Value::None),
            )],
        ),
        syntax::Pattern::As { pattern, name } => ast_node(
            "MatchAs",
            vec![
                ("pattern", ast_pattern_node(pattern)),
                ("name", Value::String(name.clone())),
            ],
        ),
    }
}

fn ast_pattern_singleton_value_node(expr: &syntax::Expr) -> Value {
    match expr {
        syntax::Expr::None => Value::None,
        syntax::Expr::Bool(value) => Value::Bool(*value),
        _ => ast_expr_node(expr),
    }
}

fn ast_type_param_node(type_param: &syntax::TypeParam) -> Value {
    let kind = match type_param.kind {
        syntax::TypeParamKind::TypeVar => "TypeVar",
        syntax::TypeParamKind::TypeVarTuple => "TypeVarTuple",
        syntax::TypeParamKind::ParamSpec => "ParamSpec",
    };
    let mut fields = vec![("name", Value::String(type_param.name.clone()))];
    if matches!(type_param.kind, syntax::TypeParamKind::TypeVar) {
        fields.push((
            "bound",
            type_param
                .bound
                .as_ref()
                .map(ast_expr_node)
                .unwrap_or(Value::None),
        ));
    }
    fields.push((
        "default_value",
        type_param
            .default
            .as_ref()
            .map(ast_expr_node)
            .unwrap_or(Value::None),
    ));
    ast_node(kind, fields)
}

fn ast_fstring_part_node(part: &syntax::FStringPart) -> Value {
    match part {
        syntax::FStringPart::Literal(value) => ast_constant_node(Value::String(value.clone())),
        syntax::FStringPart::Formatted {
            value,
            conversion,
            format_spec,
        } => ast_node(
            "FormattedValue",
            vec![
                ("value", ast_expr_node(value)),
                (
                    "conversion",
                    Value::Number(ast_fstring_conversion_code(*conversion)),
                ),
                (
                    "format_spec",
                    format_spec
                        .as_ref()
                        .map(|parts| {
                            ast_node(
                                "JoinedStr",
                                vec![(
                                    "values",
                                    ast_nodes_list(
                                        parts.iter().map(ast_fstring_part_node).collect(),
                                    ),
                                )],
                            )
                        })
                        .unwrap_or(Value::None),
                ),
            ],
        ),
    }
}

fn ast_template_string_part_node(part: &syntax::TemplateStringPart) -> Value {
    match part {
        syntax::TemplateStringPart::Literal(value) => {
            ast_constant_node(Value::String(value.clone()))
        }
        syntax::TemplateStringPart::Interpolation {
            value,
            expression,
            conversion,
            format_spec,
        } => ast_node(
            "Interpolation",
            vec![
                ("value", ast_expr_node(value)),
                ("str", Value::String(expression.clone())),
                (
                    "conversion",
                    Value::Number(ast_fstring_conversion_code(*conversion)),
                ),
                (
                    "format_spec",
                    format_spec
                        .as_ref()
                        .map(|parts| {
                            ast_node(
                                "JoinedStr",
                                vec![(
                                    "values",
                                    ast_nodes_list(
                                        parts.iter().map(ast_fstring_part_node).collect(),
                                    ),
                                )],
                            )
                        })
                        .unwrap_or(Value::None),
                ),
            ],
        ),
    }
}

fn ast_fstring_conversion_code(conversion: Option<syntax::FStringConversion>) -> i64 {
    match conversion {
        None => -1,
        Some(syntax::FStringConversion::Str) => 115,
        Some(syntax::FStringConversion::Repr) => 114,
        Some(syntax::FStringConversion::Ascii) => 97,
    }
}

fn ast_binary_op_node(op: &syntax::BinaryOp) -> Value {
    ast_node(
        match op {
            syntax::BinaryOp::Add => "Add",
            syntax::BinaryOp::Subtract => "Sub",
            syntax::BinaryOp::Multiply => "Mult",
            syntax::BinaryOp::MatrixMultiply => "MatMult",
            syntax::BinaryOp::TrueDivide => "Div",
            syntax::BinaryOp::FloorDivide => "FloorDiv",
            syntax::BinaryOp::Modulo => "Mod",
            syntax::BinaryOp::Power => "Pow",
            syntax::BinaryOp::BitOr => "BitOr",
            syntax::BinaryOp::BitXor => "BitXor",
            syntax::BinaryOp::BitAnd => "BitAnd",
            syntax::BinaryOp::LeftShift => "LShift",
            syntax::BinaryOp::RightShift => "RShift",
        },
        Vec::new(),
    )
}

fn ast_comparison_op_node(op: &syntax::ComparisonOp) -> Value {
    ast_node(
        match op {
            syntax::ComparisonOp::Equal => "Eq",
            syntax::ComparisonOp::NotEqual => "NotEq",
            syntax::ComparisonOp::Less => "Lt",
            syntax::ComparisonOp::LessEqual => "LtE",
            syntax::ComparisonOp::Greater => "Gt",
            syntax::ComparisonOp::GreaterEqual => "GtE",
            syntax::ComparisonOp::In => "In",
            syntax::ComparisonOp::NotIn => "NotIn",
            syntax::ComparisonOp::Is => "Is",
            syntax::ComparisonOp::IsNot => "IsNot",
        },
        Vec::new(),
    )
}

fn ast_unary_op_node(op: &syntax::UnaryOp) -> Value {
    ast_node(
        match op {
            syntax::UnaryOp::Not => "Not",
            syntax::UnaryOp::Positive => "UAdd",
            syntax::UnaryOp::Negative => "USub",
            syntax::UnaryOp::Invert => "Invert",
        },
        Vec::new(),
    )
}

fn ast_logical_op_node(op: &syntax::LogicalOp) -> Value {
    ast_node(
        match op {
            syntax::LogicalOp::And => "And",
            syntax::LogicalOp::Or => "Or",
        },
        Vec::new(),
    )
}

fn call_ast_constructor(
    kind: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if ast_builtin_class_attr_is_deleted(kind, "_fields") {
        return Err(format!(
            "AttributeError: type object 'ast.{kind}' has no attribute '_fields'"
        ));
    }

    let fields = ast_constructor_fields(kind);
    if args.len() > fields.len() {
        return Err(format!(
            "TypeError: {kind} constructor takes at most {} positional argument{}",
            fields.len(),
            if fields.len() == 1 { "" } else { "s" }
        ));
    }

    let mut attrs = Vec::new();
    for (index, value) in args.into_iter().enumerate() {
        attrs.push((fields[index], value));
    }

    for (keyword, value) in keywords {
        if let Some(field) = fields.iter().find(|field| **field == keyword) {
            if attrs.iter().any(|(name, _)| name == field) {
                return Err(format!(
                    "TypeError: {kind} constructor got multiple values for argument '{keyword}'"
                ));
            }
            attrs.push((*field, value));
        } else {
            attrs.push((Box::leak(keyword.into_boxed_str()), value));
        }
    }

    for field in fields.iter().copied() {
        if attrs.iter().any(|(name, _)| *name == field) {
            continue;
        }
        if let Some(value) = ast_constructor_default(kind, field) {
            attrs.push((field, value));
        }
    }

    Ok(ast_node_with_fields(kind, fields, attrs))
}

fn ast_builtin_class_attr_override(kind: &str, name: &str) -> Option<Option<Value>> {
    AST_BUILTIN_CLASS_ATTR_OVERRIDES.with(|overrides| {
        overrides
            .borrow()
            .get(&(kind.to_string(), name.to_string()))
            .cloned()
    })
}

fn ast_builtin_class_attr_is_deleted(kind: &str, name: &str) -> bool {
    matches!(ast_builtin_class_attr_override(kind, name), Some(None))
}

fn set_ast_builtin_class_attr_override(kind: &str, name: &str, value: Option<Value>) {
    AST_BUILTIN_CLASS_ATTR_OVERRIDES.with(|overrides| {
        overrides
            .borrow_mut()
            .insert((kind.to_string(), name.to_string()), value);
    });
}

fn call_ast_helper_constructor(
    kind: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if !keywords.is_empty() {
        return Err(format!("{kind}() does not accept keyword arguments"));
    }
    if !args.is_empty() {
        return Err(format!("{kind}() takes no arguments"));
    }

    let class_attrs = new_scope();
    class_attrs
        .borrow_mut()
        .insert("__module__".to_string(), Value::String("ast".to_string()));
    Ok(Value::Instance {
        class_name: kind.to_string(),
        fields: new_scope(),
        class_attrs,
        class_bases: vec![Value::Builtin(kind.to_string())],
    })
}

fn ast_constructor_fields(kind: &str) -> Vec<&'static str> {
    match kind {
        "Module" => vec!["body", "type_ignores"],
        "Interactive" => vec!["body"],
        "Expression" => vec!["body"],
        "FunctionType" => vec!["argtypes", "returns"],
        "Expr" => vec!["value"],
        "Assign" => vec!["targets", "value", "type_comment"],
        "AnnAssign" => vec!["target", "annotation", "value", "simple"],
        "TypeAlias" => vec!["name", "type_params", "value"],
        "AugAssign" => vec!["target", "op", "value"],
        "Delete" => vec!["targets"],
        "FunctionDef" | "AsyncFunctionDef" => vec![
            "name",
            "args",
            "body",
            "decorator_list",
            "returns",
            "type_comment",
            "type_params",
        ],
        "ClassDef" => vec![
            "name",
            "bases",
            "keywords",
            "body",
            "decorator_list",
            "type_params",
        ],
        "Import" => vec!["names", "is_lazy"],
        "ImportFrom" => vec!["module", "names", "level", "is_lazy"],
        "Return" => vec!["value"],
        "Global" | "Nonlocal" => vec!["names"],
        "Assert" => vec!["test", "msg"],
        "Raise" => vec!["exc", "cause"],
        "If" | "While" => vec!["test", "body", "orelse"],
        "Match" => vec!["subject", "cases"],
        "Try" | "TryStar" => vec!["body", "handlers", "orelse", "finalbody"],
        "With" | "AsyncWith" => vec!["items", "body", "type_comment"],
        "For" | "AsyncFor" => vec!["target", "iter", "body", "orelse", "type_comment"],
        "Name" => vec!["id", "ctx"],
        "Constant" => vec!["value", "kind"],
        "Attribute" => vec!["value", "attr", "ctx"],
        "BinOp" => vec!["left", "op", "right"],
        "Compare" => vec!["left", "ops", "comparators"],
        "UnaryOp" => vec!["op", "operand"],
        "BoolOp" => vec!["op", "values"],
        "IfExp" => vec!["test", "body", "orelse"],
        "NamedExpr" => vec!["target", "value"],
        "Yield" => vec!["value"],
        "YieldFrom" | "Await" => vec!["value"],
        "Starred" => vec!["value", "ctx"],
        "List" | "Tuple" => vec!["elts", "ctx"],
        "Set" => vec!["elts"],
        "ListComp" | "SetComp" | "GeneratorExp" => vec!["elt", "generators"],
        "Dict" => vec!["keys", "values"],
        "DictComp" => vec!["key", "value", "generators"],
        "Subscript" => vec!["value", "slice", "ctx"],
        "Slice" => vec!["lower", "upper", "step"],
        "Call" => vec!["func", "args", "keywords"],
        "Lambda" => vec!["args", "body"],
        "JoinedStr" | "TemplateStr" => vec!["values"],
        "FormattedValue" => vec!["value", "conversion", "format_spec"],
        "Interpolation" => vec!["value", "str", "conversion", "format_spec"],
        "arguments" => vec![
            "posonlyargs",
            "args",
            "vararg",
            "kwonlyargs",
            "kw_defaults",
            "kwarg",
            "defaults",
        ],
        "arg" => vec!["arg", "annotation", "type_comment"],
        "keyword" => vec!["arg", "value"],
        "alias" => vec!["name", "asname"],
        "ExceptHandler" => vec!["type", "name", "body"],
        "withitem" => vec!["context_expr", "optional_vars"],
        "comprehension" => vec!["target", "iter", "ifs", "is_async"],
        "match_case" => vec!["pattern", "guard", "body"],
        "MatchValue" | "MatchSingleton" => vec!["value"],
        "MatchAs" => vec!["pattern", "name"],
        "MatchOr" | "MatchSequence" => vec!["patterns"],
        "MatchMapping" => vec!["keys", "patterns", "rest"],
        "MatchClass" => vec!["cls", "patterns", "kwd_attrs", "kwd_patterns"],
        "MatchStar" => vec!["name"],
        "TypeVar" => vec!["name", "bound", "default_value"],
        "TypeVarTuple" | "ParamSpec" => vec!["name", "default_value"],
        "TypeIgnore" => vec!["lineno", "tag"],
        _ => Vec::new(),
    }
}

fn ast_constructor_field_types(kind: &str) -> Vec<&'static str> {
    match kind {
        "Module" => vec!["stmt*", "type_ignore*"],
        "Interactive" => vec!["stmt*"],
        "Expression" => vec!["expr"],
        "FunctionType" => vec!["expr*", "expr"],
        "FunctionDef" | "AsyncFunctionDef" => vec![
            "identifier",
            "arguments",
            "stmt*",
            "expr*",
            "expr?",
            "string?",
            "type_param*",
        ],
        "ClassDef" => vec![
            "identifier",
            "expr*",
            "keyword*",
            "stmt*",
            "expr*",
            "type_param*",
        ],
        "Return" => vec!["expr?"],
        "Delete" => vec!["expr*"],
        "Assign" => vec!["expr*", "expr", "string?"],
        "TypeAlias" => vec!["expr", "type_param*", "expr"],
        "AugAssign" => vec!["expr", "operator", "expr"],
        "AnnAssign" => vec!["expr", "expr", "expr?", "int"],
        "For" | "AsyncFor" => vec!["expr", "expr", "stmt*", "stmt*", "string?"],
        "While" | "If" => vec!["expr", "stmt*", "stmt*"],
        "With" | "AsyncWith" => vec!["withitem*", "stmt*", "string?"],
        "Match" => vec!["expr", "match_case*"],
        "Raise" => vec!["expr?", "expr?"],
        "Try" | "TryStar" => vec!["stmt*", "excepthandler*", "stmt*", "stmt*"],
        "Assert" => vec!["expr", "expr?"],
        "Import" => vec!["alias*", "int?"],
        "ImportFrom" => vec!["identifier?", "alias*", "int?", "int?"],
        "Global" | "Nonlocal" => vec!["identifier*"],
        "Expr" => vec!["expr"],
        "BoolOp" => vec!["boolop", "expr*"],
        "NamedExpr" => vec!["expr", "expr"],
        "BinOp" => vec!["expr", "operator", "expr"],
        "UnaryOp" => vec!["unaryop", "expr"],
        "Lambda" => vec!["arguments", "expr"],
        "IfExp" => vec!["expr", "expr", "expr"],
        "Dict" => vec!["expr?*", "expr*"],
        "Set" => vec!["expr*"],
        "ListComp" | "SetComp" | "GeneratorExp" => vec!["expr", "comprehension*"],
        "DictComp" => vec!["expr", "expr?", "comprehension*"],
        "Await" => vec!["expr"],
        "Yield" => vec!["expr?"],
        "YieldFrom" => vec!["expr"],
        "Compare" => vec!["expr", "cmpop*", "expr*"],
        "Call" => vec!["expr", "expr*", "keyword*"],
        "FormattedValue" => vec!["expr", "int", "expr?"],
        "Interpolation" => vec!["expr", "constant", "int", "expr?"],
        "JoinedStr" | "TemplateStr" => vec!["expr*"],
        "Constant" => vec!["constant", "string?"],
        "Attribute" => vec!["expr", "identifier", "expr_context"],
        "Subscript" => vec!["expr", "expr", "expr_context"],
        "Starred" => vec!["expr", "expr_context"],
        "Name" => vec!["identifier", "expr_context"],
        "List" | "Tuple" => vec!["expr*", "expr_context"],
        "Slice" => vec!["expr?", "expr?", "expr?"],
        "comprehension" => vec!["expr", "expr", "expr*", "int"],
        "ExceptHandler" => vec!["expr?", "identifier?", "stmt*"],
        "arguments" => vec!["arg*", "arg*", "arg?", "arg*", "expr?*", "arg?", "expr*"],
        "arg" => vec!["identifier", "expr?", "string?"],
        "keyword" => vec!["identifier?", "expr"],
        "alias" => vec!["identifier", "identifier?"],
        "withitem" => vec!["expr", "expr?"],
        "match_case" => vec!["pattern", "expr?", "stmt*"],
        "MatchValue" => vec!["expr"],
        "MatchSingleton" => vec!["constant"],
        "MatchSequence" => vec!["pattern*"],
        "MatchMapping" => vec!["expr*", "pattern*", "identifier?"],
        "MatchClass" => vec!["expr", "pattern*", "identifier*", "pattern*"],
        "MatchStar" => vec!["identifier?"],
        "MatchAs" => vec!["pattern?", "identifier?"],
        "MatchOr" => vec!["pattern*"],
        "TypeIgnore" => vec!["int", "string"],
        "TypeVar" => vec!["identifier", "expr?", "expr?"],
        "TypeVarTuple" | "ParamSpec" => vec!["identifier", "expr?"],
        _ => Vec::new(),
    }
}

fn ast_field_types_dict(kind: &str) -> Value {
    dict_value(
        ast_constructor_fields(kind)
            .into_iter()
            .zip(ast_constructor_field_types(kind))
            .map(|(field, ty)| (Value::String(field.to_string()), ast_field_type_value(ty)))
            .collect(),
    )
}

fn ast_field_type_value(ty: &str) -> Value {
    if let Some(inner) = ty.strip_suffix("?*") {
        return generic_alias_value(
            builtin_type_value("list"),
            vec![ast_field_type_value(inner)],
        );
    }
    if let Some(inner) = ty.strip_suffix('*') {
        return generic_alias_value(
            builtin_type_value("list"),
            vec![ast_field_type_value(inner)],
        );
    }
    if let Some(inner) = ty.strip_suffix('?') {
        return union_type_value(ast_field_type_value(inner), Value::None);
    }

    match ty {
        "identifier" | "string" => builtin_type_value("str"),
        "int" => builtin_type_value("int"),
        "constant" => builtin_type_value("object"),
        kind => ast_builtin_value_for_kind(kind),
    }
}

fn ast_type_doc(kind: &str) -> String {
    let fields = ast_constructor_fields(kind);
    if !fields.is_empty() {
        let types = ast_constructor_field_types(kind);
        let signature = fields
            .iter()
            .zip(types.iter())
            .map(|(field, ty)| format!("{ty} {field}"))
            .collect::<Vec<_>>()
            .join(", ");
        return format!("{kind}({signature})");
    }

    let children = ast_direct_subclass_kinds(kind);
    if kind != "AST" && !children.is_empty() {
        if children
            .iter()
            .all(|child| ast_constructor_fields(child).is_empty())
        {
            return format!("{kind} = {}", children.join(" | "));
        }
        let docs = children
            .iter()
            .map(|child| ast_type_doc(child))
            .collect::<Vec<_>>();
        return format!("{kind} = {}", docs.join("\n     | "));
    }

    kind.to_string()
}

fn ast_constructor_default(kind: &str, field: &str) -> Option<Value> {
    match (kind, field) {
        ("Module", "body" | "type_ignores")
        | ("Interactive", "body")
        | ("FunctionType", "argtypes")
        | ("FunctionDef" | "AsyncFunctionDef", "body" | "decorator_list" | "type_params")
        | ("ClassDef", "bases" | "keywords" | "body" | "decorator_list" | "type_params")
        | ("Import", "names")
        | ("Delete", "targets")
        | ("Global" | "Nonlocal", "names")
        | ("Match", "cases")
        | ("Try" | "TryStar", "body" | "handlers" | "orelse" | "finalbody")
        | ("With" | "AsyncWith", "items" | "body")
        | ("For" | "AsyncFor", "body" | "orelse")
        | ("Compare", "ops" | "comparators")
        | ("BoolOp", "values")
        | ("List" | "Tuple" | "Set", "elts")
        | ("ListComp" | "SetComp" | "GeneratorExp", "generators")
        | ("Dict", "keys" | "values")
        | ("DictComp", "generators")
        | ("Call", "args" | "keywords")
        | ("JoinedStr" | "TemplateStr", "values")
        | ("arguments", "posonlyargs" | "args" | "kwonlyargs" | "kw_defaults" | "defaults")
        | ("ExceptHandler", "body")
        | ("comprehension", "ifs")
        | ("match_case", "body")
        | ("MatchOr" | "MatchSequence", "patterns")
        | ("MatchMapping", "keys" | "patterns")
        | ("MatchClass", "patterns" | "kwd_attrs" | "kwd_patterns") => Some(list_value(Vec::new())),
        ("Name" | "Attribute" | "Subscript" | "Starred" | "List" | "Tuple", "ctx") => {
            Some(ast_context_node("Load"))
        }
        ("FunctionDef" | "AsyncFunctionDef", "returns" | "type_comment")
        | ("AnnAssign", "value")
        | ("Constant", "kind")
        | ("ImportFrom", "module")
        | ("Return", "value")
        | ("Assert", "msg")
        | ("Raise", "exc" | "cause")
        | ("With" | "AsyncWith" | "For" | "AsyncFor", "type_comment")
        | ("Yield", "value")
        | ("Slice", "lower" | "upper" | "step")
        | ("FormattedValue" | "Interpolation", "format_spec")
        | ("arguments", "vararg" | "kwarg")
        | ("arg", "annotation" | "type_comment")
        | ("keyword", "arg")
        | ("alias", "asname")
        | ("ExceptHandler", "type" | "name")
        | ("withitem", "optional_vars")
        | ("match_case", "guard")
        | ("MatchAs", "pattern" | "name")
        | ("MatchMapping", "rest")
        | ("MatchStar", "name")
        | ("TypeVar", "bound" | "default_value")
        | ("TypeVarTuple" | "ParamSpec", "default_value") => Some(Value::None),
        ("AnnAssign", "simple")
        | ("Import" | "ImportFrom", "is_lazy")
        | ("ImportFrom", "level")
        | ("comprehension", "is_async") => Some(Value::Number(0)),
        ("FormattedValue" | "Interpolation", "conversion") => Some(Value::Number(-1)),
        _ => None,
    }
}

fn call_ast_parse(
    vm: &mut Vm,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let mut values = vec![None, None, None, None, None, None, None];
    let names = [
        "source",
        "filename",
        "mode",
        "type_comments",
        "feature_version",
        "optimize",
        "module",
    ];
    if args.len() > 3 {
        return Err(format!(
            "TypeError: parse() takes from 1 to 3 positional arguments but {} were given",
            args.len()
        ));
    }
    for (index, value) in args.into_iter().enumerate() {
        values[index] = Some(value);
    }
    for (name, value) in keywords {
        let Some(index) = names.iter().position(|candidate| candidate == &name) else {
            return Err(format!(
                "TypeError: parse() got an unexpected keyword argument '{name}'"
            ));
        };
        if values[index].is_some() {
            return Err(format!(
                "TypeError: parse() got multiple values for argument '{name}'"
            ));
        }
        values[index] = Some(value);
    }

    let source = values[0]
        .take()
        .ok_or_else(|| "TypeError: parse() missing required argument 'source'".to_string())?;
    let filename = values[1]
        .take()
        .unwrap_or_else(|| Value::String("<unknown>".to_string()));
    let filename = match filename {
        Value::String(filename) => filename,
        value => {
            return Err(format!(
                "TypeError: expected str, bytes or os.PathLike object, not {}",
                type_name(&value)
            ));
        }
    };
    let mode = values[2]
        .take()
        .unwrap_or_else(|| Value::String("exec".to_string()));
    let mode = match mode {
        Value::String(mode) => mode,
        value => {
            return Err(format!(
                "TypeError: compile() arg 3 must be a string, not {}",
                type_name(&value)
            ));
        }
    };

    let type_comments = values[3]
        .as_ref()
        .map(is_truthy)
        .transpose()?
        .unwrap_or(false);
    let feature_version = values[4]
        .take()
        .map(parse_ast_feature_version)
        .transpose()?
        .flatten();

    let optimize = values[5]
        .take()
        .map(|value| compile_int_argument(value, "optimize"))
        .transpose()?
        .unwrap_or(-1);

    let source_for_warnings = source.clone();
    let node = parse_ast_node(source, &mode, type_comments, optimize, feature_version)?;
    emit_ast_parse_warnings(vm, &source_for_warnings, &filename)?;
    Ok(node)
}

fn emit_ast_parse_warnings(vm: &mut Vm, source: &Value, filename: &str) -> Result<(), String> {
    let source = match source {
        Value::String(source) => source.clone(),
        Value::Bytes(bytes) | Value::ByteArray(bytes) => match decode_source_for_parse(bytes) {
            Ok(source) => source,
            Err(_) => return Ok(()),
        },
        _ => return Ok(()),
    };
    let Ok((_tokens, warnings)) = lex_with_spans_for_parse(&source) else {
        return Ok(());
    };
    for warning in warnings {
        emit_ast_parse_warning(vm, warning, filename)?;
    }
    Ok(())
}

fn emit_ast_parse_warning(vm: &mut Vm, warning: LexWarning, filename: &str) -> Result<(), String> {
    let category = match warning.category {
        LexWarningCategory::SyntaxWarning => builtin_type_value("SyntaxWarning"),
    };
    vm.emit_warning_at(
        warning.message,
        category,
        filename.to_string(),
        warning.line,
    )
}

fn parse_ast_feature_version(value: Value) -> Result<Option<AstFeatureVersion>, String> {
    match value {
        Value::None => Ok(None),
        Value::Number(minor) => Ok(Some(AstFeatureVersion { major: 3, minor })),
        Value::Bool(value) => Ok(Some(AstFeatureVersion {
            major: 3,
            minor: bool_as_i64(value),
        })),
        Value::BigInt(value) => Ok(Some(AstFeatureVersion {
            major: 3,
            minor: value
                .to_i64()
                .ok_or_else(|| "OverflowError: feature_version is too large".to_string())?,
        })),
        Value::Tuple(items) if items.len() == 2 => {
            let major = compile_int_argument(items[0].clone(), "feature_version")?;
            let minor = compile_int_argument(items[1].clone(), "feature_version")?;
            if major != 3 {
                return Err("ValueError: feature_version major version must be 3".to_string());
            }
            Ok(Some(AstFeatureVersion { major, minor }))
        }
        value => Err(format!(
            "TypeError: feature_version must be a tuple or int, not {}",
            type_name(&value)
        )),
    }
}

fn parse_ast_node(
    source: Value,
    mode: &str,
    type_comments: bool,
    optimize: i64,
    feature_version: Option<AstFeatureVersion>,
) -> Result<Value, String> {
    if let Value::AstNode { kind, .. } = &source {
        if matches!(
            kind.as_str(),
            "Module" | "Expression" | "Interactive" | "FunctionType"
        ) {
            ast_apply_parse_optimizations(&source, optimize)?;
            return Ok(source);
        }
        return Err(format!(
            "TypeError: compile() arg 1 must be a string, bytes or AST object, not {}",
            kind
        ));
    }

    let source = match source {
        Value::String(source) => {
            if source.contains('\0') {
                return Err("SyntaxError: source code string cannot contain null bytes".to_string());
            }
            source
        }
        Value::Bytes(bytes) | Value::ByteArray(bytes) => {
            decode_source_for_parse(&bytes).map_err(|message| format!("SyntaxError: {message}"))?
        }
        value => {
            return Err(format!(
                "TypeError: compile() arg 1 must be a string, bytes or AST object, not {}",
                type_name(&value)
            ));
        }
    };

    match mode {
        "exec" => {
            let (spanned_tokens, _warnings) = lex_with_spans_for_parse(&source)
                .map_err(|error| format!("SyntaxError: {}", error.message))?;
            ast_validate_feature_version_tokens(&spanned_tokens, feature_version)?;
            let tokens = spanned_tokens
                .iter()
                .map(|token| token.token.clone())
                .collect::<Vec<_>>();
            let program = parse(&tokens).map_err(|message| format!("SyntaxError: {message}"))?;
            let type_ignores = if type_comments {
                ast_type_ignore_nodes(&spanned_tokens)
            } else {
                Vec::new()
            };
            let node = ast_program_node(&program, type_ignores);
            annotate_ast_parse_locations(&node, &source, &spanned_tokens);
            ast_apply_parse_optimizations(&node, optimize)?;
            Ok(node)
        }
        "eval" => parse_ast_eval_node(&source, optimize),
        "single" => {
            let (spanned_tokens, _warnings) = lex_with_spans_for_parse(&source)
                .map_err(|error| format!("SyntaxError: {}", error.message))?;
            ast_validate_feature_version_tokens(&spanned_tokens, feature_version)?;
            let tokens = spanned_tokens
                .iter()
                .map(|token| token.token.clone())
                .collect::<Vec<_>>();
            let program =
                parse_interactive(&tokens).map_err(|message| format!("SyntaxError: {message}"))?;
            let node = ast_interactive_node(&program);
            annotate_ast_parse_locations(&node, &source, &spanned_tokens);
            ast_apply_parse_optimizations(&node, optimize)?;
            Ok(node)
        }
        "func_type" => {
            let tokens =
                lex_for_parse(&source).map_err(|message| format!("SyntaxError: {message}"))?;
            let func_type =
                parse_func_type(&tokens).map_err(|message| format!("SyntaxError: {message}"))?;
            Ok(ast_function_type_node(&func_type))
        }
        _ => Err(
            "ValueError: compile() mode must be 'exec', 'eval', 'single' or 'func_type'"
                .to_string(),
        ),
    }
}

fn ast_validate_feature_version_tokens(
    tokens: &[SpannedToken],
    feature_version: Option<AstFeatureVersion>,
) -> Result<(), String> {
    let Some(version) = feature_version else {
        return Ok(());
    };

    if version < (AstFeatureVersion { major: 3, minor: 8 }) {
        if ast_tokens_have_positional_only_parameters(tokens) {
            return Err(
                "SyntaxError: positional-only parameters are only supported in Python 3.8 and greater"
                    .to_string(),
            );
        }
        if ast_tokens_have_assignment_expression(tokens) {
            return Err(
                "SyntaxError: assignment expressions are only supported in Python 3.8 and greater"
                    .to_string(),
            );
        }
    }

    if version
        < (AstFeatureVersion {
            major: 3,
            minor: 11,
        })
        && ast_tokens_have_except_star(tokens)
    {
        return Err(
            "SyntaxError: exception groups are only supported in Python 3.11 and greater"
                .to_string(),
        );
    }

    if version
        < (AstFeatureVersion {
            major: 3,
            minor: 12,
        })
        && ast_tokens_have_type_parameter_syntax(tokens)
    {
        return Err(
            "SyntaxError: type parameter syntax is only supported in Python 3.12 and greater"
                .to_string(),
        );
    }

    if version
        < (AstFeatureVersion {
            major: 3,
            minor: 13,
        })
        && ast_tokens_have_type_parameter_defaults(tokens)
    {
        return Err(
            "SyntaxError: type parameter defaults are only supported in Python 3.13 and greater"
                .to_string(),
        );
    }

    if version
        < (AstFeatureVersion {
            major: 3,
            minor: 14,
        })
        && ast_tokens_have_template_string(tokens)
    {
        return Err(
            "SyntaxError: template strings are only supported in Python 3.14 and greater"
                .to_string(),
        );
    }

    if version
        < (AstFeatureVersion {
            major: 3,
            minor: 14,
        })
        && ast_tokens_have_pep758_unparenthesized_except_tuple(tokens)
    {
        return Err(
            "SyntaxError: multiple exception types must be parenthesized before Python 3.14"
                .to_string(),
        );
    }

    Ok(())
}

fn ast_tokens_have_positional_only_parameters(tokens: &[SpannedToken]) -> bool {
    let mut index = 0;
    while index < tokens.len() {
        match &tokens[index].token {
            Token::Def => {
                if ast_function_parameters_have_positional_only_separator(tokens, index) {
                    return true;
                }
            }
            Token::Lambda => {
                if ast_lambda_parameters_have_positional_only_separator(tokens, index) {
                    return true;
                }
            }
            _ => {}
        }
        index += 1;
    }
    false
}

fn ast_function_parameters_have_positional_only_separator(
    tokens: &[SpannedToken],
    def_index: usize,
) -> bool {
    let Some(left_paren) = (def_index + 1..tokens.len()).find(|index| {
        matches!(
            tokens[*index].token,
            Token::LeftParen | Token::Colon | Token::Newline | Token::Eof
        )
    }) else {
        return false;
    };
    if !matches!(tokens[left_paren].token, Token::LeftParen) {
        return false;
    }

    let mut depth = 0usize;
    for index in left_paren..tokens.len() {
        match tokens[index].token {
            Token::LeftParen | Token::LeftBracket | Token::LeftBrace => depth += 1,
            Token::RightParen | Token::RightBracket | Token::RightBrace => {
                if matches!(tokens[index].token, Token::RightParen) && depth == 1 {
                    return false;
                }
                depth = depth.saturating_sub(1);
            }
            Token::Slash
                if depth == 1
                    && ast_token_after(tokens, index, &[Token::Comma, Token::RightParen]) =>
            {
                return true;
            }
            _ => {}
        }
    }

    false
}

fn ast_lambda_parameters_have_positional_only_separator(
    tokens: &[SpannedToken],
    lambda_index: usize,
) -> bool {
    let mut depth = 0usize;
    for index in lambda_index + 1..tokens.len() {
        match tokens[index].token {
            Token::LeftParen | Token::LeftBracket | Token::LeftBrace => depth += 1,
            Token::RightParen | Token::RightBracket | Token::RightBrace => {
                depth = depth.saturating_sub(1);
            }
            Token::Colon if depth == 0 => return false,
            Token::Slash
                if depth == 0 && ast_token_after(tokens, index, &[Token::Comma, Token::Colon]) =>
            {
                return true;
            }
            Token::Newline | Token::Eof if depth == 0 => return false,
            _ => {}
        }
    }

    false
}

fn ast_token_after(tokens: &[SpannedToken], index: usize, expected: &[Token]) -> bool {
    tokens.get(index + 1).is_some_and(|token| {
        expected
            .iter()
            .any(|candidate| ast_token_kind_matches(&token.token, candidate))
    })
}

fn ast_token_kind_matches(actual: &Token, expected: &Token) -> bool {
    matches!(
        (actual, expected),
        (Token::Comma, Token::Comma)
            | (Token::Colon, Token::Colon)
            | (Token::RightParen, Token::RightParen)
    )
}

fn ast_tokens_have_assignment_expression(tokens: &[SpannedToken]) -> bool {
    tokens
        .iter()
        .any(|token| matches!(token.token, Token::ColonEqual))
}

fn ast_tokens_have_except_star(tokens: &[SpannedToken]) -> bool {
    tokens
        .windows(2)
        .any(|pair| matches!(pair[0].token, Token::Except) && matches!(pair[1].token, Token::Star))
}

fn ast_tokens_have_type_parameter_syntax(tokens: &[SpannedToken]) -> bool {
    ast_tokens_have_type_alias_statement(tokens)
        || ast_tokens_find_type_parameter_list(tokens, |_| true).is_some()
}

fn ast_tokens_have_type_parameter_defaults(tokens: &[SpannedToken]) -> bool {
    ast_tokens_find_type_parameter_list(tokens, |start| {
        let mut depth = 0usize;
        for token in tokens.iter().skip(start) {
            match token.token {
                Token::LeftBracket => depth += 1,
                Token::RightBracket => {
                    if depth == 1 {
                        return false;
                    }
                    depth = depth.saturating_sub(1);
                }
                Token::Equal if depth == 1 => return true,
                _ => {}
            }
        }
        false
    })
    .is_some()
}

fn ast_tokens_find_type_parameter_list<F>(tokens: &[SpannedToken], predicate: F) -> Option<usize>
where
    F: Fn(usize) -> bool,
{
    for index in 0..tokens.len() {
        let candidate = match &tokens[index].token {
            Token::Def | Token::Class => {
                if matches!(
                    tokens.get(index + 1).map(|token| &token.token),
                    Some(Token::Identifier(_))
                ) && matches!(
                    tokens.get(index + 2).map(|token| &token.token),
                    Some(Token::LeftBracket)
                ) {
                    Some(index + 2)
                } else {
                    None
                }
            }
            Token::Identifier(name) if name == "type" => {
                if matches!(
                    tokens.get(index + 1).map(|token| &token.token),
                    Some(Token::Identifier(_))
                ) && matches!(
                    tokens.get(index + 2).map(|token| &token.token),
                    Some(Token::LeftBracket)
                ) {
                    Some(index + 2)
                } else {
                    None
                }
            }
            _ => None,
        };
        if let Some(start) = candidate {
            if predicate(start) {
                return Some(start);
            }
        }
    }

    None
}

fn ast_tokens_have_type_alias_statement(tokens: &[SpannedToken]) -> bool {
    tokens.windows(3).any(|window| {
        matches!(&window[0].token, Token::Identifier(name) if name == "type")
            && matches!(window[1].token, Token::Identifier(_))
            && matches!(window[2].token, Token::Equal | Token::LeftBracket)
    })
}

fn ast_tokens_have_template_string(tokens: &[SpannedToken]) -> bool {
    tokens.iter().any(|token| {
        matches!(
            token.token,
            Token::TString(_)
                | Token::TStringStart(_)
                | Token::TStringMiddle(_)
                | Token::TStringEnd(_)
        )
    })
}

fn ast_tokens_have_pep758_unparenthesized_except_tuple(tokens: &[SpannedToken]) -> bool {
    let mut index = 0;
    while index < tokens.len() {
        if !matches!(tokens[index].token, Token::Except) {
            index += 1;
            continue;
        }

        index += 1;
        if tokens
            .get(index)
            .is_some_and(|token| matches!(token.token, Token::Star))
        {
            index += 1;
        }

        if tokens
            .get(index)
            .is_some_and(|token| matches!(token.token, Token::Colon | Token::LeftParen))
        {
            continue;
        }

        let mut depth = 0usize;
        while let Some(token) = tokens.get(index) {
            match token.token {
                Token::LeftParen | Token::LeftBracket | Token::LeftBrace => depth += 1,
                Token::RightParen | Token::RightBracket | Token::RightBrace => {
                    depth = depth.saturating_sub(1);
                }
                Token::Comma if depth == 0 => return true,
                Token::Colon if depth == 0 => break,
                Token::Newline | Token::Indent | Token::Dedent | Token::Eof => break,
                _ => {}
            }
            index += 1;
        }
    }

    false
}

fn ast_type_ignore_nodes(tokens: &[SpannedToken]) -> Vec<Value> {
    tokens
        .iter()
        .filter_map(|token| match &token.token {
            Token::TypeIgnore(body) => {
                let tag = body.strip_prefix("ignore").unwrap_or(body).to_string();
                Some(ast_node(
                    "TypeIgnore",
                    vec![
                        ("lineno", Value::Number(token.line as i64)),
                        ("tag", Value::String(tag)),
                    ],
                ))
            }
            _ => None,
        })
        .collect()
}

fn parse_ast_eval_node(source: &str, optimize: i64) -> Result<Value, String> {
    if ast_eval_source_has_unexpected_indent(source) {
        return Err("IndentationError: unexpected indent".to_string());
    }

    let (spanned_tokens, _warnings) = lex_with_spans_for_parse(source)
        .map_err(|error| format!("SyntaxError: {}", error.message))?;
    let tokens = spanned_tokens
        .iter()
        .map(|token| token.token.clone())
        .collect::<Vec<_>>();
    let expr = parse_eval(&tokens).map_err(|message| match message.as_str() {
        "unexpected indent" => "IndentationError: unexpected indent".to_string(),
        _ => format!("SyntaxError: {message}"),
    })?;
    let node = ast_expression_node(&expr);
    annotate_ast_parse_locations(&node, source, &spanned_tokens);
    ast_apply_parse_optimizations(&node, optimize)?;
    Ok(node)
}

fn ast_apply_parse_optimizations(node: &Value, optimize: i64) -> Result<(), String> {
    ast_validate_constant_name_identifiers(node)?;
    ast_optimize_debug_names(node, optimize)?;
    ast_optimize_percent_format(node, optimize)?;
    ast_optimize_match_patterns(node, optimize)?;
    ast_optimize_docstrings(node, optimize)
}

fn ast_validate_constant_name_identifiers(value: &Value) -> Result<(), String> {
    let Value::AstNode {
        kind,
        fields,
        attrs,
        ..
    } = value
    else {
        return Ok(());
    };
    let _guard = AstCompileRecursionGuard::enter(value)?;

    if kind == "Name"
        && let Some(Value::String(name)) = lookup_string_key(attrs, "id")
    {
        ast_validate_name_identifier(&name)?;
    }

    for field in fields.clone() {
        let Some(child) = lookup_string_key(attrs, &field) else {
            continue;
        };
        match child {
            Value::AstNode { .. } => ast_validate_constant_name_identifiers(&child)?,
            Value::List(items) => {
                for item in items.borrow().iter() {
                    ast_validate_constant_name_identifiers(item)?;
                }
            }
            _ => {}
        }
    }

    Ok(())
}

fn ast_optimize_debug_names(node: &Value, optimize: i64) -> Result<(), String> {
    if optimize <= 0 {
        return Ok(());
    }
    ast_optimize_debug_name_value(node).map(|_| ())
}

fn ast_optimize_debug_name_value(value: &Value) -> Result<Option<Value>, String> {
    let Value::AstNode {
        kind,
        fields,
        attrs,
        ..
    } = value
    else {
        return Ok(None);
    };

    if kind == "Name" && ast_is_debug_load_name(attrs) {
        let replacement = ast_constant_node(Value::Bool(false));
        ast_copy_location_attrs(&replacement, value)?;
        return Ok(Some(replacement));
    }

    for field in fields.clone() {
        let Some(child) = lookup_string_key(attrs, &field) else {
            continue;
        };
        match child {
            Value::AstNode { .. } => {
                if let Some(replacement) = ast_optimize_debug_name_value(&child)? {
                    ast_set_attr(attrs, &field, replacement)?;
                }
            }
            Value::List(items) => {
                let old_items = items.borrow().clone();
                let mut changed = false;
                let mut new_items = Vec::with_capacity(old_items.len());
                for item in old_items {
                    if let Some(replacement) = ast_optimize_debug_name_value(&item)? {
                        new_items.push(replacement);
                        changed = true;
                    } else {
                        new_items.push(item);
                    }
                }
                if changed {
                    *items.borrow_mut() = new_items;
                }
            }
            _ => {}
        }
    }

    Ok(None)
}

fn ast_is_debug_load_name(attrs: &DictRef) -> bool {
    let is_debug_name = matches!(
        lookup_string_key(attrs, "id"),
        Some(Value::String(name)) if name == "__debug__"
    );
    let is_load_context = matches!(
        lookup_string_key(attrs, "ctx"),
        Some(Value::AstNode { kind, .. }) if kind == "Load"
    );
    is_debug_name && is_load_context
}

fn ast_optimize_percent_format(node: &Value, optimize: i64) -> Result<(), String> {
    if optimize <= 0 {
        return Ok(());
    }
    ast_optimize_percent_format_value(node).map(|_| ())
}

fn ast_optimize_percent_format_value(value: &Value) -> Result<Option<Value>, String> {
    let Value::AstNode { fields, attrs, .. } = value else {
        return Ok(None);
    };

    if let Some(replacement) = ast_percent_format_replacement(value)? {
        return Ok(Some(replacement));
    }

    for field in fields.clone() {
        let Some(child) = lookup_string_key(attrs, &field) else {
            continue;
        };
        match child {
            Value::AstNode { .. } => {
                if let Some(replacement) = ast_optimize_percent_format_value(&child)? {
                    ast_set_attr(attrs, &field, replacement)?;
                }
            }
            Value::List(items) => {
                let old_items = items.borrow().clone();
                let mut changed = false;
                let mut new_items = Vec::with_capacity(old_items.len());
                for item in old_items {
                    if let Some(replacement) = ast_optimize_percent_format_value(&item)? {
                        new_items.push(replacement);
                        changed = true;
                    } else {
                        new_items.push(item);
                    }
                }
                if changed {
                    *items.borrow_mut() = new_items;
                }
            }
            _ => {}
        }
    }

    Ok(None)
}

fn ast_percent_format_replacement(value: &Value) -> Result<Option<Value>, String> {
    if ast_node_kind(value) != Some("BinOp") {
        return Ok(None);
    }
    if ast_node_kind(&ast_lookup_field(value, "op").unwrap_or(Value::None)) != Some("Mod") {
        return Ok(None);
    }
    let Some(left) = ast_lookup_field(value, "left") else {
        return Ok(None);
    };
    if ast_node_kind(&left) != Some("Constant")
        || !matches!(ast_lookup_field(&left, "value"), Some(Value::String(format)) if format == "%s")
    {
        return Ok(None);
    }

    let Some(right) = ast_lookup_field(value, "right") else {
        return Ok(None);
    };
    if ast_node_kind(&right) != Some("Tuple") {
        return Ok(None);
    }
    let args = ast_lookup_list_field(&right, "elts");
    let [arg] = args.as_slice() else {
        return Ok(None);
    };

    let formatted = ast_node(
        "FormattedValue",
        vec![
            ("value", arg.clone()),
            ("conversion", Value::Number(115)),
            ("format_spec", Value::None),
        ],
    );
    ast_copy_location_attrs(&formatted, value)?;
    let joined = ast_node(
        "JoinedStr",
        vec![("values", ast_nodes_list(vec![formatted]))],
    );
    ast_copy_location_attrs(&joined, value)?;
    Ok(Some(joined))
}

fn ast_optimize_match_patterns(node: &Value, optimize: i64) -> Result<(), String> {
    if optimize <= 0 {
        return Ok(());
    }
    ast_optimize_match_patterns_value(node)
}

fn ast_optimize_match_patterns_value(value: &Value) -> Result<(), String> {
    let Value::AstNode {
        kind,
        fields,
        attrs,
        ..
    } = value
    else {
        return Ok(());
    };

    if kind == "MatchValue" {
        if let Some(current) = lookup_string_key(attrs, "value") {
            if let Some(replacement) = ast_fold_match_literal_expr(&current)? {
                ast_set_attr(attrs, "value", replacement)?;
            }
        }
    } else if kind == "MatchMapping" {
        if let Some(Value::List(keys)) = lookup_string_key(attrs, "keys") {
            let old_keys = keys.borrow().clone();
            let mut changed = false;
            let mut new_keys = Vec::with_capacity(old_keys.len());
            for key in old_keys {
                if let Some(replacement) = ast_fold_match_literal_expr(&key)? {
                    new_keys.push(replacement);
                    changed = true;
                } else {
                    new_keys.push(key);
                }
            }
            if changed {
                *keys.borrow_mut() = new_keys;
            }
        }
    }

    for field in fields.clone() {
        let Some(child) = lookup_string_key(attrs, &field) else {
            continue;
        };
        match child {
            Value::AstNode { .. } => ast_optimize_match_patterns_value(&child)?,
            Value::List(items) => {
                for item in items.borrow().iter() {
                    ast_optimize_match_patterns_value(item)?;
                }
            }
            _ => {}
        }
    }

    Ok(())
}

fn ast_fold_match_literal_expr(expr: &Value) -> Result<Option<Value>, String> {
    match ast_node_kind(expr) {
        Some("UnaryOp") => ast_fold_match_unary_literal_expr(expr),
        Some("BinOp") => ast_fold_match_complex_binop_expr(expr),
        _ => Ok(None),
    }
}

fn ast_fold_match_unary_literal_expr(expr: &Value) -> Result<Option<Value>, String> {
    if ast_node_kind(&ast_lookup_field(expr, "op").unwrap_or(Value::None)) != Some("USub") {
        return Ok(None);
    }
    let Some(operand) = ast_lookup_field(expr, "operand") else {
        return Ok(None);
    };
    let Some(value) = ast_constant_value(&operand) else {
        return Ok(None);
    };
    let Some(negated) = ast_negate_match_literal_value(&value) else {
        return Ok(None);
    };
    let replacement = ast_constant_node(negated);
    ast_copy_location_attrs(&replacement, expr)?;
    Ok(Some(replacement))
}

fn ast_fold_match_complex_binop_expr(expr: &Value) -> Result<Option<Value>, String> {
    let op_value = ast_lookup_field(expr, "op").unwrap_or(Value::None);
    let op = ast_node_kind(&op_value);
    if !matches!(op, Some("Add" | "Sub")) {
        return Ok(None);
    }
    let Some(left) = ast_lookup_field(expr, "left") else {
        return Ok(None);
    };
    let Some(right) = ast_lookup_field(expr, "right") else {
        return Ok(None);
    };

    let Some(real) = ast_match_signed_real_value(&left) else {
        return Ok(None);
    };
    let Some(imag) = ast_match_imaginary_value(&right) else {
        return Ok(None);
    };
    let imag = if op == Some("Sub") { -imag } else { imag };
    let replacement = ast_constant_node(Value::Complex {
        real: normalize_float_zero(real),
        imag: normalize_float_zero(imag),
    });
    ast_copy_location_attrs(&replacement, expr)?;
    Ok(Some(replacement))
}

fn ast_constant_value(node: &Value) -> Option<Value> {
    if ast_node_kind(node) != Some("Constant") {
        return None;
    }
    ast_lookup_field(node, "value")
}

fn ast_negate_match_literal_value(value: &Value) -> Option<Value> {
    match value {
        Value::Number(value) => value
            .checked_neg()
            .map(Value::Number)
            .or_else(|| Some(Value::BigInt(-BigInt::from(*value)))),
        Value::BigInt(value) => Some(normalize_big_int(-value)),
        Value::Float(value) => Some(Value::Float(normalize_float_zero(-value))),
        Value::Complex { real, imag } => Some(Value::Complex {
            real: normalize_float_zero(-real),
            imag: normalize_float_zero(-imag),
        }),
        _ => None,
    }
}

fn ast_match_signed_real_value(expr: &Value) -> Option<f64> {
    if let Some(value) = ast_constant_value(expr) {
        return ast_real_constant_to_f64(&value);
    }
    if ast_node_kind(expr) != Some("UnaryOp")
        || ast_node_kind(&ast_lookup_field(expr, "op").unwrap_or(Value::None)) != Some("USub")
    {
        return None;
    }
    let operand = ast_lookup_field(expr, "operand")?;
    let value = ast_constant_value(&operand)?;
    ast_real_constant_to_f64(&value).map(|value| normalize_float_zero(-value))
}

fn ast_real_constant_to_f64(value: &Value) -> Option<f64> {
    match value {
        Value::Number(value) => Some(*value as f64),
        Value::BigInt(value) => value.to_f64(),
        Value::Float(value) => Some(*value),
        _ => None,
    }
}

fn ast_match_imaginary_value(expr: &Value) -> Option<f64> {
    match ast_constant_value(expr)? {
        Value::Complex { real, imag } if real == 0.0 => Some(imag),
        _ => None,
    }
}

fn normalize_float_zero(value: f64) -> f64 {
    if value == 0.0 { 0.0 } else { value }
}

fn ast_optimize_docstrings(node: &Value, optimize: i64) -> Result<(), String> {
    if optimize < 2 {
        return Ok(());
    }
    ast_optimize_docstrings_value(node)
}

fn ast_optimize_docstrings_value(value: &Value) -> Result<(), String> {
    let Value::AstNode {
        kind,
        fields,
        attrs,
        ..
    } = value
    else {
        return Ok(());
    };

    if matches!(
        kind.as_str(),
        "ClassDef" | "FunctionDef" | "AsyncFunctionDef"
    ) {
        ast_optimize_docstring_body(attrs)?;
    }

    for field in fields.clone() {
        let Some(child) = lookup_string_key(attrs, &field) else {
            continue;
        };
        match child {
            Value::AstNode { .. } => ast_optimize_docstrings_value(&child)?,
            Value::List(items) => {
                for item in items.borrow().iter() {
                    ast_optimize_docstrings_value(item)?;
                }
            }
            _ => {}
        }
    }

    Ok(())
}

fn ast_optimize_docstring_body(attrs: &DictRef) -> Result<(), String> {
    let Some(Value::List(items)) = lookup_string_key(attrs, "body") else {
        return Ok(());
    };
    let mut body = items.borrow_mut();
    let Some(first) = body.first().cloned() else {
        return Ok(());
    };
    if !ast_is_docstring_stmt(&first) {
        return Ok(());
    }

    if body.len() == 1 {
        body[0] = ast_pass_replacing_docstring(&first)?;
    } else {
        body.remove(0);
    }
    Ok(())
}

fn ast_is_docstring_stmt(stmt: &Value) -> bool {
    if ast_node_kind(stmt) != Some("Expr") {
        return false;
    }
    let Some(value) = ast_lookup_field(stmt, "value") else {
        return false;
    };
    if ast_node_kind(&value) != Some("Constant") {
        return false;
    }
    matches!(ast_lookup_field(&value, "value"), Some(Value::String(_)))
}

fn ast_pass_replacing_docstring(docstring_stmt: &Value) -> Result<Value, String> {
    let pass = ast_node("Pass", Vec::new());
    let Value::AstNode {
        attrs: pass_attrs, ..
    } = &pass
    else {
        return Ok(pass);
    };
    let Value::AstNode {
        attrs: old_attrs, ..
    } = docstring_stmt
    else {
        return Ok(pass);
    };

    let lineno = ast_location_number_attr(old_attrs, "lineno")?;
    let col_offset = ast_location_number_attr(old_attrs, "col_offset")?;
    if let Some(lineno) = lineno {
        ast_set_attr(pass_attrs, "lineno", Value::Number(lineno))?;
        ast_set_attr(pass_attrs, "end_lineno", Value::Number(lineno))?;
    }
    if let Some(col_offset) = col_offset {
        ast_set_attr(pass_attrs, "col_offset", Value::Number(col_offset))?;
        ast_set_attr(pass_attrs, "end_col_offset", Value::Number(col_offset + 4))?;
    }
    Ok(pass)
}

fn ast_location_number_attr(attrs: &DictRef, name: &str) -> Result<Option<i64>, String> {
    match lookup_string_key(attrs, name) {
        Some(Value::Number(value)) => Ok(Some(value)),
        Some(Value::Bool(value)) => Ok(Some(bool_as_i64(value))),
        Some(Value::None) | None => Ok(None),
        Some(value) => Err(format!(
            "TypeError: AST location attribute '{name}' must be int, not {}",
            type_name(&value)
        )),
    }
}

fn ast_eval_source_has_unexpected_indent(source: &str) -> bool {
    for line in source.split(['\n', '\r']) {
        if line.is_empty() || line.chars().all(|ch| matches!(ch, ' ' | '\t' | '\u{000c}')) {
            continue;
        }
        return line.starts_with(' ') || line.starts_with('\t');
    }
    false
}

#[derive(Debug, Clone, Copy)]
struct AstSourceLocation {
    lineno: i64,
    col_offset: i64,
    end_lineno: i64,
    end_col_offset: i64,
}

fn annotate_ast_parse_locations(node: &Value, source: &str, tokens: &[SpannedToken]) {
    let mut annotator = AstLocationAnnotator {
        source,
        tokens,
        index: 0,
    };
    annotator.annotate_node(node);
}

struct AstLocationAnnotator<'a> {
    source: &'a str,
    tokens: &'a [SpannedToken],
    index: usize,
}

impl AstLocationAnnotator<'_> {
    fn annotate_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let kind = ast_node_kind(node)?.to_string();
        let span = match kind.as_str() {
            "Module" | "Interactive" => self.annotate_list_field(node, "body"),
            "Expression" => {
                ast_lookup_field(node, "body").and_then(|body| self.annotate_node(&body))
            }
            "Expr" => self.annotate_expr_node(node),
            "Assign" => self.annotate_assign_node(node),
            "Delete" => self.annotate_delete_node(node),
            "TypeAlias" => self.annotate_type_alias_node(node),
            "FunctionDef" => self.annotate_function_def_node(node, false),
            "AsyncFunctionDef" => self.annotate_function_def_node(node, true),
            "ClassDef" => self.annotate_class_def_node(node),
            "Import" => self.annotate_import_node(node),
            "ImportFrom" => self.annotate_import_from_node(node),
            "If" => self.annotate_if_node(node),
            "While" => self.annotate_while_node(node),
            "For" => self.annotate_for_node(node, false),
            "AsyncFor" => self.annotate_for_node(node, true),
            "With" => self.annotate_with_node(node, false),
            "AsyncWith" => self.annotate_with_node(node, true),
            "Try" | "TryStar" => self.annotate_try_node(node),
            "ExceptHandler" => self.annotate_except_handler_node(node),
            "Return" => self.annotate_keyword_value_stmt(
                node,
                |token| matches!(token, Token::Return),
                "value",
            ),
            "Global" => self.annotate_name_list_keyword_stmt(
                node,
                |token| matches!(token, Token::Global),
                "names",
            ),
            "Nonlocal" => self.annotate_name_list_keyword_stmt(
                node,
                |token| matches!(token, Token::Nonlocal),
                "names",
            ),
            "Assert" => self.annotate_assert_node(node),
            "Raise" => self.annotate_raise_node(node),
            "Yield" => self.annotate_keyword_value_stmt(
                node,
                |token| matches!(token, Token::Yield),
                "value",
            ),
            "YieldFrom" => self.annotate_yield_from_node(node),
            "Await" => self.annotate_keyword_value_stmt(
                node,
                |token| matches!(token, Token::Await),
                "value",
            ),
            "Pass" => self
                .find_token(|token| matches!(token, Token::Pass))
                .map(token_location),
            "Break" => self
                .find_token(|token| matches!(token, Token::Break))
                .map(token_location),
            "Continue" => self
                .find_token(|token| matches!(token, Token::Continue))
                .map(token_location),
            "Name" => self.annotate_name_node(node),
            "Constant" => self.annotate_constant_node(node),
            "Attribute" => self.annotate_attribute_node(node),
            "BinOp" => self.annotate_binop_node(node),
            "BoolOp" => self.annotate_boolop_node(node),
            "UnaryOp" => self.annotate_unaryop_node(node),
            "Lambda" => self.annotate_lambda_node(node),
            "IfExp" => self.annotate_ifexp_node(node),
            "JoinedStr" => self.annotate_interpolated_string_node(node, false),
            "TemplateStr" => self.annotate_interpolated_string_node(node, true),
            "Call" => self.annotate_call_node(node),
            "Subscript" => self.annotate_subscript_node(node),
            "Slice" => self.annotate_slice_node(node),
            "Starred" => self.annotate_starred_node(node),
            "Tuple" => self.annotate_tuple_node(node),
            "List" => self.annotate_list_node(node),
            "Set" => self.annotate_set_node(node),
            "Dict" => self.annotate_dict_node(node),
            "ListComp" => self.annotate_comprehension_expr_node(
                node,
                Token::LeftBracket,
                Token::RightBracket,
                &["elt"],
            ),
            "SetComp" | "GeneratorExp" => self.annotate_comprehension_expr_node(
                node,
                if kind == "GeneratorExp" {
                    Token::LeftParen
                } else {
                    Token::LeftBrace
                },
                if kind == "GeneratorExp" {
                    Token::RightParen
                } else {
                    Token::RightBrace
                },
                &["elt"],
            ),
            "DictComp" => self.annotate_comprehension_expr_node(
                node,
                Token::LeftBrace,
                Token::RightBrace,
                &["key", "value"],
            ),
            "comprehension" => self.annotate_comprehension_node(node),
            "keyword" => self.annotate_keyword_node(node),
            "alias" => self.annotate_alias_node(node),
            "TypeVar" | "TypeVarTuple" | "ParamSpec" => self.annotate_type_param_node(node),
            "arguments" => self.annotate_arguments_node(node),
            "arg" => self.annotate_arg_node(node),
            _ => self.annotate_generic_node(node),
        };

        if kind != "Expression" && kind != "Module" && kind != "Interactive" {
            if let Some(span) = span {
                set_ast_source_location(node, span);
            }
        }
        span
    }

    fn annotate_child_field(&mut self, node: &Value, field: &str) -> Option<AstSourceLocation> {
        ast_lookup_field(node, field).and_then(|child| self.annotate_node(&child))
    }

    fn annotate_wrapped_child_field(
        &mut self,
        node: &Value,
        field: &str,
    ) -> Option<AstSourceLocation> {
        ast_lookup_field(node, field).and_then(|child| self.annotate_wrapped_child(&child))
    }

    fn annotate_wrapped_child(&mut self, child: &Value) -> Option<AstSourceLocation> {
        if expr_value_owns_leading_left_paren(child) {
            return self.annotate_node(child);
        }

        let start_index = self.index;
        let (prefix, paren_depth) = self.consume_redundant_trailer_left_parens();
        if paren_depth > 0 {
            let inner = self.annotate_node(child);
            if self.next_tokens_are_right_parens(paren_depth) {
                let suffix = self.consume_redundant_trailer_right_parens(paren_depth);
                return combine_optional_spans(combine_optional_spans(prefix, inner), suffix);
            }
            self.index = start_index;
        }

        self.annotate_node(child)
    }

    fn annotate_list_field(&mut self, node: &Value, field: &str) -> Option<AstSourceLocation> {
        let mut span = None;
        for child in ast_lookup_list_field(node, field) {
            span = combine_optional_spans(span, self.annotate_node(&child));
        }
        span
    }

    fn annotate_expr_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let Some(value) = ast_lookup_field(node, "value") else {
            return None;
        };

        if !self.peek_token(|token| matches!(token, Token::LeftParen))
            || expr_value_owns_leading_left_paren(&value)
        {
            return self.annotate_node(&value);
        }

        let mut span = None;
        while self.peek_token(|token| matches!(token, Token::LeftParen)) {
            let left_paren = self
                .find_token(|token| matches!(token, Token::LeftParen))
                .map(token_location);
            span = combine_optional_spans(span, left_paren);
        }

        span = combine_optional_spans(span, self.annotate_node(&value));

        while self.peek_token(|token| matches!(token, Token::RightParen)) {
            let right_paren = self
                .find_token(|token| matches!(token, Token::RightParen))
                .map(token_location);
            span = combine_optional_spans(span, right_paren);
        }

        span
    }

    fn annotate_assign_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let targets = self.annotate_list_field(node, "targets");
        self.find_token(|token| matches!(token, Token::Equal));
        let value = self.annotate_child_field(node, "value");
        combine_optional_spans(targets, value)
    }

    fn annotate_delete_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = self
            .find_token(|token| matches!(token, Token::Del))
            .map(token_location);
        let targets = self.annotate_list_field(node, "targets");
        combine_optional_spans(start, targets)
    }

    fn annotate_type_alias_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = self
            .find_token(|token| matches!(token, Token::Identifier(name) if name == "type"))
            .map(token_location);
        let mut span = combine_optional_spans(start, self.annotate_child_field(node, "name"));
        span = combine_optional_spans(span, self.annotate_list_field(node, "type_params"));
        self.find_token(|token| matches!(token, Token::Equal));
        span = combine_optional_spans(span, self.annotate_child_field(node, "value"));
        span
    }

    fn annotate_function_def_node(
        &mut self,
        node: &Value,
        is_async: bool,
    ) -> Option<AstSourceLocation> {
        self.annotate_list_field(node, "decorator_list");
        let start = if is_async {
            self.find_token(|token| matches!(token, Token::Async))
                .map(token_location)
        } else {
            self.find_token(|token| matches!(token, Token::Def))
                .map(token_location)
        };
        if is_async {
            self.find_token(|token| matches!(token, Token::Def));
        }
        if let Some(Value::String(name)) = ast_lookup_field(node, "name") {
            self.find_token(
                |token| matches!(token, Token::Identifier(candidate) if candidate == &name),
            );
        }
        self.annotate_list_field(node, "type_params");
        self.find_token(|token| matches!(token, Token::LeftParen));
        let args = self.annotate_child_field(node, "args");
        self.find_token(|token| matches!(token, Token::RightParen));

        let mut span = combine_optional_spans(start, args);
        if self.next_token_before(
            |token| matches!(token, Token::Arrow),
            |token| matches!(token, Token::Colon),
        ) {
            self.find_token(|token| matches!(token, Token::Arrow));
            let returns = self.annotate_child_field(node, "returns");
            span = combine_optional_spans(span, returns);
        }
        self.find_token(|token| matches!(token, Token::Colon));
        let body = self.annotate_list_field(node, "body");
        combine_optional_spans(span, body)
    }

    fn annotate_class_def_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        self.annotate_list_field(node, "decorator_list");
        let start = self
            .find_token(|token| matches!(token, Token::Class))
            .map(token_location);
        if let Some(Value::String(name)) = ast_lookup_field(node, "name") {
            self.find_token(
                |token| matches!(token, Token::Identifier(candidate) if candidate == &name),
            );
        }
        self.annotate_list_field(node, "type_params");

        let mut span = start;
        if self.next_token_before(
            |token| matches!(token, Token::LeftParen),
            |token| matches!(token, Token::Colon),
        ) {
            let left_paren = self
                .find_token(|token| matches!(token, Token::LeftParen))
                .map(token_location);
            span = combine_optional_spans(span, left_paren);
            span = combine_optional_spans(span, self.annotate_list_field(node, "bases"));
            span = combine_optional_spans(span, self.annotate_list_field(node, "keywords"));
            let right_paren = self
                .find_token(|token| matches!(token, Token::RightParen))
                .map(token_location);
            span = combine_optional_spans(span, right_paren);
        }
        self.find_token(|token| matches!(token, Token::Colon));
        let body = self.annotate_list_field(node, "body");
        combine_optional_spans(span, body)
    }

    fn annotate_import_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let is_lazy =
            self.peek_token(|token| matches!(token, Token::Identifier(name) if name == "lazy"));
        let start = if is_lazy {
            self.find_token(|token| matches!(token, Token::Identifier(name) if name == "lazy"))
                .map(token_location)
        } else {
            self.find_token(|token| matches!(token, Token::Import))
                .map(token_location)
        };
        if is_lazy {
            self.find_token(|token| matches!(token, Token::Import));
        }
        let aliases = self.annotate_list_field(node, "names");
        combine_optional_spans(start, aliases)
    }

    fn annotate_import_from_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let is_lazy =
            self.peek_token(|token| matches!(token, Token::Identifier(name) if name == "lazy"));
        let start = if is_lazy {
            self.find_token(|token| matches!(token, Token::Identifier(name) if name == "lazy"))
                .map(token_location)
        } else {
            self.find_token(|token| matches!(token, Token::From))
                .map(token_location)
        };
        if is_lazy {
            self.find_token(|token| matches!(token, Token::From));
        }
        self.find_token(|token| matches!(token, Token::Import));
        let parenthesized = self.next_token_before(
            |token| matches!(token, Token::LeftParen),
            |token| matches!(token, Token::Newline | Token::Eof),
        );
        let mut span = start;
        if parenthesized {
            let left_paren = self
                .find_token(|token| matches!(token, Token::LeftParen))
                .map(token_location);
            span = combine_optional_spans(span, left_paren);
        }
        span = combine_optional_spans(span, self.annotate_list_field(node, "names"));
        if parenthesized {
            let right_paren = self
                .find_token(|token| matches!(token, Token::RightParen))
                .map(token_location);
            span = combine_optional_spans(span, right_paren);
        }
        span
    }

    fn annotate_if_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = self
            .find_token(|token| matches!(token, Token::If | Token::Elif))
            .map(token_location);
        let mut span = combine_optional_spans(start, self.annotate_child_field(node, "test"));
        self.find_token(|token| matches!(token, Token::Colon));
        span = combine_optional_spans(span, self.annotate_list_field(node, "body"));
        span = combine_optional_spans(span, self.annotate_list_field(node, "orelse"));
        span
    }

    fn annotate_while_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = self
            .find_token(|token| matches!(token, Token::While))
            .map(token_location);
        let mut span = combine_optional_spans(start, self.annotate_child_field(node, "test"));
        self.find_token(|token| matches!(token, Token::Colon));
        span = combine_optional_spans(span, self.annotate_list_field(node, "body"));
        span = combine_optional_spans(span, self.annotate_list_field(node, "orelse"));
        span
    }

    fn annotate_for_node(&mut self, node: &Value, is_async: bool) -> Option<AstSourceLocation> {
        let start = if is_async {
            self.find_token(|token| matches!(token, Token::Async))
                .map(token_location)
        } else {
            self.find_token(|token| matches!(token, Token::For))
                .map(token_location)
        };
        if is_async {
            self.find_token(|token| matches!(token, Token::For));
        }
        let mut span = combine_optional_spans(start, self.annotate_child_field(node, "target"));
        self.find_token(|token| matches!(token, Token::In));
        span = combine_optional_spans(span, self.annotate_child_field(node, "iter"));
        self.find_token(|token| matches!(token, Token::Colon));
        span = combine_optional_spans(span, self.annotate_list_field(node, "body"));
        span = combine_optional_spans(span, self.annotate_list_field(node, "orelse"));
        span
    }

    fn annotate_with_node(&mut self, node: &Value, is_async: bool) -> Option<AstSourceLocation> {
        let start = if is_async {
            self.find_token(|token| matches!(token, Token::Async))
                .map(token_location)
        } else {
            self.find_token(|token| matches!(token, Token::With))
                .map(token_location)
        };
        if is_async {
            self.find_token(|token| matches!(token, Token::With));
        }
        let mut span = combine_optional_spans(start, self.annotate_list_field(node, "items"));
        self.find_token(|token| matches!(token, Token::Colon));
        span = combine_optional_spans(span, self.annotate_list_field(node, "body"));
        span
    }

    fn annotate_try_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = self
            .find_token(|token| matches!(token, Token::Try))
            .map(token_location);
        self.find_token(|token| matches!(token, Token::Colon));
        let mut span = combine_optional_spans(start, self.annotate_list_field(node, "body"));
        span = combine_optional_spans(span, self.annotate_list_field(node, "handlers"));
        span = combine_optional_spans(span, self.annotate_list_field(node, "orelse"));
        span = combine_optional_spans(span, self.annotate_list_field(node, "finalbody"));
        span
    }

    fn annotate_except_handler_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = self
            .find_token(|token| matches!(token, Token::Except))
            .map(token_location);
        let mut span = combine_optional_spans(start, self.annotate_child_field(node, "type"));
        if self.next_token_before(
            |token| matches!(token, Token::As),
            |token| matches!(token, Token::Colon),
        ) {
            self.find_token(|token| matches!(token, Token::As));
            if let Some(Value::String(name)) = ast_lookup_field(node, "name") {
                let name = self
                    .find_token(
                        |token| matches!(token, Token::Identifier(candidate) if candidate == &name),
                    )
                    .map(token_location);
                span = combine_optional_spans(span, name);
            }
        }
        self.find_token(|token| matches!(token, Token::Colon));
        combine_optional_spans(span, self.annotate_list_field(node, "body"))
    }

    fn annotate_assert_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = self
            .find_token(|token| matches!(token, Token::Assert))
            .map(token_location);
        let mut span = combine_optional_spans(start, self.annotate_child_field(node, "test"));
        if self.peek_token(|token| matches!(token, Token::Comma)) {
            self.find_token(|token| matches!(token, Token::Comma));
            span = combine_optional_spans(span, self.annotate_child_field(node, "msg"));
        }
        span
    }

    fn annotate_raise_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = self
            .find_token(|token| matches!(token, Token::Raise))
            .map(token_location);
        let mut span = combine_optional_spans(start, self.annotate_child_field(node, "exc"));
        if self.next_token_before(
            |token| matches!(token, Token::From),
            |token| matches!(token, Token::Newline | Token::Dedent | Token::Eof),
        ) {
            self.find_token(|token| matches!(token, Token::From));
            span = combine_optional_spans(span, self.annotate_child_field(node, "cause"));
        }
        span
    }

    fn annotate_keyword_value_stmt(
        &mut self,
        node: &Value,
        keyword: impl Fn(&Token) -> bool,
        value_field: &str,
    ) -> Option<AstSourceLocation> {
        let start = self.find_token(keyword).map(token_location);
        let value = self.annotate_child_field(node, value_field);
        combine_optional_spans(start, value)
    }

    fn annotate_name_list_keyword_stmt(
        &mut self,
        node: &Value,
        keyword: impl Fn(&Token) -> bool,
        names_field: &str,
    ) -> Option<AstSourceLocation> {
        let mut span = self.find_token(keyword).map(token_location);
        for name in ast_lookup_list_field(node, names_field) {
            if let Value::String(name) = name {
                let name_span = self
                    .find_token(
                        |token| matches!(token, Token::Identifier(candidate) if candidate == &name),
                    )
                    .map(token_location);
                span = combine_optional_spans(span, name_span);
            }
        }
        span
    }

    fn annotate_yield_from_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = self
            .find_token(|token| matches!(token, Token::Yield))
            .map(token_location);
        self.find_token(|token| matches!(token, Token::From));
        let value = self.annotate_child_field(node, "value");
        combine_optional_spans(start, value)
    }

    fn annotate_name_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let name = match ast_lookup_field(node, "id") {
            Some(Value::String(name)) => name,
            _ => return None,
        };
        self.find_token(|token| matches!(token, Token::Identifier(candidate) if candidate == &name))
            .map(token_location)
    }

    fn annotate_constant_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let value = ast_lookup_field(node, "value")?;
        if let Value::String(value) = &value {
            return self.annotate_adjacent_string_constant_node(node, value);
        }
        if let Value::Bytes(value) = &value {
            return self.annotate_adjacent_bytes_constant(value);
        }

        let token = self
            .find_token(|token| ast_constant_matches_token(&value, token))?
            .clone();
        Some(token_location(&token))
    }

    fn annotate_adjacent_string_constant_node(
        &mut self,
        node: &Value,
        expected: &str,
    ) -> Option<AstSourceLocation> {
        let (span, first_token) = self.find_adjacent_string_span(expected)?;
        if self
            .source
            .get(first_token.start..first_token.end)
            .is_some_and(|text| text.starts_with('u') || text.starts_with('U'))
            && let Value::AstNode { attrs, .. } = node
        {
            let _ = ast_set_attr(attrs, "kind", Value::String("u".to_string()));
        }
        Some(span)
    }

    fn annotate_adjacent_bytes_constant(&mut self, expected: &[u8]) -> Option<AstSourceLocation> {
        self.find_adjacent_bytes_span(expected)
    }

    fn find_adjacent_string_span(
        &mut self,
        expected: &str,
    ) -> Option<(AstSourceLocation, SpannedToken)> {
        for start in self.index..self.tokens.len() {
            let Some(first_value) = string_literal_token_value(&self.tokens[start].token) else {
                continue;
            };

            let mut value = first_value;
            let first_token = self.tokens[start].clone();
            let mut span = token_location(&first_token);
            let mut cursor = start;
            loop {
                if value == expected {
                    self.index = cursor + 1;
                    return Some((span, first_token));
                }
                if !expected.starts_with(&value) {
                    break;
                }

                cursor += 1;
                let Some(token) = self.tokens.get(cursor) else {
                    break;
                };
                let Some(next_value) = string_literal_token_value(&token.token) else {
                    break;
                };
                value.push_str(&next_value);
                span = combine_optional_spans(Some(span), Some(token_location(token)))?;
            }
        }
        None
    }

    fn find_adjacent_bytes_span(&mut self, expected: &[u8]) -> Option<AstSourceLocation> {
        for start in self.index..self.tokens.len() {
            let Token::Bytes(first_value) = &self.tokens[start].token else {
                continue;
            };

            let mut value = first_value.clone();
            let mut span = token_location(&self.tokens[start]);
            let mut cursor = start;
            loop {
                if value == expected {
                    self.index = cursor + 1;
                    return Some(span);
                }
                if !expected.starts_with(&value) {
                    break;
                }

                cursor += 1;
                let Some(token) = self.tokens.get(cursor) else {
                    break;
                };
                let Token::Bytes(next_value) = &token.token else {
                    break;
                };
                value.extend(next_value.clone());
                span = combine_optional_spans(Some(span), Some(token_location(token)))?;
            }
        }
        None
    }

    fn annotate_attribute_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let (prefix, paren_depth) = self.consume_redundant_trailer_left_parens();
        let value = self.annotate_child_field(node, "value");
        let suffix = self.consume_redundant_trailer_right_parens(paren_depth);
        let mut span = combine_optional_spans(combine_optional_spans(prefix, value), suffix);
        self.find_token(|token| matches!(token, Token::Dot));
        let attr = match ast_lookup_field(node, "attr") {
            Some(Value::String(attr)) => attr,
            _ => return span,
        };
        let attr = self
            .find_token(|token| matches!(token, Token::Identifier(candidate) if candidate == &attr))
            .map(token_location);
        span = combine_optional_spans(span, attr);
        span
    }

    fn annotate_binop_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let left = self.annotate_wrapped_child_field(node, "left");
        if let Some(op) = ast_lookup_field(node, "op") {
            self.find_token(|token| ast_operator_matches_token(&op, token));
        }
        let right = self.annotate_wrapped_child_field(node, "right");
        combine_optional_spans(left, right)
    }

    fn annotate_boolop_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let op = ast_lookup_field(node, "op");
        let mut span = None;
        for (index, value) in ast_lookup_list_field(node, "values").iter().enumerate() {
            if index > 0
                && let Some(op) = &op
            {
                self.find_token(|token| ast_bool_operator_matches_token(op, token));
            }
            span = combine_optional_spans(span, self.annotate_wrapped_child(value));
        }
        span
    }

    fn annotate_unaryop_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = ast_lookup_field(node, "op").and_then(|op| {
            self.find_token(|token| ast_unary_operator_matches_token(&op, token))
                .map(token_location)
        });
        let operand = self.annotate_child_field(node, "operand");
        combine_optional_spans(start, operand)
    }

    fn annotate_lambda_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start = self
            .find_token(|token| matches!(token, Token::Lambda))
            .map(token_location);
        let args = self.annotate_child_field(node, "args");
        self.find_token(|token| matches!(token, Token::Colon));
        let body = self.annotate_child_field(node, "body");
        combine_optional_spans(combine_optional_spans(start, args), body)
    }

    fn annotate_ifexp_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let body = self.annotate_child_field(node, "body");
        self.find_token(|token| matches!(token, Token::If));
        self.annotate_child_field(node, "test");
        self.find_token(|token| matches!(token, Token::Else));
        let orelse = self.annotate_child_field(node, "orelse");
        combine_optional_spans(body, orelse)
    }

    fn annotate_interpolated_string_node(
        &mut self,
        node: &Value,
        is_template: bool,
    ) -> Option<AstSourceLocation> {
        let string_token = self
            .find_token(|token| {
                matches!(
                    (is_template, token),
                    (false, Token::FString(_)) | (true, Token::TString(_))
                )
            })?
            .clone();
        let span = token_location(&string_token);
        let string_start = string_token.start;
        let string_end = string_token.end;
        let tokens = tokenize_cpython_with_spans(self.source)
            .ok()?
            .into_iter()
            .filter(|token| token_inside_span(token, string_start, string_end))
            .collect::<Vec<_>>();
        let mut index = 0;

        for value in ast_lookup_list_field(node, "values") {
            match ast_node_kind(&value) {
                Some("Constant") => {
                    if let Some(token) = next_interpolated_middle_token(&tokens, &mut index) {
                        set_ast_source_location(&value, token_location(token));
                    }
                }
                Some("FormattedValue" | "Interpolation") => {
                    self.annotate_interpolated_replacement(&value, &tokens, &mut index);
                }
                _ => {}
            }
        }

        Some(span)
    }

    fn annotate_interpolated_replacement(
        &self,
        node: &Value,
        tokens: &[SpannedToken],
        index: &mut usize,
    ) -> Option<AstSourceLocation> {
        let left_brace = find_interpolated_token_index(tokens, *index, |token| {
            matches!(token, Token::LeftBrace)
        })?;
        let right_brace = matching_interpolated_right_brace(tokens, left_brace)?;
        let split = interpolated_replacement_value_end(tokens, left_brace + 1, right_brace);
        self.annotate_interpolated_value_expression(node, &tokens[left_brace + 1..split]);

        if let Some(format_spec) = ast_lookup_field(node, "format_spec")
            && matches!(format_spec, Value::AstNode { .. })
            && let Some(colon) = interpolated_replacement_format_colon(tokens, split, right_brace)
        {
            self.annotate_interpolated_format_spec(&format_spec, &tokens[colon..right_brace]);
        }

        let span = combine_optional_spans(
            Some(token_location(&tokens[left_brace])),
            Some(token_location(&tokens[right_brace])),
        );
        if let Some(span) = span {
            set_ast_source_location(node, span);
        }
        *index = right_brace + 1;
        span
    }

    fn annotate_interpolated_value_expression(
        &self,
        node: &Value,
        tokens: &[SpannedToken],
    ) -> Option<AstSourceLocation> {
        let mut annotator = AstLocationAnnotator {
            source: self.source,
            tokens,
            index: 0,
        };
        annotator.annotate_child_field(node, "value")
    }

    fn annotate_interpolated_format_spec(
        &self,
        node: &Value,
        tokens: &[SpannedToken],
    ) -> Option<AstSourceLocation> {
        let mut index = 0;
        for value in ast_lookup_list_field(node, "values") {
            if ast_node_kind(&value) == Some("Constant")
                && let Some(token) = next_interpolated_middle_token(tokens, &mut index)
            {
                set_ast_source_location(&value, token_location(token));
            } else if ast_node_kind(&value) == Some("FormattedValue") {
                self.annotate_interpolated_replacement(&value, tokens, &mut index);
            }
        }

        let span = combine_optional_spans(
            tokens.first().map(token_location),
            tokens.last().map(token_location),
        );
        if let Some(span) = span {
            set_ast_source_location(node, span);
        }
        span
    }

    fn annotate_call_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let (prefix, paren_depth) = self.consume_redundant_trailer_left_parens();
        let func = self.annotate_child_field(node, "func");
        let suffix = self.consume_redundant_trailer_right_parens(paren_depth);
        let left_paren = self
            .find_token(|token| matches!(token, Token::LeftParen))
            .map(token_location);
        let mut span = combine_optional_spans(combine_optional_spans(prefix, func), suffix);
        span = combine_optional_spans(span, left_paren);
        let args = ast_lookup_list_field(node, "args");
        let keywords = ast_lookup_list_field(node, "keywords");

        if args.len() == 1
            && keywords.is_empty()
            && ast_node_kind(&args[0]) == Some("GeneratorExp")
            && !self.peek_token(|token| matches!(token, Token::LeftParen))
        {
            let inner = self.annotate_generator_without_delimiters(&args[0]);
            let right_paren = self
                .find_token(|token| matches!(token, Token::RightParen))
                .map(token_location);
            let generator_span =
                combine_optional_spans(combine_optional_spans(left_paren, inner), right_paren);
            if let Some(generator_span) = generator_span {
                set_ast_source_location(&args[0], generator_span);
            }
            return combine_optional_spans(span, right_paren);
        }

        let mut arg_index = 0;
        let mut keyword_index = 0;
        while arg_index < args.len() || keyword_index < keywords.len() {
            while self.peek_token(|token| matches!(token, Token::Comma)) {
                self.find_token(|token| matches!(token, Token::Comma));
            }
            if self.peek_token(|token| matches!(token, Token::RightParen)) {
                break;
            }

            let before = self.index;
            if self.peek_token(|token| matches!(token, Token::DoubleStar))
                && keyword_index < keywords.len()
            {
                span = combine_optional_spans(span, self.annotate_node(&keywords[keyword_index]));
                keyword_index += 1;
            } else if self.peek_token(|token| matches!(token, Token::Star))
                && arg_index < args.len()
            {
                span = combine_optional_spans(span, self.annotate_node(&args[arg_index]));
                arg_index += 1;
            } else if self.peek_keyword_argument_start() && keyword_index < keywords.len() {
                span = combine_optional_spans(span, self.annotate_node(&keywords[keyword_index]));
                keyword_index += 1;
            } else if arg_index < args.len() {
                span = combine_optional_spans(span, self.annotate_node(&args[arg_index]));
                arg_index += 1;
            } else if keyword_index < keywords.len() {
                span = combine_optional_spans(span, self.annotate_node(&keywords[keyword_index]));
                keyword_index += 1;
            }

            if self.index == before {
                break;
            }
        }
        let right_paren = self
            .find_token(|token| matches!(token, Token::RightParen))
            .map(token_location);
        combine_optional_spans(span, right_paren)
    }

    fn annotate_generator_without_delimiters(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let mut span = self.annotate_child_field(node, "elt");
        span = combine_optional_spans(span, self.annotate_list_field(node, "generators"));
        span
    }

    fn annotate_subscript_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let (prefix, paren_depth) = self.consume_redundant_trailer_left_parens();
        let value = self.annotate_child_field(node, "value");
        let suffix = self.consume_redundant_trailer_right_parens(paren_depth);
        let left_bracket = self
            .find_token(|token| matches!(token, Token::LeftBracket))
            .map(token_location);
        let slice = self.annotate_child_field(node, "slice");
        let right_bracket = self
            .find_token(|token| matches!(token, Token::RightBracket))
            .map(token_location);
        let span = combine_optional_spans(combine_optional_spans(prefix, value), suffix);
        combine_optional_spans(combine_optional_spans(span, left_bracket), right_bracket).or(slice)
    }

    fn annotate_slice_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let lower = self.annotate_child_field(node, "lower");
        let first_colon = self
            .find_token(|token| matches!(token, Token::Colon))
            .map(token_location);
        let mut span = combine_optional_spans(lower, first_colon);
        span = combine_optional_spans(span, self.annotate_child_field(node, "upper"));
        if self.next_token_before(
            |token| matches!(token, Token::Colon),
            |token| {
                matches!(
                    token,
                    Token::Comma | Token::RightBracket | Token::RightParen | Token::RightBrace
                )
            },
        ) {
            let second_colon = self
                .find_token(|token| matches!(token, Token::Colon))
                .map(token_location);
            span = combine_optional_spans(span, second_colon);
        }
        combine_optional_spans(span, self.annotate_child_field(node, "step"))
    }

    fn annotate_starred_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let star = self
            .find_token(|token| matches!(token, Token::Star))
            .map(token_location);
        let value = self.annotate_child_field(node, "value");
        combine_optional_spans(star, value)
    }

    fn annotate_tuple_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let parenthesized = self.peek_token(|token| matches!(token, Token::LeftParen));
        let mut span = if parenthesized {
            self.find_token(|token| matches!(token, Token::LeftParen))
                .map(token_location)
        } else {
            None
        };
        span = combine_optional_spans(span, self.annotate_list_field(node, "elts"));

        if parenthesized {
            let right_paren = self
                .find_token(|token| matches!(token, Token::RightParen))
                .map(token_location);
            combine_optional_spans(span, right_paren)
        } else {
            if self.peek_token(|token| matches!(token, Token::Comma)) {
                let comma = self
                    .find_token(|token| matches!(token, Token::Comma))
                    .map(token_location);
                span = combine_optional_spans(span, comma);
            }
            span
        }
    }

    fn annotate_list_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let left_bracket = self
            .find_token(|token| matches!(token, Token::LeftBracket))
            .map(token_location);
        let elts = self.annotate_list_field(node, "elts");
        let right_bracket = self
            .find_token(|token| matches!(token, Token::RightBracket))
            .map(token_location);
        combine_optional_spans(combine_optional_spans(left_bracket, elts), right_bracket)
    }

    fn annotate_set_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let left_brace = self
            .find_token(|token| matches!(token, Token::LeftBrace))
            .map(token_location);
        let elts = self.annotate_list_field(node, "elts");
        let right_brace = self
            .find_token(|token| matches!(token, Token::RightBrace))
            .map(token_location);
        combine_optional_spans(combine_optional_spans(left_brace, elts), right_brace)
    }

    fn annotate_dict_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let mut span = self
            .find_token(|token| matches!(token, Token::LeftBrace))
            .map(token_location);
        let keys = ast_lookup_list_field(node, "keys");
        let values = ast_lookup_list_field(node, "values");
        for index in 0..keys.len().max(values.len()) {
            if let Some(key) = keys.get(index)
                && matches!(key, Value::AstNode { .. })
            {
                span = combine_optional_spans(span, self.annotate_node(key));
                self.find_token(|token| matches!(token, Token::Colon));
            }
            if let Some(value) = values.get(index)
                && matches!(value, Value::AstNode { .. })
            {
                span = combine_optional_spans(span, self.annotate_node(value));
            }
        }
        let right_brace = self
            .find_token(|token| matches!(token, Token::RightBrace))
            .map(token_location);
        combine_optional_spans(span, right_brace)
    }

    fn annotate_comprehension_expr_node(
        &mut self,
        node: &Value,
        open: Token,
        close: Token,
        leading_fields: &[&str],
    ) -> Option<AstSourceLocation> {
        let open = self.find_token(|token| token == &open).map(token_location);
        let mut span = open;
        for field in leading_fields {
            span = combine_optional_spans(span, self.annotate_child_field(node, field));
        }
        span = combine_optional_spans(span, self.annotate_list_field(node, "generators"));
        let close = self.find_token(|token| token == &close).map(token_location);
        combine_optional_spans(span, close)
    }

    fn annotate_comprehension_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let start_token = self.find_token(|token| matches!(token, Token::For | Token::Async));
        let is_async = start_token.is_some_and(|token| matches!(token.token, Token::Async));
        let start = start_token.map(token_location);
        if is_async {
            self.find_token(|token| matches!(token, Token::For));
        }
        let mut span = start;
        span = combine_optional_spans(span, self.annotate_child_field(node, "target"));
        self.find_token(|token| matches!(token, Token::In));
        span = combine_optional_spans(span, self.annotate_child_field(node, "iter"));
        for condition in ast_lookup_list_field(node, "ifs") {
            let if_token = self
                .find_token(|token| matches!(token, Token::If))
                .map(token_location);
            span = combine_optional_spans(span, if_token);
            span = combine_optional_spans(span, self.annotate_node(&condition));
        }
        span
    }

    fn annotate_keyword_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let mut span = None;
        if let Some(Value::String(name)) = ast_lookup_field(node, "arg") {
            span = self
                .find_token(
                    |token| matches!(token, Token::Identifier(candidate) if candidate == &name),
                )
                .map(token_location);
            self.find_token(|token| matches!(token, Token::Equal));
        } else if matches!(ast_lookup_field(node, "arg"), Some(Value::None)) {
            span = self
                .find_token(|token| matches!(token, Token::DoubleStar))
                .map(token_location);
        }
        let value = self.annotate_child_field(node, "value");
        combine_optional_spans(span, value)
    }

    fn annotate_alias_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let name = match ast_lookup_field(node, "name") {
            Some(Value::String(name)) => name,
            _ => return None,
        };
        let mut span = if name == "*" {
            self.find_token(|token| matches!(token, Token::Star))
                .map(token_location)
        } else {
            self.find_dotted_name_span(&name)
        };
        if let Some(Value::String(asname)) = ast_lookup_field(node, "asname")
            && self.next_token_before(
                |token| matches!(token, Token::As),
                |token| matches!(token, Token::Comma | Token::Newline | Token::Eof),
            )
        {
            self.find_token(|token| matches!(token, Token::As));
            let asname = self
                .find_token(
                    |token| matches!(token, Token::Identifier(candidate) if candidate == &asname),
                )
                .map(token_location);
            span = combine_optional_spans(span, asname);
        }
        span
    }

    fn annotate_type_param_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let kind = ast_node_kind(node)?;
        let name = match ast_lookup_field(node, "name") {
            Some(Value::String(name)) => name,
            _ => return None,
        };

        let prefix = match kind {
            "TypeVarTuple" => self
                .find_token(|token| matches!(token, Token::Star))
                .map(token_location),
            "ParamSpec" => self
                .find_token(|token| matches!(token, Token::DoubleStar))
                .map(token_location),
            _ => None,
        };
        let name = self
            .find_token(|token| matches!(token, Token::Identifier(candidate) if candidate == &name))
            .map(token_location);
        let mut span = combine_optional_spans(prefix, name);

        if kind == "TypeVar"
            && let Some(bound) = ast_lookup_field(node, "bound")
            && matches!(bound, Value::AstNode { .. })
        {
            self.find_token(|token| matches!(token, Token::Colon));
            span = combine_optional_spans(span, self.annotate_node(&bound));
        }

        if let Some(default) = ast_lookup_field(node, "default_value")
            && matches!(default, Value::AstNode { .. })
        {
            self.find_token(|token| matches!(token, Token::Equal));
            span = combine_optional_spans(span, self.annotate_node(&default));
        }

        span
    }

    fn annotate_arguments_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let posonlyargs = ast_lookup_list_field(node, "posonlyargs");
        let args = ast_lookup_list_field(node, "args");
        let defaults = ast_lookup_list_field(node, "defaults");

        let positional_len = posonlyargs.len() + args.len();
        let first_default = positional_len.saturating_sub(defaults.len());
        let mut span = None;
        for (index, arg) in posonlyargs.iter().chain(args.iter()).enumerate() {
            span = combine_optional_spans(span, self.annotate_node(arg));
            if let Some(default) = defaults.get(index.saturating_sub(first_default))
                && index >= first_default
                && matches!(default, Value::AstNode { .. })
            {
                self.find_token(|token| matches!(token, Token::Equal));
                span = combine_optional_spans(span, self.annotate_node(default));
            }
        }

        if let Some(vararg) = ast_lookup_field(node, "vararg")
            && matches!(vararg, Value::AstNode { .. })
        {
            span = combine_optional_spans(span, self.annotate_node(&vararg));
        }

        let kwonlyargs = ast_lookup_list_field(node, "kwonlyargs");
        let kw_defaults = ast_lookup_list_field(node, "kw_defaults");
        for (kwonlyarg, default) in kwonlyargs.iter().zip(kw_defaults.iter()) {
            span = combine_optional_spans(span, self.annotate_node(kwonlyarg));
            if matches!(default, Value::AstNode { .. }) {
                self.find_token(|token| matches!(token, Token::Equal));
                span = combine_optional_spans(span, self.annotate_node(default));
            }
        }

        if let Some(kwarg) = ast_lookup_field(node, "kwarg")
            && matches!(kwarg, Value::AstNode { .. })
        {
            span = combine_optional_spans(span, self.annotate_node(&kwarg));
        }
        span
    }

    fn annotate_arg_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let name = match ast_lookup_field(node, "arg") {
            Some(Value::String(name)) => name,
            _ => return None,
        };
        let name = self
            .find_token(|token| matches!(token, Token::Identifier(candidate) if candidate == &name))
            .map(token_location);
        if self.next_token_before(
            |token| matches!(token, Token::Colon),
            |token| {
                matches!(
                    token,
                    Token::Comma | Token::Equal | Token::RightParen | Token::Slash
                )
            },
        ) {
            self.find_token(|token| matches!(token, Token::Colon));
            let annotation = self.annotate_child_field(node, "annotation");
            combine_optional_spans(name, annotation)
        } else {
            name
        }
    }

    fn annotate_generic_node(&mut self, node: &Value) -> Option<AstSourceLocation> {
        let mut span = None;
        for child in ast_child_nodes(node).unwrap_or_default() {
            span = combine_optional_spans(span, self.annotate_node(&child));
        }
        span
    }

    fn consume_redundant_trailer_left_parens(&mut self) -> (Option<AstSourceLocation>, usize) {
        let mut span = None;
        let mut depth = 0;
        while self.peek_token(|token| matches!(token, Token::LeftParen)) {
            let token = self
                .find_token(|token| matches!(token, Token::LeftParen))
                .map(token_location);
            span = combine_optional_spans(span, token);
            depth += 1;
        }
        (span, depth)
    }

    fn consume_redundant_trailer_right_parens(
        &mut self,
        depth: usize,
    ) -> Option<AstSourceLocation> {
        let mut span = None;
        for _ in 0..depth {
            if !self.peek_token(|token| matches!(token, Token::RightParen)) {
                break;
            }
            let token = self
                .find_token(|token| matches!(token, Token::RightParen))
                .map(token_location);
            span = combine_optional_spans(span, token);
        }
        span
    }

    fn next_tokens_are_right_parens(&self, depth: usize) -> bool {
        self.tokens
            .get(self.index..self.index.saturating_add(depth))
            .is_some_and(|tokens| {
                tokens
                    .iter()
                    .all(|token| matches!(token.token, Token::RightParen))
            })
    }

    fn find_dotted_name_span(&mut self, name: &str) -> Option<AstSourceLocation> {
        let mut parts = name.split('.');
        let first = parts.next()?;
        let first = self
            .find_token(|token| matches!(token, Token::Identifier(candidate) if candidate == first))
            .map(token_location);
        let mut span = first;
        for part in parts {
            self.find_token(|token| matches!(token, Token::Dot));
            let next = self
                .find_token(
                    |token| matches!(token, Token::Identifier(candidate) if candidate == part),
                )
                .map(token_location);
            span = combine_optional_spans(span, next);
        }
        span
    }

    fn find_token(&mut self, predicate: impl Fn(&Token) -> bool) -> Option<&SpannedToken> {
        for index in self.index..self.tokens.len() {
            let token = &self.tokens[index];
            if predicate(&token.token) {
                self.index = index + 1;
                return Some(token);
            }
        }
        None
    }

    fn peek_token(&self, predicate: impl Fn(&Token) -> bool) -> bool {
        self.tokens
            .get(self.index)
            .is_some_and(|token| predicate(&token.token))
    }

    fn peek_keyword_argument_start(&self) -> bool {
        matches!(
            (
                self.tokens.get(self.index).map(|token| &token.token),
                self.tokens.get(self.index + 1).map(|token| &token.token),
            ),
            (Some(Token::Identifier(_)), Some(Token::Equal))
        )
    }

    fn next_token_before(
        &self,
        predicate: impl Fn(&Token) -> bool,
        stop: impl Fn(&Token) -> bool,
    ) -> bool {
        for token in &self.tokens[self.index..] {
            if stop(&token.token) {
                return false;
            }
            if predicate(&token.token) {
                return true;
            }
        }
        false
    }
}

fn ast_lookup_field(node: &Value, field: &str) -> Option<Value> {
    let Value::AstNode { attrs, .. } = node else {
        return None;
    };
    lookup_string_key(attrs, field)
}

fn ast_lookup_list_field(node: &Value, field: &str) -> Vec<Value> {
    match ast_lookup_field(node, field) {
        Some(Value::List(items)) => items.borrow().clone(),
        Some(Value::Tuple(items)) => items.as_ref().clone(),
        _ => Vec::new(),
    }
}

fn token_location(token: &SpannedToken) -> AstSourceLocation {
    AstSourceLocation {
        lineno: token.line as i64,
        col_offset: token.byte_column.saturating_sub(1) as i64,
        end_lineno: token.end_line as i64,
        end_col_offset: token.byte_end_column.saturating_sub(1) as i64,
    }
}

fn combine_optional_spans(
    left: Option<AstSourceLocation>,
    right: Option<AstSourceLocation>,
) -> Option<AstSourceLocation> {
    match (left, right) {
        (Some(left), Some(right)) => Some(AstSourceLocation {
            lineno: left.lineno,
            col_offset: left.col_offset,
            end_lineno: right.end_lineno,
            end_col_offset: right.end_col_offset,
        }),
        (Some(span), None) | (None, Some(span)) => Some(span),
        (None, None) => None,
    }
}

fn expr_value_owns_leading_left_paren(value: &Value) -> bool {
    matches!(
        ast_node_kind(value),
        Some("Tuple" | "GeneratorExp" | "Call" | "Subscript" | "Attribute")
    )
}

fn token_inside_span(token: &SpannedToken, start: usize, end: usize) -> bool {
    token.start >= start && token.end <= end
}

fn find_interpolated_token_index(
    tokens: &[SpannedToken],
    start: usize,
    predicate: impl Fn(&Token) -> bool,
) -> Option<usize> {
    tokens
        .iter()
        .enumerate()
        .skip(start)
        .find_map(|(index, token)| predicate(&token.token).then_some(index))
}

fn next_interpolated_middle_token<'a>(
    tokens: &'a [SpannedToken],
    index: &mut usize,
) -> Option<&'a SpannedToken> {
    let found = find_interpolated_token_index(tokens, *index, |token| {
        matches!(token, Token::FStringMiddle(_) | Token::TStringMiddle(_))
    })?;
    *index = found + 1;
    tokens.get(found)
}

fn matching_interpolated_right_brace(tokens: &[SpannedToken], left_brace: usize) -> Option<usize> {
    let mut depth = 0usize;
    for (index, token) in tokens.iter().enumerate().skip(left_brace + 1) {
        match &token.token {
            Token::RightBrace if depth == 0 => return Some(index),
            token_kind if token_opens_group(token_kind) => depth += 1,
            token_kind if token_closes_group(token_kind) => depth = depth.saturating_sub(1),
            _ => {}
        }
    }
    None
}

fn interpolated_replacement_value_end(tokens: &[SpannedToken], start: usize, end: usize) -> usize {
    let mut depth = 0usize;
    for (index, token) in tokens.iter().enumerate().take(end).skip(start) {
        match &token.token {
            Token::Exclamation | Token::Colon if depth == 0 => return index,
            token_kind if token_opens_group(token_kind) => depth += 1,
            token_kind if token_closes_group(token_kind) => depth = depth.saturating_sub(1),
            _ => {}
        }
    }
    end
}

fn interpolated_replacement_format_colon(
    tokens: &[SpannedToken],
    start: usize,
    end: usize,
) -> Option<usize> {
    let mut depth = 0usize;
    for (index, token) in tokens.iter().enumerate().take(end).skip(start) {
        match &token.token {
            Token::Colon if depth == 0 => return Some(index),
            token_kind if token_opens_group(token_kind) => depth += 1,
            token_kind if token_closes_group(token_kind) => depth = depth.saturating_sub(1),
            _ => {}
        }
    }
    None
}

fn token_opens_group(token: &Token) -> bool {
    matches!(
        token,
        Token::LeftParen | Token::LeftBracket | Token::LeftBrace
    )
}

fn token_closes_group(token: &Token) -> bool {
    matches!(
        token,
        Token::RightParen | Token::RightBracket | Token::RightBrace
    )
}

fn set_ast_source_location(node: &Value, span: AstSourceLocation) {
    let Value::AstNode { kind, attrs, .. } = node else {
        return;
    };
    if !ast_kind_supports_location(kind) {
        return;
    }

    let _ = ast_set_attr(attrs, "lineno", Value::Number(span.lineno));
    let _ = ast_set_attr(attrs, "col_offset", Value::Number(span.col_offset));
    let _ = ast_set_attr(attrs, "end_lineno", Value::Number(span.end_lineno));
    let _ = ast_set_attr(attrs, "end_col_offset", Value::Number(span.end_col_offset));
}

fn ast_constant_matches_token(value: &Value, token: &Token) -> bool {
    match (value, token) {
        (Value::Number(left), Token::Number(right)) => left == right,
        (Value::BigInt(left), Token::BigInt(right)) => left.to_string() == right.replace('_', ""),
        (Value::Float(left), Token::Float(right)) => right
            .replace('_', "")
            .parse::<f64>()
            .is_ok_and(|right| (*left - right).abs() == 0.0),
        (Value::String(left), Token::String(right)) => left == right,
        (Value::Bytes(left), Token::Bytes(right)) => left == right,
        (Value::Bool(true), Token::True) | (Value::Bool(false), Token::False) => true,
        (Value::None, Token::None) => true,
        (Value::Ellipsis, Token::Ellipsis) => true,
        (Value::Complex { real, imag }, Token::Imaginary(text)) if *real == 0.0 => text
            .trim_end_matches(['j', 'J'])
            .replace('_', "")
            .parse::<f64>()
            .is_ok_and(|right| (*imag - right).abs() == 0.0),
        _ => false,
    }
}

fn string_literal_token_value(token: &Token) -> Option<String> {
    match token {
        Token::String(value) => Some(value.clone()),
        Token::FString(parts) => {
            let mut value = String::new();
            for part in parts {
                match part {
                    TokenFStringPart::Literal(part) => value.push_str(part),
                    TokenFStringPart::Expression { .. } => return None,
                }
            }
            Some(value)
        }
        _ => None,
    }
}

fn ast_operator_matches_token(op: &Value, token: &Token) -> bool {
    matches!(
        (ast_node_kind(op), token),
        (Some("Add"), Token::Plus)
            | (Some("Sub"), Token::Minus)
            | (Some("Mult"), Token::Star)
            | (Some("MatMult"), Token::At)
            | (Some("Div"), Token::Slash)
            | (Some("FloorDiv"), Token::DoubleSlash)
            | (Some("Mod"), Token::Percent)
            | (Some("Pow"), Token::DoubleStar)
            | (Some("BitOr"), Token::Pipe)
            | (Some("BitXor"), Token::Caret)
            | (Some("BitAnd"), Token::Ampersand)
            | (Some("LShift"), Token::LeftShift)
            | (Some("RShift"), Token::RightShift)
    )
}

fn ast_bool_operator_matches_token(op: &Value, token: &Token) -> bool {
    matches!(
        (ast_node_kind(op), token),
        (Some("And"), Token::And) | (Some("Or"), Token::Or)
    )
}

fn ast_unary_operator_matches_token(op: &Value, token: &Token) -> bool {
    matches!(
        (ast_node_kind(op), token),
        (Some("Not"), Token::Not)
            | (Some("UAdd"), Token::Plus)
            | (Some("USub"), Token::Minus)
            | (Some("Invert"), Token::Tilde)
    )
}

const AST_LOCATION_ATTRIBUTES: &[&str] = &["lineno", "col_offset", "end_lineno", "end_col_offset"];

fn ast_dump_value(
    value: &Value,
    annotate_fields: bool,
    include_attributes: bool,
    show_empty: bool,
) -> String {
    ast_dump_format_value(
        value,
        annotate_fields,
        include_attributes,
        show_empty,
        None,
        0,
    )
    .0
}

fn ast_repr_value(value: &Value) -> String {
    ast_repr_format_value(value, 0)
}

fn ast_repr_value_checked(value: &Value) -> Result<String, String> {
    ast_repr_format_value_checked(value, 0)
}

fn ast_repr_format_value(value: &Value, node_depth: usize) -> String {
    match value {
        Value::AstNode {
            kind,
            fields,
            attrs,
            ..
        } => {
            if node_depth >= 3 {
                return format!("{kind}(...)");
            }

            let rendered_fields = fields
                .iter()
                .filter_map(|field| {
                    lookup_string_key(attrs, field).map(|value| {
                        format!("{field}={}", ast_repr_format_value(&value, node_depth + 1))
                    })
                })
                .collect::<Vec<_>>()
                .join(", ");
            format!("{kind}({rendered_fields})")
        }
        Value::List(items) => {
            let items = items.borrow();
            let rendered = if node_depth >= 2 && items.len() > 2 {
                let first = ast_repr_format_value(&items[0], node_depth);
                let last = ast_repr_format_value(&items[items.len() - 1], node_depth);
                format!("{first}, ..., {last}")
            } else {
                items
                    .iter()
                    .map(|item| ast_repr_format_value(item, node_depth))
                    .collect::<Vec<_>>()
                    .join(", ")
            };
            format!("[{rendered}]")
        }
        Value::Tuple(items) => {
            let rendered = items
                .iter()
                .map(|item| ast_repr_format_value(item, node_depth))
                .collect::<Vec<_>>();
            match rendered.as_slice() {
                [] => "()".to_string(),
                [item] => format!("({item},)"),
                items => format!("({})", items.join(", ")),
            }
        }
        value => repr_value(value),
    }
}

fn ast_repr_format_value_checked(value: &Value, node_depth: usize) -> Result<String, String> {
    match value {
        Value::AstNode {
            kind,
            fields,
            attrs,
            ..
        } => {
            if node_depth >= 3 {
                return Ok(format!("{kind}(...)"));
            }

            let mut rendered_fields = Vec::new();
            for field in fields {
                if let Some(value) = lookup_string_key(attrs, field) {
                    rendered_fields.push(format!(
                        "{field}={}",
                        ast_repr_format_value_checked(&value, node_depth + 1)?
                    ));
                }
            }
            Ok(format!("{kind}({})", rendered_fields.join(", ")))
        }
        Value::List(items) => {
            let items = items.borrow();
            let rendered = if node_depth >= 2 && items.len() > 2 {
                let first = ast_repr_format_value_checked(&items[0], node_depth)?;
                let last = ast_repr_format_value_checked(&items[items.len() - 1], node_depth)?;
                format!("{first}, ..., {last}")
            } else {
                items
                    .iter()
                    .map(|item| ast_repr_format_value_checked(item, node_depth))
                    .collect::<Result<Vec<_>, _>>()?
                    .join(", ")
            };
            Ok(format!("[{rendered}]"))
        }
        Value::Tuple(items) => {
            let rendered = items
                .iter()
                .map(|item| ast_repr_format_value_checked(item, node_depth))
                .collect::<Result<Vec<_>, _>>()?;
            Ok(match rendered.as_slice() {
                [] => "()".to_string(),
                [item] => format!("({item},)"),
                items => format!("({})", items.join(", ")),
            })
        }
        Value::BigInt(value) => repr_big_int_checked(value),
        value => Ok(repr_value(value)),
    }
}

fn ast_dump_format_value(
    value: &Value,
    annotate_fields: bool,
    include_attributes: bool,
    show_empty: bool,
    indent: Option<&str>,
    level: usize,
) -> (String, bool) {
    let (prefix, separator, child_level) = if let Some(indent) = indent {
        let child_level = level + 1;
        (
            format!("\n{}", indent.repeat(child_level)),
            format!(",\n{}", indent.repeat(child_level)),
            child_level,
        )
    } else {
        ("".to_string(), ", ".to_string(), level)
    };

    match value {
        Value::AstNode {
            kind,
            fields,
            attrs,
            ..
        } => {
            let mut rendered_fields = Vec::new();
            let mut skipped_positional_fields = Vec::new();
            let mut all_simple = true;
            let mut keyword_fields = annotate_fields;
            for field in fields {
                let Some(value) = lookup_string_key(attrs, field) else {
                    keyword_fields = true;
                    continue;
                };
                match ast_dump_skipped_field(kind, field, &value, show_empty) {
                    AstDumpSkippedField::NoneValue => {
                        keyword_fields = true;
                        continue;
                    }
                    AstDumpSkippedField::Buffered => {
                        if !keyword_fields {
                            skipped_positional_fields.push(
                                ast_dump_format_value(
                                    &value,
                                    annotate_fields,
                                    include_attributes,
                                    show_empty,
                                    indent,
                                    child_level,
                                )
                                .0,
                            );
                        }
                        continue;
                    }
                    AstDumpSkippedField::No => {}
                }
                if !keyword_fields {
                    rendered_fields.append(&mut skipped_positional_fields);
                }
                let (rendered, simple) = ast_dump_format_value(
                    &value,
                    annotate_fields,
                    include_attributes,
                    show_empty,
                    indent,
                    child_level,
                );
                all_simple = all_simple && simple;
                if keyword_fields {
                    rendered_fields.push(format!("{field}={rendered}"));
                } else {
                    rendered_fields.push(rendered);
                }
            }
            if include_attributes {
                for attr in ast_location_attributes(kind) {
                    let Some(value) = lookup_string_key(attrs, attr) else {
                        continue;
                    };
                    if matches!(*attr, "end_lineno" | "end_col_offset")
                        && matches!(value, Value::None)
                    {
                        continue;
                    }
                    let (rendered, simple) = ast_dump_format_value(
                        &value,
                        annotate_fields,
                        include_attributes,
                        show_empty,
                        indent,
                        child_level,
                    );
                    all_simple = all_simple && simple;
                    rendered_fields.push(format!("{attr}={rendered}"));
                }
            }
            if all_simple && rendered_fields.len() <= 3 {
                (
                    format!("{kind}({})", rendered_fields.join(", ")),
                    rendered_fields.is_empty(),
                )
            } else {
                (
                    format!("{kind}({}{})", prefix, rendered_fields.join(&separator)),
                    false,
                )
            }
        }
        Value::List(items) => {
            let items = items.borrow();
            if items.is_empty() {
                return ("[]".to_string(), true);
            }
            let rendered = items
                .iter()
                .map(|item| {
                    ast_dump_format_value(
                        item,
                        annotate_fields,
                        include_attributes,
                        show_empty,
                        indent,
                        child_level,
                    )
                    .0
                })
                .collect::<Vec<_>>()
                .join(&separator);
            (format!("[{prefix}{rendered}]"), false)
        }
        Value::Tuple(items) => {
            let rendered = items
                .iter()
                .map(|item| {
                    ast_dump_format_value(
                        item,
                        annotate_fields,
                        include_attributes,
                        show_empty,
                        indent,
                        child_level,
                    )
                    .0
                })
                .collect::<Vec<_>>();
            (
                match rendered.as_slice() {
                    [] => "()".to_string(),
                    [item] => format!("({item},)"),
                    items => format!("({})", items.join(", ")),
                },
                true,
            )
        }
        value => (repr_value(value), true),
    }
}

enum AstDumpSkippedField {
    No,
    NoneValue,
    Buffered,
}

fn ast_dump_skipped_field(
    kind: &str,
    field: &str,
    value: &Value,
    show_empty: bool,
) -> AstDumpSkippedField {
    let default = ast_constructor_default(kind, field);
    if matches!(value, Value::None) && matches!(default, Some(Value::None)) {
        return AstDumpSkippedField::NoneValue;
    }
    if !show_empty
        && matches!(value, Value::List(items) if items.borrow().is_empty())
        && matches!(default.as_ref(), Some(Value::List(items)) if items.borrow().is_empty())
    {
        return AstDumpSkippedField::Buffered;
    }
    if !show_empty
        && field == "ctx"
        && ast_node_kind(value) == Some("Load")
        && matches!(default.as_ref().and_then(ast_node_kind), Some("Load"))
        && ast_dump_kind_has_context(kind)
    {
        return AstDumpSkippedField::Buffered;
    }
    AstDumpSkippedField::No
}

fn ast_dump_kind_has_context(kind: &str) -> bool {
    matches!(
        kind,
        "Name" | "Attribute" | "Subscript" | "Starred" | "List" | "Tuple"
    )
}

fn ast_location_attributes(kind: &str) -> &'static [&'static str] {
    if ast_kind_supports_location(kind) {
        AST_LOCATION_ATTRIBUTES
    } else {
        &[]
    }
}

fn ast_kind_supports_location(kind: &str) -> bool {
    !matches!(
        kind,
        "AST"
            | "mod"
            | "Module"
            | "Expression"
            | "Interactive"
            | "FunctionType"
            | "expr_context"
            | "boolop"
            | "operator"
            | "unaryop"
            | "cmpop"
            | "Load"
            | "Store"
            | "Del"
            | "Add"
            | "Sub"
            | "Mult"
            | "MatMult"
            | "Div"
            | "FloorDiv"
            | "Mod"
            | "Pow"
            | "BitOr"
            | "BitXor"
            | "BitAnd"
            | "LShift"
            | "RShift"
            | "Eq"
            | "NotEq"
            | "Lt"
            | "LtE"
            | "Gt"
            | "GtE"
            | "In"
            | "NotIn"
            | "Is"
            | "IsNot"
            | "Not"
            | "UAdd"
            | "USub"
            | "Invert"
            | "And"
            | "Or"
            | "arguments"
            | "withitem"
            | "comprehension"
            | "match_case"
            | "type_ignore"
            | "TypeIgnore"
    )
}

fn call_ast_dump(args: Vec<Value>, keywords: Vec<(String, Value)>) -> Result<Value, String> {
    let mut values = vec![None, None, None, None, None];
    let names = [
        "node",
        "annotate_fields",
        "include_attributes",
        "indent",
        "show_empty",
    ];
    if args.len() > 3 {
        return Err(format!(
            "TypeError: dump() takes from 1 to 3 positional arguments but {} were given",
            args.len()
        ));
    }
    for (index, value) in args.into_iter().enumerate() {
        values[index] = Some(value);
    }
    for (name, value) in keywords {
        let Some(index) = names.iter().position(|candidate| candidate == &name) else {
            return Err(format!(
                "TypeError: dump() got an unexpected keyword argument '{name}'"
            ));
        };
        if values[index].is_some() {
            return Err(format!(
                "TypeError: dump() got multiple values for argument '{name}'"
            ));
        }
        values[index] = Some(value);
    }

    let node = values[0]
        .take()
        .ok_or_else(|| "TypeError: dump() missing required argument 'node'".to_string())?;
    let annotate_fields = values[1]
        .as_ref()
        .map(is_truthy)
        .transpose()?
        .unwrap_or(true);
    let include_attributes = values[2]
        .as_ref()
        .map(is_truthy)
        .transpose()?
        .unwrap_or(false);
    let indent = match values[3].take().unwrap_or(Value::None) {
        Value::None => None,
        Value::String(indent) => Some(indent),
        Value::Number(width) => Some(" ".repeat(width.max(0) as usize)),
        Value::Bool(true) => Some(" ".to_string()),
        Value::Bool(false) => Some(String::new()),
        value => {
            return Err(format!(
                "TypeError: can't multiply sequence by non-int of type '{}'",
                type_name(&value)
            ));
        }
    };
    let show_empty = values[4]
        .as_ref()
        .map(is_truthy)
        .transpose()?
        .unwrap_or(false);
    match &node {
        Value::AstNode { .. } => Ok(Value::String(match indent.as_deref() {
            Some(indent) => {
                ast_dump_format_value(
                    &node,
                    annotate_fields,
                    include_attributes,
                    show_empty,
                    Some(indent),
                    0,
                )
                .0
            }
            None => ast_dump_value(&node, annotate_fields, include_attributes, show_empty),
        })),
        value => Err(format!(
            "TypeError: expected AST, got '{}'",
            type_name(&value)
        )),
    }
}

fn call_ast_compare(args: Vec<Value>, keywords: Vec<(String, Value)>) -> Result<Value, String> {
    if args.len() != 2 {
        return Err(format!(
            "TypeError: compare() expected 2 positional arguments, got {}",
            args.len()
        ));
    }

    let mut compare_attributes = Value::Bool(false);
    let mut seen_compare_attributes = false;
    for (keyword, value) in keywords {
        match keyword.as_str() {
            "compare_attributes" => {
                if seen_compare_attributes {
                    return Err(
                        "TypeError: compare() got multiple values for argument 'compare_attributes'"
                            .to_string(),
                    );
                }
                seen_compare_attributes = true;
                compare_attributes = value;
            }
            "a" | "b" => {
                return Err(format!(
                    "TypeError: compare() got some positional-only arguments passed as keyword arguments: '{keyword}'"
                ));
            }
            _ => {
                return Err(format!(
                    "TypeError: compare() got an unexpected keyword argument '{keyword}'"
                ));
            }
        }
    }

    Ok(Value::Bool(ast_compare_values(
        &args[0],
        &args[1],
        is_truthy(&compare_attributes)?,
    )))
}

fn ast_compare_values(left: &Value, right: &Value, compare_attributes: bool) -> bool {
    if ast_compare_is_ast_object(left) || ast_compare_is_ast_object(right) {
        return ast_compare_ast_objects(left, right, compare_attributes);
    }

    if let Value::List(left_items) = left {
        let Value::List(right_items) = right else {
            return false;
        };
        let left_items = left_items.borrow();
        let right_items = right_items.borrow();
        if left_items.len() != right_items.len() {
            return false;
        }
        return left_items
            .iter()
            .zip(right_items.iter())
            .all(|(left, right)| ast_compare_values(left, right, compare_attributes));
    }

    ast_compare_leaf_values(left, right)
}

fn ast_compare_ast_objects(left: &Value, right: &Value, compare_attributes: bool) -> bool {
    if !ast_compare_same_ast_type(left, right) {
        return false;
    }

    let left_fields = ast_compare_field_names(left);
    let right_fields = ast_compare_field_names(right);
    if left_fields != right_fields {
        return false;
    }
    for field in left_fields {
        match (
            ast_compare_get_attr(left, &field),
            ast_compare_get_attr(right, &field),
        ) {
            (None, None) => {}
            (Some(left_value), Some(right_value)) => {
                if !ast_compare_values(&left_value, &right_value, compare_attributes) {
                    return false;
                }
            }
            _ => return false,
        }
    }

    if compare_attributes {
        let left_attributes = ast_compare_attribute_names(left);
        let right_attributes = ast_compare_attribute_names(right);
        if left_attributes != right_attributes {
            return false;
        }
        for attribute in left_attributes {
            match (
                ast_compare_get_attr(left, &attribute),
                ast_compare_get_attr(right, &attribute),
            ) {
                (None, None) => {}
                (Some(left_value), Some(right_value))
                    if ast_compare_values(&left_value, &right_value, compare_attributes) => {}
                _ => return false,
            }
        }
    }

    true
}

fn ast_compare_is_ast_object(value: &Value) -> bool {
    match value {
        Value::AstNode { .. } => true,
        Value::Instance { class_bases, .. } => class_bases_include_builtin(class_bases, "AST"),
        _ => false,
    }
}

fn ast_compare_same_ast_type(left: &Value, right: &Value) -> bool {
    match (left, right) {
        (
            Value::AstNode {
                kind: left_kind, ..
            },
            Value::AstNode {
                kind: right_kind, ..
            },
        ) => left_kind == right_kind,
        (
            Value::Instance {
                class_name: left_name,
                class_attrs: left_attrs,
                class_bases: left_bases,
                ..
            },
            Value::Instance {
                class_name: right_name,
                class_attrs: right_attrs,
                class_bases: right_bases,
                ..
            },
        ) if class_bases_include_builtin(left_bases, "AST")
            && class_bases_include_builtin(right_bases, "AST") =>
        {
            left_name == right_name && Rc::ptr_eq(left_attrs, right_attrs)
        }
        _ => false,
    }
}

fn ast_compare_field_names(value: &Value) -> Vec<String> {
    match value {
        Value::AstNode { fields, attrs, .. } => lookup_string_key(attrs, "_fields")
            .map(|value| ast_compare_string_sequence(&value))
            .unwrap_or_else(|| fields.clone()),
        Value::Instance {
            fields,
            class_attrs,
            ..
        } => ast_compare_instance_sequence_attr(fields, class_attrs, "_fields"),
        _ => Vec::new(),
    }
}

fn ast_compare_attribute_names(value: &Value) -> Vec<String> {
    match value {
        Value::AstNode { kind, attrs, .. } => lookup_string_key(attrs, "_attributes")
            .map(|value| ast_compare_string_sequence(&value))
            .unwrap_or_else(|| {
                ast_location_attributes(kind)
                    .iter()
                    .map(|name| (*name).to_string())
                    .collect()
            }),
        Value::Instance {
            fields,
            class_attrs,
            ..
        } => ast_compare_instance_sequence_attr(fields, class_attrs, "_attributes"),
        _ => Vec::new(),
    }
}

fn ast_compare_instance_sequence_attr(
    fields: &Scope,
    class_attrs: &Scope,
    name: &str,
) -> Vec<String> {
    fields
        .borrow()
        .get(name)
        .cloned()
        .or_else(|| class_attrs.borrow().get(name).cloned())
        .map(|value| ast_compare_string_sequence(&value))
        .unwrap_or_default()
}

fn ast_compare_string_sequence(value: &Value) -> Vec<String> {
    match value {
        Value::Tuple(items) => items
            .iter()
            .filter_map(|item| match item {
                Value::String(name) => Some(name.clone()),
                _ => None,
            })
            .collect(),
        Value::List(items) => items
            .borrow()
            .iter()
            .filter_map(|item| match item {
                Value::String(name) => Some(name.clone()),
                _ => None,
            })
            .collect(),
        _ => Vec::new(),
    }
}

fn ast_compare_get_attr(value: &Value, name: &str) -> Option<Value> {
    match value {
        Value::AstNode { kind, attrs, .. } => {
            if matches!(name, "end_lineno" | "end_col_offset") && ast_kind_supports_location(kind) {
                Some(lookup_string_key(attrs, name).unwrap_or(Value::None))
            } else {
                lookup_string_key(attrs, name)
            }
        }
        Value::Instance {
            fields,
            class_attrs,
            ..
        } => fields
            .borrow()
            .get(name)
            .cloned()
            .or_else(|| class_attrs.borrow().get(name).cloned()),
        _ => None,
    }
}

fn ast_compare_leaf_values(left: &Value, right: &Value) -> bool {
    ast_compare_leaf_same_type(left, right) && ast_compare_python_eq(left, right)
}

fn ast_compare_leaf_same_type(left: &Value, right: &Value) -> bool {
    match (left, right) {
        (Value::Number(_), Value::Number(_))
        | (Value::Number(_), Value::BigInt(_))
        | (Value::BigInt(_), Value::Number(_))
        | (Value::BigInt(_), Value::BigInt(_)) => true,
        (
            Value::Instance {
                class_name: left_name,
                class_attrs: left_attrs,
                ..
            },
            Value::Instance {
                class_name: right_name,
                class_attrs: right_attrs,
                ..
            },
        ) => left_name == right_name && Rc::ptr_eq(left_attrs, right_attrs),
        _ => std::mem::discriminant(left) == std::mem::discriminant(right),
    }
}

fn ast_compare_python_eq(left: &Value, right: &Value) -> bool {
    if is_identical(left, right) {
        return true;
    }

    match (left, right) {
        (Value::Tuple(left_items), Value::Tuple(right_items)) => {
            left_items.len() == right_items.len()
                && left_items
                    .iter()
                    .zip(right_items.iter())
                    .all(|(left, right)| ast_compare_python_eq(left, right))
        }
        (Value::List(left_items), Value::List(right_items)) => {
            let left_items = left_items.borrow();
            let right_items = right_items.borrow();
            left_items.len() == right_items.len()
                && left_items
                    .iter()
                    .zip(right_items.iter())
                    .all(|(left, right)| ast_compare_python_eq(left, right))
        }
        (Value::Instance { .. }, Value::Instance { .. }) => false,
        _ => left == right,
    }
}

fn call_ast_iter_fields(args: Vec<Value>, keywords: Vec<(String, Value)>) -> Result<Value, String> {
    let node = bind_ast_helper_node_arg("iter_fields", args, keywords)?;
    Ok(shared_iterator(Value::ListIterator {
        items: ast_iter_field_pairs(&node)?
            .into_iter()
            .map(|(field, value)| tuple_value(vec![Value::String(field), value]))
            .collect(),
        index: 0,
    }))
}

fn call_ast_iter_child_nodes(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let node = bind_ast_helper_node_arg("iter_child_nodes", args, keywords)?;
    Ok(shared_iterator(Value::ListIterator {
        items: ast_child_nodes(&node)?,
        index: 0,
    }))
}

fn call_ast_walk(args: Vec<Value>, keywords: Vec<(String, Value)>) -> Result<Value, String> {
    let node = bind_ast_helper_node_arg("walk", args, keywords)?;
    let mut queue = vec![node];
    let mut index = 0;
    while index < queue.len() {
        let children = ast_child_nodes(&queue[index])?;
        queue.extend(children);
        index += 1;
    }

    Ok(shared_iterator(Value::ListIterator {
        items: queue,
        index: 0,
    }))
}

fn call_ast_literal_eval(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let node_or_string = bind_ast_literal_eval_arg(args, keywords)?;
    let node = match node_or_string {
        Value::String(source) => {
            parse_ast_eval_node(source.trim_start_matches(|ch| matches!(ch, ' ' | '\t')), -1)?
        }
        Value::AstNode { .. } => node_or_string,
        value => return Err(ast_literal_eval_malformed_value(&value)),
    };
    ast_literal_eval_node(&node)
}

fn call_ast_copy_location(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let mut values = bind_ast_positional_keyword_args(
        "copy_location",
        ["new_node", "old_node"].as_slice(),
        args,
        keywords,
    )?;
    let new_node = values[0].take().ok_or_else(|| {
        "TypeError: copy_location() missing required argument 'new_node'".to_string()
    })?;
    let old_node = values[1].take().ok_or_else(|| {
        "TypeError: copy_location() missing required argument 'old_node'".to_string()
    })?;

    let Value::AstNode {
        kind: new_kind,
        attrs: new_attrs,
        ..
    } = &new_node
    else {
        return Err(ast_expected_node_type_error(
            "copy_location",
            "new_node",
            &new_node,
        ));
    };
    let Value::AstNode {
        kind: old_kind,
        attrs: old_attrs,
        ..
    } = &old_node
    else {
        return Err(ast_expected_node_type_error(
            "copy_location",
            "old_node",
            &old_node,
        ));
    };

    ast_copy_location_attr_refs(new_kind, new_attrs, old_kind, old_attrs)?;

    Ok(new_node)
}

fn ast_copy_location_attrs(new_node: &Value, old_node: &Value) -> Result<(), String> {
    let Value::AstNode {
        kind: new_kind,
        attrs: new_attrs,
        ..
    } = new_node
    else {
        return Ok(());
    };
    let Value::AstNode {
        kind: old_kind,
        attrs: old_attrs,
        ..
    } = old_node
    else {
        return Ok(());
    };

    ast_copy_location_attr_refs(new_kind, new_attrs, old_kind, old_attrs)
}

fn ast_copy_location_attr_refs(
    new_kind: &str,
    new_attrs: &DictRef,
    old_kind: &str,
    old_attrs: &DictRef,
) -> Result<(), String> {
    if !ast_kind_supports_location(new_kind) || !ast_kind_supports_location(old_kind) {
        return Ok(());
    }

    for attr in AST_LOCATION_ATTRIBUTES {
        match *attr {
            "lineno" | "col_offset" => {
                if let Some(value) = lookup_string_key(old_attrs, attr)
                    && !matches!(value, Value::None)
                {
                    ast_set_attr(new_attrs, attr, value)?;
                }
            }
            "end_lineno" | "end_col_offset" => {
                let value = lookup_string_key(old_attrs, attr).unwrap_or(Value::None);
                ast_set_attr(new_attrs, attr, value)?;
            }
            _ => {}
        }
    }

    Ok(())
}

fn call_ast_fix_missing_locations(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let node = bind_ast_helper_node_arg("fix_missing_locations", args, keywords)?;
    ast_fix_missing_locations_recursive(&node, 1, 0, 1, 0)?;
    Ok(node)
}

fn call_ast_increment_lineno(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let mut values = bind_ast_positional_keyword_args(
        "increment_lineno",
        ["node", "n"].as_slice(),
        args,
        keywords,
    )?;
    let node = values[0].take().ok_or_else(|| {
        "TypeError: increment_lineno() missing required argument 'node'".to_string()
    })?;
    ensure_ast_node_fields(&node)?;
    let increment = values[1]
        .take()
        .map(|value| compile_int_argument(value, "n"))
        .transpose()?
        .unwrap_or(1);

    for child in ast_walk_values(&node)? {
        ast_increment_location(&child, increment)?;
    }
    Ok(node)
}

fn call_ast_get_docstring(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let mut values = bind_ast_positional_keyword_args(
        "get_docstring",
        ["node", "clean"].as_slice(),
        args,
        keywords,
    )?;
    let node = values[0]
        .take()
        .ok_or_else(|| "TypeError: get_docstring() missing required argument 'node'".to_string())?;
    let clean = values[1]
        .as_ref()
        .map(is_truthy)
        .transpose()?
        .unwrap_or(true);
    let Some(docstring) = ast_get_raw_docstring(&node)? else {
        return Ok(Value::None);
    };
    if clean {
        Ok(Value::String(ast_clean_docstring(&docstring)))
    } else {
        Ok(Value::String(docstring))
    }
}

fn call_ast_get_source_segment(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if args.len() > 2 {
        return Err(format!(
            "TypeError: get_source_segment() takes 2 positional arguments but {} were given",
            args.len()
        ));
    }

    let mut source = None;
    let mut node = None;
    let mut padded = None;
    for (index, value) in args.into_iter().enumerate() {
        match index {
            0 => source = Some(value),
            1 => node = Some(value),
            _ => unreachable!("positional count checked above"),
        }
    }
    for (keyword, value) in keywords {
        match keyword.as_str() {
            "source" => {
                if source.is_some() {
                    return Err(
                        "TypeError: get_source_segment() got multiple values for argument 'source'"
                            .to_string(),
                    );
                }
                source = Some(value);
            }
            "node" => {
                if node.is_some() {
                    return Err(
                        "TypeError: get_source_segment() got multiple values for argument 'node'"
                            .to_string(),
                    );
                }
                node = Some(value);
            }
            "padded" => {
                if padded.is_some() {
                    return Err(
                        "TypeError: get_source_segment() got multiple values for argument 'padded'"
                            .to_string(),
                    );
                }
                padded = Some(value);
            }
            _ => {
                return Err(format!(
                    "TypeError: get_source_segment() got an unexpected keyword argument '{keyword}'"
                ));
            }
        }
    }

    let source = source.ok_or_else(|| {
        "TypeError: get_source_segment() missing required argument 'source'".to_string()
    })?;
    let source = match source {
        Value::String(source) => source,
        value => {
            return Err(format!(
                "TypeError: get_source_segment() source must be str, not {}",
                type_name(&value)
            ));
        }
    };
    let node = node.ok_or_else(|| {
        "TypeError: get_source_segment() missing required argument 'node'".to_string()
    })?;
    let padded = padded.as_ref().map(is_truthy).transpose()?.unwrap_or(false);
    let Some(location) = ast_get_source_segment_location(&node)? else {
        return Ok(Value::None);
    };
    let Some(segment) = ast_source_segment(&source, location, padded) else {
        return Ok(Value::None);
    };

    Ok(Value::String(segment))
}

fn ast_get_source_segment_location(node: &Value) -> Result<Option<AstSourceLocation>, String> {
    let Value::AstNode { attrs, .. } = node else {
        return Ok(None);
    };
    let Some(lineno) = ast_optional_location_attr(attrs, "lineno")? else {
        return Ok(None);
    };
    let Some(end_lineno) = ast_optional_location_attr(attrs, "end_lineno")? else {
        return Ok(None);
    };
    let Some(col_offset) = ast_optional_location_attr(attrs, "col_offset")? else {
        return Ok(None);
    };
    let Some(end_col_offset) = ast_optional_location_attr(attrs, "end_col_offset")? else {
        return Ok(None);
    };

    Ok(Some(AstSourceLocation {
        lineno,
        col_offset,
        end_lineno,
        end_col_offset,
    }))
}

fn ast_optional_location_attr(attrs: &DictRef, name: &str) -> Result<Option<i64>, String> {
    match lookup_string_key(attrs, name) {
        Some(Value::Number(value)) => Ok(Some(value)),
        Some(Value::Bool(value)) => Ok(Some(bool_as_i64(value))),
        Some(Value::None) | None => Ok(None),
        Some(value) => Err(format!(
            "TypeError: AST location attribute '{name}' must be int, not {}",
            type_name(&value)
        )),
    }
}

fn ast_source_segment(source: &str, location: AstSourceLocation, padded: bool) -> Option<String> {
    if location.lineno <= 0
        || location.end_lineno <= 0
        || location.col_offset < 0
        || location.end_col_offset < 0
        || location.end_lineno < location.lineno
    {
        return None;
    }

    let lineno = usize::try_from(location.lineno - 1).ok()?;
    let end_lineno = usize::try_from(location.end_lineno - 1).ok()?;
    let col_offset = usize::try_from(location.col_offset).ok()?;
    let end_col_offset = usize::try_from(location.end_col_offset).ok()?;
    let lines = ast_splitlines_no_ff(source, end_lineno + 1);
    let first_line = *lines.get(lineno)?;
    let last_line = *lines.get(end_lineno)?;

    if lineno == end_lineno {
        return ast_slice_line(first_line, col_offset, Some(end_col_offset));
    }

    let mut segment = String::new();
    if padded {
        let prefix = ast_slice_line(first_line, 0, Some(col_offset))?;
        segment.push_str(&ast_pad_whitespace(&prefix));
    }
    segment.push_str(&ast_slice_line(first_line, col_offset, None)?);
    for line in &lines[lineno + 1..end_lineno] {
        segment.push_str(line);
    }
    segment.push_str(&ast_slice_line(last_line, 0, Some(end_col_offset))?);
    Some(segment)
}

fn ast_splitlines_no_ff(source: &str, max_lines: usize) -> Vec<&str> {
    if max_lines == 0 {
        return Vec::new();
    }

    let bytes = source.as_bytes();
    let mut lines = Vec::new();
    let mut start = 0;
    let mut index = 0;
    while index < bytes.len() {
        let end = match bytes[index] {
            b'\n' => Some(index + 1),
            b'\r' if index + 1 < bytes.len() && bytes[index + 1] == b'\n' => Some(index + 2),
            b'\r' => Some(index + 1),
            _ => None,
        };
        if let Some(end) = end {
            lines.push(&source[start..end]);
            if lines.len() >= max_lines {
                return lines;
            }
            start = end;
            index = end;
        } else {
            index += 1;
        }
    }
    if lines.len() < max_lines {
        lines.push(&source[start..]);
    }
    lines
}

fn ast_slice_line(line: &str, start: usize, end: Option<usize>) -> Option<String> {
    let byte_start = start.min(line.len());
    let byte_end = end.unwrap_or(line.len()).min(line.len()).max(byte_start);
    if let Ok(segment) = std::str::from_utf8(&line.as_bytes()[byte_start..byte_end]) {
        return Some(segment.to_string());
    }

    let chars = line.chars().collect::<Vec<_>>();
    let char_start = start.min(chars.len());
    let char_end = end.unwrap_or(chars.len()).min(chars.len()).max(char_start);
    Some(chars[char_start..char_end].iter().collect())
}

fn ast_pad_whitespace(source: &str) -> String {
    source
        .chars()
        .map(|ch| {
            if matches!(ch, '\t' | '\u{000c}') {
                ch
            } else {
                ' '
            }
        })
        .collect()
}

fn ast_get_raw_docstring(node: &Value) -> Result<Option<String>, String> {
    let Some(kind) = ast_node_kind(node) else {
        return Err(ast_get_docstring_type_error(node));
    };
    if !matches!(
        kind,
        "Module" | "ClassDef" | "FunctionDef" | "AsyncFunctionDef"
    ) {
        return Err(ast_get_docstring_type_error(node));
    }

    let body = ast_lookup_list_field(node, "body");
    let Some(first) = body.first() else {
        return Ok(None);
    };
    if !matches!(ast_node_kind(first), Some("Expr")) {
        return Ok(None);
    }
    let Some(value) = ast_lookup_field(first, "value") else {
        return Ok(None);
    };
    if !matches!(ast_node_kind(&value), Some("Constant")) {
        return Ok(None);
    }
    match ast_lookup_field(&value, "value") {
        Some(Value::String(docstring)) => Ok(Some(docstring)),
        _ => Ok(None),
    }
}

fn ast_get_docstring_type_error(node: &Value) -> String {
    format!(
        "TypeError: '{}' can't have docstrings",
        ast_node_kind(node).unwrap_or_else(|| type_name(node))
    )
}

fn ast_clean_docstring(docstring: &str) -> String {
    let expanded = docstring.replace('\t', "        ");
    let mut lines = expanded.lines().map(str::to_string).collect::<Vec<_>>();
    if expanded.ends_with('\n') {
        lines.push(String::new());
    }
    if lines.is_empty() {
        return String::new();
    }

    let mut margin: Option<usize> = None;
    for line in lines.iter().skip(1) {
        let content = line.trim();
        if content.is_empty() {
            continue;
        }
        let indent = line.chars().take_while(|ch| *ch == ' ').count();
        margin = Some(margin.map_or(indent, |margin| margin.min(indent)));
    }

    lines[0] = lines[0].trim().to_string();
    if let Some(margin) = margin {
        for line in lines.iter_mut().skip(1) {
            let trim = margin.min(line.chars().take_while(|ch| *ch == ' ').count());
            *line = line.chars().skip(trim).collect();
        }
    }

    while lines.last().is_some_and(|line| line.trim().is_empty()) {
        lines.pop();
    }
    while lines.first().is_some_and(|line| line.trim().is_empty()) {
        lines.remove(0);
    }
    lines.join("\n")
}

fn bind_ast_positional_keyword_args(
    function_name: &str,
    names: &[&str],
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Vec<Option<Value>>, String> {
    if args.len() > names.len() {
        return Err(format!(
            "TypeError: {function_name}() takes at most {} positional arguments but {} were given",
            names.len(),
            args.len()
        ));
    }

    let mut values = vec![None; names.len()];
    for (index, value) in args.into_iter().enumerate() {
        values[index] = Some(value);
    }
    for (keyword, value) in keywords {
        let Some(index) = names.iter().position(|name| *name == keyword) else {
            return Err(format!(
                "TypeError: {function_name}() got an unexpected keyword argument '{keyword}'"
            ));
        };
        if values[index].is_some() {
            return Err(format!(
                "TypeError: {function_name}() got multiple values for argument '{keyword}'"
            ));
        }
        values[index] = Some(value);
    }
    Ok(values)
}

fn ast_fix_missing_locations_recursive(
    node: &Value,
    mut lineno: i64,
    mut col_offset: i64,
    mut end_lineno: i64,
    mut end_col_offset: i64,
) -> Result<(), String> {
    let Value::AstNode { kind, attrs, .. } = node else {
        return Ok(());
    };

    if ast_kind_supports_location(kind) {
        match lookup_string_key(attrs, "lineno") {
            Some(Value::Number(value)) => lineno = value,
            Some(Value::Bool(value)) => lineno = bool_as_i64(value),
            Some(_) => {}
            None => ast_set_attr(attrs, "lineno", Value::Number(lineno))?,
        }
        match lookup_string_key(attrs, "end_lineno") {
            Some(Value::Number(value)) => end_lineno = value,
            Some(Value::Bool(value)) => end_lineno = bool_as_i64(value),
            Some(Value::None) | None => {
                ast_set_attr(attrs, "end_lineno", Value::Number(end_lineno))?
            }
            Some(_) => {}
        }
        match lookup_string_key(attrs, "col_offset") {
            Some(Value::Number(value)) => col_offset = value,
            Some(Value::Bool(value)) => col_offset = bool_as_i64(value),
            Some(_) => {}
            None => ast_set_attr(attrs, "col_offset", Value::Number(col_offset))?,
        }
        match lookup_string_key(attrs, "end_col_offset") {
            Some(Value::Number(value)) => end_col_offset = value,
            Some(Value::Bool(value)) => end_col_offset = bool_as_i64(value),
            Some(Value::None) | None => {
                ast_set_attr(attrs, "end_col_offset", Value::Number(end_col_offset))?
            }
            Some(_) => {}
        }
    }

    for child in ast_child_nodes(node)? {
        ast_fix_missing_locations_recursive(
            &child,
            lineno,
            col_offset,
            end_lineno,
            end_col_offset,
        )?;
    }
    Ok(())
}

fn ast_increment_location(node: &Value, increment: i64) -> Result<(), String> {
    let Value::AstNode { kind, attrs, .. } = node else {
        return Ok(());
    };
    if kind == "TypeIgnore" {
        let lineno = lookup_string_key(attrs, "lineno")
            .map(|value| ast_location_number(value, "lineno"))
            .transpose()?
            .unwrap_or(0);
        ast_set_attr(attrs, "lineno", Value::Number(lineno + increment))?;
        return Ok(());
    }
    if !ast_kind_supports_location(kind) {
        return Ok(());
    }

    let lineno = match lookup_string_key(attrs, "lineno") {
        Some(value) => ast_location_number(value, "lineno")?,
        None => 0,
    };
    ast_set_attr(attrs, "lineno", Value::Number(lineno + increment))?;

    if let Some(value) = lookup_string_key(attrs, "end_lineno")
        && !matches!(value, Value::None)
    {
        let end_lineno = ast_location_number(value, "end_lineno")?;
        ast_set_attr(attrs, "end_lineno", Value::Number(end_lineno + increment))?;
    }

    Ok(())
}

fn ast_location_number(value: Value, _name: &str) -> Result<i64, String> {
    match value {
        Value::Number(value) => Ok(value),
        Value::Bool(value) => Ok(bool_as_i64(value)),
        value => Err(format!(
            "TypeError: unsupported operand type(s) for +: '{}' and 'int'",
            type_name(&value)
        )),
    }
}

fn ast_walk_values(node: &Value) -> Result<Vec<Value>, String> {
    ensure_ast_node_fields(node)?;
    let mut queue = vec![node.clone()];
    let mut index = 0;
    while index < queue.len() {
        let children = ast_child_nodes(&queue[index])?;
        queue.extend(children);
        index += 1;
    }
    Ok(queue)
}

fn ast_set_attr(attrs: &DictRef, name: &str, value: Value) -> Result<(), String> {
    insert_live_dict_entry(
        &mut attrs.borrow_mut(),
        Value::String(name.to_string()),
        value,
    )
}

fn ast_expected_node_type_error(function_name: &str, argument: &str, value: &Value) -> String {
    format!(
        "TypeError: {function_name}() {argument} must be AST, not {}",
        type_name(value)
    )
}

fn bind_ast_literal_eval_arg(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if args.len() > 1 {
        return Err(format!(
            "TypeError: literal_eval() takes 1 positional argument but {} were given",
            args.len()
        ));
    }

    let mut value = args.into_iter().next();
    for (keyword, keyword_value) in keywords {
        if keyword != "node_or_string" {
            return Err(format!(
                "TypeError: literal_eval() got an unexpected keyword argument '{keyword}'"
            ));
        }
        if value.is_some() {
            return Err(
                "TypeError: literal_eval() got multiple values for argument 'node_or_string'"
                    .to_string(),
            );
        }
        value = Some(keyword_value);
    }

    value.ok_or_else(|| {
        "TypeError: literal_eval() missing required argument 'node_or_string'".to_string()
    })
}

fn ast_literal_eval_node(node: &Value) -> Result<Value, String> {
    let Value::AstNode { kind, .. } = node else {
        return Err(ast_literal_eval_malformed_value(node));
    };

    match kind.as_str() {
        "Expression" => ast_literal_eval_node(&ast_required_field(node, "body")?),
        "Constant" => ast_required_field(node, "value"),
        "Tuple" => Ok(tuple_value(ast_literal_eval_sequence_items(node)?)),
        "List" => Ok(list_value(ast_literal_eval_sequence_items(node)?)),
        "Set" => ast_literal_eval_set(node),
        "Dict" => ast_literal_eval_dict(node),
        "UnaryOp" => ast_literal_eval_unary(node),
        "BinOp" => ast_literal_eval_complex_binop(node),
        "Call" => ast_literal_eval_call(node),
        _ => Err(ast_literal_eval_malformed_value(node)),
    }
}

fn ast_literal_eval_sequence_items(node: &Value) -> Result<Vec<Value>, String> {
    ast_list_field(node, "elts")?
        .into_iter()
        .map(|item| ast_literal_eval_node(&item))
        .collect()
}

fn ast_literal_eval_set(node: &Value) -> Result<Value, String> {
    let mut values = Vec::new();
    for value in ast_literal_eval_sequence_items(node)? {
        insert_set_item(&mut values, value).map_err(|message| format!("ValueError: {message}"))?;
    }
    Ok(set_value(values))
}

fn ast_literal_eval_dict(node: &Value) -> Result<Value, String> {
    let keys = ast_list_field(node, "keys")?;
    let values = ast_list_field(node, "values")?;
    if keys.len() != values.len() {
        return Err(ast_literal_eval_malformed_value(node));
    }

    let mut entries = Vec::new();
    for (key, value) in keys.into_iter().zip(values) {
        if matches!(key, Value::None) {
            return Err(ast_literal_eval_malformed_value(node));
        }
        entries.push((ast_literal_eval_node(&key)?, ast_literal_eval_node(&value)?));
    }

    build_dict(entries).map_err(|message| format!("ValueError: {message}"))
}

fn ast_literal_eval_unary(node: &Value) -> Result<Value, String> {
    let op = ast_required_field(node, "op")?;
    let operand = ast_required_field(node, "operand")?;
    match ast_node_kind(&op) {
        Some("UAdd") => ast_literal_number_constant(&operand)
            .ok_or_else(|| ast_literal_eval_malformed_value(node)),
        Some("USub") => {
            let value = ast_literal_number_constant(&operand)
                .ok_or_else(|| ast_literal_eval_malformed_value(node))?;
            negate_value(value).map_err(|message| format!("ValueError: {message}"))
        }
        _ => Err(ast_literal_eval_malformed_value(node)),
    }
}

fn ast_literal_eval_complex_binop(node: &Value) -> Result<Value, String> {
    let op = ast_required_field(node, "op")?;
    let left = ast_required_field(node, "left")?;
    let right = ast_required_field(node, "right")?;
    let left = ast_literal_signed_real_number(&left)
        .ok_or_else(|| ast_literal_eval_malformed_value(node))?;
    let right = ast_literal_complex_constant(&right)
        .ok_or_else(|| ast_literal_eval_malformed_value(node))?;

    match ast_node_kind(&op) {
        Some("Add") => add_values(left, right).map_err(|message| format!("ValueError: {message}")),
        Some("Sub") => {
            subtract_values(left, right).map_err(|message| format!("ValueError: {message}"))
        }
        _ => Err(ast_literal_eval_malformed_value(node)),
    }
}

fn ast_literal_eval_call(node: &Value) -> Result<Value, String> {
    let func = ast_required_field(node, "func")?;
    let args = ast_list_field(node, "args")?;
    let keywords = ast_list_field(node, "keywords")?;
    if args.is_empty()
        && keywords.is_empty()
        && matches!(ast_node_kind(&func), Some("Name"))
        && matches!(ast_required_field(&func, "id")?, Value::String(name) if name == "set")
    {
        return Ok(set_value(Vec::new()));
    }

    Err(ast_literal_eval_malformed_value(node))
}

fn ast_required_field(node: &Value, field: &str) -> Result<Value, String> {
    let Value::AstNode { attrs, .. } = node else {
        return Err(ast_literal_eval_malformed_value(node));
    };
    lookup_string_key(attrs, field).ok_or_else(|| ast_literal_eval_malformed_value(node))
}

fn ast_list_field(node: &Value, field: &str) -> Result<Vec<Value>, String> {
    match ast_required_field(node, field)? {
        Value::List(items) => Ok(items.borrow().clone()),
        Value::Tuple(items) => Ok(items.as_ref().clone()),
        _ => Err(ast_literal_eval_malformed_value(node)),
    }
}

fn ast_node_kind(node: &Value) -> Option<&str> {
    match node {
        Value::AstNode { kind, .. } => Some(kind.as_str()),
        _ => None,
    }
}

fn ast_literal_number_constant(node: &Value) -> Option<Value> {
    match node {
        Value::AstNode { kind, attrs, .. } if kind == "Constant" => {
            match lookup_string_key(attrs, "value")? {
                value @ (Value::Number(_)
                | Value::BigInt(_)
                | Value::Float(_)
                | Value::Complex { .. }) => Some(value),
                _ => None,
            }
        }
        _ => None,
    }
}

fn ast_literal_signed_real_number(node: &Value) -> Option<Value> {
    match node {
        Value::AstNode { kind, attrs, .. } if kind == "Constant" => {
            match lookup_string_key(attrs, "value")? {
                value @ (Value::Number(_) | Value::BigInt(_) | Value::Float(_)) => Some(value),
                _ => None,
            }
        }
        Value::AstNode { kind, attrs, .. } if kind == "UnaryOp" => {
            let op = lookup_string_key(attrs, "op")?;
            let operand = lookup_string_key(attrs, "operand")?;
            let value = ast_literal_signed_real_number(&operand)?;
            match ast_node_kind(&op) {
                Some("UAdd") => Some(value),
                Some("USub") => negate_value(value).ok(),
                _ => None,
            }
        }
        _ => None,
    }
}

fn ast_literal_complex_constant(node: &Value) -> Option<Value> {
    match node {
        Value::AstNode { kind, attrs, .. } if kind == "Constant" => {
            match lookup_string_key(attrs, "value")? {
                value @ Value::Complex { .. } => Some(value),
                _ => None,
            }
        }
        _ => None,
    }
}

fn ast_literal_eval_malformed_value(value: &Value) -> String {
    let mut message = "ValueError: malformed node or string".to_string();
    if let Value::AstNode { attrs, .. } = value
        && let Some(lineno) = lookup_string_key(attrs, "lineno").and_then(|value| match value {
            Value::Number(value) if value != 0 => Some(value),
            Value::Bool(value) if value => Some(bool_as_i64(value)),
            _ => None,
        })
    {
        message.push_str(&format!(" on line {lineno}"));
    }
    format!("{message}: {}", repr_value(value))
}

fn bind_ast_helper_node_arg(
    function_name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if args.len() > 1 {
        return Err(format!(
            "TypeError: {function_name}() takes 1 positional argument but {} were given",
            args.len()
        ));
    }

    let mut node = args.into_iter().next();
    for (keyword, value) in keywords {
        if keyword != "node" {
            return Err(format!(
                "TypeError: {function_name}() got an unexpected keyword argument '{keyword}'"
            ));
        }
        if node.is_some() {
            return Err(format!(
                "TypeError: {function_name}() got multiple values for argument 'node'"
            ));
        }
        node = Some(value);
    }

    let node = node
        .ok_or_else(|| format!("TypeError: {function_name}() missing required argument 'node'"))?;
    ensure_ast_node_fields(&node)?;
    Ok(node)
}

fn bind_ast_visitor_method_args(
    function_name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Value), String> {
    let mut values = bind_ast_positional_keyword_args(
        function_name,
        ["self", "node"].as_slice(),
        args,
        keywords,
    )?;
    let receiver = values[0]
        .take()
        .ok_or_else(|| format!("TypeError: {function_name}() missing required argument 'self'"))?;
    let node = values[1]
        .take()
        .ok_or_else(|| format!("TypeError: {function_name}() missing required argument 'node'"))?;
    ensure_ast_node_fields(&node)?;
    Ok((receiver, node))
}

fn ensure_ast_node_fields(node: &Value) -> Result<(), String> {
    if matches!(node, Value::AstNode { .. }) {
        return Ok(());
    }

    Err(format!(
        "AttributeError: '{}' object has no attribute '_fields'",
        type_name(node)
    ))
}

fn ast_iter_field_pairs(node: &Value) -> Result<Vec<(String, Value)>, String> {
    let Value::AstNode { fields, attrs, .. } = node else {
        ensure_ast_node_fields(node)?;
        unreachable!("ensure_ast_node_fields returns an error for non-AST values")
    };

    Ok(fields
        .iter()
        .filter_map(|field| lookup_string_key(attrs, field).map(|value| (field.clone(), value)))
        .collect())
}

fn ast_child_nodes(node: &Value) -> Result<Vec<Value>, String> {
    let mut children = Vec::new();
    for (_, value) in ast_iter_field_pairs(node)? {
        collect_ast_child_nodes(value, &mut children);
    }
    Ok(children)
}

fn collect_ast_child_nodes(value: Value, children: &mut Vec<Value>) {
    match value {
        Value::AstNode { .. } => children.push(value),
        Value::List(items) => {
            for item in items.borrow().iter() {
                if matches!(item, Value::AstNode { .. }) {
                    children.push(item.clone());
                }
            }
        }
        Value::Tuple(items) => {
            for item in items.iter() {
                if matches!(item, Value::AstNode { .. }) {
                    children.push(item.clone());
                }
            }
        }
        _ => {}
    }
}

fn compile_eval_argument(value: Value) -> Result<Value, String> {
    match value {
        code @ Value::CodeObject { .. } => Ok(code),
        Value::String(source) => {
            compile_code_object(Value::String(source), "<string>".to_string(), "eval")
        }
        Value::Bytes(bytes) => {
            compile_code_object(Value::Bytes(bytes), "<string>".to_string(), "eval")
        }
        Value::ByteArray(bytes) => {
            compile_code_object(Value::ByteArray(bytes), "<string>".to_string(), "eval")
        }
        value => Err(format!(
            "TypeError: eval() arg 1 must be a string or code object, not {}",
            type_name(&value)
        )),
    }
}

fn compile_exec_argument(value: Value) -> Result<Value, String> {
    match value {
        code @ Value::CodeObject { .. } => Ok(code),
        Value::String(source) => {
            compile_code_object(Value::String(source), "<string>".to_string(), "exec")
        }
        Value::Bytes(bytes) => {
            compile_code_object(Value::Bytes(bytes), "<string>".to_string(), "exec")
        }
        Value::ByteArray(bytes) => {
            compile_code_object(Value::ByteArray(bytes), "<string>".to_string(), "exec")
        }
        value => Err(format!(
            "TypeError: exec() arg 1 must be a string or code object, not {}",
            type_name(&value)
        )),
    }
}

#[derive(Clone)]
struct ExecScopeWriteback {
    scope: Scope,
    dict: DictRef,
}

fn bind_eval_exec_args(
    function_name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Vec<Option<Value>>, String> {
    let mut values = vec![None, None, None];
    let names = ["source", "globals", "locals"];
    if args.len() > values.len() {
        return Err(format!(
            "TypeError: {function_name}() expected 1 to 3 arguments, got {}",
            args.len()
        ));
    }
    for (index, value) in args.into_iter().enumerate() {
        values[index] = Some(value);
    }
    for (name, value) in keywords {
        let Some(index) = names.iter().position(|candidate| candidate == &name) else {
            return Err(format!(
                "TypeError: {function_name}() got an unexpected keyword argument '{name}'"
            ));
        };
        if values[index].is_some() {
            return Err(format!(
                "TypeError: {function_name}() got multiple values for argument '{name}'"
            ));
        }
        values[index] = Some(value);
    }
    if values[0].is_none() {
        return Err(format!(
            "TypeError: {function_name}() missing required argument 'source'"
        ));
    }
    Ok(values)
}

fn bind_import_args(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Vec<Option<Value>>, String> {
    let mut values = vec![None, None, None, None, None];
    let names = ["name", "globals", "locals", "fromlist", "level"];
    if args.len() > values.len() {
        return Err(format!(
            "TypeError: __import__() expected at most 5 arguments, got {}",
            args.len()
        ));
    }
    for (index, value) in args.into_iter().enumerate() {
        values[index] = Some(value);
    }
    for (name, value) in keywords {
        let Some(index) = names.iter().position(|candidate| candidate == &name) else {
            return Err(format!(
                "TypeError: __import__() got an unexpected keyword argument '{name}'"
            ));
        };
        if values[index].is_some() {
            return Err(format!(
                "TypeError: __import__() got multiple values for argument '{name}'"
            ));
        }
        values[index] = Some(value);
    }
    if values[0].is_none() {
        return Err("TypeError: __import__() missing required argument 'name'".to_string());
    }
    Ok(values)
}

fn import_returns_root(fromlist: &Value) -> bool {
    match fromlist {
        Value::None => true,
        Value::Tuple(items) => items.is_empty(),
        Value::List(items) => items.borrow().is_empty(),
        _ => false,
    }
}

fn eval_scopes_from_optional_args(
    globals_arg: Option<Value>,
    locals_arg: Option<Value>,
    default_globals: Scope,
    default_locals: Scope,
    default_is_module: bool,
) -> Result<(Scope, Scope, Vec<ExecScopeWriteback>, bool), String> {
    match (globals_arg, locals_arg) {
        (None, None) => Ok((
            default_globals,
            default_locals,
            Vec::new(),
            default_is_module,
        )),
        (Some(globals), None) => {
            let (globals, writeback) = eval_scope_argument(&globals, "globals", true)?;
            Ok((
                globals.clone(),
                globals,
                writeback.into_iter().collect(),
                true,
            ))
        }
        (None, Some(locals)) => {
            let (locals, writeback) = eval_scope_argument(&locals, "locals", false)?;
            Ok((
                default_globals,
                locals,
                writeback.into_iter().collect(),
                false,
            ))
        }
        (Some(globals), Some(locals)) => {
            if same_scope_mapping(&globals, &locals) {
                let (scope, writeback) = eval_scope_argument(&globals, "globals", true)?;
                return Ok((scope.clone(), scope, writeback.into_iter().collect(), false));
            }

            let (globals, global_writeback) = eval_scope_argument(&globals, "globals", true)?;
            let (locals, local_writeback) = eval_scope_argument(&locals, "locals", false)?;
            let mut writebacks = Vec::new();
            push_unique_writeback(&mut writebacks, global_writeback);
            push_unique_writeback(&mut writebacks, local_writeback);
            Ok((globals, locals, writebacks, false))
        }
    }
}

fn eval_scope_argument(
    value: &Value,
    role: &str,
    inject_builtins: bool,
) -> Result<(Scope, Option<ExecScopeWriteback>), String> {
    match value {
        Value::ScopeDict(scope) => {
            if inject_builtins {
                ensure_scope_has_builtins(scope);
            }
            Ok((scope.clone(), None))
        }
        Value::Dict(entries) => {
            if inject_builtins {
                ensure_dict_has_builtins(entries)?;
            }
            let scope = dict_to_scope(entries);
            Ok((
                scope.clone(),
                Some(ExecScopeWriteback {
                    scope,
                    dict: entries.clone(),
                }),
            ))
        }
        value if dict_subclass_entries(value).is_some() => {
            let entries =
                dict_subclass_entries(value).expect("dict subclass entries exist after guard");
            if inject_builtins {
                ensure_dict_has_builtins(&entries)?;
            }
            let scope = dict_subclass_to_scope(value, &entries);
            Ok((
                scope.clone(),
                Some(ExecScopeWriteback {
                    scope,
                    dict: entries.clone(),
                }),
            ))
        }
        value => Err(format!(
            "TypeError: {role} must be a dict, not {}",
            type_name(value)
        )),
    }
}

fn exec_scopes_from_optional_args(
    globals_arg: Option<Value>,
    locals_arg: Option<Value>,
    default_globals: Scope,
    default_locals: Scope,
    default_is_module: bool,
) -> Result<(Scope, Scope, Vec<ExecScopeWriteback>, bool), String> {
    match (globals_arg, locals_arg) {
        (None, None) => Ok((
            default_globals,
            default_locals,
            Vec::new(),
            default_is_module,
        )),
        (Some(globals), None) => {
            let (scope, writeback) = exec_scope_argument(&globals, "globals", true)?;
            let writebacks = writeback.into_iter().collect();
            Ok((scope.clone(), scope, writebacks, true))
        }
        (None, Some(locals)) => {
            let (local_scope, local_writeback) = exec_scope_argument(&locals, "locals", false)?;
            let writebacks = local_writeback.into_iter().collect();
            Ok((default_globals, local_scope, writebacks, false))
        }
        (Some(globals), Some(locals)) => {
            if same_scope_mapping(&globals, &locals) {
                let (scope, writeback) = exec_scope_argument(&globals, "globals", true)?;
                return Ok((scope.clone(), scope, writeback.into_iter().collect(), false));
            }

            let (global_scope, global_writeback) = exec_scope_argument(&globals, "globals", true)?;
            let (local_scope, local_writeback) = exec_scope_argument(&locals, "locals", false)?;
            let mut writebacks = Vec::new();
            push_unique_writeback(&mut writebacks, global_writeback);
            push_unique_writeback(&mut writebacks, local_writeback);
            Ok((global_scope, local_scope, writebacks, false))
        }
    }
}

fn exec_scope_argument(
    value: &Value,
    role: &str,
    inject_builtins: bool,
) -> Result<(Scope, Option<ExecScopeWriteback>), String> {
    match value {
        Value::ScopeDict(scope) => {
            if inject_builtins {
                ensure_scope_has_builtins(scope);
            }
            Ok((scope.clone(), None))
        }
        Value::Dict(entries) => {
            if inject_builtins {
                ensure_dict_has_builtins(entries)?;
            }
            let scope = dict_to_scope(entries);
            Ok((
                scope.clone(),
                Some(ExecScopeWriteback {
                    scope,
                    dict: entries.clone(),
                }),
            ))
        }
        value if dict_subclass_entries(value).is_some() => {
            let entries =
                dict_subclass_entries(value).expect("dict subclass entries exist after guard");
            if inject_builtins {
                ensure_dict_has_builtins(&entries)?;
            }
            let scope = dict_subclass_to_scope(value, &entries);
            Ok((
                scope.clone(),
                Some(ExecScopeWriteback {
                    scope,
                    dict: entries.clone(),
                }),
            ))
        }
        value => Err(format!(
            "TypeError: {role} must be a dict, not {}",
            type_name(value)
        )),
    }
}

fn same_scope_mapping(left: &Value, right: &Value) -> bool {
    match (left, right) {
        (Value::ScopeDict(left), Value::ScopeDict(right)) => Rc::ptr_eq(left, right),
        (Value::Dict(left), Value::Dict(right)) => Rc::ptr_eq(left, right),
        _ => match (dict_subclass_entries(left), dict_subclass_entries(right)) {
            (Some(left), Some(right)) => Rc::ptr_eq(&left, &right),
            _ => false,
        },
    }
}

fn push_unique_writeback(
    writebacks: &mut Vec<ExecScopeWriteback>,
    writeback: Option<ExecScopeWriteback>,
) {
    let Some(writeback) = writeback else {
        return;
    };
    if !writebacks
        .iter()
        .any(|existing| Rc::ptr_eq(&existing.dict, &writeback.dict))
    {
        writebacks.push(writeback);
    }
}

impl Vm {
    fn lookup_builtin_mapping(
        &mut self,
        builtins: &Value,
        name: &str,
    ) -> Result<Option<Value>, String> {
        match builtins {
            Value::Dict(entries) | Value::MappingProxy { entries } => {
                Ok(lookup_string_key(entries, name))
            }
            Value::ScopeDict(scope) => Ok(scope.borrow().get(name).cloned()),
            value if dict_subclass_entries(value).is_some() => {
                if let Some(value) = self.lookup_custom_mapping_item(value, name)? {
                    return Ok(Some(value));
                }
                Ok(lookup_string_key(
                    &dict_subclass_entries(value).expect("dict subclass entries exist after guard"),
                    name,
                ))
            }
            value => Err(format!(
                "TypeError: __builtins__ must be a dict, not {}",
                type_name(value)
            )),
        }
    }
}

fn import_root_name(name: &str) -> &str {
    name.split('.')
        .next()
        .expect("import name always has at least one part")
}

fn lookup_string_key(entries: &DictRef, name: &str) -> Option<Value> {
    entries.borrow().iter().find_map(|(key, value)| match key {
        Value::String(key) if key == name => Some(value.clone()),
        _ => None,
    })
}

fn default_builtin_value(name: &str) -> Option<Value> {
    if name == "Ellipsis" {
        Some(Value::Ellipsis)
    } else if name == "NotImplemented" {
        Some(Value::NotImplemented)
    } else if is_builtin_name(name) {
        Some(Value::Builtin(name.to_string()))
    } else {
        None
    }
}

