fn dict_subclass_entries(value: &Value) -> Option<DictRef> {
    let Value::Instance {
        fields,
        class_bases,
        ..
    } = value
    else {
        return None;
    };
    if !class_bases_include_builtin(class_bases, "dict") {
        return None;
    }
    match fields.borrow().get(DICT_SUBCLASS_STORAGE_FIELD).cloned() {
        Some(Value::Dict(entries)) => Some(entries),
        _ => None,
    }
}

fn set_subclass_items(value: &Value) -> Option<SetRef> {
    let Value::Instance {
        fields,
        class_bases,
        ..
    } = value
    else {
        return None;
    };
    if !class_bases_include_builtin(class_bases, "set") {
        return None;
    }
    match fields.borrow().get(SET_SUBCLASS_STORAGE_FIELD).cloned() {
        Some(Value::Set(items)) => Some(items),
        _ => None,
    }
}

fn frozen_set_subclass_items(value: &Value) -> Option<FrozenSetRef> {
    let Value::Instance {
        fields,
        class_bases,
        ..
    } = value
    else {
        return None;
    };
    if !class_bases_include_builtin(class_bases, "frozenset") {
        return None;
    }
    match fields
        .borrow()
        .get(FROZEN_SET_SUBCLASS_STORAGE_FIELD)
        .cloned()
    {
        Some(Value::FrozenSet(items)) => Some(items),
        _ => None,
    }
}

fn is_simple_namespace_value(value: &Value) -> bool {
    match value {
        Value::SimpleNamespace { .. } => true,
        Value::Instance { class_bases, .. } => {
            class_bases_include_builtin(class_bases, "SimpleNamespace")
        }
        _ => false,
    }
}

fn dict_subclass_method(receiver: Value, name: &str) -> Option<Value> {
    if dict_subclass_entries(&receiver).is_some()
        && matches!(
            name,
            "clear"
                | "copy"
                | "get"
                | "items"
                | "keys"
                | "pop"
                | "popitem"
                | "setdefault"
                | "update"
                | "values"
                | "__contains__"
                | "__delitem__"
                | "__getitem__"
                | "__len__"
                | "__iter__"
                | "__setitem__"
        )
    {
        Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("dict.{name}"))),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        })
    } else {
        None
    }
}

fn set_subclass_method(receiver: Value, name: &str) -> Option<Value> {
    if set_subclass_items(&receiver).is_some() && is_builtin_set_type_method("set", name) {
        Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("set.{name}"))),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        })
    } else {
        None
    }
}

fn frozen_set_subclass_method(receiver: Value, name: &str) -> Option<Value> {
    if frozen_set_subclass_items(&receiver).is_some()
        && is_builtin_set_type_method("frozenset", name)
    {
        Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("frozenset.{name}"))),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        })
    } else {
        None
    }
}

fn mappingproxy_order_type_error(left: &Value, right: &Value, op: &str) -> Option<String> {
    if is_mapping_proxy_value(left) || is_mapping_proxy_value(right) {
        Some(format!(
            "TypeError: '{op}' not supported between instances of '{}' and '{}'",
            type_name(left),
            type_name(right)
        ))
    } else {
        None
    }
}

