fn instance_has_callable_special_method(value: &Value, name: &str) -> bool {
    instance_special_method(value, name)
        .as_ref()
        .is_some_and(is_callable_value)
}

fn instance_special_method_is_none(value: &Value, name: &str) -> bool {
    let Value::Instance {
        class_attrs,
        class_bases,
        ..
    } = value
    else {
        return false;
    };

    class_special_method_is_none(class_attrs, class_bases, name)
}

fn instance_abc_bases_include(value: &Value, target_name: &str) -> bool {
    let Value::Instance { class_bases, .. } = value else {
        return false;
    };

    class_bases
        .iter()
        .any(|base| class_is_subclass_of_builtin(base, target_name))
}

fn instance_class_explicitly_inherits_builtin(value: &Value, target_name: &str) -> bool {
    let Value::Instance { class_bases, .. } = value else {
        return false;
    };

    class_bases_explicitly_include_builtin(class_bases, target_name)
}

fn sequence_abc_mixin_method(bases: &[Value], receiver: Value, name: &str) -> Option<Value> {
    if !class_bases_explicitly_include_builtin(bases, "Sequence")
        && !class_bases_explicitly_include_builtin(bases, "MutableSequence")
    {
        return None;
    }
    if !matches!(
        name,
        "__iter__" | "__contains__" | "__reversed__" | "index" | "count"
    ) {
        return None;
    }

    Some(Value::BoundMethod {
        function: Box::new(Value::Builtin(format!("Sequence.{name}"))),
        receiver: Box::new(receiver),
        identity: Rc::new(()),
    })
}

fn mutable_sequence_abc_mixin_method(
    bases: &[Value],
    receiver: Value,
    name: &str,
) -> Option<Value> {
    if !class_bases_explicitly_include_builtin(bases, "MutableSequence") {
        return None;
    }
    if !matches!(
        name,
        "append" | "clear" | "reverse" | "extend" | "pop" | "remove" | "__iadd__"
    ) {
        return None;
    }

    Some(Value::BoundMethod {
        function: Box::new(Value::Builtin(format!("MutableSequence.{name}"))),
        receiver: Box::new(receiver),
        identity: Rc::new(()),
    })
}

fn ast_node_visitor_mixin_method(bases: &[Value], receiver: Value, name: &str) -> Option<Value> {
    if class_bases_explicitly_include_builtin(bases, "NodeTransformer")
        && matches!(name, "visit" | "generic_visit")
    {
        let method = if name == "generic_visit" {
            "NodeTransformer.generic_visit"
        } else {
            "NodeVisitor.visit"
        };
        return Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(method.to_string())),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        });
    }

    if class_bases_explicitly_include_builtin(bases, "NodeVisitor")
        && matches!(name, "visit" | "generic_visit")
    {
        return Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("NodeVisitor.{name}"))),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        });
    }

    None
}

fn mapping_abc_mixin_method(bases: &[Value], receiver: Value, name: &str) -> Option<Value> {
    if !class_bases_include_builtin(bases, "Mapping")
        && !class_bases_include_builtin(bases, "MutableMapping")
    {
        return None;
    }
    if !matches!(
        name,
        "get" | "__contains__" | "keys" | "items" | "values" | "__eq__"
    ) {
        return None;
    }

    Some(Value::BoundMethod {
        function: Box::new(Value::Builtin(format!("Mapping.{name}"))),
        receiver: Box::new(receiver),
        identity: Rc::new(()),
    })
}

