fn sequence_abc_bind_one_value_arg(
    method: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Value), String> {
    let mut args = args.into_iter();
    let Some(receiver) = args.next() else {
        return Err(format!("{method}() missing required argument 'self'"));
    };

    let rest = args.collect::<Vec<_>>();
    if rest.len() > 1 {
        return Err(format!(
            "{method}() expected 1 argument, got {}",
            rest.len()
        ));
    }

    let mut value = rest.into_iter().next();
    for (name, keyword_value) in keywords {
        match name.as_str() {
            "value" => {
                if value.is_some() {
                    return Err(format!(
                        "{method}() got multiple values for argument 'value'"
                    ));
                }
                value = Some(keyword_value);
            }
            _ => {
                return Err(format!(
                    "{method}() got an unexpected keyword argument '{name}'"
                ));
            }
        }
    }

    let value = value.ok_or_else(|| format!("{method}() missing required argument 'value'"))?;
    Ok((receiver, value))
}

fn sequence_abc_bind_index_args(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Value, Value, Option<Value>), String> {
    let mut args = args.into_iter();
    let Some(receiver) = args.next() else {
        return Err("index() missing required argument 'self'".to_string());
    };

    let rest = args.collect::<Vec<_>>();
    if rest.len() > 3 {
        return Err(format!(
            "index() expected at most 3 arguments, got {}",
            rest.len()
        ));
    }

    let mut value = None;
    let mut start = None;
    let mut stop = None;
    for (index, arg) in rest.into_iter().enumerate() {
        match index {
            0 => value = Some(arg),
            1 => start = Some(arg),
            2 => stop = Some(arg),
            _ => unreachable!("index() positional arity is checked above"),
        }
    }

    for (name, keyword_value) in keywords {
        match name.as_str() {
            "value" => {
                if value.is_some() {
                    return Err("index() got multiple values for argument 'value'".to_string());
                }
                value = Some(keyword_value);
            }
            "start" => {
                if start.is_some() {
                    return Err("index() got multiple values for argument 'start'".to_string());
                }
                start = Some(keyword_value);
            }
            "stop" => {
                if stop.is_some() {
                    return Err("index() got multiple values for argument 'stop'".to_string());
                }
                stop = Some(keyword_value);
            }
            _ => {
                return Err(format!(
                    "index() got an unexpected keyword argument '{name}'"
                ));
            }
        }
    }

    let value = value.ok_or_else(|| "index() missing required argument 'value'".to_string())?;
    Ok((receiver, value, start.unwrap_or(Value::Number(0)), stop))
}

