#[derive(Default)]
struct MinMaxOptions {
    key: Option<Value>,
    default: Option<Value>,
}

#[derive(Default)]
struct SortedOptions {
    key: Option<Value>,
    reverse: Option<bool>,
}

#[derive(Clone)]
struct SortItem {
    value: Value,
    key: Value,
}

fn minmax_options(name: &str, keywords: Vec<(String, Value)>) -> Result<MinMaxOptions, String> {
    let mut options = MinMaxOptions::default();
    for (keyword, value) in keywords {
        match keyword.as_str() {
            "key" => {
                if options.key.is_some() {
                    return Err(format!(
                        "{name}() got multiple values for keyword argument 'key'"
                    ));
                }
                options.key = Some(value);
            }
            "default" => {
                if options.default.is_some() {
                    return Err(format!(
                        "{name}() got multiple values for keyword argument 'default'"
                    ));
                }
                options.default = Some(value);
            }
            _ => {
                return Err(format!(
                    "'{keyword}' is an invalid keyword argument for {name}()"
                ));
            }
        }
    }
    Ok(options)
}

fn sorted_options(
    positional_count: usize,
    keywords: Vec<(String, Value)>,
) -> Result<SortedOptions, String> {
    let mut options = SortedOptions::default();
    for (keyword, value) in keywords {
        match keyword.as_str() {
            "key" => {
                if options.key.is_some() {
                    return Err(
                        "sorted() got multiple values for keyword argument 'key'".to_string()
                    );
                }
                options.key = Some(value);
            }
            "reverse" => {
                if options.reverse.is_some() {
                    return Err(
                        "sorted() got multiple values for keyword argument 'reverse'".to_string(),
                    );
                }
                options.reverse = Some(sorted_reverse_option(value)?);
            }
            "iterable" if positional_count == 0 => {
                return Err("TypeError: sorted expected 1 argument, got 0".to_string());
            }
            _ => {
                return Err(format!(
                    "TypeError: '{keyword}' is an invalid keyword argument for sort()"
                ));
            }
        }
    }
    Ok(options)
}

fn list_sort_options(keywords: Vec<(String, Value)>) -> Result<SortedOptions, String> {
    let mut options = SortedOptions::default();
    for (keyword, value) in keywords {
        match keyword.as_str() {
            "key" => {
                if options.key.is_some() {
                    return Err("sort() got multiple values for keyword argument 'key'".to_string());
                }
                options.key = Some(value);
            }
            "reverse" => {
                if options.reverse.is_some() {
                    return Err(
                        "sort() got multiple values for keyword argument 'reverse'".to_string()
                    );
                }
                options.reverse = Some(sorted_reverse_option(value)?);
            }
            _ => {
                return Err(format!(
                    "'{keyword}' is an invalid keyword argument for sort()"
                ));
            }
        }
    }
    Ok(options)
}

fn sorted_reverse_option(value: Value) -> Result<bool, String> {
    match value {
        Value::Bool(value) => Ok(value),
        Value::Number(value) => Ok(value != 0),
        Value::BigInt(value) => Ok(!value.is_zero()),
        Value::Float(_) => Err("integer argument expected, got float".to_string()),
        value => Err(format!(
            "an integer is required (got type {})",
            type_name(&value)
        )),
    }
}

fn sort_items_by_key(items: &mut [SortItem], reverse: bool) -> Result<(), String> {
    for index in 1..items.len() {
        let item = items[index].clone();
        let mut insertion_index = index;

        while insertion_index > 0 {
            let ordering =
                compare_values(item.key.clone(), items[insertion_index - 1].key.clone())?;
            let should_move_left = if reverse {
                ordering.is_gt()
            } else {
                ordering.is_lt()
            };
            if !should_move_left {
                break;
            }

            items[insertion_index] = items[insertion_index - 1].clone();
            insertion_index -= 1;
        }

        items[insertion_index] = item;
    }

    Ok(())
}

fn reject_sum_start(value: &Value) -> Result<(), String> {
    match value {
        Value::String(_) => Err("sum() can't sum strings [use ''.join(seq) instead]".to_string()),
        Value::Bytes(_) => Err("sum() can't sum bytes [use b''.join(seq) instead]".to_string()),
        Value::ByteArray(_) => {
            Err("sum() can't sum bytearray [use b''.join(seq) instead]".to_string())
        }
        _ => Ok(()),
    }
}

fn call_id(args: Vec<Value>) -> Result<Value, String> {
    let [value] = args.as_slice() else {
        return Err(format!(
            "TypeError: id() expected 1 argument, got {}",
            args.len()
        ));
    };

    Ok(identity_value(value))
}

fn call_divmod(args: Vec<Value>) -> Result<Value, String> {
    let [left, right] = args.as_slice() else {
        return Err(format!(
            "TypeError: divmod expected 2 arguments, got {}",
            args.len()
        ));
    };

    let quotient = floor_divide_values(left.clone(), right.clone())
        .map_err(|message| divmod_error_message(&message, left.clone(), right.clone()))?;
    let remainder = modulo_values(left.clone(), right.clone())
        .map_err(|message| divmod_error_message(&message, left.clone(), right.clone()))?;
    Ok(tuple_value(vec![quotient, remainder]))
}

fn divmod_error_message(message: &str, left: Value, right: Value) -> String {
    if is_zero_division_error_message(message) || message.starts_with("TypeError: ") {
        return message.to_string();
    }
    format!(
        "TypeError: unsupported operand type(s) for divmod(): '{}' and '{}'",
        type_name(&left),
        type_name(&right)
    )
}

fn call_ord(args: Vec<Value>) -> Result<Value, String> {
    let [value] = args.as_slice() else {
        return Err(format!(
            "TypeError: ord() expected 1 argument, got {}",
            args.len()
        ));
    };

    let codepoint = match value {
        Value::String(value) => {
            let mut chars = value.chars();
            let Some(ch) = chars.next() else {
                return Err(
                    "TypeError: ord() expected a character, but string of length 0 found"
                        .to_string(),
                );
            };
            if chars.next().is_some() {
                return Err(format!(
                    "TypeError: ord() expected a character, but string of length {} found",
                    value.chars().count()
                ));
            }
            ch as u32
        }
        Value::Bytes(value) | Value::ByteArray(value) => {
            let [byte] = value.as_slice() else {
                return Err(format!(
                    "TypeError: ord() expected a character, but string of length {} found",
                    value.len()
                ));
            };
            u32::from(*byte)
        }
        value => {
            return Err(format!(
                "TypeError: ord() expected string of length 1, but {} found",
                type_name(value)
            ));
        }
    };

    Ok(Value::Number(i64::from(codepoint)))
}

fn call_template_convert(args: Vec<Value>) -> Result<Value, String> {
    let [value, conversion] = args.as_slice() else {
        return Err(format!(
            "TypeError: convert() expected 2 arguments, got {}",
            args.len()
        ));
    };

    match conversion {
        Value::None => Ok(value.clone()),
        Value::String(conversion) if conversion == "r" => {
            Ok(Value::String(repr_value_checked(value)?))
        }
        Value::String(conversion) if conversion == "s" => {
            Ok(Value::String(str_value_checked(value)?))
        }
        Value::String(conversion) if conversion == "a" => {
            Ok(Value::String(ascii_repr_value_checked(value)?))
        }
        conversion => Err(format!(
            "ValueError: invalid conversion specifier: {conversion}"
        )),
    }
}

fn call_template_constructor(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if !keywords.is_empty() {
        return Err("TypeError: Template.__new__ only accepts *args arguments".to_string());
    }

    let mut strings: Vec<String> = Vec::new();
    let mut interpolations: Vec<TemplateInterpolation> = Vec::new();
    let mut last_was_str = false;

    for arg in args {
        match arg {
            Value::String(value) => {
                if last_was_str {
                    strings
                        .last_mut()
                        .expect("template constructor has a previous string")
                        .push_str(&value);
                } else {
                    strings.push(value);
                }
                last_was_str = true;
            }
            Value::TemplateInterpolation(interpolation) => {
                if !last_was_str {
                    strings.push(String::new());
                }
                interpolations.push(interpolation);
                last_was_str = false;
            }
            value => {
                return Err(format!(
                    "TypeError: Template.__new__ *args need to be of type 'str' or 'Interpolation', got {}",
                    type_name(&value)
                ));
            }
        }
    }

    if !last_was_str {
        strings.push(String::new());
    }

    Ok(Value::Template {
        strings,
        interpolations,
    })
}

fn call_interpolation_constructor(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if args.len() > 4 {
        return Err(format!(
            "TypeError: Interpolation() expected at most 4 arguments, got {}",
            args.len()
        ));
    }

    let mut values = vec![None, None, None, None];
    for (index, value) in args.into_iter().enumerate() {
        values[index] = Some(value);
    }

    for (name, value) in keywords {
        let Some(index) = interpolation_argument_index(&name) else {
            return Err(format!(
                "TypeError: Interpolation() got an unexpected keyword argument '{name}'"
            ));
        };
        if values[index].is_some() {
            return Err(format!(
                "TypeError: Interpolation() got multiple values for argument '{name}'"
            ));
        }
        values[index] = Some(value);
    }

    let value = values[0].take().ok_or_else(|| {
        "TypeError: Interpolation() missing required argument 'value'".to_string()
    })?;
    let expression = template_string_argument(
        values[1]
            .take()
            .unwrap_or_else(|| Value::String(String::new())),
        "expression",
    )?;
    let conversion = template_conversion_argument(values[2].take().unwrap_or(Value::None))?;
    let format_spec = template_string_argument(
        values[3]
            .take()
            .unwrap_or_else(|| Value::String(String::new())),
        "format_spec",
    )?;

    Ok(Value::TemplateInterpolation(TemplateInterpolation {
        value: Box::new(value),
        expression,
        conversion,
        format_spec,
    }))
}

fn interpolation_argument_index(name: &str) -> Option<usize> {
    match name {
        "value" => Some(0),
        "expression" => Some(1),
        "conversion" => Some(2),
        "format_spec" => Some(3),
        _ => None,
    }
}

fn template_string_argument(value: Value, name: &str) -> Result<String, String> {
    match value {
        Value::String(value) => Ok(value),
        value => Err(format!(
            "TypeError: Interpolation() argument '{name}' must be str, not {}",
            type_name(&value)
        )),
    }
}

fn template_conversion_argument(value: Value) -> Result<Option<String>, String> {
    match value {
        Value::None => Ok(None),
        Value::String(value) if matches!(value.as_str(), "a" | "r" | "s") => Ok(Some(value)),
        Value::String(_) => Err(
            "ValueError: Interpolation() argument 'conversion' must be one of 's', 'a' or 'r'"
                .to_string(),
        ),
        value => Err(format!(
            "TypeError: Interpolation() argument 'conversion' must be str, not {}",
            type_name(&value)
        )),
    }
}

fn format_prefixed_integer(value: &BigInt, prefix: &str, radix: u32) -> String {
    let digits = value.abs().to_str_radix(radix);
    if value.is_negative() {
        format!("-{prefix}{digits}")
    } else {
        format!("{prefix}{digits}")
    }
}

fn round_float_to_int(value: f64) -> Result<Value, String> {
    if value.is_nan() {
        return Err("ValueError: cannot convert float NaN to integer".to_string());
    }
    if value.is_infinite() {
        return Err("OverflowError: cannot convert float infinity to integer".to_string());
    }

    let rounded = round_ties_to_even(value);
    if rounded >= i64::MIN as f64 && rounded <= i64::MAX as f64 {
        Ok(Value::Number(rounded as i64))
    } else {
        Ok(normalize_big_int(BigInt::from(rounded as i128)))
    }
}

fn round_float_to_ndigits(value: f64, ndigits: i64) -> Result<f64, String> {
    if !value.is_finite() {
        return Ok(value);
    }
    if ndigits.abs() > 308 {
        return if ndigits > 0 {
            Ok(value)
        } else {
            Ok(value.signum() * 0.0)
        };
    }

    let factor = 10_f64.powi(ndigits.abs() as i32);
    if ndigits >= 0 {
        Ok(round_ties_to_even(value * factor) / factor)
    } else {
        Ok(round_ties_to_even(value / factor) * factor)
    }
}

fn round_ties_to_even(value: f64) -> f64 {
    let floor = value.floor();
    let fraction = value - floor;
    if fraction < 0.5 {
        floor
    } else if fraction > 0.5 {
        floor + 1.0
    } else if (floor as i128) % 2 == 0 {
        floor
    } else {
        floor + 1.0
    }
}

fn round_big_int_to_ndigits(value: BigInt, ndigits: i64) -> Value {
    if ndigits >= 0 || value.is_zero() {
        return normalize_big_int(value);
    }

    let Ok(places) = u32::try_from(-ndigits) else {
        return Value::Number(0);
    };
    if places > 1000 {
        return Value::Number(0);
    }

    let factor = BigInt::from(10).pow(places);
    let sign = if value.is_negative() { -1 } else { 1 };
    let abs_value = value.abs();
    let quotient = &abs_value / &factor;
    let remainder = &abs_value % &factor;
    let twice_remainder = &remainder * BigInt::from(2);
    let rounded_quotient = match twice_remainder.cmp(&factor) {
        Ordering::Less => quotient,
        Ordering::Greater => quotient + 1,
        Ordering::Equal if quotient.is_odd() => quotient + 1,
        Ordering::Equal => quotient,
    };
    let rounded = rounded_quotient * factor * BigInt::from(sign);
    normalize_big_int(rounded)
}

fn call_sqrt(args: Vec<Value>) -> Result<Value, String> {
    let [value] = args.as_slice() else {
        return Err(format!("sqrt() expected 1 argument, got {}", args.len()));
    };

    let value = number_as_f64(value.clone())
        .ok_or_else(|| format!("sqrt() argument must be a number, got {}", value))?;

    if value < 0.0 {
        return Err("math domain error".to_string());
    }

    Ok(Value::Float(value.sqrt()))
}

fn reversed_value(value: Value) -> Result<Value, String> {
    match value {
        Value::List(items) => Ok(shared_iterator(Value::ReverseIterator {
            items: items.borrow().clone(),
            index: 0,
        })),
        Value::Tuple(items) => Ok(shared_iterator(Value::ReverseIterator {
            items: items.as_ref().clone(),
            index: 0,
        })),
        Value::String(value) => Ok(shared_iterator(Value::ReverseIterator {
            items: value
                .chars()
                .map(|ch| Value::String(ch.to_string()))
                .collect(),
            index: 0,
        })),
        Value::Bytes(value) => Ok(shared_iterator(Value::ReverseIterator {
            items: value
                .into_iter()
                .map(|byte| Value::Number(byte as i64))
                .collect(),
            index: 0,
        })),
        Value::ByteArray(value) => Ok(shared_iterator(Value::ReverseIterator {
            items: value
                .into_iter()
                .map(|byte| Value::Number(byte as i64))
                .collect(),
            index: 0,
        })),
        Value::Range { start, stop, step } => Ok(shared_iterator(Value::ReverseIterator {
            items: range_values(start, stop, step)?
                .into_iter()
                .map(Value::Number)
                .collect(),
            index: 0,
        })),
        Value::Dict(entries) => {
            let (keys, expected_len, expected_version) = {
                let entries_ref = entries.borrow();
                (
                    entries_ref.iter().map(|(key, _)| key.clone()).collect(),
                    entries_ref.len(),
                    entries_ref.version,
                )
            };
            Ok(shared_iterator(Value::DictReverseIterator {
                kind: DictViewKind::Keys,
                entries,
                keys,
                index: 0,
                expected_len,
                expected_version,
            }))
        }
        Value::MappingProxy { entries } => {
            let (keys, expected_len, expected_version) = {
                let entries_ref = entries.borrow();
                (
                    entries_ref.iter().map(|(key, _)| key.clone()).collect(),
                    entries_ref.len(),
                    entries_ref.version,
                )
            };
            Ok(shared_iterator(Value::DictReverseIterator {
                kind: DictViewKind::Keys,
                entries,
                keys,
                index: 0,
                expected_len,
                expected_version,
            }))
        }
        Value::DictView { kind, entries } => {
            let (keys, expected_len, expected_version) = {
                let entries_ref = entries.borrow();
                (
                    entries_ref.iter().map(|(key, _)| key.clone()).collect(),
                    entries_ref.len(),
                    entries_ref.version,
                )
            };
            Ok(shared_iterator(Value::DictReverseIterator {
                kind,
                entries,
                keys,
                index: 0,
                expected_len,
                expected_version,
            }))
        }
        value => Err(format!(
            "TypeError: '{}' object is not reversible",
            type_name(&value)
        )),
    }
}

fn call_str_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    match name {
        "str.split" => return call_str_split_method(name, args, keywords, false),
        "str.rsplit" => return call_str_split_method(name, args, keywords, true),
        "str.splitlines" => return call_str_splitlines_method(name, args, keywords),
        "str.expandtabs" => return call_str_expandtabs_method(name, args, keywords),
        "str.encode" => return call_str_encode_method(name, args, keywords),
        _ => {}
    }

    if !keywords.is_empty() {
        return Err(format!(
            "{}() does not accept keyword arguments",
            method_display_name(name)
        ));
    }

    call_immutable_sequence_method(name, args)
}

fn call_immutable_sequence_method(name: &str, args: Vec<Value>) -> Result<Value, String> {
    match name {
        "str.startswith" => return call_str_prefix_suffix_method(name, args, true),
        "str.endswith" => return call_str_prefix_suffix_method(name, args, false),
        "str.find" => return call_str_find_method(name, args, false, false),
        "str.rfind" => return call_str_find_method(name, args, true, false),
        "str.index" => return call_str_find_method(name, args, false, true),
        "str.rindex" => return call_str_find_method(name, args, true, true),
        "str.count" => return call_str_count_method(name, args),
        "str.lower" => return call_str_case_method(name, args, false),
        "str.upper" => return call_str_case_method(name, args, true),
        "str.capitalize" => return call_str_transform_method(name, args, string_capitalize),
        "str.title" => return call_str_transform_method(name, args, string_title),
        "str.swapcase" => return call_str_transform_method(name, args, string_swapcase),
        "str.casefold" => return call_str_transform_method(name, args, string_casefold),
        "str.islower" => return call_str_predicate_method(name, args, string_islower),
        "str.isupper" => return call_str_predicate_method(name, args, string_isupper),
        "str.istitle" => return call_str_predicate_method(name, args, string_istitle),
        "str.isspace" => return call_str_predicate_method(name, args, string_isspace),
        "str.isalpha" => return call_str_predicate_method(name, args, string_isalpha),
        "str.isalnum" => return call_str_predicate_method(name, args, string_isalnum),
        "str.isdigit" => return call_str_predicate_method(name, args, string_isdigit),
        "str.isdecimal" => return call_str_predicate_method(name, args, string_isdecimal),
        "str.isnumeric" => return call_str_predicate_method(name, args, string_isnumeric),
        "str.isascii" => return call_str_predicate_method(name, args, string_isascii),
        "str.isidentifier" => return call_str_predicate_method(name, args, string_isidentifier),
        "str.isprintable" => return call_str_predicate_method(name, args, string_isprintable),
        "str.splitlines" => return call_str_splitlines_method(name, args, Vec::new()),
        "str.expandtabs" => return call_str_expandtabs_method(name, args, Vec::new()),
        "str.replace" => return call_str_replace_method(name, args),
        "str.removeprefix" => return call_str_remove_affix_method(name, args, true),
        "str.removesuffix" => return call_str_remove_affix_method(name, args, false),
        "str.partition" => return call_str_partition_method(name, args, false),
        "str.rpartition" => return call_str_partition_method(name, args, true),
        "str.split" => return call_str_split_method(name, args, Vec::new(), false),
        "str.rsplit" => return call_str_split_method(name, args, Vec::new(), true),
        "str.translate" => return call_str_translate_method(name, args),
        "str.encode" => return call_str_encode_method(name, args, Vec::new()),
        "bytes.decode" | "bytearray.decode" => {
            return call_bytes_decode_method(name, args, Vec::new());
        }
        "bytes.hex" | "bytearray.hex" => {
            return call_bytes_hex_method(name, args, Vec::new());
        }
        "str.strip" => return call_str_strip_method(name, args, true, true),
        "str.lstrip" => return call_str_strip_method(name, args, true, false),
        "str.rstrip" => return call_str_strip_method(name, args, false, true),
        "str.ljust" => return call_str_justify_method(name, args, JustifyMode::Left),
        "str.rjust" => return call_str_justify_method(name, args, JustifyMode::Right),
        "str.center" => return call_str_justify_method(name, args, JustifyMode::Center),
        "str.zfill" => return call_str_zfill_method(name, args),
        _ => {}
    }

    match method_display_name(name) {
        "__contains__" => {
            let [receiver, needle] = args.as_slice() else {
                return Err(format!(
                    "__contains__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(Value::Bool(contains_value(
                needle.clone(),
                receiver.clone(),
            )?))
        }
        "__getitem__" => {
            let [receiver, index] = args.as_slice() else {
                return Err(format!(
                    "__getitem__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            load_subscript(receiver.clone(), index.clone())
        }
        "__len__" => {
            let [receiver] = args.as_slice() else {
                return Err(format!(
                    "__len__() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let len = i64::try_from(value_len(receiver)?)
                .map_err(|_| "len() result is too large".to_string())?;
            Ok(Value::Number(len))
        }
        _ => Err(format!("unknown builtin: {name}")),
    }
}

fn call_str_prefix_suffix_method(
    name: &str,
    args: Vec<Value>,
    starts_with: bool,
) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if rest.is_empty() {
        return Err(format!(
            "TypeError: {method}() expected at least 1 argument, got 0"
        ));
    }
    if rest.len() > 3 {
        return Err(format!(
            "TypeError: {method}() expected at most 3 arguments, got {}",
            rest.len()
        ));
    }

    let prefixes = str_prefix_suffix_values(&rest[0], method)?;
    if prefixes.is_empty() {
        return Ok(Value::Bool(false));
    }

    let (start, stop) = string_search_bounds(&rest[1..], receiver.chars().count(), method)?;
    if start > stop {
        return Ok(Value::Bool(false));
    }
    let start = usize::try_from(start).map_err(|_| "string index out of range".to_string())?;
    let stop = usize::try_from(stop).map_err(|_| "string index out of range".to_string())?;

    let window = receiver
        .chars()
        .skip(start)
        .take(stop - start)
        .collect::<String>();
    let matched = prefixes.iter().any(|prefix| {
        if starts_with {
            window.starts_with(prefix)
        } else {
            window.ends_with(prefix)
        }
    });
    Ok(Value::Bool(matched))
}

fn call_str_find_method(
    name: &str,
    args: Vec<Value>,
    reverse: bool,
    raise_on_missing: bool,
) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if rest.is_empty() {
        return Err(format!(
            "TypeError: {method}() expected at least 1 argument, got 0"
        ));
    }
    if rest.len() > 3 {
        return Err(format!(
            "TypeError: {method}() expected at most 3 arguments, got {}",
            rest.len()
        ));
    }

    let needle = match &rest[0] {
        Value::String(value) => value,
        value => {
            return Err(format!(
                "TypeError: {method} first arg must be str, not {}",
                type_name(value)
            ));
        }
    };
    let (start, stop) = string_search_bounds(&rest[1..], receiver.chars().count(), method)?;
    match string_find_index(receiver, needle, start, stop, reverse)? {
        Some(index) => Ok(Value::Number(index)),
        None if raise_on_missing => Err("ValueError: substring not found".to_string()),
        None => Ok(Value::Number(-1)),
    }
}

fn string_find_index(
    haystack: &str,
    needle: &str,
    start: i64,
    stop: i64,
    reverse: bool,
) -> Result<Option<i64>, String> {
    if start > stop {
        return Ok(None);
    }

    let haystack_chars = haystack.chars().collect::<Vec<_>>();
    let needle_chars = needle.chars().collect::<Vec<_>>();
    let start = usize::try_from(start).map_err(|_| "string index out of range".to_string())?;
    let stop = usize::try_from(stop).map_err(|_| "string index out of range".to_string())?;

    if needle_chars.is_empty() {
        let index = if reverse { stop } else { start };
        return i64::try_from(index)
            .map(Some)
            .map_err(|_| "string index out of range".to_string());
    }

    if needle_chars.len() > stop.saturating_sub(start) {
        return Ok(None);
    }

    let last_start = stop - needle_chars.len();
    let found = if reverse {
        (start..=last_start).rev().find(|candidate| {
            haystack_chars[*candidate..*candidate + needle_chars.len()] == needle_chars
        })
    } else {
        (start..=last_start).find(|candidate| {
            haystack_chars[*candidate..*candidate + needle_chars.len()] == needle_chars
        })
    };

    found
        .map(|index| i64::try_from(index).map_err(|_| "string index out of range".to_string()))
        .transpose()
}

fn call_str_count_method(name: &str, args: Vec<Value>) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if rest.is_empty() {
        return Err(format!(
            "TypeError: {method}() expected at least 1 argument, got 0"
        ));
    }
    if rest.len() > 3 {
        return Err(format!(
            "TypeError: {method}() expected at most 3 arguments, got {}",
            rest.len()
        ));
    }

    let needle = match &rest[0] {
        Value::String(value) => value,
        value => {
            return Err(format!(
                "TypeError: {method} first arg must be str, not {}",
                type_name(value)
            ));
        }
    };
    let (start, stop) = string_search_bounds(&rest[1..], receiver.chars().count(), method)?;
    string_count_matches(receiver, needle, start, stop).map(Value::Number)
}

fn string_count_matches(
    haystack: &str,
    needle: &str,
    start: i64,
    stop: i64,
) -> Result<i64, String> {
    if start > stop {
        return Ok(0);
    }

    let haystack_chars = haystack.chars().collect::<Vec<_>>();
    let needle_chars = needle.chars().collect::<Vec<_>>();
    let start = usize::try_from(start).map_err(|_| "string index out of range".to_string())?;
    let stop = usize::try_from(stop).map_err(|_| "string index out of range".to_string())?;

    if needle_chars.is_empty() {
        let count = stop
            .checked_sub(start)
            .and_then(|count| count.checked_add(1))
            .ok_or_else(|| "string index out of range".to_string())?;
        return i64::try_from(count).map_err(|_| "string count is too large".to_string());
    }

    if needle_chars.len() > stop.saturating_sub(start) {
        return Ok(0);
    }

    let mut index = start;
    let mut count = 0usize;
    while index + needle_chars.len() <= stop {
        if haystack_chars[index..index + needle_chars.len()] == needle_chars {
            count += 1;
            index += needle_chars.len();
        } else {
            index += 1;
        }
    }

    i64::try_from(count).map_err(|_| "string count is too large".to_string())
}

fn call_str_case_method(name: &str, args: Vec<Value>, upper: bool) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if !rest.is_empty() {
        return Err(format!(
            "TypeError: {method}() expected 0 arguments, got {}",
            rest.len()
        ));
    }

    let value = if upper {
        receiver
            .chars()
            .flat_map(char::to_uppercase)
            .collect::<String>()
    } else {
        string_lower(receiver)
    };
    Ok(Value::String(value))
}

fn call_str_transform_method(
    name: &str,
    args: Vec<Value>,
    transform: fn(&str) -> String,
) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if !rest.is_empty() {
        return Err(format!(
            "TypeError: {method}() expected 0 arguments, got {}",
            rest.len()
        ));
    }

    Ok(Value::String(transform(receiver)))
}

fn call_str_predicate_method(
    name: &str,
    args: Vec<Value>,
    predicate: fn(&str) -> bool,
) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if !rest.is_empty() {
        return Err(format!(
            "TypeError: {method}() expected 0 arguments, got {}",
            rest.len()
        ));
    }

    Ok(Value::Bool(predicate(receiver)))
}

fn string_capitalize(value: &str) -> String {
    let mut chars = value.char_indices();
    let Some((_, first)) = chars.next() else {
        return String::new();
    };

    let mut result = titlecase_char(first);
    for (index, ch) in chars {
        result.push_str(&lowercase_char_at(value, index, ch));
    }
    result
}

fn string_title(value: &str) -> String {
    let mut result = String::new();
    let mut previous_cased = false;

    for (index, ch) in value.char_indices() {
        if is_cased_char(ch) {
            if previous_cased {
                result.push_str(&lowercase_char_at(value, index, ch));
            } else {
                result.push_str(&titlecase_char(ch));
            }
            previous_cased = true;
        } else {
            result.push(ch);
            previous_cased = false;
        }
    }

    result
}

fn string_lower(value: &str) -> String {
    let mut result = String::new();
    for (index, ch) in value.char_indices() {
        result.push_str(&lowercase_char_at(value, index, ch));
    }
    result
}

fn string_swapcase(value: &str) -> String {
    let mut result = String::new();
    for ch in value.chars() {
        if ch.is_lowercase() {
            result.push_str(&uppercase_char(ch));
        } else if ch.is_uppercase() {
            result.push_str(&lowercase_char(ch));
        } else {
            result.push(ch);
        }
    }
    result
}

fn string_casefold(value: &str) -> String {
    let mut result = String::new();
    for ch in value.chars() {
        result.push_str(&casefold_char(ch));
    }
    result
}

fn is_cased_char(ch: char) -> bool {
    ch.is_lowercase() || ch.is_uppercase() || is_titlecase_char(ch)
}

fn is_titlecase_char(ch: char) -> bool {
    matches!(
        ch,
        '\u{01c5}' | '\u{01c8}' | '\u{01cb}' | '\u{01f2}' | '\u{1ffc}'
    )
}

fn titlecase_char(ch: char) -> String {
    match ch {
        '\u{1ff3}' | '\u{1ffc}' => "\u{1ffc}".to_string(),
        '\u{1fa1}' => "\u{1fa9}".to_string(),
        '\u{fb01}' => "Fi".to_string(),
        ch => uppercase_char(ch),
    }
}

fn uppercase_char(ch: char) -> String {
    ch.to_uppercase().collect()
}

fn lowercase_char(ch: char) -> String {
    ch.to_lowercase().collect()
}

fn lowercase_char_at(value: &str, index: usize, ch: char) -> String {
    if ch == '\u{03a3}' && is_final_sigma_context(value, index, ch) {
        "\u{03c2}".to_string()
    } else {
        lowercase_char(ch)
    }
}

fn is_final_sigma_context(value: &str, index: usize, ch: char) -> bool {
    let preceded_by_cased = value[..index]
        .chars()
        .rev()
        .find(|candidate| !is_case_ignorable_char(*candidate))
        .is_some_and(is_cased_char);
    if !preceded_by_cased {
        return false;
    }

    let following_start = index + ch.len_utf8();
    !value[following_start..]
        .chars()
        .find(|candidate| !is_case_ignorable_char(*candidate))
        .is_some_and(is_cased_char)
}

fn is_case_ignorable_char(ch: char) -> bool {
    matches!(
        get_general_category(ch),
        GeneralCategory::NonspacingMark
            | GeneralCategory::SpacingMark
            | GeneralCategory::EnclosingMark
            | GeneralCategory::Format
            | GeneralCategory::ModifierLetter
            | GeneralCategory::ModifierSymbol
    )
}

fn casefold_char(ch: char) -> String {
    match ch {
        '\u{00b5}' => "\u{03bc}".to_string(),
        '\u{00df}' | '\u{1e9e}' => "ss".to_string(),
        '\u{0345}' => "\u{03b9}".to_string(),
        '\u{fb01}' => "fi".to_string(),
        '\u{fb02}' => "fl".to_string(),
        ch => lowercase_char(ch),
    }
}

fn string_islower(value: &str) -> bool {
    let mut has_cased = false;
    for ch in value.chars() {
        if ch.is_uppercase() || is_titlecase_char(ch) {
            return false;
        }
        if ch.is_lowercase() {
            has_cased = true;
        }
    }
    has_cased
}

fn string_isupper(value: &str) -> bool {
    let mut has_cased = false;
    for ch in value.chars() {
        if ch.is_lowercase() || is_titlecase_char(ch) {
            return false;
        }
        if ch.is_uppercase() {
            has_cased = true;
        }
    }
    has_cased
}

fn string_istitle(value: &str) -> bool {
    let mut has_cased = false;
    let mut previous_cased = false;

    for ch in value.chars() {
        if ch.is_lowercase() {
            if !previous_cased {
                return false;
            }
            has_cased = true;
            previous_cased = true;
        } else if ch.is_uppercase() || is_titlecase_char(ch) {
            if previous_cased {
                return false;
            }
            has_cased = true;
            previous_cased = true;
        } else {
            previous_cased = false;
        }
    }

    has_cased
}

fn string_isspace(value: &str) -> bool {
    !value.is_empty() && value.chars().all(char::is_whitespace)
}

fn string_isalpha(value: &str) -> bool {
    !value.is_empty() && value.chars().all(char::is_alphabetic)
}

fn string_isalnum(value: &str) -> bool {
    !value.is_empty() && value.chars().all(char::is_alphanumeric)
}

fn string_isdigit(value: &str) -> bool {
    !value.is_empty() && value.chars().all(is_digit_char)
}

fn string_isdecimal(value: &str) -> bool {
    !value.is_empty() && value.chars().all(is_decimal_char)
}

fn string_isnumeric(value: &str) -> bool {
    !value.is_empty() && value.chars().all(char::is_numeric)
}

fn string_isascii(value: &str) -> bool {
    value.is_ascii()
}

fn string_isidentifier(value: &str) -> bool {
    let mut chars = value.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    if !is_identifier_start(first) {
        return false;
    }
    chars.all(is_identifier_continue)
}

fn is_identifier_start(ch: char) -> bool {
    ch == '_' || unicode_ident::is_xid_start(ch)
}

fn is_identifier_continue(ch: char) -> bool {
    ch == '_' || unicode_ident::is_xid_continue(ch)
}

fn string_isprintable(value: &str) -> bool {
    value.chars().all(is_printable_char)
}

fn is_printable_char(ch: char) -> bool {
    ch == ' '
        || !matches!(
            get_general_category(ch),
            GeneralCategory::Control
                | GeneralCategory::Format
                | GeneralCategory::PrivateUse
                | GeneralCategory::Surrogate
                | GeneralCategory::Unassigned
                | GeneralCategory::LineSeparator
                | GeneralCategory::ParagraphSeparator
                | GeneralCategory::SpaceSeparator
        )
}

fn is_digit_char(ch: char) -> bool {
    is_decimal_char(ch)
        || matches!(ch, '\u{00b2}' | '\u{00b3}' | '\u{00b9}')
        || matches!(ch, '\u{2460}'..='\u{2468}')
        || matches!(ch, '\u{2474}'..='\u{247c}')
        || matches!(ch, '\u{2488}'..='\u{2490}')
        || matches!(ch, '\u{1f100}'..='\u{1f10a}')
}

fn is_decimal_char(ch: char) -> bool {
    matches!(
        ch,
        '0'..='9'
            | '\u{0660}'..='\u{0669}'
            | '\u{06f0}'..='\u{06f9}'
            | '\u{07c0}'..='\u{07c9}'
            | '\u{0966}'..='\u{096f}'
            | '\u{09e6}'..='\u{09ef}'
            | '\u{0a66}'..='\u{0a6f}'
            | '\u{0ae6}'..='\u{0aef}'
            | '\u{0b66}'..='\u{0b6f}'
            | '\u{0be6}'..='\u{0bef}'
            | '\u{0c66}'..='\u{0c6f}'
            | '\u{0ce6}'..='\u{0cef}'
            | '\u{0d66}'..='\u{0d6f}'
            | '\u{0de6}'..='\u{0def}'
            | '\u{0e50}'..='\u{0e59}'
            | '\u{0ed0}'..='\u{0ed9}'
            | '\u{0f20}'..='\u{0f29}'
            | '\u{1040}'..='\u{1049}'
            | '\u{1090}'..='\u{1099}'
            | '\u{17e0}'..='\u{17e9}'
            | '\u{1810}'..='\u{1819}'
            | '\u{1946}'..='\u{194f}'
            | '\u{19d0}'..='\u{19d9}'
            | '\u{1a80}'..='\u{1a89}'
            | '\u{1a90}'..='\u{1a99}'
            | '\u{1b50}'..='\u{1b59}'
            | '\u{1bb0}'..='\u{1bb9}'
            | '\u{1c40}'..='\u{1c49}'
            | '\u{1c50}'..='\u{1c59}'
            | '\u{a620}'..='\u{a629}'
            | '\u{a8d0}'..='\u{a8d9}'
            | '\u{a900}'..='\u{a909}'
            | '\u{a9d0}'..='\u{a9d9}'
            | '\u{a9f0}'..='\u{a9f9}'
            | '\u{aa50}'..='\u{aa59}'
            | '\u{abf0}'..='\u{abf9}'
            | '\u{104a0}'..='\u{104a9}'
            | '\u{10d30}'..='\u{10d39}'
            | '\u{11066}'..='\u{1106f}'
            | '\u{110f0}'..='\u{110f9}'
            | '\u{11136}'..='\u{1113f}'
            | '\u{111d0}'..='\u{111d9}'
            | '\u{112f0}'..='\u{112f9}'
            | '\u{11450}'..='\u{11459}'
            | '\u{114d0}'..='\u{114d9}'
            | '\u{11650}'..='\u{11659}'
            | '\u{116c0}'..='\u{116c9}'
            | '\u{11730}'..='\u{11739}'
            | '\u{118e0}'..='\u{118e9}'
            | '\u{11950}'..='\u{11959}'
            | '\u{11c50}'..='\u{11c59}'
            | '\u{11d50}'..='\u{11d59}'
            | '\u{11da0}'..='\u{11da9}'
            | '\u{11f50}'..='\u{11f59}'
            | '\u{16a60}'..='\u{16a69}'
            | '\u{16ac0}'..='\u{16ac9}'
            | '\u{16b50}'..='\u{16b59}'
            | '\u{1d7ce}'..='\u{1d7ff}'
    )
}

fn call_str_splitlines_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if rest.len() + keywords.len() > 1 {
        return Err(format!(
            "TypeError: {method}() expected at most 1 argument, got {}",
            rest.len() + keywords.len()
        ));
    }

    let keepends = match (rest, keywords.as_slice()) {
        ([], []) => false,
        ([value], []) => is_truthy(value)?,
        ([], [(keyword, value)]) if keyword == "keepends" => is_truthy(value)?,
        ([], [(keyword, _)]) => {
            return Err(format!(
                "TypeError: '{keyword}' is an invalid keyword argument for {method}()"
            ));
        }
        _ => unreachable!("splitlines arity checked above"),
    };

    let lines = string_splitlines(receiver, keepends)
        .into_iter()
        .map(Value::String)
        .collect::<Vec<_>>();
    Ok(list_value(lines))
}

fn string_splitlines(value: &str, keepends: bool) -> Vec<String> {
    let mut lines = Vec::new();
    let mut line_start = 0;
    let mut chars = value.char_indices().peekable();

    while let Some((index, ch)) = chars.next() {
        let Some(line_break_end) = string_line_break_end(index, ch, &mut chars) else {
            continue;
        };
        let line_end = if keepends { line_break_end } else { index };
        lines.push(value[line_start..line_end].to_string());
        line_start = line_break_end;
    }

    if line_start < value.len() {
        lines.push(value[line_start..].to_string());
    }

    lines
}

fn string_line_break_end(
    index: usize,
    ch: char,
    chars: &mut std::iter::Peekable<std::str::CharIndices<'_>>,
) -> Option<usize> {
    if ch == '\r' {
        let mut end = index + ch.len_utf8();
        if let Some((next_index, '\n')) = chars.peek().copied() {
            chars.next();
            end = next_index + '\n'.len_utf8();
        }
        return Some(end);
    }

    if matches!(
        ch,
        '\n' | '\u{000b}' | '\u{000c}' | '\u{001c}'
            ..='\u{001e}' | '\u{0085}' | '\u{2028}' | '\u{2029}'
    ) {
        return Some(index + ch.len_utf8());
    }

    None
}

fn call_str_expandtabs_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if rest.len() + keywords.len() > 1 {
        return Err(format!(
            "TypeError: {method}() expected at most 1 argument, got {}",
            rest.len() + keywords.len()
        ));
    }

    let tabsize = match (rest, keywords.as_slice()) {
        ([], []) => 8,
        ([value], []) => string_tabsize_argument(value, method)?,
        ([], [(keyword, value)]) if keyword == "tabsize" => string_tabsize_argument(value, method)?,
        ([], [(keyword, _)]) => {
            return Err(format!(
                "TypeError: '{keyword}' is an invalid keyword argument for {method}()"
            ));
        }
        _ => unreachable!("expandtabs arity checked above"),
    };

    Ok(Value::String(string_expandtabs(receiver, tabsize)?))
}

fn string_expandtabs(value: &str, tabsize: i32) -> Result<String, String> {
    let mut expanded = String::new();
    let mut column = 0usize;
    let tabsize = usize::try_from(tabsize).unwrap_or(0);

    for ch in value.chars() {
        match ch {
            '\t' if tabsize == 0 => {}
            '\t' => {
                let spaces = tabsize - (column % tabsize);
                expanded.push_str(&" ".repeat(spaces));
                column = column
                    .checked_add(spaces)
                    .ok_or_else(|| "OverflowError: expanded string is too long".to_string())?;
            }
            '\n' | '\r' => {
                expanded.push(ch);
                column = 0;
            }
            ch => {
                expanded.push(ch);
                column = column
                    .checked_add(1)
                    .ok_or_else(|| "OverflowError: expanded string is too long".to_string())?;
            }
        }
    }

    Ok(expanded)
}

fn string_tabsize_argument(value: &Value, method: &str) -> Result<i32, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(*value) as i32),
        Value::Number(value) => i32::try_from(*value)
            .map_err(|_| "OverflowError: Python int too large to convert to C int".to_string()),
        Value::BigInt(value) => value
            .to_i32()
            .ok_or_else(|| "OverflowError: Python int too large to convert to C int".to_string()),
        value => Err(format!(
            "TypeError: {method} tabsize must be an integer, not {}",
            type_name(value)
        )),
    }
}

fn call_str_replace_method(name: &str, args: Vec<Value>) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if rest.len() < 2 {
        return Err(format!(
            "TypeError: {method}() expected at least 2 arguments, got {}",
            rest.len()
        ));
    }
    if rest.len() > 3 {
        return Err(format!(
            "TypeError: {method}() expected at most 3 arguments, got {}",
            rest.len()
        ));
    }

    let old = match &rest[0] {
        Value::String(value) => value,
        value => {
            return Err(format!(
                "TypeError: {method} first arg must be str, not {}",
                type_name(value)
            ));
        }
    };
    let new = match &rest[1] {
        Value::String(value) => value,
        value => {
            return Err(format!(
                "TypeError: {method} second arg must be str, not {}",
                type_name(value)
            ));
        }
    };
    let count = match rest.get(2) {
        Some(value) => string_replace_count_argument(value, method)?,
        None => -1,
    };

    Ok(Value::String(string_replace(receiver, old, new, count)?))
}

fn call_str_remove_affix_method(
    name: &str,
    args: Vec<Value>,
    remove_prefix: bool,
) -> Result<Value, String> {
    let method = method_display_name(name);
    let [Value::String(receiver), affix] = args.as_slice() else {
        return Err(format!(
            "TypeError: {method}() expected 1 argument, got {}",
            method_arg_count(&args)
        ));
    };

    let Value::String(affix) = affix else {
        return Err(format!(
            "TypeError: {method} first arg must be str, not {}",
            type_name(affix)
        ));
    };

    let value = if remove_prefix {
        receiver.strip_prefix(affix).unwrap_or(receiver)
    } else if affix.is_empty() {
        receiver
    } else {
        receiver.strip_suffix(affix).unwrap_or(receiver)
    };
    Ok(Value::String(value.to_string()))
}

fn call_str_partition_method(name: &str, args: Vec<Value>, reverse: bool) -> Result<Value, String> {
    let method = method_display_name(name);
    let [Value::String(receiver), separator] = args.as_slice() else {
        return Err(format!(
            "TypeError: {method}() expected 1 argument, got {}",
            method_arg_count(&args)
        ));
    };

    let Value::String(separator) = separator else {
        return Err(format!(
            "TypeError: {method} first arg must be str, not {}",
            type_name(separator)
        ));
    };
    if separator.is_empty() {
        return Err("ValueError: empty separator".to_string());
    }

    Ok(tuple_value(
        string_partition(receiver, separator, reverse)
            .into_iter()
            .map(Value::String)
            .collect(),
    ))
}

fn string_partition(receiver: &str, separator: &str, reverse: bool) -> Vec<String> {
    let found = if reverse {
        receiver.rfind(separator)
    } else {
        receiver.find(separator)
    };

    let Some(index) = found else {
        return if reverse {
            vec![String::new(), String::new(), receiver.to_string()]
        } else {
            vec![receiver.to_string(), String::new(), String::new()]
        };
    };

    let after = index + separator.len();
    vec![
        receiver[..index].to_string(),
        separator.to_string(),
        receiver[after..].to_string(),
    ]
}

#[derive(Clone)]
enum TextEncoding {
    Utf8,
    Ascii,
    Latin1,
    Utf16,
    Utf16Le,
    Utf16Be,
    EncodingRs {
        encoding: &'static Encoding,
        name: String,
    },
}

#[derive(Clone, Copy)]
enum CodecErrorMode {
    Strict,
    Ignore,
    Replace,
}

#[derive(Clone, Copy)]
enum Utf16Endian {
    Little,
    Big,
}

fn call_str_encode_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let method = method_display_name(name);
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!("TypeError: {method}() expected a str receiver"));
    };

    Ok(Value::Bytes(encode_text_with_options(
        receiver, rest, keywords,
    )?))
}

fn call_bytes_decode_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(format!("TypeError: {method}() expected 0 arguments, got 0"));
    };
    let bytes = match receiver {
        Value::Bytes(value) | Value::ByteArray(value) => value,
        value => {
            return Err(format!(
                "TypeError: {method}() expected a bytes-like receiver, got {}",
                type_name(value)
            ));
        }
    };

    Ok(Value::String(decode_bytes_with_options(
        bytes, rest, keywords,
    )?))
}

fn encode_text_with_options(
    text: &str,
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<Vec<u8>, String> {
    let (encoding, errors) = codec_options("encode", args, keywords)?;
    encode_text(text, encoding, errors)
}

fn decode_bytes_with_options(
    bytes: &[u8],
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<String, String> {
    let (encoding, errors) = codec_options("decode", args, keywords)?;
    decode_bytes(bytes, encoding, errors)
}

fn call_bytes_hex_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(format!("TypeError: {method}() expected 0 arguments, got 0"));
    };
    let bytes = match receiver {
        Value::Bytes(value) | Value::ByteArray(value) => value,
        value => {
            return Err(format!(
                "TypeError: {method}() expected a bytes-like receiver, got {}",
                type_name(value)
            ));
        }
    };

    let mut slots = constructor_slots(method, rest.to_vec(), keywords, &["sep", "bytes_per_sep"])?;
    let bytes_per_sep = slots[1]
        .take()
        .map(|value| integer_value_to_i64(value, "bytes_per_sep"))
        .transpose()?
        .unwrap_or(1);
    let separator = slots[0].as_ref().map(hex_separator).transpose()?;

    Ok(Value::String(bytes_hex(bytes, separator, bytes_per_sep)))
}

fn call_bytes_fromhex(name: &str, args: Vec<Value>) -> Result<Value, String> {
    let [source] = args.as_slice() else {
        return Err(format!(
            "TypeError: {name}() takes exactly one argument ({} given)",
            args.len()
        ));
    };

    let bytes = bytes_fromhex(source)?;
    if name.starts_with("bytearray.") {
        Ok(Value::ByteArray(bytes))
    } else {
        Ok(Value::Bytes(bytes))
    }
}

fn bytes_hex(bytes: &[u8], separator: Option<char>, bytes_per_sep: i64) -> String {
    let hex = bytes
        .iter()
        .map(|byte| format!("{byte:02x}"))
        .collect::<Vec<_>>();
    let Some(separator) = separator else {
        return hex.join("");
    };
    if bytes_per_sep == 0 || bytes.is_empty() {
        return hex.join("");
    }

    let group = bytes_per_sep.unsigned_abs() as usize;
    if group >= bytes.len() {
        return hex.join("");
    }

    let mut output = String::new();
    if bytes_per_sep > 0 {
        let first_group = match bytes.len() % group {
            0 => group,
            value => value,
        };
        for (index, item) in hex.iter().enumerate() {
            if index > 0
                && (index == first_group
                    || index > first_group && (index - first_group) % group == 0)
            {
                output.push(separator);
            }
            output.push_str(item);
        }
    } else {
        for (index, item) in hex.iter().enumerate() {
            if index > 0 && index % group == 0 {
                output.push(separator);
            }
            output.push_str(item);
        }
    }
    output
}

fn hex_separator(value: &Value) -> Result<char, String> {
    match value {
        Value::String(value) => {
            let mut chars = value.chars();
            let Some(ch) = chars.next() else {
                return Err("ValueError: sep must be length 1.".to_string());
            };
            if chars.next().is_some() {
                return Err("ValueError: sep must be length 1.".to_string());
            }
            if !ch.is_ascii() {
                return Err("ValueError: sep must be ASCII.".to_string());
            }
            Ok(ch)
        }
        Value::Bytes(value) => {
            let [byte] = value.as_slice() else {
                return Err("ValueError: sep must be length 1.".to_string());
            };
            if !byte.is_ascii() {
                return Err("ValueError: sep must be ASCII.".to_string());
            }
            Ok(*byte as char)
        }
        value => Err(format!(
            "TypeError: object of type '{}' has no len()",
            type_name(value)
        )),
    }
}

fn bytes_fromhex(value: &Value) -> Result<Vec<u8>, String> {
    let text = match value {
        Value::String(value) => value.clone(),
        Value::Bytes(value) | Value::ByteArray(value) => {
            let mut text = String::new();
            for byte in value {
                if !byte.is_ascii() {
                    return Err(
                        "ValueError: non-hexadecimal number found in fromhex() arg".to_string()
                    );
                }
                text.push(*byte as char);
            }
            text
        }
        value => {
            return Err(format!(
                "TypeError: fromhex() argument must be str or bytes-like, not {}",
                type_name(value)
            ));
        }
    };

    let mut digits = Vec::new();
    for (index, ch) in text.chars().enumerate() {
        if ch.is_ascii_whitespace() {
            continue;
        }
        let Some(value) = ch.to_digit(16) else {
            return Err(format!(
                "ValueError: non-hexadecimal number found in fromhex() arg at position {index}"
            ));
        };
        digits.push((index, value as u8));
    }

    if digits.len() % 2 != 0 {
        let index = digits.last().map(|(index, _)| *index + 1).unwrap_or(0);
        return Err(format!(
            "ValueError: non-hexadecimal number found in fromhex() arg at position {index}"
        ));
    }

    Ok(digits
        .chunks_exact(2)
        .map(|pair| (pair[0].1 << 4) | pair[1].1)
        .collect())
}

fn codec_options(
    method: &str,
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<(TextEncoding, CodecErrorMode), String> {
    if args.len() > 2 {
        return Err(format!(
            "TypeError: {method}() expected at most 2 arguments, got {}",
            args.len()
        ));
    }

    let mut encoding = args
        .first()
        .map(|value| codec_string_arg(value, "encoding"))
        .transpose()?;
    let mut errors = args
        .get(1)
        .map(|value| codec_string_arg(value, "errors"))
        .transpose()?;

    for (keyword, value) in keywords {
        match keyword.as_str() {
            "encoding" => {
                if encoding.is_some() {
                    return Err(format!(
                        "TypeError: {method}() got multiple values for argument 'encoding'"
                    ));
                }
                encoding = Some(codec_string_arg(&value, "encoding")?);
            }
            "errors" => {
                if errors.is_some() {
                    return Err(format!(
                        "TypeError: {method}() got multiple values for argument 'errors'"
                    ));
                }
                errors = Some(codec_string_arg(&value, "errors")?);
            }
            _ => {
                return Err(format!(
                    "TypeError: '{keyword}' is an invalid keyword argument for {method}()"
                ));
            }
        }
    }

    let encoding = lookup_text_encoding(encoding.as_deref().unwrap_or("utf-8"))?;
    let errors = lookup_codec_errors(errors.as_deref().unwrap_or("strict"))?;
    Ok((encoding, errors))
}

fn codec_options_from_values(
    method: &str,
    encoding: Option<&Value>,
    errors: Option<&Value>,
) -> Result<(TextEncoding, CodecErrorMode), String> {
    let encoding = encoding
        .map(|value| codec_string_arg(value, "encoding"))
        .transpose()?;
    let errors = errors
        .map(|value| codec_string_arg(value, "errors"))
        .transpose()?;
    let encoding = lookup_text_encoding(encoding.as_deref().unwrap_or("utf-8"))?;
    let errors = lookup_codec_errors(errors.as_deref().unwrap_or("strict"))
        .map_err(|error| if method == "str" { error } else { error })?;
    Ok((encoding, errors))
}

fn constructor_slots(
    function: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
    params: &[&str],
) -> Result<Vec<Option<Value>>, String> {
    if args.len() > params.len() {
        return Err(format!(
            "TypeError: {function}() expected at most {} arguments, got {}",
            params.len(),
            args.len()
        ));
    }

    let mut slots = vec![None; params.len()];
    for (index, value) in args.into_iter().enumerate() {
        slots[index] = Some(value);
    }

    for (keyword, value) in keywords {
        let Some(index) = params.iter().position(|param| *param == keyword) else {
            return Err(format!(
                "TypeError: '{keyword}' is an invalid keyword argument for {function}()"
            ));
        };
        if slots[index].is_some() {
            return Err(format!(
                "TypeError: {function}() got multiple values for argument '{keyword}'"
            ));
        }
        slots[index] = Some(value);
    }

    Ok(slots)
}

fn reject_bytes_encoding_without_string(
    encoding: Option<&Value>,
    errors: Option<&Value>,
) -> Result<(), String> {
    if errors.is_some() {
        return Err("TypeError: errors without a string argument".to_string());
    }
    if encoding.is_some() {
        return Err("TypeError: encoding without a string argument".to_string());
    }
    Ok(())
}

fn validate_optional_codec_string(value: Option<&Value>, name: &str) -> Result<(), String> {
    if let Some(value) = value {
        codec_string_arg(value, name)?;
    }
    Ok(())
}

fn codec_string_arg(value: &Value, name: &str) -> Result<String, String> {
    match value {
        Value::String(value) => Ok(value.clone()),
        value => Err(format!(
            "TypeError: {name} must be str, not {}",
            type_name(value)
        )),
    }
}

fn lookup_text_encoding(name: &str) -> Result<TextEncoding, String> {
    let normalized = name
        .chars()
        .filter(|ch| *ch != '-' && *ch != '_')
        .flat_map(char::to_lowercase)
        .collect::<String>();
    match normalized.as_str() {
        "utf8" => Ok(TextEncoding::Utf8),
        "ascii" | "usascii" => Ok(TextEncoding::Ascii),
        "latin1" | "latin" | "iso88591" => Ok(TextEncoding::Latin1),
        "utf16" => Ok(TextEncoding::Utf16),
        "utf16le" => Ok(TextEncoding::Utf16Le),
        "utf16be" => Ok(TextEncoding::Utf16Be),
        _ => Encoding::for_label(name.as_bytes())
            .map(|encoding| TextEncoding::EncodingRs {
                encoding,
                name: name.to_string(),
            })
            .ok_or_else(|| format!("LookupError: unknown encoding: {name}")),
    }
}

fn lookup_codec_errors(name: &str) -> Result<CodecErrorMode, String> {
    match name {
        "strict" => Ok(CodecErrorMode::Strict),
        "ignore" => Ok(CodecErrorMode::Ignore),
        "replace" => Ok(CodecErrorMode::Replace),
        _ => Err(format!("LookupError: unknown error handler name '{name}'")),
    }
}

fn encode_text(
    text: &str,
    encoding: TextEncoding,
    errors: CodecErrorMode,
) -> Result<Vec<u8>, String> {
    match encoding {
        TextEncoding::Utf8 => Ok(text.as_bytes().to_vec()),
        TextEncoding::Ascii => encode_single_byte_text(text, 0x7f, "ascii", errors),
        TextEncoding::Latin1 => encode_single_byte_text(text, 0xff, "latin-1", errors),
        TextEncoding::Utf16 => Ok(encode_utf16_text(text, Utf16Endian::Little, true)),
        TextEncoding::Utf16Le => Ok(encode_utf16_text(text, Utf16Endian::Little, false)),
        TextEncoding::Utf16Be => Ok(encode_utf16_text(text, Utf16Endian::Big, false)),
        TextEncoding::EncodingRs { encoding, name } => {
            encode_encoding_rs_text(text, encoding, &name, errors)
        }
    }
}

fn encode_single_byte_text(
    text: &str,
    max: u32,
    encoding_name: &str,
    errors: CodecErrorMode,
) -> Result<Vec<u8>, String> {
    let mut bytes = Vec::new();
    for (index, ch) in text.chars().enumerate() {
        let codepoint = ch as u32;
        if codepoint <= max {
            bytes.push(codepoint as u8);
            continue;
        }

        match errors {
            CodecErrorMode::Strict => {
                return Err(format!(
                    "UnicodeEncodeError: '{encoding_name}' codec can't encode character in position {index}: ordinal not in range"
                ));
            }
            CodecErrorMode::Ignore => {}
            CodecErrorMode::Replace => bytes.push(b'?'),
        }
    }
    Ok(bytes)
}

fn encode_utf16_text(text: &str, endian: Utf16Endian, with_bom: bool) -> Vec<u8> {
    let mut bytes = Vec::new();
    if with_bom {
        bytes.extend([0xff, 0xfe]);
    }
    for unit in text.encode_utf16() {
        let pair = match endian {
            Utf16Endian::Little => unit.to_le_bytes(),
            Utf16Endian::Big => unit.to_be_bytes(),
        };
        bytes.extend(pair);
    }
    bytes
}

fn encode_encoding_rs_text(
    text: &str,
    encoding: &'static Encoding,
    encoding_name: &str,
    errors: CodecErrorMode,
) -> Result<Vec<u8>, String> {
    if matches!(errors, CodecErrorMode::Strict) {
        let mut encoder = encoding.new_encoder();
        let mut bytes = Vec::with_capacity(
            encoder
                .max_buffer_length_from_utf8_without_replacement(text.len())
                .unwrap_or(text.len().saturating_mul(4)),
        );
        let (result, read) =
            encoder.encode_from_utf8_to_vec_without_replacement(text, &mut bytes, true);
        return match result {
            encoding_rs::EncoderResult::InputEmpty => Ok(bytes),
            encoding_rs::EncoderResult::Unmappable(_) => {
                let index = text[..read].chars().count();
                Err(format!(
                    "UnicodeEncodeError: '{encoding_name}' codec can't encode character in position {index}: ordinal not in range"
                ))
            }
            encoding_rs::EncoderResult::OutputFull => Err(format!(
                "UnicodeEncodeError: '{encoding_name}' codec output overflow"
            )),
        };
    }

    let mut bytes = Vec::new();
    for ch in text.chars() {
        let piece = ch.to_string();
        let mut encoder = encoding.new_encoder();
        let needed = encoder
            .max_buffer_length_from_utf8_without_replacement(piece.len())
            .unwrap_or(piece.len().saturating_mul(4));
        bytes.reserve(needed);
        let (result, _) =
            encoder.encode_from_utf8_to_vec_without_replacement(&piece, &mut bytes, true);
        match result {
            encoding_rs::EncoderResult::InputEmpty => {}
            encoding_rs::EncoderResult::Unmappable(_) => match errors {
                CodecErrorMode::Ignore => {}
                CodecErrorMode::Replace => bytes.push(b'?'),
                CodecErrorMode::Strict => unreachable!("strict handled above"),
            },
            encoding_rs::EncoderResult::OutputFull => {
                return Err(format!(
                    "UnicodeEncodeError: '{encoding_name}' codec output overflow"
                ));
            }
        }
    }
    Ok(bytes)
}

fn decode_bytes(
    bytes: &[u8],
    encoding: TextEncoding,
    errors: CodecErrorMode,
) -> Result<String, String> {
    match encoding {
        TextEncoding::Utf8 => decode_utf8_bytes(bytes, errors),
        TextEncoding::Ascii => decode_ascii_bytes(bytes, errors),
        TextEncoding::Latin1 => Ok(bytes.iter().map(|byte| *byte as char).collect()),
        TextEncoding::Utf16 => decode_utf16_bytes(bytes, None, errors),
        TextEncoding::Utf16Le => decode_utf16_bytes(bytes, Some(Utf16Endian::Little), errors),
        TextEncoding::Utf16Be => decode_utf16_bytes(bytes, Some(Utf16Endian::Big), errors),
        TextEncoding::EncodingRs { encoding, name } => {
            decode_encoding_rs_bytes(bytes, encoding, &name, errors)
        }
    }
}

fn decode_utf8_bytes(bytes: &[u8], errors: CodecErrorMode) -> Result<String, String> {
    match errors {
        CodecErrorMode::Strict => String::from_utf8(bytes.to_vec())
            .map_err(|_| "UnicodeDecodeError: 'utf-8' codec can't decode bytes".to_string()),
        CodecErrorMode::Replace => Ok(String::from_utf8_lossy(bytes).into_owned()),
        CodecErrorMode::Ignore => {
            let mut output = String::new();
            let mut index = 0usize;
            while index < bytes.len() {
                match std::str::from_utf8(&bytes[index..]) {
                    Ok(valid) => {
                        output.push_str(valid);
                        break;
                    }
                    Err(error) => {
                        let valid_up_to = error.valid_up_to();
                        output.push_str(
                            std::str::from_utf8(&bytes[index..index + valid_up_to]).map_err(
                                |_| {
                                    "UnicodeDecodeError: 'utf-8' codec can't decode bytes"
                                        .to_string()
                                },
                            )?,
                        );
                        index += valid_up_to + error.error_len().unwrap_or(1);
                    }
                }
            }
            Ok(output)
        }
    }
}

fn decode_ascii_bytes(bytes: &[u8], errors: CodecErrorMode) -> Result<String, String> {
    let mut output = String::new();
    for (index, byte) in bytes.iter().enumerate() {
        if *byte <= 0x7f {
            output.push(*byte as char);
            continue;
        }

        match errors {
            CodecErrorMode::Strict => {
                return Err(format!(
                    "UnicodeDecodeError: 'ascii' codec can't decode byte 0x{byte:02x} in position {index}: ordinal not in range"
                ));
            }
            CodecErrorMode::Ignore => {}
            CodecErrorMode::Replace => output.push('\u{fffd}'),
        }
    }
    Ok(output)
}

fn decode_utf16_bytes(
    bytes: &[u8],
    forced_endian: Option<Utf16Endian>,
    errors: CodecErrorMode,
) -> Result<String, String> {
    let (endian, start) = match forced_endian {
        Some(endian) => (endian, 0),
        None if bytes.starts_with(&[0xff, 0xfe]) => (Utf16Endian::Little, 2),
        None if bytes.starts_with(&[0xfe, 0xff]) => (Utf16Endian::Big, 2),
        None => (Utf16Endian::Little, 0),
    };

    let mut units = Vec::new();
    let mut index = start;
    while index + 1 < bytes.len() {
        let unit = match endian {
            Utf16Endian::Little => u16::from_le_bytes([bytes[index], bytes[index + 1]]),
            Utf16Endian::Big => u16::from_be_bytes([bytes[index], bytes[index + 1]]),
        };
        units.push(unit);
        index += 2;
    }
    if index < bytes.len() {
        match errors {
            CodecErrorMode::Strict => {
                return Err(
                    "UnicodeDecodeError: 'utf-16' codec can't decode truncated data".to_string(),
                );
            }
            CodecErrorMode::Ignore => {}
            CodecErrorMode::Replace => units.push(0xfffd),
        }
    }

    let mut output = String::new();
    for decoded in std::char::decode_utf16(units) {
        match decoded {
            Ok(ch) => output.push(ch),
            Err(_) => match errors {
                CodecErrorMode::Strict => {
                    return Err(
                        "UnicodeDecodeError: 'utf-16' codec can't decode surrogate".to_string()
                    );
                }
                CodecErrorMode::Ignore => {}
                CodecErrorMode::Replace => output.push('\u{fffd}'),
            },
        }
    }
    Ok(output)
}

fn decode_encoding_rs_bytes(
    bytes: &[u8],
    encoding: &'static Encoding,
    encoding_name: &str,
    errors: CodecErrorMode,
) -> Result<String, String> {
    if bytes
        .iter()
        .any(|byte| is_python_undefined_encoding_byte(encoding_name, *byte))
    {
        return decode_encoding_rs_bytes_with_python_undefined(
            bytes,
            encoding,
            encoding_name,
            errors,
        );
    }

    match errors {
        CodecErrorMode::Strict => encoding
            .decode_without_bom_handling_and_without_replacement(bytes)
            .map(|decoded| decoded.into_owned())
            .ok_or_else(|| {
                format!("UnicodeDecodeError: '{encoding_name}' codec can't decode bytes")
            }),
        CodecErrorMode::Replace => {
            let (decoded, _had_errors) = encoding.decode_without_bom_handling(bytes);
            Ok(decoded.into_owned())
        }
        CodecErrorMode::Ignore => {
            let mut output = String::new();
            for byte in bytes {
                if let Some(decoded) =
                    encoding.decode_without_bom_handling_and_without_replacement(&[*byte])
                {
                    output.push_str(&decoded);
                }
            }
            Ok(output)
        }
    }
}

fn decode_encoding_rs_bytes_with_python_undefined(
    bytes: &[u8],
    encoding: &'static Encoding,
    encoding_name: &str,
    errors: CodecErrorMode,
) -> Result<String, String> {
    if matches!(errors, CodecErrorMode::Strict) {
        return Err(format!(
            "UnicodeDecodeError: '{encoding_name}' codec can't decode bytes"
        ));
    }

    let mut output = String::new();
    let mut segment = Vec::new();
    for byte in bytes {
        if is_python_undefined_encoding_byte(encoding_name, *byte) {
            if !segment.is_empty() {
                let (decoded, _) = encoding.decode_without_bom_handling(&segment);
                output.push_str(&decoded);
                segment.clear();
            }
            if matches!(errors, CodecErrorMode::Replace) {
                output.push('\u{fffd}');
            }
        } else {
            segment.push(*byte);
        }
    }
    if !segment.is_empty() {
        let (decoded, _) = encoding.decode_without_bom_handling(&segment);
        output.push_str(&decoded);
    }
    Ok(output)
}

fn is_python_undefined_encoding_byte(encoding_name: &str, byte: u8) -> bool {
    let normalized = encoding_name
        .chars()
        .filter(|ch| *ch != '-' && *ch != '_')
        .flat_map(char::to_lowercase)
        .collect::<String>();
    match normalized.as_str() {
        "cp1251" | "windows1251" => byte == 0x98,
        "cp1252" | "windows1252" => matches!(byte, 0x81 | 0x8d | 0x8f | 0x90 | 0x9d),
        _ => false,
    }
}

fn call_str_translate_method(name: &str, args: Vec<Value>) -> Result<Value, String> {
    let method = method_display_name(name);
    let [Value::String(receiver), table] = args.as_slice() else {
        return Err(format!(
            "TypeError: {method}() expected 1 argument, got {}",
            method_arg_count(&args)
        ));
    };

    let Value::Dict(entries) = table else {
        return Err(format!(
            "TypeError: {method} table must be a mapping, not {}",
            type_name(table)
        ));
    };

    let entries = entries.borrow();
    let mut translated = String::new();
    for ch in receiver.chars() {
        let key = Value::Number(ch as u32 as i64);
        match dict_lookup(&entries, &key) {
            None => translated.push(ch),
            Some(Value::None) => {}
            Some(Value::String(replacement)) => translated.push_str(&replacement),
            Some(value) => translated.push(translation_codepoint_char(&value)?),
        }
    }

    Ok(Value::String(translated))
}

fn call_str_maketrans(args: Vec<Value>) -> Result<Value, String> {
    match args.as_slice() {
        [] => Err("TypeError: maketrans expected at least 1 argument, got 0".to_string()),
        [Value::Dict(entries)] => {
            let mut translated_entries = Vec::new();
            for (key, value) in entries.borrow().iter() {
                translated_entries.push((maketrans_key(key)?, maketrans_value(value)?));
            }
            build_dict(translated_entries)
        }
        [from, to] | [from, to, _] => {
            let (Value::String(from), Value::String(to)) = (from, to) else {
                return Err("TypeError: maketrans arguments must be strings".to_string());
            };
            let from_chars = from.chars().collect::<Vec<_>>();
            let to_chars = to.chars().collect::<Vec<_>>();
            if from_chars.len() != to_chars.len() {
                return Err(
                    "ValueError: the first two maketrans arguments must have equal length"
                        .to_string(),
                );
            }

            let mut entries = from_chars
                .into_iter()
                .zip(to_chars)
                .map(|(from, to)| {
                    (
                        Value::Number(from as u32 as i64),
                        Value::Number(to as u32 as i64),
                    )
                })
                .collect::<Vec<_>>();

            if let Some(delete) = args.get(2) {
                let Value::String(delete) = delete else {
                    return Err("TypeError: maketrans deletechars must be a string".to_string());
                };
                entries.extend(
                    delete
                        .chars()
                        .map(|ch| (Value::Number(ch as u32 as i64), Value::None)),
                );
            }

            build_dict(entries)
        }
        [_] => Err(
            "TypeError: if you give only one argument to maketrans it must be a dict".to_string(),
        ),
        values => Err(format!(
            "TypeError: maketrans expected at most 3 arguments, got {}",
            values.len()
        )),
    }
}

fn maketrans_key(key: &Value) -> Result<Value, String> {
    match key {
        Value::String(value) => {
            let mut chars = value.chars();
            let Some(ch) = chars.next() else {
                return Err(
                    "ValueError: string keys in translate table must be of length 1".to_string(),
                );
            };
            if chars.next().is_some() {
                return Err(
                    "ValueError: string keys in translate table must be of length 1".to_string(),
                );
            }
            Ok(Value::Number(ch as u32 as i64))
        }
        Value::Bool(value) => Ok(Value::Number(bool_as_i64(*value))),
        Value::Number(value) => Ok(Value::Number(*value)),
        Value::BigInt(value) => Ok(Value::BigInt(value.clone())),
        value => Err(format!(
            "TypeError: keys in translate table must be str or int, not {}",
            type_name(value)
        )),
    }
}

fn maketrans_value(value: &Value) -> Result<Value, String> {
    match value {
        Value::None | Value::String(_) | Value::Bool(_) | Value::Number(_) | Value::BigInt(_) => {
            Ok(value.clone())
        }
        value => Err(format!(
            "TypeError: values in translate table must be str, int, or None, not {}",
            type_name(value)
        )),
    }
}

fn translation_codepoint_char(value: &Value) -> Result<char, String> {
    let codepoint = match value {
        Value::Bool(value) => bool_as_i64(*value),
        Value::Number(value) => *value,
        Value::BigInt(value) => value.to_i64().unwrap_or(i64::MAX),
        value => {
            return Err(format!(
                "TypeError: character mapping must return integer, None or str, not {}",
                type_name(value)
            ));
        }
    };

    if !(0..=0x10ffff).contains(&codepoint) {
        return Err("ValueError: character mapping must be in range(0x110000)".to_string());
    }
    char::from_u32(codepoint as u32)
        .ok_or_else(|| "ValueError: character mapping must be in range(0x110000)".to_string())
}

fn string_replace(receiver: &str, old: &str, new: &str, count: i64) -> Result<String, String> {
    if count == 0 {
        return Ok(receiver.to_string());
    }

    let limit = limited_replacement_count(count);
    if old.is_empty() {
        return string_replace_empty_needle(receiver, new, limit);
    }

    let receiver_chars = receiver.chars().collect::<Vec<_>>();
    let old_chars = old.chars().collect::<Vec<_>>();
    let mut output = String::new();
    let mut index = 0usize;
    let mut replacements = 0usize;

    while index < receiver_chars.len() {
        if limit.is_none_or(|limit| replacements < limit)
            && index + old_chars.len() <= receiver_chars.len()
            && receiver_chars[index..index + old_chars.len()] == old_chars
        {
            output.push_str(new);
            replacements += 1;
            index += old_chars.len();
        } else {
            output.push(receiver_chars[index]);
            index += 1;
        }
    }

    Ok(output)
}

fn string_replace_empty_needle(
    receiver: &str,
    new: &str,
    limit: Option<usize>,
) -> Result<String, String> {
    let chars = receiver.chars().collect::<Vec<_>>();
    let mut output = String::new();
    let mut replacements = 0usize;

    for ch in chars {
        if limit.is_none_or(|limit| replacements < limit) {
            output.push_str(new);
            replacements += 1;
        }
        output.push(ch);
    }

    if limit.is_none_or(|limit| replacements < limit) {
        output.push_str(new);
    }

    Ok(output)
}

fn limited_replacement_count(count: i64) -> Option<usize> {
    if count < 0 {
        None
    } else {
        Some(usize::try_from(count).unwrap_or(usize::MAX))
    }
}

fn string_replace_count_argument(value: &Value, method: &str) -> Result<i64, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(*value)),
        Value::Number(value) => Ok(*value),
        Value::BigInt(value) => Ok(value.to_i64().unwrap_or_else(|| {
            if value.is_negative() {
                i64::MIN
            } else {
                i64::MAX
            }
        })),
        value => Err(format!(
            "TypeError: {method} count must be an integer, not {}",
            type_name(value)
        )),
    }
}

fn call_str_split_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
    reverse: bool,
) -> Result<Value, String> {
    let (receiver, separator, maxsplit) = str_split_arguments(name, args, keywords)?;
    let parts = match separator {
        Some(separator) => string_split_separator(&receiver, &separator, maxsplit, reverse)?,
        None => string_split_whitespace(&receiver, maxsplit, reverse),
    };
    Ok(list_value(parts.into_iter().map(Value::String).collect()))
}

fn str_split_arguments(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<(String, Option<String>, i64), String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if rest.len() > 2 {
        return Err(format!(
            "TypeError: {method}() expected at most 2 arguments, got {}",
            rest.len()
        ));
    }

    let mut separator = rest.first().cloned();
    let mut maxsplit = rest.get(1).cloned();
    for (keyword, value) in keywords {
        match keyword.as_str() {
            "sep" => {
                if separator.is_some() {
                    return Err(format!(
                        "TypeError: {method}() got multiple values for argument 'sep'"
                    ));
                }
                separator = Some(value);
            }
            "maxsplit" => {
                if maxsplit.is_some() {
                    return Err(format!(
                        "TypeError: {method}() got multiple values for argument 'maxsplit'"
                    ));
                }
                maxsplit = Some(value);
            }
            _ => {
                return Err(format!(
                    "TypeError: {method}() got an unexpected keyword argument '{keyword}'"
                ));
            }
        }
    }

    let separator = match separator {
        None | Some(Value::None) => None,
        Some(Value::String(value)) if value.is_empty() => {
            return Err("ValueError: empty separator".to_string());
        }
        Some(Value::String(value)) => Some(value),
        Some(value) => {
            return Err(format!(
                "TypeError: {method} separator must be str or None, not {}",
                type_name(&value)
            ));
        }
    };
    let maxsplit = match maxsplit {
        Some(value) => string_split_maxsplit_argument(&value, method)?,
        None => -1,
    };

    Ok((receiver.clone(), separator, maxsplit))
}

fn string_split_separator(
    receiver: &str,
    separator: &str,
    maxsplit: i64,
    reverse: bool,
) -> Result<Vec<String>, String> {
    if separator.is_empty() {
        return Err("ValueError: empty separator".to_string());
    }
    if reverse {
        Ok(string_rsplit_separator(receiver, separator, maxsplit))
    } else {
        Ok(string_split_separator_forward(
            receiver, separator, maxsplit,
        ))
    }
}

fn string_split_separator_forward(receiver: &str, separator: &str, maxsplit: i64) -> Vec<String> {
    let receiver_chars = receiver.chars().collect::<Vec<_>>();
    let separator_chars = separator.chars().collect::<Vec<_>>();
    let limit = limited_replacement_count(maxsplit);
    if matches!(limit, Some(0)) {
        return vec![receiver.to_string()];
    }

    let mut parts = Vec::new();
    let mut start = 0usize;
    let mut index = 0usize;
    let mut splits = 0usize;
    while index + separator_chars.len() <= receiver_chars.len() {
        if limit.is_some_and(|limit| splits >= limit) {
            break;
        }
        if receiver_chars[index..index + separator_chars.len()] == separator_chars {
            parts.push(chars_to_string(&receiver_chars[start..index]));
            splits += 1;
            index += separator_chars.len();
            start = index;
        } else {
            index += 1;
        }
    }
    parts.push(chars_to_string(&receiver_chars[start..]));
    parts
}

fn string_rsplit_separator(receiver: &str, separator: &str, maxsplit: i64) -> Vec<String> {
    let receiver_chars = receiver.chars().collect::<Vec<_>>();
    let separator_chars = separator.chars().collect::<Vec<_>>();
    let limit = limited_replacement_count(maxsplit);
    if matches!(limit, Some(0)) {
        return vec![receiver.to_string()];
    }

    let mut parts = Vec::new();
    let mut end = receiver_chars.len();
    let mut search_end = receiver_chars.len();
    let mut splits = 0usize;
    while search_end >= separator_chars.len() {
        if limit.is_some_and(|limit| splits >= limit) {
            break;
        }
        let Some(position) = (0..=search_end - separator_chars.len())
            .rev()
            .find(|position| {
                receiver_chars[*position..*position + separator_chars.len()] == separator_chars
            })
        else {
            break;
        };
        parts.push(chars_to_string(
            &receiver_chars[position + separator_chars.len()..end],
        ));
        splits += 1;
        end = position;
        search_end = position;
    }
    parts.push(chars_to_string(&receiver_chars[..end]));
    parts.reverse();
    parts
}

fn string_split_whitespace(receiver: &str, maxsplit: i64, reverse: bool) -> Vec<String> {
    if reverse {
        string_rsplit_whitespace(receiver, maxsplit)
    } else {
        string_split_whitespace_forward(receiver, maxsplit)
    }
}

fn string_split_whitespace_forward(receiver: &str, maxsplit: i64) -> Vec<String> {
    let chars = receiver.chars().collect::<Vec<_>>();
    let limit = limited_replacement_count(maxsplit);
    let mut parts = Vec::new();
    let mut index = 0usize;
    let mut splits = 0usize;

    while index < chars.len() && chars[index].is_whitespace() {
        index += 1;
    }

    while index < chars.len() {
        if limit.is_some_and(|limit| splits >= limit) {
            parts.push(chars_to_string(&chars[index..]));
            return parts;
        }

        let start = index;
        while index < chars.len() && !chars[index].is_whitespace() {
            index += 1;
        }
        parts.push(chars_to_string(&chars[start..index]));

        while index < chars.len() && chars[index].is_whitespace() {
            index += 1;
        }
        if index < chars.len() {
            splits += 1;
        }
    }

    parts
}

fn string_rsplit_whitespace(receiver: &str, maxsplit: i64) -> Vec<String> {
    let chars = receiver.chars().collect::<Vec<_>>();
    let limit = limited_replacement_count(maxsplit);
    let mut parts = Vec::new();
    let mut end = chars.len();
    let mut splits = 0usize;

    while end > 0 && chars[end - 1].is_whitespace() {
        end -= 1;
    }

    while end > 0 {
        if limit.is_some_and(|limit| splits >= limit) {
            parts.push(chars_to_string(&chars[..end]));
            parts.reverse();
            return parts;
        }

        let part_end = end;
        while end > 0 && !chars[end - 1].is_whitespace() {
            end -= 1;
        }
        parts.push(chars_to_string(&chars[end..part_end]));

        while end > 0 && chars[end - 1].is_whitespace() {
            end -= 1;
        }
        if end > 0 {
            splits += 1;
        }
    }

    parts.reverse();
    parts
}

fn string_split_maxsplit_argument(value: &Value, method: &str) -> Result<i64, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(*value)),
        Value::Number(value) => Ok(*value),
        Value::BigInt(value) => Ok(value.to_i64().unwrap_or_else(|| {
            if value.is_negative() {
                i64::MIN
            } else {
                i64::MAX
            }
        })),
        value => Err(format!(
            "TypeError: {method} maxsplit must be an integer, not {}",
            type_name(value)
        )),
    }
}

fn chars_to_string(chars: &[char]) -> String {
    chars.iter().collect()
}

#[derive(Clone, Copy)]
enum JustifyMode {
    Left,
    Right,
    Center,
}

fn call_str_justify_method(
    name: &str,
    args: Vec<Value>,
    mode: JustifyMode,
) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if rest.is_empty() {
        return Err(format!(
            "TypeError: {method}() expected at least 1 argument, got 0"
        ));
    }
    if rest.len() > 2 {
        return Err(format!(
            "TypeError: {method}() expected at most 2 arguments, got {}",
            rest.len()
        ));
    }

    let width = string_width_argument(&rest[0], method)?;
    let fill = match rest.get(1) {
        Some(value) => string_fill_character(value, method)?,
        None => ' ',
    };
    let length = receiver.chars().count();
    if width <= length {
        return Ok(Value::String(receiver.clone()));
    }

    let padding = width - length;
    let (left, right) = match mode {
        JustifyMode::Left => (0, padding),
        JustifyMode::Right => (padding, 0),
        JustifyMode::Center => (padding / 2, padding - padding / 2),
    };
    Ok(Value::String(format!(
        "{}{}{}",
        fill.to_string().repeat(left),
        receiver,
        fill.to_string().repeat(right)
    )))
}

fn call_str_zfill_method(name: &str, args: Vec<Value>) -> Result<Value, String> {
    let [Value::String(receiver), width] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected 1 argument, got {}",
            method_display_name(name),
            method_arg_count(&args)
        ));
    };
    let width = string_width_argument(width, method_display_name(name))?;
    let length = receiver.chars().count();
    if width <= length {
        return Ok(Value::String(receiver.clone()));
    }

    let zeros = "0".repeat(width - length);
    if let Some(sign) = receiver.chars().next()
        && matches!(sign, '+' | '-')
    {
        let rest: String = receiver.chars().skip(1).collect();
        return Ok(Value::String(format!("{sign}{zeros}{rest}")));
    }

    Ok(Value::String(format!("{zeros}{receiver}")))
}

fn string_width_argument(value: &Value, method: &str) -> Result<usize, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(*value) as usize),
        Value::Number(value) if *value <= 0 => Ok(0),
        Value::Number(value) => {
            usize::try_from(*value).map_err(|_| format!("{method} width is too large"))
        }
        Value::BigInt(value) if value.is_negative() => Ok(0),
        Value::BigInt(value) => value
            .to_usize()
            .ok_or_else(|| format!("{method} width is too large")),
        value => Err(format!(
            "TypeError: {method} width must be an integer, not {}",
            type_name(value)
        )),
    }
}

fn string_fill_character(value: &Value, method: &str) -> Result<char, String> {
    let Value::String(fill) = value else {
        return Err(format!(
            "TypeError: {method} fill character must be str, not {}",
            type_name(value)
        ));
    };
    let mut chars = fill.chars();
    let Some(fill) = chars.next() else {
        return Err("TypeError: The fill character must be exactly one character long".to_string());
    };
    if chars.next().is_some() {
        return Err("TypeError: The fill character must be exactly one character long".to_string());
    }
    Ok(fill)
}

fn call_str_strip_method(
    name: &str,
    args: Vec<Value>,
    strip_left: bool,
    strip_right: bool,
) -> Result<Value, String> {
    let [Value::String(receiver), rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected a str receiver",
            method_display_name(name)
        ));
    };
    let method = method_display_name(name);
    if rest.len() > 1 {
        return Err(format!(
            "TypeError: {method}() expected at most 1 argument, got {}",
            rest.len()
        ));
    }

    let stripped = match rest.first() {
        None | Some(Value::None) => {
            string_strip_by(receiver, strip_left, strip_right, |ch| ch.is_whitespace())
        }
        Some(Value::String(chars)) => {
            let strip_chars = chars.chars().collect::<Vec<_>>();
            string_strip_by(receiver, strip_left, strip_right, |ch| {
                strip_chars.contains(&ch)
            })
        }
        Some(value) => {
            return Err(format!(
                "TypeError: {method} arg must be None or str, not {}",
                type_name(value)
            ));
        }
    };

    Ok(Value::String(stripped))
}

fn string_strip_by(
    receiver: &str,
    strip_left: bool,
    strip_right: bool,
    should_strip: impl Fn(char) -> bool,
) -> String {
    let chars = receiver.chars().collect::<Vec<_>>();
    let mut start = 0usize;
    let mut end = chars.len();

    if strip_left {
        while start < end && should_strip(chars[start]) {
            start += 1;
        }
    }

    if strip_right {
        while end > start && should_strip(chars[end - 1]) {
            end -= 1;
        }
    }

    chars_to_string(&chars[start..end])
}

fn str_prefix_suffix_values(value: &Value, method: &str) -> Result<Vec<String>, String> {
    match value {
        Value::String(value) => Ok(vec![value.clone()]),
        Value::Tuple(items) => items
            .iter()
            .map(|item| match item {
                Value::String(value) => Ok(value.clone()),
                value => Err(format!(
                    "TypeError: {method} first arg must be str or a tuple of str, not {}",
                    type_name(value)
                )),
            })
            .collect(),
        value => Err(format!(
            "TypeError: {method} first arg must be str or a tuple of str, not {}",
            type_name(value)
        )),
    }
}

fn string_search_bounds(args: &[Value], len: usize, method: &str) -> Result<(i64, i64), String> {
    let len = i64::try_from(len).map_err(|_| "string is too large".to_string())?;
    let start = match args.first() {
        Some(value) => string_bound_argument(value, 0, method)?,
        None => 0,
    };
    let stop = match args.get(1) {
        Some(value) => string_bound_argument(value, len, method)?,
        None => len,
    };
    Ok((
        normalize_string_start_bound(start, len),
        normalize_string_stop_bound(stop, len),
    ))
}

fn normalize_string_start_bound(value: i64, len: i64) -> i64 {
    if value < 0 {
        (value + len).max(0)
    } else {
        value
    }
}

fn normalize_string_stop_bound(value: i64, len: i64) -> i64 {
    if value < 0 {
        (value + len).max(0)
    } else {
        value.min(len)
    }
}

fn string_bound_argument(value: &Value, default: i64, method: &str) -> Result<i64, String> {
    match value {
        Value::None => Ok(default),
        Value::Bool(value) => Ok(bool_as_i64(*value)),
        Value::Number(value) => Ok(*value),
        Value::BigInt(value) => Ok(value.to_i64().unwrap_or_else(|| {
            if value.is_negative() {
                i64::MIN
            } else {
                i64::MAX
            }
        })),
        value => Err(format!(
            "TypeError: {method} slice indices must be integers or None, got {}",
            type_name(value)
        )),
    }
}

fn call_int_method(name: &str, args: Vec<Value>) -> Result<Value, String> {
    match name {
        "int.bit_length" => {
            let [receiver] = args.as_slice() else {
                return Err(format!(
                    "bit_length() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(normalize_big_int(BigInt::from(
                integer_magnitude(receiver)?.bits(),
            )))
        }
        "int.bit_count" => {
            let [receiver] = args.as_slice() else {
                return Err(format!(
                    "bit_count() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(normalize_big_int(BigInt::from(
                integer_magnitude(receiver)?.count_ones(),
            )))
        }
        "int.conjugate" => {
            let [receiver] = args.as_slice() else {
                return Err(format!(
                    "conjugate() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            integer_value(receiver.clone())
        }
        "int.as_integer_ratio" => {
            let [receiver] = args.as_slice() else {
                return Err(format!(
                    "as_integer_ratio() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(tuple_value(vec![
                integer_value(receiver.clone())?,
                Value::Number(1),
            ]))
        }
        _ => Err(format!("unknown builtin: {name}")),
    }
}

fn integer_value(value: Value) -> Result<Value, String> {
    match value {
        Value::Bool(value) => Ok(Value::Number(bool_as_i64(value))),
        value @ (Value::Number(_) | Value::BigInt(_)) => Ok(value),
        value => Err(format!(
            "int method receiver must be int, got {}",
            type_name(&value)
        )),
    }
}

fn integer_magnitude(value: &Value) -> Result<num_bigint::BigUint, String> {
    match value {
        Value::Bool(value) => Ok(BigInt::from(bool_as_i64(*value)).magnitude().clone()),
        Value::Number(value) => Ok(BigInt::from(*value).magnitude().clone()),
        Value::BigInt(value) => Ok(value.magnitude().clone()),
        value => Err(format!(
            "int method receiver must be int, got {}",
            type_name(value)
        )),
    }
}

fn call_float_method(name: &str, args: Vec<Value>) -> Result<Value, String> {
    match name {
        "float.conjugate" => {
            let [Value::Float(value)] = args.as_slice() else {
                return Err(format!(
                    "conjugate() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(Value::Float(*value))
        }
        "float.is_integer" => {
            let [Value::Float(value)] = args.as_slice() else {
                return Err(format!(
                    "is_integer() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(Value::Bool(value.is_finite() && value.fract() == 0.0))
        }
        "float.as_integer_ratio" => {
            let [Value::Float(value)] = args.as_slice() else {
                return Err(format!(
                    "as_integer_ratio() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            float_as_integer_ratio(*value)
        }
        _ => Err(format!("unknown builtin: {name}")),
    }
}

fn float_as_integer_ratio(value: f64) -> Result<Value, String> {
    if value.is_nan() {
        return Err("ValueError: cannot convert NaN to integer ratio".to_string());
    }
    if value.is_infinite() {
        return Err("OverflowError: cannot convert Infinity to integer ratio".to_string());
    }
    if value == 0.0 {
        return Ok(tuple_value(vec![Value::Number(0), Value::Number(1)]));
    }

    let bits = value.to_bits();
    let negative = (bits >> 63) != 0;
    let exponent_bits = ((bits >> 52) & 0x7ff) as i32;
    let mut mantissa = bits & ((1_u64 << 52) - 1);
    let mut exponent = if exponent_bits == 0 {
        1 - 1023 - 52
    } else {
        mantissa |= 1_u64 << 52;
        exponent_bits - 1023 - 52
    };

    if exponent < 0 {
        let reduction = mantissa.trailing_zeros().min((-exponent) as u32);
        mantissa >>= reduction;
        exponent += reduction as i32;
    }

    let mut numerator = BigInt::from(mantissa);
    if negative {
        numerator = -numerator;
    }

    let (numerator, denominator) = if exponent >= 0 {
        (numerator << exponent as usize, BigInt::from(1))
    } else {
        (numerator, BigInt::from(1) << (-exponent) as usize)
    };

    Ok(tuple_value(vec![
        normalize_big_int(numerator),
        normalize_big_int(denominator),
    ]))
}

fn call_list_method(name: &str, args: Vec<Value>) -> Result<Value, String> {
    match name {
        "list.append" => {
            let [Value::List(items), item] = args.as_slice() else {
                return Err(format!(
                    "append() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            items.borrow_mut().push(item.clone());
            Ok(Value::None)
        }
        "list.extend" => {
            let [Value::List(items), iterable] = args.as_slice() else {
                return Err(format!(
                    "extend() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let values = sequence_values(iterable.clone())?;
            items.borrow_mut().extend(values);
            Ok(Value::None)
        }
        "list.clear" => {
            let [Value::List(items)] = args.as_slice() else {
                return Err(format!(
                    "clear() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            items.borrow_mut().clear();
            Ok(Value::None)
        }
        "list.copy" => {
            let [Value::List(items)] = args.as_slice() else {
                return Err(format!(
                    "copy() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(list_value(items.borrow().clone()))
        }
        "list.__contains__" => {
            let [Value::List(items), needle] = args.as_slice() else {
                return Err(format!(
                    "__contains__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(Value::Bool(
                items.borrow().iter().any(|item| item == needle),
            ))
        }
        "list.__delitem__" => {
            let [list @ Value::List(_), index] = args.as_slice() else {
                return Err(format!(
                    "__delitem__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            delete_subscript(list.clone(), index.clone())?;
            Ok(Value::None)
        }
        "list.__getitem__" => {
            let [list @ Value::List(_), index] = args.as_slice() else {
                return Err(format!(
                    "__getitem__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            load_subscript(list.clone(), index.clone())
        }
        "list.__len__" => {
            let [Value::List(items)] = args.as_slice() else {
                return Err(format!(
                    "__len__() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let len = i64::try_from(items.borrow().len())
                .map_err(|_| "len() result is too large".to_string())?;
            Ok(Value::Number(len))
        }
        "list.__setitem__" => {
            let [list @ Value::List(_), index, value] = args.as_slice() else {
                return Err(format!(
                    "__setitem__() expected 2 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            store_subscript(list.clone(), index.clone(), value.clone())?;
            Ok(Value::None)
        }
        "list.count" => {
            let [Value::List(items), needle] = args.as_slice() else {
                return Err(format!(
                    "count() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let count = items.borrow().iter().filter(|item| *item == needle).count();
            let count =
                i64::try_from(count).map_err(|_| "count() result is too large".to_string())?;
            Ok(Value::Number(count))
        }
        "list.index" => {
            let [Value::List(items), needle, rest @ ..] = args.as_slice() else {
                return Err(format!(
                    "index expected at least 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if rest.len() > 2 {
                return Err(format!(
                    "index expected at most 3 arguments, got {}",
                    method_arg_count(&args)
                ));
            }

            let items = items.borrow();
            let len = items.len();
            let (start, stop) = list_search_bounds(rest, len)?;
            let found = items[start..stop]
                .iter()
                .position(|item| item == needle)
                .map(|index| start + index);
            match found {
                Some(index) => {
                    let index = i64::try_from(index)
                        .map_err(|_| "index() result is too large".to_string())?;
                    Ok(Value::Number(index))
                }
                None => Err(format!("ValueError: {needle} is not in list")),
            }
        }
        "list.insert" => {
            let [Value::List(items), index, value] = args.as_slice() else {
                return Err(format!(
                    "insert expected 2 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let index = normalized_insert_index(index, items.borrow().len())?;
            items.borrow_mut().insert(index, value.clone());
            Ok(Value::None)
        }
        "list.reverse" => {
            let [Value::List(items)] = args.as_slice() else {
                return Err(format!(
                    "reverse() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            items.borrow_mut().reverse();
            Ok(Value::None)
        }
        "list.pop" => {
            let [Value::List(items), rest @ ..] = args.as_slice() else {
                return Err("pop() expected a list receiver".to_string());
            };
            if rest.len() > 1 {
                return Err(format!(
                    "pop() expected at most 1 argument, got {}",
                    rest.len()
                ));
            }

            let mut items = items.borrow_mut();
            if items.is_empty() {
                return Err("IndexError: pop from empty list".to_string());
            }
            let index = match rest {
                [] => items.len() - 1,
                [index] => normalized_index(index.clone(), items.len(), "list")?,
                _ => unreachable!("list.pop arity is checked before matching index"),
            };

            Ok(items.remove(index))
        }
        "list.remove" => {
            let [Value::List(items), needle] = args.as_slice() else {
                return Err(format!(
                    "remove() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let mut items = items.borrow_mut();
            let Some(index) = items.iter().position(|item| item == needle) else {
                return Err("ValueError: list.remove(x): x not in list".to_string());
            };
            items.remove(index);
            Ok(Value::None)
        }
        _ => Err(format!("unknown builtin: {name}")),
    }
}

fn call_dict_method(
    vm: &mut Vm,
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    match name {
        "dict.clear" => {
            reject_method_keywords(name, &keywords)?;
            let [receiver] = args.as_slice() else {
                return Err(format!(
                    "clear() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let Some(entries) = dict_receiver_entries(receiver) else {
                return Err("clear() expected a dict receiver".to_string());
            };
            let mut entries = entries.borrow_mut();
            if !entries.is_empty() {
                entries.clear();
                mark_dict_changed(&mut entries);
            }
            Ok(Value::None)
        }
        "dict.copy" => {
            reject_method_keywords(name, &keywords)?;
            let [receiver] = args.as_slice() else {
                return Err(format!(
                    "copy() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let Some(entries) = dict_receiver_entries(receiver) else {
                return Err("copy() expected a dict receiver".to_string());
            };
            build_dict(entries.borrow().clone())
        }
        "dict.__contains__" => {
            reject_method_keywords(name, &keywords)?;
            let [dict, key] = args.as_slice() else {
                return Err(format!(
                    "__contains__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if dict_receiver_entries(dict).is_none() {
                return Err("__contains__() expected a dict receiver".to_string());
            }
            Ok(Value::Bool(contains_value(key.clone(), dict.clone())?))
        }
        "dict.__delitem__" => {
            reject_method_keywords(name, &keywords)?;
            let [dict @ Value::Dict(_), key] = args.as_slice() else {
                return Err(format!(
                    "__delitem__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            delete_subscript(dict.clone(), key.clone())?;
            Ok(Value::None)
        }
        "dict.__getitem__" => {
            reject_method_keywords(name, &keywords)?;
            let [dict, key] = args.as_slice() else {
                return Err(format!(
                    "__getitem__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if let Some(entries) = dict_subclass_entries(dict) {
                vm.load_dict_subclass_subscript(dict.clone(), entries, key.clone())
            } else if matches!(dict, Value::Dict(_)) {
                load_subscript(dict.clone(), key.clone())
            } else {
                Err("__getitem__() expected a dict receiver".to_string())
            }
        }
        "dict.__len__" => {
            reject_method_keywords(name, &keywords)?;
            let [dict] = args.as_slice() else {
                return Err(format!(
                    "__len__() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            if dict_receiver_entries(dict).is_none() {
                return Err("__len__() expected a dict receiver".to_string());
            }
            let len = i64::try_from(value_len(dict)?)
                .map_err(|_| "len() result is too large".to_string())?;
            Ok(Value::Number(len))
        }
        "dict.__setitem__" => {
            reject_method_keywords(name, &keywords)?;
            let [dict @ Value::Dict(_), key, value] = args.as_slice() else {
                return Err(format!(
                    "__setitem__() expected 2 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            store_subscript(dict.clone(), key.clone(), value.clone())?;
            Ok(Value::None)
        }
        "dict.get" => {
            reject_method_keywords(name, &keywords)?;
            let [receiver, key, rest @ ..] = args.as_slice() else {
                return Err("get() expected a dict receiver".to_string());
            };
            let Some(entries) = dict_receiver_entries(receiver) else {
                return Err("get() expected a dict receiver".to_string());
            };
            if rest.len() > 1 {
                return Err(format!(
                    "get() expected at most 2 arguments, got {}",
                    rest.len() + 1
                ));
            }
            ensure_hashable_key(key)?;
            let default = rest.first().cloned().unwrap_or(Value::None);
            Ok(entries
                .borrow()
                .iter()
                .find(|(existing_key, _)| dict_keys_equal(existing_key, key))
                .map(|(_, value)| value.clone())
                .unwrap_or(default))
        }
        "dict.items" => {
            reject_method_keywords(name, &keywords)?;
            let [receiver] = args.as_slice() else {
                return Err(format!(
                    "items() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let Some(entries) = dict_receiver_entries(receiver) else {
                return Err("items() expected a dict receiver".to_string());
            };
            Ok(dict_view_value(DictViewKind::Items, entries.clone()))
        }
        "dict.keys" => {
            reject_method_keywords(name, &keywords)?;
            let [receiver] = args.as_slice() else {
                return Err(format!(
                    "keys() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let Some(entries) = dict_receiver_entries(receiver) else {
                return Err("keys() expected a dict receiver".to_string());
            };
            Ok(dict_view_value(DictViewKind::Keys, entries.clone()))
        }
        "dict.pop" => {
            reject_method_keywords(name, &keywords)?;
            let [Value::Dict(entries), key, rest @ ..] = args.as_slice() else {
                return Err("pop() expected a dict receiver".to_string());
            };
            if rest.len() > 1 {
                return Err(format!(
                    "pop() expected at most 2 arguments, got {}",
                    rest.len() + 1
                ));
            }
            ensure_hashable_key(key)?;
            let mut entries = entries.borrow_mut();
            if let Some(position) = entries
                .iter()
                .position(|(existing_key, _)| dict_keys_equal(existing_key, key))
            {
                let (_, value) = entries.remove(position);
                mark_dict_changed(&mut entries);
                return Ok(value);
            }
            if let Some(default) = rest.first() {
                return Ok(default.clone());
            }
            Err(format!("KeyError: {}", format_key_error(key)))
        }
        "dict.popitem" => {
            reject_method_keywords(name, &keywords)?;
            let [Value::Dict(entries)] = args.as_slice() else {
                return Err(format!(
                    "popitem() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let mut entries = entries.borrow_mut();
            let Some((key, value)) = entries.pop() else {
                return Err("KeyError: popitem(): dictionary is empty".to_string());
            };
            mark_dict_changed(&mut entries);
            Ok(tuple_value(vec![key, value]))
        }
        "dict.setdefault" => {
            reject_method_keywords(name, &keywords)?;
            let [Value::Dict(entries), key, rest @ ..] = args.as_slice() else {
                return Err("setdefault() expected a dict receiver".to_string());
            };
            if rest.len() > 1 {
                return Err(format!(
                    "setdefault() expected at most 2 arguments, got {}",
                    rest.len() + 1
                ));
            }
            ensure_hashable_key(key)?;
            if let Some((_, value)) = entries
                .borrow()
                .iter()
                .find(|(existing_key, _)| dict_keys_equal(existing_key, key))
            {
                return Ok(value.clone());
            }

            let default = rest.first().cloned().unwrap_or(Value::None);
            insert_live_dict_entry(&mut entries.borrow_mut(), key.clone(), default.clone())?;
            Ok(default)
        }
        "dict.update" => {
            let [Value::Dict(entries), rest @ ..] = args.as_slice() else {
                return Err("update() expected a dict receiver".to_string());
            };
            if rest.len() > 1 {
                return Err(format!(
                    "update() expected at most 1 argument, got {}",
                    rest.len()
                ));
            }

            let mut updates = Vec::new();
            if let Some(source) = rest.first() {
                updates.extend(vm.dict_entries_from_update_source(source.clone())?);
            }
            updates.extend(
                keywords
                    .into_iter()
                    .map(|(key, value)| (Value::String(key), value)),
            );

            let mut entries = entries.borrow_mut();
            for (key, value) in updates {
                insert_live_dict_entry(&mut entries, key, value)?;
            }
            Ok(Value::None)
        }
        "dict.values" => {
            reject_method_keywords(name, &keywords)?;
            let [receiver] = args.as_slice() else {
                return Err(format!(
                    "values() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let Some(entries) = dict_receiver_entries(receiver) else {
                return Err("values() expected a dict receiver".to_string());
            };
            Ok(dict_view_value(DictViewKind::Values, entries.clone()))
        }
        _ => Err(format!("unknown builtin: {name}")),
    }
}

fn dict_receiver_entries(value: &Value) -> Option<DictRef> {
    match value {
        Value::Dict(entries) => Some(entries.clone()),
        value => dict_subclass_entries(value),
    }
}

fn set_receiver_items(value: &Value) -> Option<SetRef> {
    match value {
        Value::Set(items) => Some(items.clone()),
        value => set_subclass_items(value),
    }
}

fn frozen_set_receiver_items(value: &Value) -> Option<FrozenSetRef> {
    match value {
        Value::FrozenSet(items) => Some(items.clone()),
        value => frozen_set_subclass_items(value),
    }
}

fn set_subclass_instance(
    name: String,
    _type_params: Vec<Value>,
    attrs: Scope,
    bases: Vec<Value>,
    storage: Value,
) -> Value {
    let fields = new_scope();
    fields
        .borrow_mut()
        .insert(SET_SUBCLASS_STORAGE_FIELD.to_string(), storage);
    Value::Instance {
        class_name: name,
        fields,
        class_attrs: attrs,
        class_bases: bases,
    }
}

fn frozen_set_subclass_instance(
    name: String,
    _type_params: Vec<Value>,
    attrs: Scope,
    bases: Vec<Value>,
    storage: Value,
) -> Value {
    let fields = new_scope();
    fields
        .borrow_mut()
        .insert(FROZEN_SET_SUBCLASS_STORAGE_FIELD.to_string(), storage);
    Value::Instance {
        class_name: name,
        fields,
        class_attrs: attrs,
        class_bases: bases,
    }
}

fn normalize_set_method_args(mut args: Vec<Value>) -> Vec<Value> {
    if let Some(items) = args.first().and_then(set_receiver_items) {
        args[0] = Value::Set(items);
    }
    args
}

fn normalize_frozen_set_method_args(mut args: Vec<Value>) -> Vec<Value> {
    if let Some(items) = args.first().and_then(frozen_set_receiver_items) {
        args[0] = Value::FrozenSet(items);
    }
    args
}

fn call_set_method(vm: &mut Vm, name: &str, args: Vec<Value>) -> Result<Value, String> {
    let args = normalize_set_method_args(args);
    match name {
        "set.add" => {
            let [Value::Set(items), item] = args.as_slice() else {
                return Err(format!(
                    "add() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            vm.insert_live_set_item(items, item.clone())?;
            Ok(Value::None)
        }
        "set.clear" => {
            let [Value::Set(items)] = args.as_slice() else {
                return Err(format!(
                    "clear() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            items.borrow_mut().clear();
            Ok(Value::None)
        }
        "set.copy" => {
            let [Value::Set(items)] = args.as_slice() else {
                return Err(format!(
                    "copy() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(set_value(items.borrow().clone()))
        }
        "set.__init__" => {
            let [Value::Set(items), values @ ..] = args.as_slice() else {
                return Err("__init__() expected a set receiver".to_string());
            };
            if values.len() > 1 {
                return Err(format!(
                    "__init__() expected at most 1 argument, got {}",
                    method_arg_count(&args)
                ));
            }

            items.borrow_mut().clear();
            if let [iterable] = values {
                for value in vm.collect_iterable_values_propagating(iterable.clone())? {
                    vm.insert_live_set_item(items, value)?;
                }
            }
            Ok(Value::None)
        }
        "set.__new__" => {
            let Some((class, _values)) = args.split_first() else {
                return Err("__new__() missing required argument 'type'".to_string());
            };
            match class {
                Value::Builtin(name) if name == "set" => vm.build_set(Vec::new()),
                Value::Class {
                    name,
                    type_params,
                    bases,
                    attrs,
                } if class_bases_include_builtin(bases, "set") => {
                    let storage = vm.build_set(Vec::new())?;
                    Ok(set_subclass_instance(
                        name.clone(),
                        type_params.clone(),
                        attrs.clone(),
                        bases.clone(),
                        storage,
                    ))
                }
                value => Err(format!(
                    "TypeError: set.__new__() argument 1 must be a set subtype, not {}",
                    type_name(value)
                )),
            }
        }
        "set.__and__" => {
            let [set @ Value::Set(_), other] = args.as_slice() else {
                return Err(format!(
                    "__and__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_set_operator_value(other) {
                return Ok(Value::NotImplemented);
            }
            vm.bit_and_values(set.clone(), other.clone())
        }
        "set.__contains__" => {
            let [set @ Value::Set(_), item] = args.as_slice() else {
                return Err(format!(
                    "__contains__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(Value::Bool(vm.contains_value(item.clone(), set.clone())?))
        }
        "set.__eq__" => {
            let [set @ Value::Set(_), other] = args.as_slice() else {
                return Err(format!(
                    "__eq__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_set_operator_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(vm.equal_values(set.clone(), other.clone())?))
        }
        "set.__ge__" => {
            let [set @ Value::Set(_), other] = args.as_slice() else {
                return Err(format!(
                    "__ge__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_set_operator_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(
                vm.greater_equal_values(set.clone(), other.clone())?,
            ))
        }
        "set.__gt__" => {
            let [set @ Value::Set(_), other] = args.as_slice() else {
                return Err(format!(
                    "__gt__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_set_operator_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(vm.greater_values(set.clone(), other.clone())?))
        }
        "set.__le__" => {
            let [set @ Value::Set(_), other] = args.as_slice() else {
                return Err(format!(
                    "__le__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_set_operator_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(
                vm.less_equal_values(set.clone(), other.clone())?,
            ))
        }
        "set.__len__" => {
            let [set @ Value::Set(_)] = args.as_slice() else {
                return Err(format!(
                    "__len__() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let len = i64::try_from(value_len(set)?)
                .map_err(|_| "len() result is too large".to_string())?;
            Ok(Value::Number(len))
        }
        "set.__lt__" => {
            let [set @ Value::Set(_), other] = args.as_slice() else {
                return Err(format!(
                    "__lt__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_set_operator_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(vm.less_values(set.clone(), other.clone())?))
        }
        "set.__ne__" => {
            let [set @ Value::Set(_), other] = args.as_slice() else {
                return Err(format!(
                    "__ne__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_set_operator_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(!vm.equal_values(set.clone(), other.clone())?))
        }
        "set.__or__" => {
            let [set @ Value::Set(_), other] = args.as_slice() else {
                return Err(format!(
                    "__or__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_set_operator_value(other) {
                return Ok(Value::NotImplemented);
            }
            vm.bit_or_values(set.clone(), other.clone())
        }
        "set.__sub__" => {
            let [set @ Value::Set(_), other] = args.as_slice() else {
                return Err(format!(
                    "__sub__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_set_operator_value(other) {
                return Ok(Value::NotImplemented);
            }
            vm.subtract_values(set.clone(), other.clone())
        }
        "set.__xor__" => {
            let [set @ Value::Set(_), other] = args.as_slice() else {
                return Err(format!(
                    "__xor__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_set_operator_value(other) {
                return Ok(Value::NotImplemented);
            }
            vm.bit_xor_values(set.clone(), other.clone())
        }
        "set.difference" => {
            let [Value::Set(items), iterables @ ..] = args.as_slice() else {
                return Err("difference() expected a set receiver".to_string());
            };
            let snapshot = items.borrow().clone();
            vm.set_difference_from_iterables_with_kind(SetResultKind::Set, snapshot, iterables)
        }
        "set.difference_update" => {
            let [Value::Set(items), iterables @ ..] = args.as_slice() else {
                return Err("difference_update() expected a set receiver".to_string());
            };
            let snapshot = items.borrow().clone();
            let Value::Set(result) = vm.set_difference_from_iterables_with_kind(
                SetResultKind::Set,
                snapshot,
                iterables,
            )?
            else {
                unreachable!("set_difference_from_iterables returns a set");
            };
            *items.borrow_mut() = result.borrow().clone();
            Ok(Value::None)
        }
        "set.discard" => {
            let [Value::Set(items), item] = args.as_slice() else {
                return Err(format!(
                    "discard() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let snapshot = items.borrow().clone();
            let position = vm.set_lookup_position(&snapshot, item)?;
            if let Some(position) = position {
                let mut items = items.borrow_mut();
                if position < items.len() {
                    items.remove(position);
                }
            }
            Ok(Value::None)
        }
        "set.intersection" => {
            let [Value::Set(items), iterables @ ..] = args.as_slice() else {
                return Err("intersection() expected a set receiver".to_string());
            };
            let snapshot = items.borrow().clone();
            vm.set_intersection_from_iterables_with_kind(SetResultKind::Set, snapshot, iterables)
        }
        "set.intersection_update" => {
            let [Value::Set(items), iterables @ ..] = args.as_slice() else {
                return Err("intersection_update() expected a set receiver".to_string());
            };
            let snapshot = items.borrow().clone();
            let Value::Set(result) = vm.set_intersection_from_iterables_with_kind(
                SetResultKind::Set,
                snapshot,
                iterables,
            )?
            else {
                unreachable!("set_intersection_from_iterables returns a set");
            };
            *items.borrow_mut() = result.borrow().clone();
            Ok(Value::None)
        }
        "set.isdisjoint" => {
            let [Value::Set(items), iterable] = args.as_slice() else {
                return Err(format!(
                    "isdisjoint() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let snapshot = items.borrow().clone();
            Ok(Value::Bool(vm.set_is_disjoint_from_iterable(
                &snapshot,
                iterable.clone(),
            )?))
        }
        "set.issubset" => {
            let [Value::Set(items), iterable] = args.as_slice() else {
                return Err(format!(
                    "issubset() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let snapshot = items.borrow().clone();
            Ok(Value::Bool(
                vm.set_is_subset_of_iterable(&snapshot, iterable.clone())?,
            ))
        }
        "set.issuperset" => {
            let [Value::Set(items), iterable] = args.as_slice() else {
                return Err(format!(
                    "issuperset() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let snapshot = items.borrow().clone();
            Ok(Value::Bool(vm.set_is_superset_of_iterable(
                &snapshot,
                iterable.clone(),
            )?))
        }
        "set.pop" => {
            let [Value::Set(items)] = args.as_slice() else {
                return Err(format!(
                    "pop() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let mut items = items.borrow_mut();
            if items.is_empty() {
                return Err("KeyError: pop from an empty set".to_string());
            }
            Ok(items.remove(0))
        }
        "set.remove" => {
            let [Value::Set(items), item] = args.as_slice() else {
                return Err(format!(
                    "remove() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let snapshot = items.borrow().clone();
            let position = vm.set_lookup_position(&snapshot, item)?;
            if let Some(position) = position {
                let mut items = items.borrow_mut();
                if position < items.len() {
                    items.remove(position);
                }
                Ok(Value::None)
            } else {
                raise_key_error_value(vm, item.clone())
            }
        }
        "set.symmetric_difference" => {
            let [Value::Set(items), iterable] = args.as_slice() else {
                return Err(format!(
                    "symmetric_difference() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let snapshot = items.borrow().clone();
            vm.set_symmetric_difference_from_iterable_with_kind(
                SetResultKind::Set,
                snapshot,
                iterable,
            )
        }
        "set.symmetric_difference_update" => {
            let [Value::Set(items), iterable] = args.as_slice() else {
                return Err(format!(
                    "symmetric_difference_update() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let snapshot = items.borrow().clone();
            let Value::Set(result) = vm.set_symmetric_difference_from_iterable_with_kind(
                SetResultKind::Set,
                snapshot,
                iterable,
            )?
            else {
                unreachable!("set_symmetric_difference_from_iterable returns a set");
            };
            *items.borrow_mut() = result.borrow().clone();
            Ok(Value::None)
        }
        "set.union" => {
            let [Value::Set(items), iterables @ ..] = args.as_slice() else {
                return Err("union() expected a set receiver".to_string());
            };
            let snapshot = items.borrow().clone();
            vm.set_union_from_iterables_with_kind(SetResultKind::Set, snapshot, iterables)
        }
        "set.update" => {
            let [Value::Set(items), iterables @ ..] = args.as_slice() else {
                return Err("update() expected a set receiver".to_string());
            };
            let mut updates = Vec::new();
            for iterable in iterables {
                updates.extend(vm.collect_iterable_values_propagating(iterable.clone())?);
            }

            for value in updates {
                vm.insert_live_set_item(items, value)?;
            }
            Ok(Value::None)
        }
        _ => Err(format!("unknown builtin: {name}")),
    }
}

fn call_frozen_set_method(vm: &mut Vm, name: &str, args: Vec<Value>) -> Result<Value, String> {
    let args = normalize_frozen_set_method_args(args);
    match name {
        "frozenset.copy" => {
            let [Value::FrozenSet(items)] = args.as_slice() else {
                return Err(format!(
                    "copy() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(Value::FrozenSet(items.clone()))
        }
        "frozenset.__and__" => {
            let [set @ Value::FrozenSet(_), other] = args.as_slice() else {
                return Err(format!(
                    "__and__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_exact_set_value(other) {
                return Ok(Value::NotImplemented);
            }
            vm.bit_and_values(set.clone(), other.clone())
        }
        "frozenset.__contains__" => {
            let [set @ Value::FrozenSet(_), item] = args.as_slice() else {
                return Err(format!(
                    "__contains__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(Value::Bool(vm.contains_value(item.clone(), set.clone())?))
        }
        "frozenset.__eq__" => {
            let [set @ Value::FrozenSet(_), other] = args.as_slice() else {
                return Err(format!(
                    "__eq__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_exact_set_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(vm.equal_values(set.clone(), other.clone())?))
        }
        "frozenset.__ge__" => {
            let [set @ Value::FrozenSet(_), other] = args.as_slice() else {
                return Err(format!(
                    "__ge__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_exact_set_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(
                vm.greater_equal_values(set.clone(), other.clone())?,
            ))
        }
        "frozenset.__gt__" => {
            let [set @ Value::FrozenSet(_), other] = args.as_slice() else {
                return Err(format!(
                    "__gt__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_exact_set_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(vm.greater_values(set.clone(), other.clone())?))
        }
        "frozenset.__hash__" => {
            let [set @ Value::FrozenSet(_)] = args.as_slice() else {
                return Err(format!(
                    "__hash__() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            hash_value(set)
        }
        "frozenset.__init__" => {
            let [Value::FrozenSet(_), ..] = args.as_slice() else {
                return Err("__init__() expected a frozenset receiver".to_string());
            };
            Ok(Value::None)
        }
        "frozenset.__new__" => {
            let Some((class, values)) = args.split_first() else {
                return Err("__new__() missing required argument 'type'".to_string());
            };
            if values.len() > 1 {
                return Err(format!(
                    "{} expected at most 1 argument, got {}",
                    class_display_name(class),
                    values.len()
                ));
            }
            let storage = match values {
                [] => vm.build_frozen_set(Vec::new())?,
                [iterable] => vm.call_frozen_set(vec![iterable.clone()])?,
                _ => unreachable!("values length checked above"),
            };
            match class {
                Value::Builtin(name) if name == "frozenset" => Ok(storage),
                Value::Class {
                    name,
                    type_params,
                    bases,
                    attrs,
                } if class_bases_include_builtin(bases, "frozenset") => {
                    Ok(frozen_set_subclass_instance(
                        name.clone(),
                        type_params.clone(),
                        attrs.clone(),
                        bases.clone(),
                        storage,
                    ))
                }
                value => Err(format!(
                    "TypeError: frozenset.__new__() argument 1 must be a frozenset subtype, not {}",
                    type_name(value)
                )),
            }
        }
        "frozenset.__le__" => {
            let [set @ Value::FrozenSet(_), other] = args.as_slice() else {
                return Err(format!(
                    "__le__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_exact_set_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(
                vm.less_equal_values(set.clone(), other.clone())?,
            ))
        }
        "frozenset.__len__" => {
            let [set @ Value::FrozenSet(_)] = args.as_slice() else {
                return Err(format!(
                    "__len__() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            };
            let len = i64::try_from(value_len(set)?)
                .map_err(|_| "len() result is too large".to_string())?;
            Ok(Value::Number(len))
        }
        "frozenset.__lt__" => {
            let [set @ Value::FrozenSet(_), other] = args.as_slice() else {
                return Err(format!(
                    "__lt__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_exact_set_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(vm.less_values(set.clone(), other.clone())?))
        }
        "frozenset.__ne__" => {
            let [set @ Value::FrozenSet(_), other] = args.as_slice() else {
                return Err(format!(
                    "__ne__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_exact_set_value(other) {
                return Ok(Value::NotImplemented);
            }
            Ok(Value::Bool(!vm.equal_values(set.clone(), other.clone())?))
        }
        "frozenset.__or__" => {
            let [set @ Value::FrozenSet(_), other] = args.as_slice() else {
                return Err(format!(
                    "__or__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_exact_set_value(other) {
                return Ok(Value::NotImplemented);
            }
            vm.bit_or_values(set.clone(), other.clone())
        }
        "frozenset.__sub__" => {
            let [set @ Value::FrozenSet(_), other] = args.as_slice() else {
                return Err(format!(
                    "__sub__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_exact_set_value(other) {
                return Ok(Value::NotImplemented);
            }
            vm.subtract_values(set.clone(), other.clone())
        }
        "frozenset.__xor__" => {
            let [set @ Value::FrozenSet(_), other] = args.as_slice() else {
                return Err(format!(
                    "__xor__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            if !is_exact_set_value(other) {
                return Ok(Value::NotImplemented);
            }
            vm.bit_xor_values(set.clone(), other.clone())
        }
        "frozenset.difference" => {
            let [Value::FrozenSet(items), iterables @ ..] = args.as_slice() else {
                return Err("difference() expected a frozenset receiver".to_string());
            };
            vm.set_difference_from_iterables_with_kind(
                SetResultKind::FrozenSet,
                items.as_ref().clone(),
                iterables,
            )
        }
        "frozenset.intersection" => {
            let [Value::FrozenSet(items), iterables @ ..] = args.as_slice() else {
                return Err("intersection() expected a frozenset receiver".to_string());
            };
            vm.set_intersection_from_iterables_with_kind(
                SetResultKind::FrozenSet,
                items.as_ref().clone(),
                iterables,
            )
        }
        "frozenset.isdisjoint" => {
            let [Value::FrozenSet(items), iterable] = args.as_slice() else {
                return Err(format!(
                    "isdisjoint() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(Value::Bool(
                vm.set_is_disjoint_from_iterable(items, iterable.clone())?,
            ))
        }
        "frozenset.issubset" => {
            let [Value::FrozenSet(items), iterable] = args.as_slice() else {
                return Err(format!(
                    "issubset() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(Value::Bool(
                vm.set_is_subset_of_iterable(items, iterable.clone())?,
            ))
        }
        "frozenset.issuperset" => {
            let [Value::FrozenSet(items), iterable] = args.as_slice() else {
                return Err(format!(
                    "issuperset() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            Ok(Value::Bool(
                vm.set_is_superset_of_iterable(items, iterable.clone())?,
            ))
        }
        "frozenset.symmetric_difference" => {
            let [Value::FrozenSet(items), iterable] = args.as_slice() else {
                return Err(format!(
                    "symmetric_difference() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            vm.set_symmetric_difference_from_iterable_with_kind(
                SetResultKind::FrozenSet,
                items.as_ref().clone(),
                iterable,
            )
        }
        "frozenset.union" => {
            let [Value::FrozenSet(items), iterables @ ..] = args.as_slice() else {
                return Err("union() expected a frozenset receiver".to_string());
            };
            vm.set_union_from_iterables_with_kind(
                SetResultKind::FrozenSet,
                items.as_ref().clone(),
                iterables,
            )
        }
        _ => Err(format!("unknown builtin: {name}")),
    }
}

fn is_exact_set_value(value: &Value) -> bool {
    matches!(value, Value::Set(_) | Value::FrozenSet(_))
        || set_subclass_items(value).is_some()
        || frozen_set_subclass_items(value).is_some()
}

#[derive(Clone, Copy)]
enum SetResultKind {
    Set,
    FrozenSet,
}

fn set_result_kind(value: &Value) -> SetResultKind {
    if matches!(value, Value::FrozenSet(_)) || frozen_set_subclass_items(value).is_some() {
        SetResultKind::FrozenSet
    } else {
        SetResultKind::Set
    }
}

fn set_result_value(kind: SetResultKind, items: Vec<Value>) -> Value {
    match kind {
        SetResultKind::Set => set_value(items),
        SetResultKind::FrozenSet => frozen_set_value(items),
    }
}

fn set_union_from_iterables_with_kind(
    kind: SetResultKind,
    mut items: Vec<Value>,
    iterables: &[Value],
) -> Result<Value, String> {
    for iterable in iterables {
        for value in sequence_values(iterable.clone())? {
            insert_set_item(&mut items, value)?;
        }
    }
    Ok(set_result_value(kind, items))
}

fn set_intersection_from_iterables_with_kind(
    kind: SetResultKind,
    mut items: Vec<Value>,
    iterables: &[Value],
) -> Result<Value, String> {
    for iterable in iterables {
        let other = set_iterable_lookup_values(iterable.clone())?;
        items.retain(|item| set_contains_value(&other, item));
    }
    Ok(set_result_value(kind, items))
}

fn set_difference_from_iterables_with_kind(
    kind: SetResultKind,
    mut items: Vec<Value>,
    iterables: &[Value],
) -> Result<Value, String> {
    for iterable in iterables {
        let other = set_iterable_lookup_values(iterable.clone())?;
        items.retain(|item| !set_contains_value(&other, item));
    }
    Ok(set_result_value(kind, items))
}

fn set_symmetric_difference_from_iterable_with_kind(
    kind: SetResultKind,
    mut items: Vec<Value>,
    iterable: &Value,
) -> Result<Value, String> {
    let mut other = Vec::new();
    for value in sequence_values(iterable.clone())? {
        insert_set_item(&mut other, value)?;
    }

    for value in other {
        if let Some(position) = items.iter().position(|existing| existing == &value) {
            items.remove(position);
        } else {
            items.push(value);
        }
    }
    Ok(set_result_value(kind, items))
}

fn push_unique_set_value(items: &mut Vec<Value>, value: Value) -> Result<(), String> {
    ensure_hashable_key(&value)?;
    if !set_contains_value(items, &value) {
        items.push(value);
    }
    Ok(())
}

fn set_operator_operand(value: Value, op: &str) -> Result<Vec<Value>, String> {
    match value {
        Value::Set(items) => Ok(items.borrow().clone()),
        Value::FrozenSet(items) => Ok(items.as_ref().clone()),
        value if set_subclass_items(&value).is_some() => Ok(set_subclass_items(&value)
            .expect("set subclass items exist after guard")
            .borrow()
            .clone()),
        value if frozen_set_subclass_items(&value).is_some() => {
            Ok(frozen_set_subclass_items(&value)
                .expect("frozenset subclass items exist after guard")
                .as_ref()
                .clone())
        }
        Value::DictView { kind, entries } if dict_view_is_set_like(kind) => {
            Ok(dict_view_values(kind, &entries))
        }
        value => Err(format!(
            "unsupported operand type(s) for {op}: set and {}",
            type_name(&value)
        )),
    }
}

fn is_set_operator_value(value: &Value) -> bool {
    matches!(
        value,
        Value::Set(_) | Value::FrozenSet(_) | Value::DictView { .. }
    ) || set_subclass_items(value).is_some()
        || frozen_set_subclass_items(value).is_some()
}

fn set_contains_value(items: &[Value], value: &Value) -> bool {
    items.iter().any(|item| item == value)
}

fn set_iterable_lookup_values(iterable: Value) -> Result<Vec<Value>, String> {
    let values = sequence_values(iterable)?;
    for value in &values {
        ensure_hashable_key(value)?;
    }
    Ok(values)
}

fn dict_view_is_set_like(kind: DictViewKind) -> bool {
    matches!(kind, DictViewKind::Keys | DictViewKind::Items)
}

fn dict_view_type_name(kind: DictViewKind) -> &'static str {
    match kind {
        DictViewKind::Keys => "dict_keys",
        DictViewKind::Values => "dict_values",
        DictViewKind::Items => "dict_items",
    }
}

fn set_is_subset(left: &[Value], right: &[Value]) -> bool {
    left.iter().all(|item| set_contains_value(right, item))
}

fn set_is_proper_subset(left: &[Value], right: &[Value]) -> bool {
    left.len() < right.len() && set_is_subset(left, right)
}

fn set_is_superset(left: &[Value], right: &[Value]) -> bool {
    set_is_subset(right, left)
}

fn set_is_proper_superset(left: &[Value], right: &[Value]) -> bool {
    left.len() > right.len() && set_is_superset(left, right)
}

fn dict_entries_from_update_source(value: Value) -> Result<Vec<(Value, Value)>, String> {
    match value {
        Value::Dict(entries) | Value::MappingProxy { entries } => Ok(entries.borrow().clone()),
        Value::UserDict { data } => Ok(data.borrow().clone()),
        value => {
            let items = sequence_values(value)?;
            let mut entries = Vec::new();
            for item in items {
                let pair = sequence_values(item)?;
                match pair.as_slice() {
                    [key, value] => entries.push((key.clone(), value.clone())),
                    values => {
                        return Err(format!(
                            "dictionary update sequence element has length {}; 2 is required",
                            values.len()
                        ));
                    }
                }
            }
            Ok(entries)
        }
    }
}

fn mapping_entries(value: &Value) -> Result<Vec<(Value, Value)>, String> {
    match value {
        Value::Dict(entries) | Value::MappingProxy { entries } => Ok(entries.borrow().clone()),
        Value::UserDict { data } => Ok(data.borrow().clone()),
        Value::ChainMap { maps } => chain_map_entries(maps),
        value if dict_subclass_entries(value).is_some() => Ok(dict_subclass_entries(value)
            .expect("dict subclass entries exist after guard")
            .borrow()
            .clone()),
        value => Err(format!("{} is not a mapping", type_name(value))),
    }
}

fn chain_map_entries(maps: &[Value]) -> Result<Vec<(Value, Value)>, String> {
    let mut entries = Vec::new();
    for map in maps.iter().rev() {
        for (key, value) in mapping_entries(map)? {
            insert_dict_entry(&mut entries, key, value)?;
        }
    }
    Ok(entries)
}

fn chain_map_get_item_optional(maps: &[Value], key: &Value) -> Result<Option<Value>, String> {
    ensure_hashable_key(key)?;
    for map in maps {
        for (existing_key, value) in mapping_entries(map)? {
            if dict_keys_equal(&existing_key, key) {
                return Ok(Some(value));
            }
        }
    }
    Ok(None)
}

fn chain_map_get_item(maps: &[Value], key: Value) -> Result<Value, String> {
    chain_map_get_item_optional(maps, &key)?
        .ok_or_else(|| format!("KeyError: {}", format_key_error(&key)))
}

fn chain_map_contains_key(maps: &[Value], key: &Value) -> Result<bool, String> {
    Ok(chain_map_get_item_optional(maps, key)?.is_some())
}

fn dict_union_from_entries(
    mut entries: Vec<(Value, Value)>,
    updates: Vec<(Value, Value)>,
) -> Result<Value, String> {
    for (key, value) in updates {
        insert_dict_entry(&mut entries, key, value)?;
    }
    build_dict(entries)
}

fn reject_method_keywords(name: &str, keywords: &[(String, Value)]) -> Result<(), String> {
    if keywords.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "{}() does not accept keyword arguments",
            method_display_name(name)
        ))
    }
}

fn list_search_bounds(args: &[Value], len: usize) -> Result<(usize, usize), String> {
    let len = i64::try_from(len).map_err(|_| "list is too large".to_string())?;
    let start = match args.first() {
        Some(value) => list_bound_argument(value, "list index")?,
        None => 0,
    };
    let stop = match args.get(1) {
        Some(value) => list_bound_argument(value, "list index")?,
        None => len,
    };

    let start = normalize_positive_slice_bound(start, len);
    let stop = normalize_positive_slice_bound(stop, len).max(start);
    let start = usize::try_from(start).map_err(|_| "list index out of range".to_string())?;
    let stop = usize::try_from(stop).map_err(|_| "list index out of range".to_string())?;
    Ok((start, stop))
}

fn normalized_insert_index(index: &Value, len: usize) -> Result<usize, String> {
    let len = i64::try_from(len).map_err(|_| "list is too large".to_string())?;
    let index = list_bound_argument(index, "insert index")?;
    let index = normalize_positive_slice_bound(index, len);
    usize::try_from(index).map_err(|_| "list index out of range".to_string())
}

fn list_bound_argument(value: &Value, context: &str) -> Result<i64, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(*value)),
        Value::Number(value) => Ok(*value),
        Value::BigInt(value) => Ok(value.to_i64().unwrap_or_else(|| {
            if value.is_negative() {
                i64::MIN
            } else {
                i64::MAX
            }
        })),
        value => Err(format!("{context} must be an integer, got {value}")),
    }
}

fn method_arg_count(args: &[Value]) -> usize {
    args.len().saturating_sub(1)
}

fn is_iterator_protocol_method(name: &str) -> bool {
    matches!(
        method_display_name(name),
        "__iter__" | "__next__" | "__length_hint__"
    )
}

fn method_display_name(name: &str) -> &str {
    name.rsplit('.').next().unwrap_or(name)
}

fn value_len(value: &Value) -> Result<usize, String> {
    match value {
        Value::String(value) => Ok(value.chars().count()),
        Value::Bytes(value) => Ok(value.len()),
        Value::ByteArray(value) => Ok(value.len()),
        Value::List(items) => Ok(items.borrow().len()),
        Value::Tuple(items) => Ok(items.len()),
        Value::Set(items) => Ok(items.borrow().len()),
        Value::FrozenSet(items) => Ok(items.len()),
        Value::Dict(entries) => Ok(entries.borrow().len()),
        Value::MappingProxy { entries } => Ok(entries.borrow().len()),
        Value::ChainMap { maps } => Ok(chain_map_entries(maps)?.len()),
        Value::UserDict { data } => Ok(data.borrow().len()),
        Value::ScopeDict(scope) => Ok(scope.borrow().len()),
        Value::DictView { entries, .. } => Ok(entries.borrow().len()),
        Value::Range { start, stop, step } => Ok(range_values(*start, *stop, *step)?.len()),
        value => Err(format!(
            "TypeError: object of type '{}' has no len()",
            type_name(value)
        )),
    }
}

fn len_result_from_value(value: Value) -> Result<usize, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(value) as usize),
        Value::Number(value) if value >= 0 => usize::try_from(value)
            .map_err(|_| "OverflowError: len() result is too large".to_string()),
        Value::Number(_) => Err("ValueError: __len__() should return >= 0".to_string()),
        Value::BigInt(value) if !value.is_negative() => value
            .to_usize()
            .ok_or_else(|| "OverflowError: len() result is too large".to_string()),
        Value::BigInt(_) => Err("ValueError: __len__() should return >= 0".to_string()),
        value => Err(format!(
            "TypeError: '{}' object cannot be interpreted as an integer",
            type_name(&value)
        )),
    }
}

fn uses_sequence_index_protocol(value: &Value) -> bool {
    matches!(
        value,
        Value::List(_)
            | Value::Tuple(_)
            | Value::String(_)
            | Value::Bytes(_)
            | Value::ByteArray(_)
            | Value::Range { .. }
    )
}

fn integer_dunder_result(method: &str, result: Value) -> Result<Value, String> {
    match numeric_bool_value(result) {
        Value::Number(value) => Ok(Value::Number(value)),
        Value::BigInt(value) => Ok(normalize_big_int(value)),
        value => Err(format!(
            "TypeError: {method} returned non-int (type {})",
            type_name(&value)
        )),
    }
}

fn integer_value_to_i64(value: Value, context: &str) -> Result<i64, String> {
    match value {
        Value::Number(value) => Ok(value),
        Value::BigInt(value) => value
            .to_i64()
            .ok_or_else(|| format!("{context} is too large")),
        value => Err(format!(
            "TypeError: {context} must be an integer, got {}",
            type_name(&value)
        )),
    }
}

fn advance_plain_iterator(iterator: &mut Value) -> Result<IteratorAdvance, String> {
    match iterator {
        Value::Iterator(state) => advance_plain_iterator(&mut state.borrow_mut()),
        Value::RangeIterator {
            current,
            stop,
            step,
        } => {
            if range_is_exhausted(*current, *stop, *step) {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = *current;
            *current = current
                .checked_add(*step)
                .ok_or_else(|| "range iterator overflow".to_string())?;
            Ok(IteratorAdvance::Yield(Value::Number(value)))
        }
        Value::ListIterator { items, index } => {
            if *index >= items.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = items[*index].clone();
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::TupleIterator { items, index } | Value::TemplateIterator { items, index } => {
            if *index >= items.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = items[*index].clone();
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::StringIterator { chars, index } => {
            if *index >= chars.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = Value::String(chars[*index].clone());
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::BytesIterator { bytes, index } => {
            if *index >= bytes.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = Value::Number(bytes[*index] as i64);
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::SetIterator {
            items,
            index,
            source,
            expected_len,
        } => {
            if source
                .as_ref()
                .is_some_and(|items| items.borrow().len() != *expected_len)
            {
                *index = items.len();
                return Err("RuntimeError: Set changed size during iteration".to_string());
            }
            if *index >= items.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = items[*index].clone();
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::DictIterator {
            kind,
            entries,
            index,
            expected_len,
            expected_version,
        } => {
            let value = {
                let entries = entries.borrow();
                if entries.len() != *expected_len {
                    return Err(
                        "RuntimeError: dictionary changed size during iteration".to_string()
                    );
                }
                if entries.version != *expected_version {
                    return Err(
                        "RuntimeError: dictionary keys changed during iteration".to_string()
                    );
                }
                if *index >= entries.len() {
                    return Ok(IteratorAdvance::Complete(Value::None));
                }
                let (key, value) = &entries[*index];
                match kind {
                    DictViewKind::Keys => key.clone(),
                    DictViewKind::Values => value.clone(),
                    DictViewKind::Items => tuple_value(vec![key.clone(), value.clone()]),
                }
            };
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::ReverseIterator { items, index } => {
            if *index >= items.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let reverse_index = items.len() - 1 - *index;
            let value = items[reverse_index].clone();
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::DictReverseIterator {
            kind,
            entries,
            keys,
            index,
            expected_len,
            expected_version: _,
        } => {
            let value = 'next_value: {
                let entries = entries.borrow();
                if entries.len() != *expected_len {
                    return Err(
                        "RuntimeError: dictionary changed size during iteration".to_string()
                    );
                }
                while *index < keys.len() {
                    let original_index = keys.len() - 1 - *index;
                    *index += 1;
                    let Some((current_index, (key, value))) =
                        entries.iter().enumerate().find(|(_, (candidate, _))| {
                            dict_keys_equal(candidate, &keys[original_index])
                        })
                    else {
                        continue;
                    };
                    if current_index > original_index {
                        continue;
                    }
                    break 'next_value Some(match kind {
                        DictViewKind::Keys => key.clone(),
                        DictViewKind::Values => value.clone(),
                        DictViewKind::Items => tuple_value(vec![key.clone(), value.clone()]),
                    });
                }
                None
            };
            match value {
                Some(value) => Ok(IteratorAdvance::Yield(value)),
                None => Ok(IteratorAdvance::Complete(Value::None)),
            }
        }
        Value::EnumerateIterator { iterator, index } => {
            match advance_plain_iterator(iterator.as_mut())? {
                IteratorAdvance::Yield(value) => {
                    let item_index = normalize_big_int(index.clone());
                    *index += BigInt::from(1);
                    Ok(IteratorAdvance::Yield(tuple_value(vec![item_index, value])))
                }
                IteratorAdvance::Complete(value) => Ok(IteratorAdvance::Complete(value)),
                IteratorAdvance::Raised => Ok(IteratorAdvance::Raised),
            }
        }
        Value::ZipIterator { iterators, strict } => advance_plain_zip_iterator(iterators, *strict),
        value => Err(format!("TypeError: {value} is not an iterator")),
    }
}

fn advance_plain_zip_iterator(
    iterators: &mut [Value],
    strict: bool,
) -> Result<IteratorAdvance, String> {
    if iterators.is_empty() {
        return Ok(IteratorAdvance::Complete(Value::None));
    }

    let mut values = Vec::new();
    for index in 0..iterators.len() {
        match advance_plain_iterator(&mut iterators[index])? {
            IteratorAdvance::Yield(value) => values.push(value),
            IteratorAdvance::Complete(value) => {
                if strict {
                    return advance_plain_strict_zip_after_complete(iterators, index, value);
                }
                return Ok(IteratorAdvance::Complete(value));
            }
            IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
        }
    }

    Ok(IteratorAdvance::Yield(tuple_value(values)))
}

fn advance_plain_strict_zip_after_complete(
    iterators: &mut [Value],
    completed_index: usize,
    completion: Value,
) -> Result<IteratorAdvance, String> {
    if completed_index > 0 {
        return Err(format!(
            "ValueError: {}",
            zip_strict_length_error(completed_index + 1, "shorter")
        ));
    }

    for index in 1..iterators.len() {
        match advance_plain_iterator(&mut iterators[index])? {
            IteratorAdvance::Yield(_) => {
                return Err(format!(
                    "ValueError: {}",
                    zip_strict_length_error(index + 1, "longer")
                ));
            }
            IteratorAdvance::Complete(_) => {}
            IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
        }
    }

    Ok(IteratorAdvance::Complete(completion))
}

fn zip_strict_length_error(argument_index: usize, relation: &str) -> String {
    let prior = if argument_index == 2 {
        "argument 1".to_string()
    } else {
        format!("arguments 1-{}", argument_index - 1)
    };
    format!("zip() argument {argument_index} is {relation} than {prior}")
}

fn map_strict_length_error(argument_index: usize, relation: &str) -> String {
    let prior = if argument_index == 2 {
        "argument 1".to_string()
    } else {
        format!("arguments 1-{}", argument_index - 1)
    };
    format!("map() argument {argument_index} is {relation} than {prior}")
}

fn shared_iterator(iterator: Value) -> Value {
    Value::Iterator(Rc::new(RefCell::new(iterator)))
}

fn build_dict(entries: Vec<(Value, Value)>) -> Result<Value, String> {
    dict_ref_from_entries(entries).map(Value::Dict)
}

fn dict_ref_from_entries(entries: Vec<(Value, Value)>) -> Result<DictRef, String> {
    let mut dict = Vec::new();

    for (key, value) in entries {
        insert_dict_entry(&mut dict, key, value)?;
    }

    let Value::Dict(entries) = dict_value(dict) else {
        unreachable!("dict_value always returns a dict")
    };
    Ok(entries)
}

fn insert_set_item(items: &mut Vec<Value>, item: Value) -> Result<(), String> {
    ensure_hashable_key(&item)?;

    if !items.iter().any(|existing| existing == &item) {
        items.push(item);
    }

    Ok(())
}

fn set_lookup_key_value(value: &Value) -> Value {
    match value {
        Value::Set(items) => frozen_set_value(items.borrow().clone()),
        value => value.clone(),
    }
}

fn insert_dict_entry(
    entries: &mut Vec<(Value, Value)>,
    key: Value,
    value: Value,
) -> Result<bool, String> {
    ensure_hashable_key(&key)?;

    if let Some((_, existing_value)) = entries
        .iter_mut()
        .find(|(existing_key, _)| dict_keys_equal(existing_key, &key))
    {
        *existing_value = value;
        Ok(false)
    } else {
        entries.push((key, value));
        Ok(true)
    }
}

fn insert_live_dict_entry(
    entries: &mut DictStorage,
    key: Value,
    value: Value,
) -> Result<(), String> {
    if insert_dict_entry(&mut entries.entries, key, value)? {
        mark_dict_changed(entries);
    }
    Ok(())
}

fn mark_dict_changed(entries: &mut DictStorage) {
    entries.version = entries.version.wrapping_add(1);
}

fn dict_entries_from_mapping(value: Value) -> Result<Vec<(Value, Value)>, String> {
    match value {
        Value::Dict(entries) => Ok(entries.borrow().clone()),
        value => Err(format!("dict update source must be a dict, got {value}")),
    }
}

fn instance_hash_method(value: &Value) -> Result<Option<Value>, String> {
    let Value::Instance {
        class_name,
        class_attrs,
        class_bases,
        ..
    } = value
    else {
        return Ok(None);
    };

    if let Some(method) = find_class_attr(class_attrs, class_bases, "__hash__") {
        if matches!(method, Value::None) {
            return Err(format!("TypeError: unhashable type: '{class_name}'"));
        }
        return Ok(Some(bind_method(method, value.clone())));
    }

    if set_subclass_items(value).is_some() {
        Err(format!("TypeError: unhashable type: '{class_name}'"))
    } else if let Some(items) = frozen_set_subclass_items(value) {
        Ok(Some(Value::BoundMethod {
            function: Box::new(Value::Builtin("frozenset.__hash__".to_string())),
            receiver: Box::new(Value::FrozenSet(items)),
            identity: Rc::new(()),
        }))
    } else {
        Ok(None)
    }
}

fn hash_result_from_special_method(value: Value) -> Result<Value, String> {
    match numeric_bool_value(value) {
        Value::Number(value) => Ok(Value::Number(value)),
        Value::BigInt(value) => Ok(normalize_big_int(value)),
        _ => Err("TypeError: __hash__ method should return an integer".to_string()),
    }
}

fn identity_value(value: &Value) -> Value {
    normalize_big_int(BigInt::from(identity_bits(value)))
}

fn identity_bits(value: &Value) -> u64 {
    match value {
        Value::List(items) => rc_identity_bits(items),
        Value::Tuple(items) => rc_plain_identity_bits(items),
        Value::Set(items) => rc_identity_bits(items),
        Value::FrozenSet(items) => rc_plain_identity_bits(items),
        Value::Dict(entries) => rc_identity_bits(entries),
        Value::ScopeDict(scope) => scope_identity_bits(scope),
        Value::DictView { entries, .. } => rc_identity_bits(entries),
        Value::MappingView { mapping, .. } => identity_bits(mapping),
        Value::MappingProxy { entries } => rc_identity_bits(entries),
        Value::ChainMap { maps } => maps.as_ptr() as usize as u64,
        Value::UserDict { data } => rc_identity_bits(data),
        Value::SimpleNamespace { fields } => rc_identity_bits(fields),
        Value::Generator(state) => rc_identity_bits(state),
        Value::Coroutine(state) => rc_identity_bits(state),
        Value::CoroutineAwait(state) => rc_identity_bits(state),
        Value::AsyncGenerator(state) => rc_identity_bits(state),
        Value::AsyncGeneratorNext { state, .. } => rc_identity_bits(state),
        Value::AsyncGeneratorThrow { state, .. } => rc_identity_bits(state),
        Value::AsyncGeneratorClose(state) => rc_identity_bits(state),
        Value::Iterator(value) => rc_identity_bits(value),
        Value::Class { attrs, .. } => scope_identity_bits(attrs),
        Value::Instance { fields, .. } => scope_identity_bits(fields),
        Value::Module { attrs, .. } => scope_identity_bits(attrs),
        Value::Function { identity, .. } => rc_plain_identity_bits(identity),
        _ => stable_identity_bits(value),
    }
}

fn stable_identity_bits(value: &Value) -> u64 {
    let mut hasher = DefaultHasher::new();
    "id".hash(&mut hasher);
    format!("{value:?}").hash(&mut hasher);
    hasher.finish()
}

fn scope_identity_bits(scope: &Scope) -> u64 {
    Rc::as_ptr(scope) as usize as u64
}

fn rc_identity_bits<T>(value: &Rc<RefCell<T>>) -> u64 {
    Rc::as_ptr(value) as usize as u64
}

fn rc_plain_identity_bits<T>(value: &Rc<T>) -> u64 {
    Rc::as_ptr(value) as usize as u64
}

fn hash_value(value: &Value) -> Result<Value, String> {
    let mut hasher = DefaultHasher::new();
    hash_value_into(value, &mut hasher)?;
    Ok(Value::Number(hasher.finish() as i64))
}

fn hash_value_into(value: &Value, hasher: &mut DefaultHasher) -> Result<(), String> {
    match value {
        Value::Number(value) => hash_integer_value(&BigInt::from(*value), hasher),
        Value::BigInt(value) => hash_integer_value(value, hasher),
        Value::Bool(value) => hash_integer_value(&BigInt::from(bool_as_i64(*value)), hasher),
        Value::Float(value) if value.is_finite() && value.fract() == 0.0 => {
            if let Some(value) = value.to_i64() {
                hash_integer_value(&BigInt::from(value), hasher);
            } else {
                hash_float_value(*value, hasher);
            }
        }
        Value::Float(value) => hash_float_value(*value, hasher),
        Value::Complex { real, imag } if *imag == 0.0 => {
            hash_value_into(&Value::Float(*real), hasher)?;
        }
        Value::Complex { real, imag } => {
            "complex".hash(hasher);
            real.to_bits().hash(hasher);
            imag.to_bits().hash(hasher);
        }
        Value::String(value) => hash_bytes_like(value.as_bytes(), hasher),
        Value::Bytes(value) => hash_bytes_like(value, hasher),
        Value::Tuple(items) => {
            "tuple".hash(hasher);
            items.len().hash(hasher);
            for item in items.iter() {
                hash_value_into(item, hasher)?;
            }
        }
        Value::FrozenSet(items) => {
            "frozenset".hash(hasher);
            let mut hash = 0_u64;
            for item in items.iter() {
                let mut item_hasher = DefaultHasher::new();
                hash_value_into(item, &mut item_hasher)?;
                hash ^= item_hasher.finish();
            }
            items.len().hash(hasher);
            hash.hash(hasher);
        }
        Value::Slice { start, stop, step } => {
            "slice".hash(hasher);
            hash_optional_slice_part(start, hasher)?;
            hash_optional_slice_part(stop, hasher)?;
            hash_optional_slice_part(step, hasher)?;
        }
        Value::CodeObject {
            mode,
            filename,
            instructions,
            ..
        } => {
            "code".hash(hasher);
            mode.hash(hasher);
            filename.hash(hasher);
            format!("{instructions:?}").hash(hasher);
        }
        Value::Range { start, stop, step } => {
            "range".hash(hasher);
            start.hash(hasher);
            stop.hash(hasher);
            step.hash(hasher);
        }
        Value::Function { identity, .. } => {
            "function".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::Generator(state) => hash_rc_identity("generator", state, hasher),
        Value::Coroutine(state) => hash_rc_identity("coroutine", state, hasher),
        Value::CoroutineAwait(state) => hash_rc_identity("coroutine_wrapper", state, hasher),
        Value::AwaitIterator(value) => {
            "await_iterator".hash(hasher);
            hash_value_into(value, hasher)?;
        }
        Value::AsyncGenerator(state) => hash_rc_identity("async_generator", state, hasher),
        Value::AsyncGeneratorNext {
            state,
            send,
            default,
        } => {
            hash_rc_identity("async_generator_asend", state, hasher);
            hash_value_into(send, hasher)?;
            if let Some(default) = default {
                hash_value_into(default, hasher)?;
            }
        }
        Value::AsyncGeneratorThrow { state, exception } => {
            hash_rc_identity("async_generator_athrow", state, hasher);
            hash_value_into(exception, hasher)?;
        }
        Value::AsyncGeneratorClose(state) => {
            hash_rc_identity("async_generator_aclose", state, hasher)
        }
        Value::AnextDefault { awaitable, default } => {
            "anext_awaitable".hash(hasher);
            hash_value_into(awaitable, hasher)?;
            hash_value_into(default, hasher)?;
        }
        Value::Class { name, attrs, .. } => {
            "type".hash(hasher);
            name.hash(hasher);
            hash_scope_identity(attrs, hasher);
        }
        Value::TypeParam { kind, name, .. } => {
            "type_param".hash(hasher);
            kind.hash(hasher);
            name.hash(hasher);
        }
        Value::TypeAlias { name, .. } => {
            "type_alias".hash(hasher);
            name.hash(hasher);
        }
        Value::GenericAlias { origin, args } => {
            "generic_alias".hash(hasher);
            hash_value_into(origin, hasher)?;
            for arg in args {
                hash_value_into(arg, hasher)?;
            }
        }
        Value::Unpack(value) => {
            "unpack".hash(hasher);
            hash_value_into(value, hasher)?;
        }
        Value::PicklePayload(value) => {
            "pickle_payload".hash(hasher);
            hash_value_into(value, hasher)?;
        }
        Value::TemplateInterpolation(interpolation) => {
            "interpolation".hash(hasher);
            interpolation.expression.hash(hasher);
            interpolation.format_spec.hash(hasher);
            hash_value_into(&interpolation.value, hasher)?;
        }
        Value::Instance {
            class_name, fields, ..
        } => {
            "instance".hash(hasher);
            class_name.hash(hasher);
            hash_scope_identity(fields, hasher);
        }
        Value::Property { .. } => "property".hash(hasher),
        Value::MemberDescriptor { name, owner_name } => {
            "member_descriptor".hash(hasher);
            name.hash(hasher);
            owner_name.hash(hasher);
        }
        Value::StaticMethod { function } => {
            "staticmethod".hash(hasher);
            hash_value_into(function, hasher)?;
        }
        Value::ClassMethod { function } => {
            "classmethod".hash(hasher);
            hash_value_into(function, hasher)?;
        }
        Value::Super {
            class,
            object,
            identity,
        } => {
            "super".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
            hash_value_into(class, hasher)?;
            hash_value_into(object, hasher)?;
        }
        Value::BoundMethod {
            function, receiver, ..
        } => {
            "method".hash(hasher);
            hash_value_into(function, hasher)?;
            hash_value_into(receiver, hasher)?;
        }
        Value::AstNode { identity, .. } => {
            "ast_node".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::Module { name, attrs } => {
            "module".hash(hasher);
            name.hash(hasher);
            hash_scope_identity(attrs, hasher);
        }
        Value::Builtin(name) => {
            "builtin".hash(hasher);
            name.hash(hasher);
        }
        Value::None => "None".hash(hasher),
        Value::NotImplemented => "NotImplemented".hash(hasher),
        Value::Ellipsis => "Ellipsis".hash(hasher),
        Value::MappingProxyObject { mapping } => hash_value_into(mapping, hasher)?,
        Value::List(_)
        | Value::ByteArray(_)
        | Value::Set(_)
        | Value::Dict(_)
        | Value::ScopeDict(_)
        | Value::SimpleNamespace { .. }
        | Value::DictView { .. }
        | Value::MappingView { .. }
        | Value::MappingProxy { .. }
        | Value::ChainMap { .. }
        | Value::UserDict { .. }
        | Value::Template { .. }
        | Value::Exception { .. }
        | Value::RangeIterator { .. }
        | Value::ListIterator { .. }
        | Value::TupleIterator { .. }
        | Value::TemplateIterator { .. }
        | Value::StringIterator { .. }
        | Value::BytesIterator { .. }
        | Value::SetIterator { .. }
        | Value::DictIterator { .. }
        | Value::ReverseIterator { .. }
        | Value::DictReverseIterator { .. }
        | Value::SequenceReverseIterator { .. }
        | Value::EnumerateIterator { .. }
        | Value::ZipIterator { .. }
        | Value::MapIterator { .. }
        | Value::FilterIterator { .. }
        | Value::CallIterator { .. }
        | Value::SequenceIterator { .. }
        | Value::Iterator(_) => {
            return Err(format!(
                "TypeError: unhashable type: '{}'",
                type_name(value)
            ));
        }
    }

    Ok(())
}

fn hash_integer_value(value: &BigInt, hasher: &mut DefaultHasher) {
    "int".hash(hasher);
    value.hash(hasher);
}

fn hash_float_value(value: f64, hasher: &mut DefaultHasher) {
    "float".hash(hasher);
    if value == 0.0 {
        0_u64.hash(hasher);
    } else {
        value.to_bits().hash(hasher);
    }
}

fn hash_bytes_like(value: &[u8], hasher: &mut DefaultHasher) {
    "bytes_like".hash(hasher);
    value.hash(hasher);
}

fn hash_optional_slice_part(
    value: &Option<Box<Value>>,
    hasher: &mut DefaultHasher,
) -> Result<(), String> {
    match value {
        Some(value) => hash_value_into(value, hasher),
        None => {
            "None".hash(hasher);
            Ok(())
        }
    }
}

fn hash_scope_identity(scope: &Scope, hasher: &mut DefaultHasher) {
    "scope".hash(hasher);
    (Rc::as_ptr(scope) as usize).hash(hasher);
}

fn hash_rc_identity<T>(tag: &str, value: &Rc<RefCell<T>>, hasher: &mut DefaultHasher) {
    tag.hash(hasher);
    (Rc::as_ptr(value) as usize).hash(hasher);
}

fn ensure_hashable_key(value: &Value) -> Result<(), String> {
    if is_hashable_key(value) {
        Ok(())
    } else {
        Err(format!("TypeError: unhashable key: {value}"))
    }
}

fn ensure_set_lookup_key(value: &Value) -> Result<(), String> {
    match value {
        Value::Set(items) => {
            for item in items.borrow().iter() {
                ensure_hashable_key(item)?;
            }
            Ok(())
        }
        value => ensure_hashable_key(value),
    }
}

fn is_hashable_key(value: &Value) -> bool {
    match value {
        Value::Number(_)
        | Value::BigInt(_)
        | Value::Float(_)
        | Value::Complex { .. }
        | Value::String(_)
        | Value::Bytes(_)
        | Value::Bool(_)
        | Value::CodeObject { .. }
        | Value::Range { .. }
        | Value::Function { .. }
        | Value::Generator(_)
        | Value::Coroutine(_)
        | Value::CoroutineAwait(_)
        | Value::AwaitIterator(_)
        | Value::AsyncGenerator(_)
        | Value::AsyncGeneratorNext { .. }
        | Value::AsyncGeneratorThrow { .. }
        | Value::AsyncGeneratorClose(_)
        | Value::AnextDefault { .. }
        | Value::Class { .. }
        | Value::TypeParam { .. }
        | Value::TypeAlias { .. }
        | Value::GenericAlias { .. }
        | Value::Unpack(_)
        | Value::PicklePayload(_)
        | Value::TemplateInterpolation(_)
        | Value::Instance { .. }
        | Value::Property { .. }
        | Value::MemberDescriptor { .. }
        | Value::StaticMethod { .. }
        | Value::ClassMethod { .. }
        | Value::Super { .. }
        | Value::BoundMethod { .. }
        | Value::AstNode { .. }
        | Value::Module { .. }
        | Value::Builtin(_)
        | Value::None
        | Value::NotImplemented
        | Value::Ellipsis => true,
        Value::Tuple(items) => items.iter().all(is_hashable_key),
        Value::FrozenSet(items) => items.iter().all(is_hashable_key),
        Value::Slice { start, stop, step } => {
            optional_slice_part_is_hashable(start)
                && optional_slice_part_is_hashable(stop)
                && optional_slice_part_is_hashable(step)
        }
        Value::MappingProxyObject { mapping } => is_hashable_key(mapping),
        Value::List(_)
        | Value::ByteArray(_)
        | Value::Set(_)
        | Value::Dict(_)
        | Value::ScopeDict(_)
        | Value::SimpleNamespace { .. }
        | Value::DictView { .. }
        | Value::MappingView { .. }
        | Value::MappingProxy { .. }
        | Value::ChainMap { .. }
        | Value::UserDict { .. }
        | Value::Template { .. }
        | Value::Exception { .. }
        | Value::RangeIterator { .. }
        | Value::ListIterator { .. }
        | Value::TupleIterator { .. }
        | Value::TemplateIterator { .. }
        | Value::StringIterator { .. }
        | Value::BytesIterator { .. }
        | Value::SetIterator { .. }
        | Value::DictIterator { .. }
        | Value::ReverseIterator { .. }
        | Value::DictReverseIterator { .. }
        | Value::SequenceReverseIterator { .. }
        | Value::EnumerateIterator { .. }
        | Value::ZipIterator { .. }
        | Value::MapIterator { .. }
        | Value::FilterIterator { .. }
        | Value::CallIterator { .. }
        | Value::SequenceIterator { .. }
        | Value::Iterator(_) => false,
    }
}

fn optional_slice_part_is_hashable(value: &Option<Box<Value>>) -> bool {
    value.as_deref().map(is_hashable_key).unwrap_or(true)
}

fn dict_keys_equal(left: &Value, right: &Value) -> bool {
    left == right
}

fn dict_lookup(entries: &[(Value, Value)], key: &Value) -> Option<Value> {
    entries
        .iter()
        .find(|(existing_key, _)| dict_keys_equal(existing_key, key))
        .map(|(_, value)| value.clone())
}

fn dict_entries_equal(left: &[(Value, Value)], right: &[(Value, Value)]) -> bool {
    left.len() == right.len()
        && left.iter().all(|(key, value)| {
            right
                .iter()
                .find(|(other_key, _)| dict_keys_equal(other_key, key))
                .is_some_and(|(_, other_value)| other_value == value)
        })
}

fn format_key_error(value: &Value) -> String {
    match value {
        Value::String(value) => repr_string(value),
        value => value.to_string(),
    }
}

fn key_error_exception(key: Value) -> MiniException {
    let message = format_key_error(&key);
    MiniException {
        type_name: "KeyError".to_string(),
        type_hierarchy: builtin_exception_type_hierarchy("KeyError"),
        type_object: None,
        message: Some(message),
        args: vec![key],
        attrs: Vec::new(),
        cause: None,
        context: None,
        suppress_context: false,
        exceptions: None,
    }
}

fn raise_key_error_value(vm: &mut Vm, key: Value) -> Result<Value, String> {
    vm.raise_exception(key_error_exception(key), true)?;
    Ok(Value::None)
}

fn get_iter(value: Value) -> Result<Value, String> {
    match value {
        Value::Range { start, stop, step } => Ok(shared_iterator(Value::RangeIterator {
            current: start,
            stop,
            step,
        })),
        Value::List(items) => Ok(shared_iterator(Value::ListIterator {
            items: items.borrow().clone(),
            index: 0,
        })),
        Value::Tuple(items) => Ok(shared_iterator(Value::TupleIterator {
            items: items.as_ref().clone(),
            index: 0,
        })),
        Value::Template {
            strings,
            interpolations,
        } => Ok(shared_iterator(Value::TemplateIterator {
            items: template_iter_values(strings, interpolations),
            index: 0,
        })),
        Value::String(value) => Ok(shared_iterator(Value::StringIterator {
            chars: value.chars().map(|ch| ch.to_string()).collect(),
            index: 0,
        })),
        Value::Bytes(value) => Ok(shared_iterator(Value::BytesIterator {
            bytes: value,
            index: 0,
        })),
        Value::ByteArray(value) => Ok(shared_iterator(Value::BytesIterator {
            bytes: value,
            index: 0,
        })),
        Value::Set(items) => {
            let items_ref = items.borrow();
            let values = items_ref.clone();
            let expected_len = items_ref.len();
            drop(items_ref);
            Ok(shared_iterator(Value::SetIterator {
                items: values,
                index: 0,
                source: Some(items),
                expected_len,
            }))
        }
        Value::FrozenSet(items) => Ok(shared_iterator(Value::SetIterator {
            items: items.as_ref().clone(),
            index: 0,
            source: None,
            expected_len: items.len(),
        })),
        Value::Dict(entries) => {
            let (expected_len, expected_version) = {
                let entries_ref = entries.borrow();
                (entries_ref.len(), entries_ref.version)
            };
            Ok(shared_iterator(Value::DictIterator {
                kind: DictViewKind::Keys,
                entries,
                index: 0,
                expected_len,
                expected_version,
            }))
        }
        Value::MappingProxy { entries } => {
            let (expected_len, expected_version) = {
                let entries_ref = entries.borrow();
                (entries_ref.len(), entries_ref.version)
            };
            Ok(shared_iterator(Value::DictIterator {
                kind: DictViewKind::Keys,
                entries,
                index: 0,
                expected_len,
                expected_version,
            }))
        }
        Value::ChainMap { maps } => Ok(shared_iterator(Value::ListIterator {
            items: chain_map_entries(&maps)?
                .into_iter()
                .map(|(key, _)| key)
                .collect(),
            index: 0,
        })),
        Value::ScopeDict(scope) => get_iter(scope_dict_snapshot(&scope)),
        Value::DictView { kind, entries } => {
            let (expected_len, expected_version) = {
                let entries_ref = entries.borrow();
                (entries_ref.len(), entries_ref.version)
            };
            Ok(shared_iterator(Value::DictIterator {
                kind,
                entries,
                index: 0,
                expected_len,
                expected_version,
            }))
        }
        Value::RangeIterator {
            current,
            stop,
            step,
        } => Ok(shared_iterator(Value::RangeIterator {
            current,
            stop,
            step,
        })),
        Value::ListIterator { items, index } => {
            Ok(shared_iterator(Value::ListIterator { items, index }))
        }
        Value::TupleIterator { items, index } => {
            Ok(shared_iterator(Value::TupleIterator { items, index }))
        }
        Value::TemplateIterator { items, index } => {
            Ok(shared_iterator(Value::TemplateIterator { items, index }))
        }
        Value::StringIterator { chars, index } => {
            Ok(shared_iterator(Value::StringIterator { chars, index }))
        }
        Value::BytesIterator { bytes, index } => {
            Ok(shared_iterator(Value::BytesIterator { bytes, index }))
        }
        Value::SetIterator {
            items,
            index,
            source,
            expected_len,
        } => Ok(shared_iterator(Value::SetIterator {
            items,
            index,
            source,
            expected_len,
        })),
        Value::DictIterator {
            kind,
            entries,
            index,
            expected_len,
            expected_version,
        } => Ok(shared_iterator(Value::DictIterator {
            kind,
            entries,
            index,
            expected_len,
            expected_version,
        })),
        Value::ReverseIterator { items, index } => {
            Ok(shared_iterator(Value::ReverseIterator { items, index }))
        }
        Value::DictReverseIterator {
            kind,
            entries,
            keys,
            index,
            expected_len,
            expected_version,
        } => Ok(shared_iterator(Value::DictReverseIterator {
            kind,
            entries,
            keys,
            index,
            expected_len,
            expected_version,
        })),
        Value::EnumerateIterator { iterator, index } => {
            Ok(shared_iterator(Value::EnumerateIterator {
                iterator,
                index,
            }))
        }
        Value::ZipIterator { iterators, strict } => {
            Ok(shared_iterator(Value::ZipIterator { iterators, strict }))
        }
        Value::MapIterator {
            function,
            iterators,
            strict,
        } => Ok(shared_iterator(Value::MapIterator {
            function,
            iterators,
            strict,
        })),
        Value::FilterIterator { function, iterator } => {
            Ok(shared_iterator(Value::FilterIterator {
                function,
                iterator,
            }))
        }
        Value::CallIterator {
            callable,
            sentinel,
            done,
        } => Ok(shared_iterator(Value::CallIterator {
            callable,
            sentinel,
            done,
        })),
        Value::Iterator(state) => Ok(Value::Iterator(state)),
        Value::Generator(state) => Ok(Value::Generator(state)),
        Value::CoroutineAwait(state) => Ok(Value::CoroutineAwait(state)),
        Value::AwaitIterator(iterator) => Ok(Value::AwaitIterator(iterator)),
        value => Err(format!("{value} is not iterable")),
    }
}

fn match_mapping_keys(mapping: &Value, keys: &[Value]) -> Result<bool, String> {
    match mapping {
        Value::Dict(entries) => {
            let entries = entries.borrow();
            if entries.len() < keys.len() {
                return Ok(false);
            }

            let mut seen = Vec::new();
            for key in keys {
                ensure_hashable_key(key)?;
                if seen
                    .iter()
                    .any(|existing_key| dict_keys_equal(existing_key, key))
                {
                    return Err(format!(
                        "ValueError: mapping pattern checks duplicate key ({})",
                        repr_value(key)
                    ));
                }
                seen.push(key.clone());
            }

            Ok(keys.iter().all(|key| {
                entries
                    .iter()
                    .any(|(existing_key, _)| dict_keys_equal(existing_key, key))
            }))
        }
        _ => Ok(false),
    }
}

fn match_class_pattern(subject: &Value, class: &Value) -> Result<bool, String> {
    match class {
        Value::Class { name, attrs, .. } => match subject {
            Value::Instance {
                class_name,
                class_attrs,
                class_bases,
                ..
            } => Ok(class_matches_target(
                class_name,
                class_attrs,
                class_bases,
                name,
                attrs,
            )),
            _ => Ok(false),
        },
        Value::Builtin(name) if is_class_like_builtin(name) => {
            Ok(value_matches_builtin_class(subject, name))
        }
        _ => Err("called match pattern must be a class".to_string()),
    }
}

fn class_matches_target(
    class_name: &str,
    class_attrs: &Scope,
    class_bases: &[Value],
    target_name: &str,
    target_attrs: &Scope,
) -> bool {
    (class_name == target_name && Rc::ptr_eq(class_attrs, target_attrs))
        || class_bases
            .iter()
            .any(|base| class_value_matches_target(base, target_name, target_attrs))
}

fn class_value_matches_target(class: &Value, target_name: &str, target_attrs: &Scope) -> bool {
    match class {
        Value::Class {
            name, attrs, bases, ..
        } => {
            (name == target_name && Rc::ptr_eq(attrs, target_attrs))
                || bases
                    .iter()
                    .any(|base| class_value_matches_target(base, target_name, target_attrs))
        }
        _ => false,
    }
}

fn value_matches_user_class(
    subject: &Value,
    target_name: &str,
    target_attrs: &Scope,
    target_bases: &[Value],
) -> bool {
    match subject {
        Value::Instance {
            class_name,
            class_attrs,
            class_bases,
            ..
        } => class_matches_target(
            class_name,
            class_attrs,
            class_bases,
            target_name,
            target_attrs,
        ),
        Value::Exception { type_hierarchy, .. }
            if class_bases_derive_from_exception(target_bases) =>
        {
            type_hierarchy
                .iter()
                .any(|type_name| type_name == target_name)
        }
        _ => false,
    }
}

fn value_matches_builtin_class(subject: &Value, class_name: &str) -> bool {
    match class_name {
        "object" => true,
        "int" => matches!(
            subject,
            Value::Bool(_) | Value::Number(_) | Value::BigInt(_)
        ),
        "float" => matches!(subject, Value::Float(_)),
        "complex" => matches!(subject, Value::Complex { .. }),
        "str" => matches!(subject, Value::String(_)),
        "bytes" => matches!(subject, Value::Bytes(_)),
        "bytearray" => matches!(subject, Value::ByteArray(_)),
        "bool" => matches!(subject, Value::Bool(_)),
        "list" => matches!(subject, Value::List(_)),
        "dict" => matches!(subject, Value::Dict(_)) || dict_subclass_entries(subject).is_some(),
        "ChainMap" => matches!(subject, Value::ChainMap { .. }),
        "SimpleNamespace" => is_simple_namespace_value(subject),
        "tuple" => matches!(subject, Value::Tuple(_)),
        "set" => matches!(subject, Value::Set(_)) || set_subclass_items(subject).is_some(),
        "frozenset" => {
            matches!(subject, Value::FrozenSet(_)) || frozen_set_subclass_items(subject).is_some()
        }
        "range" => matches!(subject, Value::Range { .. }),
        "slice" => matches!(subject, Value::Slice { .. }),
        "property" => matches!(subject, Value::Property { .. }),
        "super" => matches!(subject, Value::Super { .. }),
        "staticmethod" => matches!(subject, Value::StaticMethod { .. }),
        "classmethod" => matches!(subject, Value::ClassMethod { .. }),
        "type" => {
            matches!(subject, Value::Class { .. })
                || matches!(subject, Value::Builtin(name) if is_builtin_type_object_name(name))
        }
        name if is_ast_type_name(name) => {
            let kind = ast_builtin_kind(name).expect("guard checked AST builtin kind");
            match subject {
                Value::AstNode {
                    kind: subject_kind, ..
                } => ast_kind_inherits(subject_kind, kind),
                Value::Instance { class_bases, .. } => {
                    class_bases_include_builtin(class_bases, name)
                }
                _ => false,
            }
        }
        "Template" => matches!(subject, Value::Template { .. }),
        "Interpolation" => matches!(subject, Value::TemplateInterpolation(_)),
        "NodeVisitor" => matches!(
            subject,
            Value::Instance {
                class_name,
                class_bases,
                ..
            } if class_name == "NodeVisitor" || class_bases_include_builtin(class_bases, "NodeVisitor")
        ),
        "NodeTransformer" => matches!(
            subject,
            Value::Instance {
                class_name,
                class_bases,
                ..
            } if class_name == "NodeTransformer" || class_bases_include_builtin(class_bases, "NodeTransformer")
        ),
        "Hashable" => is_hashable_abc_value(subject),
        "Iterable" => is_iterable_abc_value(subject),
        "Iterator" => is_iterator_abc_value(subject),
        "Generator" => is_generator_abc_value(subject),
        "Reversible" => is_reversible_abc_value(subject),
        "Awaitable" => is_awaitable_abc_value(subject),
        "Coroutine" => is_coroutine_abc_value(subject),
        "AsyncIterable" => is_async_iterable_abc_value(subject),
        "AsyncIterator" => is_async_iterator_abc_value(subject),
        "AsyncGenerator" => is_async_generator_abc_value(subject),
        "Sized" => is_sized_abc_value(subject),
        "Container" => is_container_abc_value(subject),
        "Callable" => is_callable_abc_value(subject),
        "Collection" => is_collection_abc_value(subject),
        "Buffer" => is_buffer_abc_value(subject),
        "Sequence" => is_sequence_abc_value(subject),
        "MutableSequence" => is_mutable_sequence_abc_value(subject),
        "ByteString" => is_byte_string_abc_value(subject),
        "Mapping" => is_mapping_abc_value(subject),
        "MutableMapping" => is_mutable_mapping_abc_value(subject),
        "MappingView" => is_mapping_view_abc_value(subject),
        "KeysView" => is_keys_view_abc_value(subject),
        "ItemsView" => is_items_view_abc_value(subject),
        "ValuesView" => is_values_view_abc_value(subject),
        "Set" => is_set_abc_value(subject),
        "MutableSet" => is_mutable_set_abc_value(subject),
        name if is_builtin_iterator_type_name(name) => type_name(subject) == name,
        name if is_builtin_iterable_type_name(name) => type_name(subject) == name,
        name if is_exception_type_name(name) => matches!(
            subject,
            Value::Exception {
                type_name,
                type_hierarchy,
                ..
            } if exception_matches_type_name(
                &MiniException {
                    type_name: type_name.clone(),
                    type_hierarchy: type_hierarchy.clone(),
                    type_object: None,
                    message: None,
                    args: Vec::new(),
                    attrs: Vec::new(),
                    exceptions: None,
                    cause: None,
                    context: None,
                    suppress_context: false,
                },
                name,
            )
        ),
        _ => false,
    }
}

fn validate_match_class_arguments(
    class: &Value,
    positional_count: usize,
    keyword_names: &[String],
) -> Result<(), String> {
    if let Value::Builtin(name) = class
        && is_class_like_builtin(name)
    {
        if let Some(match_args) = builtin_match_args(name) {
            if positional_count > match_args.len() {
                return Err(format!(
                    "{name}() accepts {} positional sub-patterns",
                    match_args.len()
                ));
            }

            let mut positional_names: Vec<&str> = Vec::new();
            for attr_name in match_args.iter().take(positional_count) {
                if positional_names
                    .iter()
                    .copied()
                    .chain(keyword_names.iter().map(String::as_str))
                    .any(|existing| existing == *attr_name)
                {
                    return Err(format!(
                        "{name}() got multiple sub-patterns for attribute '{attr_name}'"
                    ));
                }
                positional_names.push(attr_name.as_str());
            }

            return Ok(());
        }

        let max_positional = if builtin_accepts_match_self(name) {
            1
        } else {
            0
        };
        if positional_count > max_positional {
            return Err(format!(
                "{name}() accepts {max_positional} positional sub-pattern{}",
                if max_positional == 1 { "" } else { "s" }
            ));
        }
        return Ok(());
    }

    let Value::Class {
        name, attrs, bases, ..
    } = class
    else {
        return Ok(());
    };

    let Some(match_args) = find_class_attr(attrs, bases, "__match_args__") else {
        if positional_count > 0 {
            return Err(format!("{name}() accepts 0 positional sub-patterns"));
        }
        return Ok(());
    };

    let Value::Tuple(items) = match_args else {
        return Err(format!("{name}.__match_args__ must be a tuple"));
    };

    if positional_count > items.len() {
        return Err(format!(
            "{name}() accepts {} positional sub-patterns",
            items.len()
        ));
    }

    let mut positional_names = Vec::new();
    for value in items.iter().take(positional_count) {
        let Value::String(attr_name) = value else {
            return Err(format!(
                "{name}.__match_args__ elements must be strings, got {value}"
            ));
        };

        if positional_names
            .iter()
            .chain(keyword_names.iter())
            .any(|existing| existing == attr_name)
        {
            return Err(format!(
                "{name}() got multiple sub-patterns for attribute '{attr_name}'"
            ));
        }

        positional_names.push(attr_name.clone());
    }

    Ok(())
}

fn load_match_class_positional(
    subject: Value,
    class: &Value,
    index: usize,
) -> Result<Option<Value>, String> {
    if let Value::Builtin(name) = class
        && is_class_like_builtin(name)
    {
        if let Some(match_args) = builtin_match_args(name) {
            let Some(attr_name) = match_args.get(index) else {
                return Ok(None);
            };
            return load_match_attribute(subject, attr_name);
        }

        if index == 0 && builtin_accepts_match_self(name) {
            return Ok(Some(subject));
        }
        let max_positional = if builtin_accepts_match_self(name) {
            1
        } else {
            0
        };
        return Err(format!(
            "{name}() accepts {max_positional} positional sub-pattern{}",
            if max_positional == 1 { "" } else { "s" }
        ));
    }

    let Some(name) = match_class_positional_attr_name(class, index)? else {
        return Ok(None);
    };

    load_match_attribute(subject, &name)
}

fn match_class_positional_attr_name(class: &Value, index: usize) -> Result<Option<String>, String> {
    let Value::Class {
        name, attrs, bases, ..
    } = class
    else {
        return Ok(None);
    };

    let Some(match_args) = find_class_attr(attrs, bases, "__match_args__") else {
        return Ok(None);
    };

    let Value::Tuple(items) = match_args else {
        return Err(format!("{name}.__match_args__ must be a tuple"));
    };

    if index >= items.len() {
        return Err(format!(
            "{name}() accepts {} positional sub-patterns",
            items.len()
        ));
    }

    match &items[index] {
        Value::String(attr_name) => Ok(Some(attr_name.clone())),
        value => Err(format!(
            "{name}.__match_args__ elements must be strings, got {value}"
        )),
    }
}

fn load_match_attribute(object: Value, name: &str) -> Result<Option<Value>, String> {
    match load_attribute(object, name) {
        Ok(value) => Ok(Some(value)),
        Err(message) if message.starts_with("AttributeError:") => Ok(None),
        Err(message) => Err(message),
    }
}

fn load_mapping_rest(mapping: Value, keys: &[Value]) -> Result<Value, String> {
    match mapping {
        Value::Dict(entries) => {
            let entries = entries.borrow();
            let mut rest = Vec::new();
            for (key, value) in entries.iter() {
                if !keys
                    .iter()
                    .any(|matched_key| dict_keys_equal(matched_key, key))
                {
                    insert_dict_entry(&mut rest, key.clone(), value.clone())?;
                }
            }
            Ok(dict_value(rest))
        }
        value => Err(format!("{value} is not a mapping pattern subject")),
    }
}

fn match_sequence_length(value: &Value, min_len: usize, exact: bool) -> bool {
    sequence_pattern_len(value)
        .map(|len| {
            if exact {
                len == min_len
            } else {
                len >= min_len
            }
        })
        .unwrap_or(false)
}

fn sequence_pattern_len(value: &Value) -> Option<usize> {
    match value {
        Value::List(items) => Some(items.borrow().len()),
        Value::Tuple(items) => Some(items.len()),
        Value::Range { start, stop, step } => range_values(*start, *stop, *step)
            .ok()
            .map(|values| values.len()),
        _ => None,
    }
}

fn load_sequence_rest(value: Value, start: usize, suffix: usize) -> Result<Value, String> {
    let values = sequence_pattern_values(value)?;
    let stop = values
        .len()
        .checked_sub(suffix)
        .ok_or_else(|| "sequence pattern suffix is longer than the subject".to_string())?;
    if start > stop {
        return Err("sequence pattern rest bounds are invalid".to_string());
    }

    Ok(list_value(values[start..stop].to_vec()))
}

fn sequence_pattern_values(value: Value) -> Result<Vec<Value>, String> {
    match value {
        Value::List(items) => Ok(items.borrow().clone()),
        Value::Tuple(items) => Ok(items.as_ref().clone()),
        Value::Range { start, stop, step } => Ok(range_values(start, stop, step)?
            .into_iter()
            .map(Value::Number)
            .collect()),
        value => Err(format!("{value} is not a sequence pattern subject")),
    }
}

fn sequence_values(value: Value) -> Result<Vec<Value>, String> {
    match value {
        Value::List(items) => Ok(items.borrow().clone()),
        Value::Tuple(items) => Ok(items.as_ref().clone()),
        Value::Set(items) => Ok(items.borrow().clone()),
        Value::FrozenSet(items) => Ok(items.as_ref().clone()),
        Value::Dict(entries) => Ok(entries
            .borrow()
            .iter()
            .map(|(key, _)| key.clone())
            .collect()),
        Value::MappingProxy { entries } => Ok(entries
            .borrow()
            .iter()
            .map(|(key, _)| key.clone())
            .collect()),
        Value::UserDict { data } => Ok(data.borrow().iter().map(|(key, _)| key.clone()).collect()),
        Value::ChainMap { maps } => Ok(chain_map_entries(&maps)?
            .into_iter()
            .map(|(key, _)| key)
            .collect()),
        Value::ScopeDict(scope) => Ok(scope_dict_keys(&scope)),
        Value::DictView { kind, entries } => Ok(dict_view_values(kind, &entries)),
        Value::String(value) => Ok(value
            .chars()
            .map(|ch| Value::String(ch.to_string()))
            .collect()),
        Value::Bytes(value) => Ok(value
            .into_iter()
            .map(|byte| Value::Number(byte as i64))
            .collect()),
        Value::ByteArray(value) => Ok(value
            .into_iter()
            .map(|byte| Value::Number(byte as i64))
            .collect()),
        Value::Range { start, stop, step } => Ok(range_values(start, stop, step)?
            .into_iter()
            .map(Value::Number)
            .collect()),
        Value::RangeIterator { .. }
        | Value::ListIterator { .. }
        | Value::TupleIterator { .. }
        | Value::TemplateIterator { .. }
        | Value::StringIterator { .. }
        | Value::BytesIterator { .. }
        | Value::SetIterator { .. }
        | Value::DictIterator { .. }
        | Value::ReverseIterator { .. }
        | Value::DictReverseIterator { .. }
        | Value::EnumerateIterator { .. }
        | Value::ZipIterator { .. }
        | Value::MapIterator { .. }
        | Value::FilterIterator { .. }
        | Value::Iterator(_) => collect_plain_iterator_values(value),
        value => Err(format!("{value} is not iterable")),
    }
}

fn collect_plain_iterator_values(mut iterator: Value) -> Result<Vec<Value>, String> {
    let mut values = Vec::new();

    loop {
        match advance_plain_iterator(&mut iterator)? {
            IteratorAdvance::Yield(value) => values.push(value),
            IteratorAdvance::Complete(_) | IteratorAdvance::Raised => return Ok(values),
        }
    }
}

fn load_subscript(object: Value, index: Value) -> Result<Value, String> {
    match object {
        Value::List(items) => match index {
            Value::Slice { start, stop, step } => load_slice(
                Value::List(items),
                unbox_slice_part(start),
                unbox_slice_part(stop),
                unbox_slice_part(step),
            ),
            index => {
                let items = items.borrow();
                let index = normalized_index(index, items.len(), "list")?;
                items
                    .get(index)
                    .cloned()
                    .ok_or_else(|| "list index out of range".to_string())
            }
        },
        Value::Tuple(items) => match index {
            Value::Slice { start, stop, step } => load_slice(
                Value::Tuple(items),
                unbox_slice_part(start),
                unbox_slice_part(stop),
                unbox_slice_part(step),
            ),
            index => {
                let index = normalized_index(index, items.len(), "tuple")?;
                items
                    .get(index)
                    .cloned()
                    .ok_or_else(|| "tuple index out of range".to_string())
            }
        },
        Value::String(value) => match index {
            Value::Slice { start, stop, step } => load_slice(
                Value::String(value),
                unbox_slice_part(start),
                unbox_slice_part(stop),
                unbox_slice_part(step),
            ),
            index => {
                let index = normalized_index(index, value.chars().count(), "string")?;
                value
                    .chars()
                    .nth(index)
                    .map(|ch| Value::String(ch.to_string()))
                    .ok_or_else(|| "string index out of range".to_string())
            }
        },
        Value::Bytes(value) => match index {
            Value::Slice { start, stop, step } => load_slice(
                Value::Bytes(value),
                unbox_slice_part(start),
                unbox_slice_part(stop),
                unbox_slice_part(step),
            ),
            index => {
                let index = normalized_index(index, value.len(), "bytes")?;
                value
                    .get(index)
                    .map(|byte| Value::Number(*byte as i64))
                    .ok_or_else(|| "bytes index out of range".to_string())
            }
        },
        Value::ByteArray(value) => match index {
            Value::Slice { start, stop, step } => load_slice(
                Value::ByteArray(value),
                unbox_slice_part(start),
                unbox_slice_part(stop),
                unbox_slice_part(step),
            ),
            index => {
                let index = normalized_index(index, value.len(), "bytearray")?;
                value
                    .get(index)
                    .map(|byte| Value::Number(*byte as i64))
                    .ok_or_else(|| "bytearray index out of range".to_string())
            }
        },
        Value::Range { start, stop, step } => match index {
            Value::Slice {
                start: slice_start,
                stop: slice_stop,
                step: slice_step,
            } => load_slice(
                Value::Range { start, stop, step },
                unbox_slice_part(slice_start),
                unbox_slice_part(slice_stop),
                unbox_slice_part(slice_step),
            ),
            index => {
                let values = range_values(start, stop, step)?;
                let index = normalized_index(index, values.len(), "range")?;
                values
                    .get(index)
                    .copied()
                    .map(Value::Number)
                    .ok_or_else(|| "range object index out of range".to_string())
            }
        },
        Value::Dict(entries) => {
            ensure_hashable_key(&index)?;
            entries
                .borrow()
                .iter()
                .find(|(key, _)| dict_keys_equal(key, &index))
                .map(|(_, value)| value.clone())
                .ok_or_else(|| format!("KeyError: {}", format_key_error(&index)))
        }
        Value::MappingProxy { entries } => {
            ensure_hashable_key(&index)?;
            entries
                .borrow()
                .iter()
                .find(|(key, _)| dict_keys_equal(key, &index))
                .map(|(_, value)| value.clone())
                .ok_or_else(|| format!("KeyError: {}", format_key_error(&index)))
        }
        Value::UserDict { data } => {
            ensure_hashable_key(&index)?;
            data.borrow()
                .iter()
                .find(|(key, _)| dict_keys_equal(key, &index))
                .map(|(_, value)| value.clone())
                .ok_or_else(|| format!("KeyError: {}", format_key_error(&index)))
        }
        Value::ChainMap { maps } => chain_map_get_item(&maps, index),
        Value::ScopeDict(scope) => {
            ensure_hashable_key(&index)?;
            scope_dict_lookup(&scope, &index)
                .ok_or_else(|| format!("KeyError: {}", format_key_error(&index)))
        }
        Value::Builtin(name) if is_class_like_builtin(&name) => Ok(Value::GenericAlias {
            origin: Box::new(Value::Builtin(name)),
            args: generic_alias_args(index),
        }),
        Value::Class { .. } => Ok(Value::GenericAlias {
            origin: Box::new(object),
            args: generic_alias_args(index),
        }),
        value => Err(format!("{value} is not subscriptable")),
    }
}

fn generic_alias_args(index: Value) -> Vec<Value> {
    match index {
        Value::Tuple(items) => items.as_ref().clone(),
        value => vec![value],
    }
}

fn store_subscript(object: Value, index: Value, value: Value) -> Result<Value, String> {
    match object {
        Value::List(items) => match index {
            Value::Slice { start, stop, step } => store_slice(
                Value::List(items),
                unbox_slice_part(start),
                unbox_slice_part(stop),
                unbox_slice_part(step),
                value,
            ),
            index => {
                let mut borrowed = items.borrow_mut();
                let index = normalized_index(index, borrowed.len(), "list")?;
                if let Some(slot) = borrowed.get_mut(index) {
                    *slot = value;
                    drop(borrowed);
                    Ok(Value::List(items))
                } else {
                    Err("list index out of range".to_string())
                }
            }
        },
        Value::Dict(entries) => {
            ensure_hashable_key(&index)?;
            insert_live_dict_entry(&mut entries.borrow_mut(), index, value)?;
            Ok(Value::Dict(entries))
        }
        Value::ScopeDict(scope) => {
            insert_scope_dict_entry(&scope, index, value)?;
            Ok(Value::ScopeDict(scope))
        }
        Value::MappingProxy { .. } => {
            Err("TypeError: 'mappingproxy' object does not support item assignment".to_string())
        }
        Value::Tuple(_) => Err("'tuple' object does not support item assignment".to_string()),
        Value::String(_) => Err("'str' object does not support item assignment".to_string()),
        Value::Range { .. } => Err("'range' object does not support item assignment".to_string()),
        value => Err(format!("{value} does not support item assignment")),
    }
}

fn delete_subscript(object: Value, index: Value) -> Result<Value, String> {
    match object {
        Value::List(items) => match index {
            Value::Slice { start, stop, step } => delete_slice(
                Value::List(items),
                unbox_slice_part(start),
                unbox_slice_part(stop),
                unbox_slice_part(step),
            ),
            index => {
                let mut borrowed = items.borrow_mut();
                let index = normalized_index(index, borrowed.len(), "list")?;
                borrowed.remove(index);
                drop(borrowed);
                Ok(Value::List(items))
            }
        },
        Value::Dict(entries) => {
            ensure_hashable_key(&index)?;
            let mut entries_borrowed = entries.borrow_mut();
            if let Some(position) = entries_borrowed
                .iter()
                .position(|(key, _)| dict_keys_equal(key, &index))
            {
                entries_borrowed.remove(position);
                mark_dict_changed(&mut entries_borrowed);
                drop(entries_borrowed);
                Ok(Value::Dict(entries))
            } else {
                Err(format!("KeyError: {}", format_key_error(&index)))
            }
        }
        Value::ScopeDict(scope) => {
            delete_scope_dict_entry(&scope, &index)?;
            Ok(Value::ScopeDict(scope))
        }
        Value::MappingProxy { .. } => {
            Err("TypeError: 'mappingproxy' object does not support item deletion".to_string())
        }
        Value::Tuple(_) => Err("'tuple' object does not support item deletion".to_string()),
        Value::String(_) => Err("'str' object does not support item deletion".to_string()),
        Value::Range { .. } => Err("'range' object does not support item deletion".to_string()),
        value => Err(format!("{value} does not support item deletion")),
    }
}

fn store_slice(
    object: Value,
    start: Option<Value>,
    stop: Option<Value>,
    step: Option<Value>,
    value: Value,
) -> Result<Value, String> {
    match object {
        Value::List(items) => {
            let start = slice_bound(start)?;
            let stop = slice_bound(stop)?;
            let step = slice_bound(step)?;
            let step_value = slice_step_value(step)?;
            let replacement = sequence_values(value)?;
            let mut borrowed = items.borrow_mut();

            if step_value == 1 {
                let (start, stop) = contiguous_slice_bounds(borrowed.len(), start, stop)?;
                borrowed.splice(start..stop, replacement);
            } else {
                let indices = slice_indices(borrowed.len(), start, stop, Some(step_value))?;
                if replacement.len() != indices.len() {
                    return Err(format!(
                        "attempt to assign sequence of size {} to extended slice of size {}",
                        replacement.len(),
                        indices.len()
                    ));
                }

                for (index, value) in indices.into_iter().zip(replacement) {
                    borrowed[index] = value;
                }
            }

            drop(borrowed);
            Ok(Value::List(items))
        }
        Value::Tuple(_) => Err("'tuple' object does not support item assignment".to_string()),
        Value::String(_) => Err("'str' object does not support item assignment".to_string()),
        Value::Range { .. } => Err("'range' object does not support item assignment".to_string()),
        value => Err(format!("{value} does not support slice assignment")),
    }
}

fn delete_slice(
    object: Value,
    start: Option<Value>,
    stop: Option<Value>,
    step: Option<Value>,
) -> Result<Value, String> {
    match object {
        Value::List(items) => {
            let start = slice_bound(start)?;
            let stop = slice_bound(stop)?;
            let step = slice_bound(step)?;
            let step_value = slice_step_value(step)?;
            let mut borrowed = items.borrow_mut();

            if step_value == 1 {
                let (start, stop) = contiguous_slice_bounds(borrowed.len(), start, stop)?;
                borrowed.drain(start..stop);
            } else {
                let mut indices = slice_indices(borrowed.len(), start, stop, Some(step_value))?;
                indices.sort_unstable_by(|left, right| right.cmp(left));
                for index in indices {
                    borrowed.remove(index);
                }
            }

            drop(borrowed);
            Ok(Value::List(items))
        }
        Value::Tuple(_) => Err("'tuple' object does not support item deletion".to_string()),
        Value::String(_) => Err("'str' object does not support item deletion".to_string()),
        Value::Range { .. } => Err("'range' object does not support item deletion".to_string()),
        value => Err(format!("{value} does not support slice deletion")),
    }
}

fn load_slice(
    object: Value,
    start: Option<Value>,
    stop: Option<Value>,
    step: Option<Value>,
) -> Result<Value, String> {
    match object {
        Value::List(items) => {
            let items = items.borrow();
            let indices = slice_indices(
                items.len(),
                slice_bound(start)?,
                slice_bound(stop)?,
                slice_bound(step)?,
            )?;
            let items = indices
                .into_iter()
                .map(|index| items[index].clone())
                .collect();
            Ok(list_value(items))
        }
        Value::Tuple(items) => {
            let indices = slice_indices(
                items.len(),
                slice_bound(start)?,
                slice_bound(stop)?,
                slice_bound(step)?,
            )?;
            let items = indices
                .into_iter()
                .map(|index| items[index].clone())
                .collect();
            Ok(tuple_value(items))
        }
        Value::String(value) => {
            let chars = value.chars().collect::<Vec<_>>();
            let indices = slice_indices(
                chars.len(),
                slice_bound(start)?,
                slice_bound(stop)?,
                slice_bound(step)?,
            )?;
            let value = indices
                .into_iter()
                .map(|index| chars[index])
                .collect::<String>();
            Ok(Value::String(value))
        }
        Value::Bytes(value) => {
            let indices = slice_indices(
                value.len(),
                slice_bound(start)?,
                slice_bound(stop)?,
                slice_bound(step)?,
            )?;
            let value = indices.into_iter().map(|index| value[index]).collect();
            Ok(Value::Bytes(value))
        }
        Value::ByteArray(value) => {
            let indices = slice_indices(
                value.len(),
                slice_bound(start)?,
                slice_bound(stop)?,
                slice_bound(step)?,
            )?;
            let value = indices.into_iter().map(|index| value[index]).collect();
            Ok(Value::ByteArray(value))
        }
        Value::Range {
            start: range_start,
            stop: range_stop,
            step: range_step,
        } => {
            let values = range_values(range_start, range_stop, range_step)?;
            let start = slice_bound(start)?;
            let stop = slice_bound(stop)?;
            let step = slice_bound(step)?;
            let slice_step = slice_step_value(step)?;
            let indices = slice_indices(values.len(), start, stop, step)?;

            if let Some(first_index) = indices.first().copied() {
                let last_index = indices
                    .last()
                    .copied()
                    .expect("nonempty indices has a last index");
                let new_step = range_step
                    .checked_mul(slice_step)
                    .ok_or_else(|| "range slice step overflow".to_string())?;
                let new_start = values[first_index];
                let last_value = values[last_index];
                let new_stop = last_value
                    .checked_add(new_step)
                    .ok_or_else(|| "range slice stop overflow".to_string())?;

                Ok(Value::Range {
                    start: new_start,
                    stop: new_stop,
                    step: new_step,
                })
            } else {
                Ok(Value::Range {
                    start: 0,
                    stop: 0,
                    step: 1,
                })
            }
        }
        value => Err(format!("{value} does not support slicing")),
    }
}

fn slice_bound(value: Option<Value>) -> Result<Option<i64>, String> {
    match value {
        Some(Value::Bool(value)) => Ok(Some(bool_as_i64(value))),
        Some(Value::Number(value)) => Ok(Some(value)),
        Some(Value::BigInt(value)) => value
            .to_i64()
            .map(Some)
            .ok_or_else(|| "slice index is too large".to_string()),
        Some(Value::None) => Ok(None),
        Some(value) => Err(format!("slice indices must be integers, got {value}")),
        None => Ok(None),
    }
}

fn slice_step_value(step: Option<i64>) -> Result<i64, String> {
    let step = step.unwrap_or(1);
    if step == 0 {
        return Err("ValueError: slice step cannot be zero".to_string());
    }

    Ok(step)
}

fn contiguous_slice_bounds(
    len: usize,
    start: Option<i64>,
    stop: Option<i64>,
) -> Result<(usize, usize), String> {
    let len = i64::try_from(len).map_err(|_| "sequence is too large".to_string())?;
    let start = normalize_positive_slice_bound(start.unwrap_or(0), len);
    let stop = normalize_positive_slice_bound(stop.unwrap_or(len), len).max(start);

    Ok((
        usize::try_from(start).map_err(|_| "slice index out of range".to_string())?,
        usize::try_from(stop).map_err(|_| "slice index out of range".to_string())?,
    ))
}

fn slice_indices(
    len: usize,
    start: Option<i64>,
    stop: Option<i64>,
    step: Option<i64>,
) -> Result<Vec<usize>, String> {
    let len = i64::try_from(len).map_err(|_| "sequence is too large".to_string())?;
    let (start, stop, step) = normalized_slice_indices(len, start, stop, step)?;
    let mut indices = Vec::new();

    if step > 0 {
        let mut index = start;

        while index < stop {
            indices
                .push(usize::try_from(index).map_err(|_| "slice index out of range".to_string())?);
            index = index
                .checked_add(step)
                .ok_or_else(|| "slice index overflow".to_string())?;
        }
    } else {
        let mut index = start;

        while index > stop {
            indices
                .push(usize::try_from(index).map_err(|_| "slice index out of range".to_string())?);
            index = index
                .checked_add(step)
                .ok_or_else(|| "slice index overflow".to_string())?;
        }
    }

    Ok(indices)
}

fn normalized_slice_indices(
    len: i64,
    start: Option<i64>,
    stop: Option<i64>,
    step: Option<i64>,
) -> Result<(i64, i64, i64), String> {
    let step = slice_step_value(step)?;
    if step > 0 {
        Ok((
            normalize_positive_slice_bound(start.unwrap_or(0), len),
            normalize_positive_slice_bound(stop.unwrap_or(len), len),
            step,
        ))
    } else {
        Ok((
            start
                .map(|value| normalize_negative_slice_bound(value, len))
                .unwrap_or(len - 1),
            stop.map(|value| normalize_negative_slice_bound(value, len))
                .unwrap_or(-1),
            step,
        ))
    }
}

fn normalize_positive_slice_bound(value: i64, len: i64) -> i64 {
    let value = if value < 0 { value + len } else { value };
    value.clamp(0, len)
}

fn normalize_negative_slice_bound(value: i64, len: i64) -> i64 {
    let value = if value < 0 { value + len } else { value };
    value.clamp(-1, len - 1)
}

fn normalized_index(index: Value, len: usize, type_name: &str) -> Result<usize, String> {
    let index = match index {
        Value::Bool(value) => bool_as_i64(value),
        Value::Number(value) => value,
        Value::BigInt(value) => value
            .to_i64()
            .ok_or_else(|| format!("{type_name} index out of range"))?,
        value => return Err(format!("{type_name} indices must be integers, got {value}")),
    };

    let len = i64::try_from(len).map_err(|_| format!("{type_name} is too large"))?;
    let normalized = if index < 0 { len + index } else { index };

    if normalized < 0 || normalized >= len {
        return Err(match type_name {
            "string" => "string index out of range".to_string(),
            "range" => "range object index out of range".to_string(),
            _ => format!("{type_name} index out of range"),
        });
    }

    usize::try_from(normalized).map_err(|_| format!("{type_name} index out of range"))
}

fn range_values(start: i64, stop: i64, step: i64) -> Result<Vec<i64>, String> {
    let mut values = Vec::new();
    let mut current = start;

    while !range_is_exhausted(current, stop, step) {
        values.push(current);
        current = current
            .checked_add(step)
            .ok_or_else(|| "range overflow".to_string())?;
    }

    Ok(values)
}

fn range_is_exhausted(current: i64, stop: i64, step: i64) -> bool {
    if step > 0 {
        current >= stop
    } else {
        current <= stop
    }
}

fn bool_as_i64(value: bool) -> i64 {
    if value { 1 } else { 0 }
}

fn numeric_bool_value(value: Value) -> Value {
    match value {
        Value::Bool(value) => Value::Number(bool_as_i64(value)),
        value => value,
    }
}

fn numeric_bool_operands(left: Value, right: Value) -> (Value, Value) {
    (numeric_bool_value(left), numeric_bool_value(right))
}

fn add_values(left: Value, right: Value) -> Result<Value, String> {
    let (left, right) = numeric_bool_operands(left, right);
    match (left, right) {
        (Value::Number(left), Value::Number(right)) => {
            Ok(normalize_big_int(BigInt::from(left) + BigInt::from(right)))
        }
        (Value::Number(left), Value::BigInt(right)) => {
            Ok(normalize_big_int(BigInt::from(left) + right))
        }
        (Value::BigInt(left), Value::Number(right)) => {
            Ok(normalize_big_int(left + BigInt::from(right)))
        }
        (Value::BigInt(left), Value::BigInt(right)) => Ok(normalize_big_int(left + right)),
        (Value::Number(left), Value::Float(right)) => Ok(Value::Float(left as f64 + right)),
        (Value::Float(left), Value::Number(right)) => Ok(Value::Float(left + right as f64)),
        (Value::BigInt(left), Value::Float(right)) => left
            .to_f64()
            .map(|left| Value::Float(left + right))
            .ok_or_else(|| "integer is too large to add to float".to_string()),
        (Value::Float(left), Value::BigInt(right)) => right
            .to_f64()
            .map(|right| Value::Float(left + right))
            .ok_or_else(|| "integer is too large to add to float".to_string()),
        (Value::Float(left), Value::Float(right)) => Ok(Value::Float(left + right)),
        (
            Value::Complex {
                real: left_real,
                imag: left_imag,
            },
            Value::Complex {
                real: right_real,
                imag: right_imag,
            },
        ) => Ok(Value::Complex {
            real: left_real + right_real,
            imag: left_imag + right_imag,
        }),
        (Value::Complex { real, imag }, Value::Number(value)) => Ok(Value::Complex {
            real: real + value as f64,
            imag,
        }),
        (Value::Complex { real, imag }, Value::BigInt(value)) => value
            .to_f64()
            .map(|value| Value::Complex {
                real: real + value,
                imag,
            })
            .ok_or_else(|| "integer is too large to add to complex".to_string()),
        (Value::Complex { real, imag }, Value::Float(value)) => Ok(Value::Complex {
            real: real + value,
            imag,
        }),
        (Value::Number(value), Value::Complex { real, imag }) => Ok(Value::Complex {
            real: value as f64 + real,
            imag,
        }),
        (Value::BigInt(value), Value::Complex { real, imag }) => value
            .to_f64()
            .map(|value| Value::Complex {
                real: value + real,
                imag,
            })
            .ok_or_else(|| "integer is too large to add to complex".to_string()),
        (Value::Float(value), Value::Complex { real, imag }) => Ok(Value::Complex {
            real: value + real,
            imag,
        }),
        (
            Value::Template {
                strings: left_strings,
                interpolations: left_interpolations,
            },
            Value::Template {
                strings: right_strings,
                interpolations: right_interpolations,
            },
        ) => Ok(concatenate_templates(
            left_strings,
            left_interpolations,
            right_strings,
            right_interpolations,
        )),
        (Value::Template { .. }, right) => Err(format!(
            "TypeError: can only concatenate string.templatelib.Template (not \"{}\") to string.templatelib.Template",
            type_name(&right)
        )),
        (Value::String(left), Value::String(right)) => Ok(Value::String(left + &right)),
        (Value::String(_), Value::Template { .. }) => Err(
            "TypeError: can only concatenate str (not \"string.templatelib.Template\") to str"
                .to_string(),
        ),
        (Value::Bytes(mut left), Value::Bytes(right)) => {
            left.extend(right);
            Ok(Value::Bytes(left))
        }
        (Value::ByteArray(mut left), Value::ByteArray(right)) => {
            left.extend(right);
            Ok(Value::ByteArray(left))
        }
        (Value::ByteArray(mut left), Value::Bytes(right)) => {
            left.extend(right);
            Ok(Value::ByteArray(left))
        }
        (Value::List(left), Value::List(right)) => {
            let mut items = left.borrow().clone();
            items.extend(right.borrow().iter().cloned());
            Ok(list_value(items))
        }
        (Value::Tuple(left), Value::Tuple(right)) => {
            let mut items = left.as_ref().clone();
            items.extend(right.iter().cloned());
            Ok(tuple_value(items))
        }
        (left, right) => Err(format!(
            "TypeError: unsupported operand type(s) for +: '{}' and '{}'",
            type_name(&left),
            type_name(&right)
        )),
    }
}

fn in_place_add_values(left: Value, right: Value) -> Result<Value, String> {
    match left {
        Value::List(items) => {
            let values = sequence_values(right)?;
            items.borrow_mut().extend(values);
            Ok(Value::List(items))
        }
        left => add_values(left, right),
    }
}

fn concatenate_templates(
    mut left_strings: Vec<String>,
    mut left_interpolations: Vec<TemplateInterpolation>,
    right_strings: Vec<String>,
    right_interpolations: Vec<TemplateInterpolation>,
) -> Value {
    let mut right_strings = right_strings.into_iter();

    if let Some(first_right) = right_strings.next() {
        left_strings
            .last_mut()
            .expect("template strings always has a current literal")
            .push_str(&first_right);
    }

    left_interpolations.extend(right_interpolations);
    left_strings.extend(right_strings);

    Value::Template {
        strings: left_strings,
        interpolations: left_interpolations,
    }
}

fn template_iter_values(
    strings: Vec<String>,
    interpolations: Vec<TemplateInterpolation>,
) -> Vec<Value> {
    let mut values = Vec::new();
    let mut interpolations = interpolations.into_iter();

    for string in strings {
        if !string.is_empty() {
            values.push(Value::String(string));
        }
        if let Some(interpolation) = interpolations.next() {
            values.push(Value::TemplateInterpolation(interpolation));
        }
    }

    values
}

fn subtract_values(left: Value, right: Value) -> Result<Value, String> {
    if is_set_operator_value(&left) || is_set_operator_value(&right) {
        let kind = set_result_kind(&left);
        let left = set_operator_operand(left, "-")?;
        let right = set_operator_operand(right, "-")?;
        return set_difference_from_iterables_with_kind(kind, left, &[set_value(right)]);
    }

    let (left, right) = numeric_bool_operands(left, right);
    match (left, right) {
        (Value::Number(left), Value::Number(right)) => {
            Ok(normalize_big_int(BigInt::from(left) - BigInt::from(right)))
        }
        (Value::Number(left), Value::BigInt(right)) => {
            Ok(normalize_big_int(BigInt::from(left) - right))
        }
        (Value::BigInt(left), Value::Number(right)) => {
            Ok(normalize_big_int(left - BigInt::from(right)))
        }
        (Value::BigInt(left), Value::BigInt(right)) => Ok(normalize_big_int(left - right)),
        (Value::Number(left), Value::Float(right)) => Ok(Value::Float(left as f64 - right)),
        (Value::Float(left), Value::Number(right)) => Ok(Value::Float(left - right as f64)),
        (Value::BigInt(left), Value::Float(right)) => left
            .to_f64()
            .map(|left| Value::Float(left - right))
            .ok_or_else(|| "integer is too large to subtract float".to_string()),
        (Value::Float(left), Value::BigInt(right)) => right
            .to_f64()
            .map(|right| Value::Float(left - right))
            .ok_or_else(|| "integer is too large to subtract from float".to_string()),
        (Value::Float(left), Value::Float(right)) => Ok(Value::Float(left - right)),
        (
            Value::Complex {
                real: left_real,
                imag: left_imag,
            },
            Value::Complex {
                real: right_real,
                imag: right_imag,
            },
        ) => Ok(Value::Complex {
            real: left_real - right_real,
            imag: left_imag - right_imag,
        }),
        (Value::Complex { real, imag }, Value::Number(value)) => Ok(Value::Complex {
            real: real - value as f64,
            imag,
        }),
        (Value::Complex { real, imag }, Value::BigInt(value)) => value
            .to_f64()
            .map(|value| Value::Complex {
                real: real - value,
                imag,
            })
            .ok_or_else(|| "integer is too large to subtract from complex".to_string()),
        (Value::Complex { real, imag }, Value::Float(value)) => Ok(Value::Complex {
            real: real - value,
            imag,
        }),
        (Value::Number(value), Value::Complex { real, imag }) => Ok(Value::Complex {
            real: value as f64 - real,
            imag: -imag,
        }),
        (Value::BigInt(value), Value::Complex { real, imag }) => value
            .to_f64()
            .map(|value| Value::Complex {
                real: value - real,
                imag: -imag,
            })
            .ok_or_else(|| "integer is too large to subtract complex".to_string()),
        (Value::Float(value), Value::Complex { real, imag }) => Ok(Value::Complex {
            real: value - real,
            imag: -imag,
        }),
        (left, right) => Err(format!("cannot subtract {left} and {right}")),
    }
}

fn multiply_values(left: Value, right: Value) -> Result<Value, String> {
    let (left, right) = numeric_bool_operands(left, right);
    match (left, right) {
        (Value::Number(left), Value::Number(right)) => {
            Ok(normalize_big_int(BigInt::from(left) * BigInt::from(right)))
        }
        (Value::Number(left), Value::BigInt(right)) => {
            Ok(normalize_big_int(BigInt::from(left) * right))
        }
        (Value::BigInt(left), Value::Number(right)) => {
            Ok(normalize_big_int(left * BigInt::from(right)))
        }
        (Value::BigInt(left), Value::BigInt(right)) => Ok(normalize_big_int(left * right)),
        (Value::Number(left), Value::Float(right)) => Ok(Value::Float(left as f64 * right)),
        (Value::Float(left), Value::Number(right)) => Ok(Value::Float(left * right as f64)),
        (Value::BigInt(left), Value::Float(right)) => left
            .to_f64()
            .map(|left| Value::Float(left * right))
            .ok_or_else(|| "integer is too large to multiply by float".to_string()),
        (Value::Float(left), Value::BigInt(right)) => right
            .to_f64()
            .map(|right| Value::Float(left * right))
            .ok_or_else(|| "integer is too large to multiply by float".to_string()),
        (Value::Float(left), Value::Float(right)) => Ok(Value::Float(left * right)),
        (
            Value::Complex {
                real: left_real,
                imag: left_imag,
            },
            Value::Complex {
                real: right_real,
                imag: right_imag,
            },
        ) => Ok(Value::Complex {
            real: left_real * right_real - left_imag * right_imag,
            imag: left_real * right_imag + left_imag * right_real,
        }),
        (Value::Complex { real, imag }, Value::Number(value))
        | (Value::Number(value), Value::Complex { real, imag }) => Ok(Value::Complex {
            real: real * value as f64,
            imag: imag * value as f64,
        }),
        (Value::Complex { real, imag }, Value::BigInt(value))
        | (Value::BigInt(value), Value::Complex { real, imag }) => value
            .to_f64()
            .map(|value| Value::Complex {
                real: real * value,
                imag: imag * value,
            })
            .ok_or_else(|| "integer is too large to multiply by complex".to_string()),
        (Value::Complex { real, imag }, Value::Float(value))
        | (Value::Float(value), Value::Complex { real, imag }) => Ok(Value::Complex {
            real: real * value,
            imag: imag * value,
        }),
        (Value::List(items), Value::Number(count)) | (Value::Number(count), Value::List(items)) => {
            Ok(list_value(repeat_values(items.borrow().clone(), count)?))
        }
        (Value::List(items), Value::BigInt(count)) | (Value::BigInt(count), Value::List(items)) => {
            Ok(list_value(repeat_values(
                items.borrow().clone(),
                big_int_repeat_count(&count)?,
            )?))
        }
        (Value::Tuple(items), Value::Number(count))
        | (Value::Number(count), Value::Tuple(items)) => {
            Ok(tuple_value(repeat_values(items.as_ref().clone(), count)?))
        }
        (Value::Tuple(items), Value::BigInt(count))
        | (Value::BigInt(count), Value::Tuple(items)) => Ok(tuple_value(repeat_values(
            items.as_ref().clone(),
            big_int_repeat_count(&count)?,
        )?)),
        (Value::String(value), Value::Number(count))
        | (Value::Number(count), Value::String(value)) => {
            Ok(Value::String(repeat_string(value, count)?))
        }
        (Value::String(value), Value::BigInt(count))
        | (Value::BigInt(count), Value::String(value)) => Ok(Value::String(repeat_string(
            value,
            big_int_repeat_count(&count)?,
        )?)),
        (Value::Bytes(value), Value::Number(count))
        | (Value::Number(count), Value::Bytes(value)) => {
            Ok(Value::Bytes(repeat_bytes(value, count)?))
        }
        (Value::Bytes(value), Value::BigInt(count))
        | (Value::BigInt(count), Value::Bytes(value)) => Ok(Value::Bytes(repeat_bytes(
            value,
            big_int_repeat_count(&count)?,
        )?)),
        (Value::ByteArray(value), Value::Number(count))
        | (Value::Number(count), Value::ByteArray(value)) => {
            Ok(Value::ByteArray(repeat_bytes(value, count)?))
        }
        (Value::ByteArray(value), Value::BigInt(count))
        | (Value::BigInt(count), Value::ByteArray(value)) => Ok(Value::ByteArray(repeat_bytes(
            value,
            big_int_repeat_count(&count)?,
        )?)),
        (left, right) => Err(format!("cannot multiply {left} and {right}")),
    }
}

fn big_int_repeat_count(count: &BigInt) -> Result<i64, String> {
    count
        .to_i64()
        .ok_or_else(|| "sequence repeat count is too large".to_string())
}

fn repeat_values(values: Vec<Value>, count: i64) -> Result<Vec<Value>, String> {
    if count <= 0 {
        return Ok(Vec::new());
    }

    let count =
        usize::try_from(count).map_err(|_| "sequence repeat count is too large".to_string())?;
    values
        .len()
        .checked_mul(count)
        .ok_or_else(|| "sequence repeat count is too large".to_string())?;

    let mut repeated = Vec::with_capacity(values.len() * count);
    for _ in 0..count {
        repeated.extend(values.iter().cloned());
    }
    Ok(repeated)
}

fn repeat_string(value: String, count: i64) -> Result<String, String> {
    if count <= 0 {
        return Ok(String::new());
    }

    let count =
        usize::try_from(count).map_err(|_| "sequence repeat count is too large".to_string())?;
    value
        .len()
        .checked_mul(count)
        .ok_or_else(|| "sequence repeat count is too large".to_string())?;

    Ok(value.repeat(count))
}

fn repeat_bytes(value: Vec<u8>, count: i64) -> Result<Vec<u8>, String> {
    if count <= 0 {
        return Ok(Vec::new());
    }

    let count =
        usize::try_from(count).map_err(|_| "sequence repeat count is too large".to_string())?;
    value
        .len()
        .checked_mul(count)
        .ok_or_else(|| "sequence repeat count is too large".to_string())?;

    let mut repeated = Vec::with_capacity(value.len() * count);
    for _ in 0..count {
        repeated.extend_from_slice(&value);
    }
    Ok(repeated)
}

fn true_divide_values(left: Value, right: Value) -> Result<Value, String> {
    let (left, right) = numeric_bool_operands(left, right);
    let (left_display, right_display) = (left.to_string(), right.to_string());
    match (number_as_f64(left), number_as_f64(right)) {
        (Some(_), Some(0.0)) => Err("division by zero".to_string()),
        (Some(left), Some(right)) => Ok(Value::Float(left / right)),
        _ => Err(format!("cannot divide {left_display} and {right_display}")),
    }
}

fn is_zero_division_error_message(message: &str) -> bool {
    matches!(
        message,
        "division by zero"
            | "integer division or modulo by zero"
            | "float floor division by zero"
            | "float modulo"
            | "0.0 cannot be raised to a negative power"
    )
}

fn floor_divide_values(left: Value, right: Value) -> Result<Value, String> {
    let (left, right) = numeric_bool_operands(left, right);
    match (left, right) {
        (Value::Number(_), Value::Number(0)) => {
            Err("integer division or modulo by zero".to_string())
        }
        (Value::BigInt(_), Value::BigInt(ref right)) if right.is_zero() => {
            Err("integer division or modulo by zero".to_string())
        }
        (Value::Number(_), Value::BigInt(ref right)) if right.is_zero() => {
            Err("integer division or modulo by zero".to_string())
        }
        (Value::BigInt(_), Value::Number(0)) => {
            Err("integer division or modulo by zero".to_string())
        }
        (Value::Number(left), Value::Number(right)) => Ok(normalize_big_int(
            BigInt::from(left).div_floor(&BigInt::from(right)),
        )),
        (Value::Number(left), Value::BigInt(right)) => {
            Ok(normalize_big_int(BigInt::from(left).div_floor(&right)))
        }
        (Value::BigInt(left), Value::Number(right)) => {
            Ok(normalize_big_int(left.div_floor(&BigInt::from(right))))
        }
        (Value::BigInt(left), Value::BigInt(right)) => {
            Ok(normalize_big_int(left.div_floor(&right)))
        }
        (left, right) => {
            let (left_display, right_display) = (left.to_string(), right.to_string());
            match (number_as_f64(left), number_as_f64(right)) {
                (Some(_), Some(0.0)) => Err("float floor division by zero".to_string()),
                (Some(left), Some(right)) => Ok(Value::Float((left / right).floor())),
                _ => Err(format!(
                    "cannot floor divide {left_display} and {right_display}"
                )),
            }
        }
    }
}

fn modulo_values(left: Value, right: Value) -> Result<Value, String> {
    if let Value::String(format) = left {
        return percent_format_string(&format, right).map(Value::String);
    }

    let (left, right) = numeric_bool_operands(left, right);
    match (left, right) {
        (Value::Number(_), Value::Number(0)) => {
            Err("integer division or modulo by zero".to_string())
        }
        (Value::BigInt(_), Value::BigInt(ref right)) if right.is_zero() => {
            Err("integer division or modulo by zero".to_string())
        }
        (Value::Number(_), Value::BigInt(ref right)) if right.is_zero() => {
            Err("integer division or modulo by zero".to_string())
        }
        (Value::BigInt(_), Value::Number(0)) => {
            Err("integer division or modulo by zero".to_string())
        }
        (Value::Number(left), Value::Number(right)) => Ok(normalize_big_int(
            BigInt::from(left).mod_floor(&BigInt::from(right)),
        )),
        (Value::Number(left), Value::BigInt(right)) => {
            Ok(normalize_big_int(BigInt::from(left).mod_floor(&right)))
        }
        (Value::BigInt(left), Value::Number(right)) => {
            Ok(normalize_big_int(left.mod_floor(&BigInt::from(right))))
        }
        (Value::BigInt(left), Value::BigInt(right)) => {
            Ok(normalize_big_int(left.mod_floor(&right)))
        }
        (left, right) => {
            let (left_display, right_display) = (left.to_string(), right.to_string());
            match (number_as_f64(left), number_as_f64(right)) {
                (Some(_), Some(0.0)) => Err("float modulo".to_string()),
                (Some(left), Some(right)) => {
                    Ok(Value::Float(left - (left / right).floor() * right))
                }
                _ => Err(format!("cannot modulo {left_display} and {right_display}")),
            }
        }
    }
}

fn percent_format_string(format: &str, value: Value) -> Result<String, String> {
    let mapping = match &value {
        Value::Dict(_)
        | Value::MappingProxy { .. }
        | Value::ChainMap { .. }
        | Value::UserDict { .. }
        | Value::ScopeDict(_) => Some(value.clone()),
        _ => None,
    };
    let args = match value {
        Value::Tuple(items) => items.as_ref().clone(),
        value => vec![value],
    };
    let mut arg_index = 0;
    let mut used_mapping = false;
    let mut output = String::new();
    let mut chars = format.chars().peekable();

    while let Some(ch) = chars.next() {
        if ch != '%' {
            output.push(ch);
            continue;
        }

        let mut spec = parse_percent_format_spec(&mut chars)?;
        if spec.is_plain_percent() {
            output.push('%');
            continue;
        }

        if spec.mapping_key.is_some() && spec.uses_dynamic_width_or_precision() {
            return Err(
                "ValueError: * cannot be used with a parenthesised mapping key".to_string(),
            );
        }
        if spec.mapping_key.is_none() && used_mapping {
            return Err("ValueError: format requires a parenthesised mapping key".to_string());
        }
        resolve_percent_dynamic_spec(&mut spec, &args, &mut arg_index)?;

        let arg = if let Some(key) = &spec.mapping_key {
            used_mapping = true;
            let mapping = mapping
                .as_ref()
                .ok_or_else(|| "TypeError: format requires a mapping".to_string())?;
            load_subscript(mapping.clone(), Value::String(key.clone()))?
        } else {
            take_percent_arg(&args, &mut arg_index)?
        };

        match spec.specifier {
            's' => output.push_str(&percent_format_text(str_value_checked(&arg)?, &spec)),
            'r' => output.push_str(&percent_format_text(repr_value_checked(&arg)?, &spec)),
            'a' => output.push_str(&percent_format_text(ascii_repr_value_checked(&arg)?, &spec)),
            'd' | 'i' | 'u' => output.push_str(&percent_format_integer(&arg, &spec)?),
            'x' | 'X' | 'o' => output.push_str(&percent_format_integer_radix(&arg, &spec)?),
            'c' => output.push_str(&percent_format_text(percent_format_char(&arg)?, &spec)),
            'f' | 'F' | 'e' | 'E' | 'g' | 'G' => {
                output.push_str(&percent_format_float(&arg, &spec)?)
            }
            specifier => {
                return Err(format!("ValueError: unsupported format %{specifier}"));
            }
        }
    }

    if !used_mapping && arg_index < args.len() {
        return Err("TypeError: not all arguments converted during string formatting".to_string());
    }

    Ok(output)
}

#[derive(Default)]
struct PercentFormatSpec {
    mapping_key: Option<String>,
    alternate: bool,
    zero_pad: bool,
    left_align: bool,
    sign: Option<char>,
    width: Option<usize>,
    width_from_arg: bool,
    precision: Option<usize>,
    precision_from_arg: bool,
    specifier: char,
}

impl PercentFormatSpec {
    fn is_plain_percent(&self) -> bool {
        self.specifier == '%'
            && self.mapping_key.is_none()
            && !self.alternate
            && !self.zero_pad
            && !self.left_align
            && self.sign.is_none()
            && self.width.is_none()
            && !self.width_from_arg
            && self.precision.is_none()
            && !self.precision_from_arg
    }

    fn uses_dynamic_width_or_precision(&self) -> bool {
        self.width_from_arg || self.precision_from_arg
    }
}

fn parse_percent_format_spec(
    chars: &mut std::iter::Peekable<std::str::Chars<'_>>,
) -> Result<PercentFormatSpec, String> {
    if chars.peek().is_none() {
        return Err("ValueError: stray %".to_string());
    }

    let mut spec = PercentFormatSpec::default();
    if chars.peek().copied() == Some('(') {
        chars.next();
        let mut key = String::new();
        loop {
            match chars.next() {
                Some(')') => break,
                Some(ch) => key.push(ch),
                None => return Err("ValueError: incomplete format key".to_string()),
            }
        }
        spec.mapping_key = Some(key);
    }

    while let Some(ch) = chars.peek().copied() {
        match ch {
            '#' => spec.alternate = true,
            '0' => spec.zero_pad = true,
            '-' => spec.left_align = true,
            '+' => spec.sign = Some('+'),
            ' ' if spec.sign != Some('+') => spec.sign = Some(' '),
            ' ' => {}
            _ => break,
        }
        chars.next();
    }

    if chars.peek().copied() == Some('*') {
        chars.next();
        spec.width_from_arg = true;
    } else {
        spec.width = parse_percent_usize(chars)?;
    }
    if chars.peek().copied() == Some('.') {
        chars.next();
        if chars.peek().copied() == Some('*') {
            chars.next();
            spec.precision_from_arg = true;
        } else {
            spec.precision = Some(parse_percent_usize(chars)?.unwrap_or(0));
        }
    }
    while matches!(chars.peek().copied(), Some('h' | 'l' | 'L')) {
        chars.next();
    }
    spec.specifier = chars
        .next()
        .ok_or_else(|| "ValueError: stray %".to_string())?;
    Ok(spec)
}

fn parse_percent_usize(
    chars: &mut std::iter::Peekable<std::str::Chars<'_>>,
) -> Result<Option<usize>, String> {
    let mut digits = String::new();
    while let Some(ch) = chars.peek().copied() {
        if !ch.is_ascii_digit() {
            break;
        }
        digits.push(ch);
        chars.next();
    }
    if digits.is_empty() {
        Ok(None)
    } else {
        digits
            .parse::<usize>()
            .map(Some)
            .map_err(|_| "OverflowError: formatted field width is too large".to_string())
    }
}

fn resolve_percent_dynamic_spec(
    spec: &mut PercentFormatSpec,
    args: &[Value],
    arg_index: &mut usize,
) -> Result<(), String> {
    if spec.width_from_arg {
        let value = take_percent_arg(args, arg_index)?;
        let width = percent_star_integer(&value)?;
        if width.is_negative() {
            spec.left_align = true;
        }
        spec.width = Some(
            width
                .abs()
                .to_usize()
                .ok_or_else(|| "OverflowError: format argument too big for width".to_string())?,
        );
    }

    if spec.precision_from_arg {
        let value = take_percent_arg(args, arg_index)?;
        let precision = percent_star_integer(&value)?;
        spec.precision = if precision.is_negative() {
            Some(0)
        } else {
            Some(precision.to_usize().ok_or_else(|| {
                "OverflowError: format argument too big for precision".to_string()
            })?)
        };
    }

    Ok(())
}

fn take_percent_arg(args: &[Value], arg_index: &mut usize) -> Result<Value, String> {
    let arg = args
        .get(*arg_index)
        .ok_or_else(|| "TypeError: not enough arguments for format string".to_string())?;
    *arg_index += 1;
    Ok(arg.clone())
}

fn percent_star_integer(value: &Value) -> Result<BigInt, String> {
    match value {
        Value::Bool(value) => Ok(BigInt::from(bool_as_i64(*value))),
        Value::Number(value) => Ok(BigInt::from(*value)),
        Value::BigInt(value) => Ok(value.clone()),
        _ => Err("TypeError: * wants int".to_string()),
    }
}

fn percent_format_text(mut text: String, spec: &PercentFormatSpec) -> String {
    if let Some(precision) = spec.precision {
        text = text.chars().take(precision).collect();
    }
    percent_pad_text(text, spec)
}

fn percent_pad_text(text: String, spec: &PercentFormatSpec) -> String {
    let Some(width) = spec.width else {
        return text;
    };
    let len = text.chars().count();
    if len >= width {
        return text;
    }
    let padding = " ".repeat(width - len);
    if spec.left_align {
        format!("{text}{padding}")
    } else {
        format!("{padding}{text}")
    }
}

fn percent_format_integer(value: &Value, spec: &PercentFormatSpec) -> Result<String, String> {
    let value = match value {
        Value::Bool(value) => BigInt::from(bool_as_i64(*value)),
        Value::Number(value) => BigInt::from(*value),
        Value::BigInt(value) => value.clone(),
        Value::Float(value) => percent_float_to_integer(*value)?,
        value => Err(format!(
            "TypeError: %d format: a real number is required, not {}",
            type_name(value)
        ))?,
    };
    percent_format_integer_body(&value, 10, false, spec)
}

fn percent_format_integer_radix(value: &Value, spec: &PercentFormatSpec) -> Result<String, String> {
    let value = match value {
        Value::Bool(value) => BigInt::from(bool_as_i64(*value)),
        Value::Number(value) => BigInt::from(*value),
        Value::BigInt(value) => value.clone(),
        value => {
            return Err(format!(
                "TypeError: %{} format: an integer is required, not {}",
                spec.specifier,
                type_name(value)
            ));
        }
    };
    let (radix, uppercase) = match spec.specifier {
        'x' => (16, false),
        'X' => (16, true),
        'o' => (8, false),
        _ => unreachable!("caller filters old-style integer radix specifiers"),
    };
    percent_format_integer_body(&value, radix, uppercase, spec)
}

fn percent_format_integer_body(
    value: &BigInt,
    radix: u32,
    uppercase: bool,
    spec: &PercentFormatSpec,
) -> Result<String, String> {
    let negative = value.is_negative();
    let mut digits = if spec.precision == Some(0) && value.is_zero() {
        String::new()
    } else {
        value.abs().to_str_radix(radix)
    };
    if radix == 10 {
        let max_digits = get_int_max_str_digits();
        if max_digits != 0 && digits.len() > max_digits {
            return Err(int_string_conversion_limit_error(max_digits, digits.len()));
        }
    }
    if uppercase {
        digits = digits.to_uppercase();
    }

    if let Some(precision) = spec.precision {
        if digits.len() < precision {
            digits = format!("{}{}", "0".repeat(precision - digits.len()), digits);
        }
    }

    let sign = if negative {
        "-"
    } else if matches!(spec.sign, Some('+')) {
        "+"
    } else if matches!(spec.sign, Some(' ')) {
        " "
    } else {
        ""
    };
    let prefix = if spec.alternate {
        format_integer_prefix(radix, uppercase)
    } else {
        ""
    };

    if spec.zero_pad && !spec.left_align {
        if let Some(width) = spec.width {
            let fixed_len = sign.len() + prefix.len();
            let min_digits = width.saturating_sub(fixed_len);
            if digits.len() < min_digits {
                digits = format!("{}{}", "0".repeat(min_digits - digits.len()), digits);
            }
        }
    }

    let body = format!("{sign}{prefix}{digits}");
    Ok(percent_pad_text(body, spec))
}

fn percent_format_char(value: &Value) -> Result<String, String> {
    match value {
        Value::String(value) => {
            if value.chars().count() == 1 {
                Ok(value.clone())
            } else {
                Err(format!(
                    "TypeError: %c requires int or char, not a string of length {}",
                    value.chars().count()
                ))
            }
        }
        Value::Bool(value) => percent_format_codepoint(BigInt::from(bool_as_i64(*value))),
        Value::Number(value) => percent_format_codepoint(BigInt::from(*value)),
        Value::BigInt(value) => percent_format_codepoint(value.clone()),
        value => Err(format!(
            "TypeError: %c requires int or char, not {}",
            type_name(value)
        )),
    }
}

fn percent_format_codepoint(value: BigInt) -> Result<String, String> {
    let Some(code_point) = value.to_u32() else {
        return Err("OverflowError: %c arg not in range(0x110000)".to_string());
    };
    let Some(ch) = char::from_u32(code_point) else {
        return Err("OverflowError: %c arg not in range(0x110000)".to_string());
    };
    Ok(ch.to_string())
}

fn percent_float_to_integer(value: f64) -> Result<BigInt, String> {
    if value.is_nan() {
        return Err("ValueError: cannot convert float NaN to integer".to_string());
    }
    if value.is_infinite() {
        return Err("OverflowError: cannot convert float infinity to integer".to_string());
    }
    value
        .trunc()
        .to_i64()
        .map(BigInt::from)
        .ok_or_else(|| "OverflowError: cannot convert float to integer".to_string())
}

fn percent_format_float(value: &Value, spec: &PercentFormatSpec) -> Result<String, String> {
    let value = percent_float_value(value, spec.specifier)?;
    let precision = spec.precision.unwrap_or(6);
    let mut body = match spec.specifier {
        'f' | 'F' => format!("{value:.precision$}"),
        'e' => normalize_float_exponent(format!("{value:.precision$e}")),
        'E' => normalize_float_exponent(format!("{value:.precision$E}")),
        'g' => percent_format_general_float(value, precision, spec.alternate, false),
        'G' => percent_format_general_float(value, precision, spec.alternate, true),
        _ => unreachable!("caller filters old-style float specifiers"),
    };
    if !body.starts_with('-') && matches!(spec.sign, Some('+') | Some(' ')) {
        body.insert(0, spec.sign.expect("sign was just matched"));
    }
    Ok(percent_pad_numeric_text(body, spec))
}

fn percent_float_value(value: &Value, specifier: char) -> Result<f64, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(*value) as f64),
        Value::Number(value) => Ok(*value as f64),
        Value::BigInt(value) => value.to_f64().ok_or_else(|| {
            format!("OverflowError: %{specifier} format: a real number is required")
        }),
        Value::Float(value) => Ok(*value),
        value => Err(format!(
            "TypeError: %{specifier} format: a real number is required, not {}",
            type_name(value)
        )),
    }
}

fn percent_format_general_float(
    value: f64,
    precision: usize,
    alternate: bool,
    uppercase: bool,
) -> String {
    let precision = precision.max(1);
    if value == 0.0 {
        let body = format!("{value:.precision$}", precision = precision - 1);
        return if alternate {
            body
        } else {
            strip_float_trailing_zeros(body)
        };
    }

    let exponent = value.abs().log10().floor() as i32;
    if exponent < -4 || exponent >= precision as i32 {
        let digits_after_decimal = precision - 1;
        let body = if uppercase {
            format!("{value:.digits_after_decimal$E}")
        } else {
            format!("{value:.digits_after_decimal$e}")
        };
        let body = normalize_float_exponent(body);
        if alternate {
            body
        } else {
            strip_general_float_trailing_zeros(body)
        }
    } else {
        let digits_after_decimal = if exponent >= 0 {
            precision as i32 - exponent - 1
        } else {
            precision as i32 - 1 - exponent
        }
        .max(0) as usize;
        let body = format!("{value:.digits_after_decimal$}");
        if alternate {
            body
        } else {
            strip_float_trailing_zeros(body)
        }
    }
}

fn normalize_float_exponent(value: String) -> String {
    let Some(index) = value.find(['e', 'E']) else {
        return value;
    };
    let (mantissa, exponent) = value.split_at(index);
    let marker = &exponent[..1];
    let exponent = exponent[1..].parse::<i32>().unwrap_or(0);
    let sign = if exponent < 0 { '-' } else { '+' };
    format!("{mantissa}{marker}{sign}{:02}", exponent.abs())
}

fn strip_general_float_trailing_zeros(value: String) -> String {
    let Some(index) = value.find(['e', 'E']) else {
        return strip_float_trailing_zeros(value);
    };
    let (mantissa, exponent) = value.split_at(index);
    format!(
        "{}{}",
        strip_float_trailing_zeros(mantissa.to_string()),
        exponent
    )
}

fn strip_float_trailing_zeros(mut value: String) -> String {
    if !value.contains('.') {
        return value;
    }
    while value.ends_with('0') {
        value.pop();
    }
    if value.ends_with('.') {
        value.pop();
    }
    if value == "-0" {
        "-0".to_string()
    } else {
        value
    }
}

fn percent_pad_numeric_text(text: String, spec: &PercentFormatSpec) -> String {
    let Some(width) = spec.width else {
        return text;
    };
    let len = text.chars().count();
    if len >= width {
        return text;
    }
    let padding = " ".repeat(width - len);
    if spec.left_align {
        return format!("{text}{padding}");
    }
    if spec.zero_pad {
        let mut chars = text.chars();
        if let Some(first) = chars.next()
            && matches!(first, '+' | '-' | ' ')
        {
            let rest = chars.collect::<String>();
            return format!("{first}{}{rest}", "0".repeat(width - len));
        }
        return format!("{}{text}", "0".repeat(width - len));
    }
    format!("{padding}{text}")
}

fn power_values(left: Value, right: Value) -> Result<Value, String> {
    let (left, right) = numeric_bool_operands(left, right);
    match (left, right) {
        (Value::Number(left), Value::Number(right)) if right < 0 => {
            negative_integer_power(BigInt::from(left), BigInt::from(right))
        }
        (Value::BigInt(left), Value::Number(right)) if right < 0 => {
            negative_integer_power(left, BigInt::from(right))
        }
        (Value::Number(left), Value::BigInt(right)) if right.is_negative() => {
            negative_integer_power(BigInt::from(left), right)
        }
        (Value::BigInt(left), Value::BigInt(right)) if right.is_negative() => {
            negative_integer_power(left, right)
        }
        (Value::Number(left), Value::Number(right)) => {
            let exponent = u32::try_from(right)
                .map_err(|_| "negative exponent is not supported".to_string())?;
            Ok(normalize_big_int(BigInt::from(left).pow(exponent)))
        }
        (Value::BigInt(left), Value::Number(right)) => {
            let exponent = u32::try_from(right)
                .map_err(|_| "negative exponent is not supported".to_string())?;
            Ok(normalize_big_int(left.pow(exponent)))
        }
        (Value::Number(left), Value::BigInt(right)) => {
            let exponent = right
                .to_u32()
                .ok_or_else(|| "integer exponent is too large".to_string())?;
            Ok(normalize_big_int(BigInt::from(left).pow(exponent)))
        }
        (Value::BigInt(left), Value::BigInt(right)) => {
            let exponent = right
                .to_u32()
                .ok_or_else(|| "integer exponent is too large".to_string())?;
            Ok(normalize_big_int(left.pow(exponent)))
        }
        (left, right) => {
            let (left_display, right_display) = (left.to_string(), right.to_string());
            match (number_as_f64(left), number_as_f64(right)) {
                (Some(left), Some(right)) => Ok(Value::Float(left.powf(right))),
                _ => Err(format!("cannot power {left_display} and {right_display}")),
            }
        }
    }
}

fn negative_integer_power(base: BigInt, exponent: BigInt) -> Result<Value, String> {
    if base.is_zero() {
        return Err("0.0 cannot be raised to a negative power".to_string());
    }
    let base = base
        .to_f64()
        .ok_or_else(|| "int too large to convert to float".to_string())?;
    let exponent = exponent
        .to_f64()
        .ok_or_else(|| "integer exponent is too large".to_string())?;
    Ok(Value::Float(base.powf(exponent)))
}

fn modular_inverse(value: &BigInt, modulus: &BigInt) -> Option<BigInt> {
    let mut previous_coefficient = BigInt::zero();
    let mut coefficient = BigInt::from(1);
    let mut previous_remainder = modulus.clone();
    let mut remainder = value.mod_floor(modulus);

    while !remainder.is_zero() {
        let quotient = &previous_remainder / &remainder;

        let next_coefficient = &previous_coefficient - &quotient * &coefficient;
        previous_coefficient = coefficient;
        coefficient = next_coefficient;

        let next_remainder = &previous_remainder - &quotient * &remainder;
        previous_remainder = remainder;
        remainder = next_remainder;
    }

    if previous_remainder != BigInt::from(1) {
        return None;
    }
    if previous_coefficient.is_negative() {
        previous_coefficient += modulus;
    }
    Some(previous_coefficient)
}

fn pow_mod_type_error() -> String {
    "TypeError: pow() 3rd argument not allowed unless all arguments are integers".to_string()
}

fn bit_or_values(left: Value, right: Value) -> Result<Value, String> {
    if is_set_operator_value(&left) || is_set_operator_value(&right) {
        let kind = set_result_kind(&left);
        let left = set_operator_operand(left, "|")?;
        let right = set_operator_operand(right, "|")?;
        return set_union_from_iterables_with_kind(kind, left, &[set_value(right)]);
    }

    if is_type_union_operand(&left) && is_type_union_operand(&right) {
        return Ok(union_type_value(left, right));
    }

    match (left, right) {
        (Value::Bool(left), Value::Bool(right)) => Ok(Value::Bool(left | right)),
        (Value::Dict(left), Value::Dict(right)) => {
            dict_union_from_entries(left.borrow().clone(), right.borrow().clone())
        }
        (Value::MappingProxy { entries: left }, Value::Dict(right))
        | (Value::Dict(left), Value::MappingProxy { entries: right })
        | (Value::MappingProxy { entries: left }, Value::MappingProxy { entries: right }) => {
            dict_union_from_entries(left.borrow().clone(), right.borrow().clone())
        }
        (Value::MappingProxy { .. }, right) => Err(format!(
            "TypeError: unsupported operand type(s) for |: 'dict' and '{}'",
            type_name(&right)
        )),
        (left, Value::MappingProxy { .. }) => Err(format!(
            "TypeError: unsupported operand type(s) for |: '{}' and 'dict'",
            type_name(&left)
        )),
        (left, right) => {
            let (left, right) = numeric_bool_operands(left, right);
            bit_or_numbers(left, right)
        }
    }
}

fn is_type_union_operand(value: &Value) -> bool {
    match value {
        Value::Builtin(name) => is_builtin_type_object_name(name),
        Value::None => true,
        Value::Class { .. }
        | Value::TypeParam { .. }
        | Value::TypeAlias { .. }
        | Value::GenericAlias { .. } => true,
        _ => false,
    }
}

fn union_type_value(left: Value, right: Value) -> Value {
    let mut args = Vec::new();
    extend_union_args(&mut args, left);
    extend_union_args(&mut args, right);
    generic_alias_value(builtin_type_value("Union"), args)
}

fn extend_union_args(args: &mut Vec<Value>, value: Value) {
    match value {
        Value::GenericAlias {
            origin,
            args: nested,
        } if matches!(origin.as_ref(), Value::Builtin(name) if name == "Union") => {
            for value in nested {
                push_unique_union_arg(args, value);
            }
        }
        value => push_unique_union_arg(args, value),
    }
}

fn push_unique_union_arg(args: &mut Vec<Value>, value: Value) {
    let value = match value {
        Value::None => builtin_type_value("NoneType"),
        value => value,
    };
    if !args.iter().any(|existing| existing == &value) {
        args.push(value);
    }
}

fn in_place_bit_or_values(left: Value, right: Value) -> Result<Value, String> {
    match left {
        Value::MappingProxy { .. } | Value::MappingProxyObject { .. } => {
            Err("TypeError: '|=' is not supported by mappingproxy; use '|' instead".to_string())
        }
        Value::Dict(entries) => {
            let updates = dict_entries_from_update_source(right)?;
            let mut entries_ref = entries.borrow_mut();
            for (key, value) in updates {
                insert_live_dict_entry(&mut entries_ref, key, value)?;
            }
            drop(entries_ref);
            Ok(Value::Dict(entries))
        }
        Value::Set(items) => {
            let other = set_operator_operand(right, "|=")?;
            let mut items_ref = items.borrow_mut();
            for value in other {
                insert_set_item(&mut items_ref, value)?;
            }
            drop(items_ref);
            Ok(Value::Set(items))
        }
        left => bit_or_values(left, right),
    }
}

fn bit_or_numbers(left: Value, right: Value) -> Result<Value, String> {
    match (left, right) {
        (Value::Number(left), Value::Number(right)) => {
            Ok(normalize_big_int(BigInt::from(left) | BigInt::from(right)))
        }
        (Value::Number(left), Value::BigInt(right)) => {
            Ok(normalize_big_int(BigInt::from(left) | right))
        }
        (Value::BigInt(left), Value::Number(right)) => {
            Ok(normalize_big_int(left | BigInt::from(right)))
        }
        (Value::BigInt(left), Value::BigInt(right)) => Ok(normalize_big_int(left | right)),
        (left, right) => Err(format!("cannot bitwise-or {left} and {right}")),
    }
}

fn bit_xor_values(left: Value, right: Value) -> Result<Value, String> {
    if is_set_operator_value(&left) || is_set_operator_value(&right) {
        let kind = set_result_kind(&left);
        let left = set_operator_operand(left, "^")?;
        let right = set_operator_operand(right, "^")?;
        return set_symmetric_difference_from_iterable_with_kind(kind, left, &set_value(right));
    }

    match (left, right) {
        (Value::Bool(left), Value::Bool(right)) => Ok(Value::Bool(left ^ right)),
        (left, right) => {
            let (left, right) = numeric_bool_operands(left, right);
            bit_xor_numbers(left, right)
        }
    }
}

