fn left_shift_values(left: Value, right: Value) -> Result<Value, String> {
    let (left, right) = numeric_bool_operands(left, right);
    match (left, right) {
        (Value::Number(_), Value::Number(right)) if right < 0 => {
            Err("negative shift count".to_string())
        }
        (Value::BigInt(_), Value::Number(right)) if right < 0 => {
            Err("negative shift count".to_string())
        }
        (Value::Number(_), Value::BigInt(ref right))
        | (Value::BigInt(_), Value::BigInt(ref right))
            if right < &BigInt::zero() =>
        {
            Err("negative shift count".to_string())
        }
        (Value::Number(left), Value::Number(right)) => {
            let shift = u32::try_from(right).map_err(|_| "negative shift count".to_string())?;
            Ok(normalize_big_int(BigInt::from(left) << shift))
        }
        (Value::BigInt(left), Value::Number(right)) => {
            let shift = usize::try_from(right).map_err(|_| "negative shift count".to_string())?;
            Ok(normalize_big_int(left << shift))
        }
        (Value::Number(left), Value::BigInt(right)) => {
            let shift = right
                .to_usize()
                .ok_or_else(|| "shift count is too large".to_string())?;
            Ok(normalize_big_int(BigInt::from(left) << shift))
        }
        (Value::BigInt(left), Value::BigInt(right)) => {
            let shift = right
                .to_usize()
                .ok_or_else(|| "shift count is too large".to_string())?;
            Ok(normalize_big_int(left << shift))
        }
        (left, right) => Err(format!("cannot left-shift {left} and {right}")),
    }
}

